gameforge.collect_quest_lv92._145_npcChat = "Juwelen f\252r die Waffenforschung"
gameforge.collect_quest_lv92._150_say = "Tu? Aici? \206mi pare r\227u dar \238nc\227 nu am terminat de[ENTER]cercetat ultima bijuterie. Revino mai t\226rziu."
gameforge.collect_quest_lv92._160_say = "Nu ai g\227sit \238nc\227 nimic? Atunci de ce te afli[ENTER]aici? Hai, gr\227be\186te-te! Revino c\226nd aduci cu tine[ENTER]ni\186te bijuterii!"
gameforge.collect_quest_lv92._170_say = "Ai g\227sit o bijuterie? Minunat! A\186teapt\227 o[ENTER]secund\227, trebuie s\227 m\227 asigur ..."
gameforge.collect_quest_lv92._180_say = "Oh da, este bun\227. F\227r\227 \238ndoial\227 este una dintre[ENTER]cele mai frumoase bijuterii pe care le-am v\227zut.[ENTER]Mul\254umesc!"
gameforge.collect_quest_lv92._190_say = "Dar dup\227 cum bine \186tii \238nc\227 mai am nevoie de %s[ENTER]bijuterii cu a\186a calitate superioar\227. Acorda-mi o[ENTER]zi pentru a o studia pe aceasta. Dup\227 asta po\254i[ENTER]aduce pe urm\227toarea."
gameforge.collect_quest_lv92._200_say = "Mult noroc!"
gameforge.collect_quest_lv92._210_say = "Aceasta a fost ultim\227 bijuterie, ai str\238ns toate[ENTER]cele 10 bijuterii. \206\254i sunt recunosc\227tor ... \186i[ENTER]nu voi fi zg\238rcit cu recompensa. Acum alege!"
