gameforge.deviltower_zone._230_say = "Nivelul t\227u este prea sc\227zut. Nu \238\254i pot permite[ENTER]s\227 calci etajele superioare. Revino c\226nd ai[ENTER]adunat mai mult\227 experien\254\227. Ai nevoie cel pu\254in[ENTER]de nivelul 75. "
gameforge.deviltower_zone._240_dNotice = "Harta Turnului Zin-Sa-Gui deschide calea catre[ENTER]urmatorul etaj. Le poti gasi distrugand Pietrele[ENTER]Metin."
gameforge.deviltower_zone._250_say = "Aceast\227 hart\227 te teleporteaz\227 la etajul 7 al[ENTER]Turnului Demonului."
gameforge.deviltower_zone._260_dNotice = "G\227se\186te cheia potrivit\227.[ENTER]Ai nevoie de cheia Zin-Bong-In pentru a deschide[ENTER]pecetea Sa-Soein \186i a ajunge la etajul urm\227tor."
gameforge.deviltower_zone._270_dNotice = "Ucide conduc\227torul demonilor."
gameforge.deviltower_zone._280_dNotice = "Ai \238ndeplinit sarcina cu succes \186i vei fi[ENTER]teleportat afar\227 \238n pu\254ine minute."
gameforge.deviltower_zone._290_dNotice = "Te astept in Catacomba Diavolului![ENTER]Urmeaza-ma iar mania mea te va invalui ca o[ENTER]tornada!"
gameforge.deviltower_zone._30_say = "\206n acest turn mi\186un\227 diavoli.[ENTER]Doar cei mai puternici ajung \238n v\226rf.[ENTER]Se spune totu\186i, c\227 niciunul care intr\227 \238n turn,[ENTER]nu \238l va p\227r\227si \238n via\254\227.[ENTER]Nu po\254i intra, deoarece nu ai atins \238nc\227 nivelul[ENTER]40."
gameforge.deviltower_zone._40_say = "Acest turn este plin de demoni. Numai cei mai[ENTER]puternici pot ajunge in varf. Zvonul zice ca[ENTER]nimeni care a intrat in acel turn nu a iesit viu.[ENTER]Inca iti mai doresti sa intri in Turnul[ENTER]Demonilor?"
gameforge.deviltower_zone._50_dNotice = "Te afli la poarta sigilata de la etajul 3.[ENTER]Multe pietre false te asteapta pentru a te induce[ENTER]in eroare si numai una dintre ele este Piatra[ENTER]Metin cu adevarat importanta. Trebuie sa o[ENTER]distrugi in 15 minute sau nu vei putea trece prin[ENTER]poarta."
