gameforge.deviltower_zone._70_dNotice = "Minute r\227mase: 5"
gameforge.deviltower_zone._80_dNotice = "Timpul a expirat."
gameforge.deviltower_zone._90_dNotice = "Pietrele metin false dispar..."
