gameforge.dragon_lair_access._090_notice = "Grupul lui %s \238ncearc\227 s\227 omoare Dragonul[ENTER]Albastru!"
gameforge.dragon_lair_access._100_say = "Nu ai destule chei! Pentru a activa portalul am[ENTER]nevoie"
