gameforge.dragon_lair_access._120_say = "Un alt grup \238ncearc\227 deja s\227 omoare dragonul.[ENTER]Trebuie s\227 a\186tep\254i pana c\226nd s\227 intri \238n Templul[ENTER]Dragonului."
gameforge.dragon_lair_access._130_say = "Dac\227 vrei te pot duce imediat la b\238rlogul[ENTER]dragonului. D\227-mi"
gameforge.dragon_lair_access._140_select = "Poftim, ia asta \186i las\227-m\227 s\227 intru!"
