gameforge.dragon_lair_weekly._020_sayTitle = "Fantoma unui r\227zboinic:"
gameforge.dragon_lair_weekly._030_say = "Dore\186ti o Marmur\227 Transformare, a\186a-i? Pentru a[ENTER]fabrica o bucat\227 am nevoie de 150,000 Yang \186i %s[ENTER]din urm\227toarele materiale:"
gameforge.dragon_lair_weekly._040_say = "Adu-mi materialele \186i 150,000 Yang \186i voi crea o[ENTER]Marmur\227 Transformare. Oricum, din cauza m\226inilor[ENTER]mele b\227tr\226ne, nu pot garanta c\227 nu vor exista[ENTER]gre\186eli."
