gameforge.dragon_lair_weekly._110_sayTitle = "Materialele pentru Marmur\227 Transformare"
gameforge.dragon_lair_weekly._120_sendLetter = "Materiale Colectate"
gameforge.dragon_lair_weekly._130_sayTitle = "Toate Materialele Colectate"
gameforge.dragon_lair_weekly._140_say = "Mai ai nevoie de %s din urm\227toarele materiale:"
gameforge.dragon_lair_weekly._150_say = "Ai colectat toate materialele necesare.[ENTER]\206ntoarce-te la Fantoma unui R\227zboinic. \206l vei[ENTER]g\227si la nivelul doi din Grota Exilului. De[ENTER]asemenea, ai nevoie \186i de 150,000 Yang pentru a[ENTER]primi marmura."
