gameforge.find_brother_article._200_say = "O nu! Am rugat \186i pe al\254ii s\227 m\227 ajute, dar[ENTER]niciunul nu s-a mai \238ntors. E\186ti ultima mea[ENTER]speran\254\227.[ENTER]Uite, acesta este lucrul meu cel mai de pre\254.[ENTER]\222i-l dau ca r\227splat\227."
