gameforge.find_brother_article._260_sayReward = "Recompensa lui Mirine a fost acceptat\227."
gameforge.find_brother_article._270_sendLetter = "Recompensa lui Mirine."
gameforge.find_brother_article._280_say = "Dezvele\186ti recompensa lui Mirinae \186i descoperi o[ENTER]sabie cu un m\226ner minunat \238mpodobit."
gameforge.find_brother_article._290_say = "O arm\227 minunat\227. Dar... ce e asta? Lama e rupt\227![ENTER]Aceast\227 frumoas\227 m\227iestrie este prea bun\227 pentru[ENTER]a fi aruncat\227. Ar trebui s\227-i duc buc\227\254ile[ENTER]Fierarului."
