gameforge.find_brother_article._310_sendLetter = "Mergi la Fierar"
gameforge.find_brother_article._320_say = "Mirine a fost at\226t de recunosc\227toare pentru[ENTER]ajutorul t\227u \238nc\226t \254i-a dat cel mai de pre\254 lucru[ENTER]al ei: o sabie minunat\227 care, din p\227cate este[ENTER]rupt\227. La prima vedere \238\254i dai seama c\227 este o[ENTER]arm\227 foarte valoroas\227, astfel \238nc\226t decizi s\227 o[ENTER]duci la reparat."
