gameforge.find_brother_article._340_npcChat = "Po\254i repara sabia?"
gameforge.find_brother_article._350_say = "Aceasta este o sabie minunat\227! I-a apar\254inut lui[ENTER]Mirine, nu-i a\186a? Am auzit c\227 ai ajutat-o. Foarte[ENTER]bine, pari un om corect, de aceea nu \238\254i voi cere[ENTER]nimic pentru repara\254ia armei. A\186teapt\227 un[ENTER]minut..."
