gameforge.find_brother_article._390_sayReward = "Ai primit o Sabie Bastard+2."
gameforge.find_brother_article._400_sayReward = "Ai primit o Sabie Barbar\227+2."
gameforge.find_brother_article._40_say = "Treceam din \238nt\226mplare pe aici \186i te-am auzit[ENTER]pl\226ng\226nd."
gameforge.find_brother_article._50_say = "Oh, nu am realizat c\227 e cineva \238n preajm\227...[ENTER]Numele meu e Mirine. M\227 po\254i ajuta cumva? Fratele[ENTER]meu mai mare e mort. A fos pe pe drum dup\227[ENTER]medicamente, dar apoi...[ENTER]Singurul lucru care mi-a r\227mas de la el este[ENTER]vederea morm\226ntului \186i un suvenir: uniforma lui[ENTER]neagr\227."
gameforge.find_brother_article._60_sayTitle = "Mirina:"
gameforge.find_brother_article._70_say = "\206n drumul meu spre cas\227, Banda V\226ntul Negru a[ENTER]ap\227rut - una din cele mai infame bande de[ENTER]asasini. A trebuit s\227 fug de ei \186i am pierdut[ENTER]suvenirul fratelui meu. Mi-e prea fric\227 s\227 m\227[ENTER]\238ntorc acolo \186i s\227-l caut. Po\254i s-o faci tu[ENTER]pentru mine?"
