gameforge.find_squareguard._110_sayTitle = "Gardian:"
gameforge.find_squareguard._120_say = "Poti sa iei licoarea rosie de la Vanzatoarea[ENTER]Magazinului General. Este chiar acolo. Daca nu[ENTER]poti sa o vezi, urmeaza cercul luminos de pe[ENTER]harta mare sau punctul rosu care clipeste de pe[ENTER]harta mica!"
gameforge.find_squareguard._130_sayTitle = "Negustoreasa de diverse:"
gameforge.find_squareguard._131_targetVid = "Negustoreasa de diverse:"
gameforge.find_squareguard._140_say = "Ziua bun\227 aventurierule![ENTER]Oh, Gardianul te-a trimis la mine? Are nevoie de[ENTER]o Licoare Ro\186ie? O sa-ti dau cinci.[ENTER]Poftim, ia-le. Ele servesc la refacerea puterii[ENTER]de via\254\227 \186i sunt foarte gustoase."
gameforge.find_squareguard._150_say = "E\186ti \238nc\227 proasp\227t venit, dar sunt convins\227, c\227[ENTER]\238n cur\226nd vei deveni un client fidel.[ENTER]De aceea po\254i lua licorile gratuit.[ENTER]Mai vino pe aici. "
gameforge.find_squareguard._160_sayReward = "Ai primit 5 licori ro\186ii de la negustoreasa de[ENTER]diverse."
gameforge.find_squareguard._170_sayReward = "Licorile Ro\186ii sunt pentru refacerea punctelor de[ENTER]via\254\227 (PV)."
gameforge.find_squareguard._180_sendLetter = "\206ntoarcerea la Gardian"
gameforge.find_squareguard._190_sayReward = "\206ntoarce-te la paznic \186i pred\227-i o Licoare Rosie."
gameforge.find_squareguard._200_say = "Nu ai primit Licoarea Rosie?[ENTER]P\227cat! \206n fine, p\227streaz\227 restul pentru efortul[ENTER]t\227u.[ENTER]\206n alt\227 ordine de idei, \238nv\227\254\227torii se afl\227 \238n[ENTER]c\227utarea ta. Ar trebui s\227 mergi la[ENTER]ei. "
gameforge.find_squareguard._20_sayReward = "Mergi \238n ora\186 \186i vorbe\186te cu Gardianul. O s\227[ENTER]prime\186ti prima ta misiune.[ENTER]Gardianul poate fi g\227sit \238n centrul ora\186ului."
gameforge.find_squareguard._210_say = "Mul\254umesc mult c\227 mi-ai adus licoarea! Astfel nu[ENTER]a trebuit s\227 p\227r\227sesc locul aici \238n sat \186i mi-am[ENTER]putut face datoria mai bine. Vrei s\227 \186tii ce[ENTER]func\254ie \238ndeplinesc eu? \206n general anun\254[ENTER]informa\254ii de folos. Pe de alt\227 parte se mai[ENTER]\238nt\226mpl\227 s\227 ofer ajutor celor afla\254i \238n nevoie[ENTER]sau celor care sunt ataca\254i. R\227spund mai ales de[ENTER]bresle. Dac\227 \238ntr-o bun\227 zi vei fi interesat de o[ENTER]breasl\227, vino pur \186i simplu la[ENTER]mine. "
gameforge.find_squareguard._220_say = "\206n alt\227 ordine de idei, \238nv\227\254\227torii te caut\227. Ar[ENTER]trebui s\227 mergi la ei. Oh, era s\227 uit! \206n semn de[ENTER]recompens\227 po\254i s\227 p\227strezi restul![ENTER]Ne vom revedea cu siguran\254\227. "
gameforge.find_squareguard._30_sayTitle = "Gardian:"
gameforge.find_squareguard._40_say = "Bun venit la noi \238n sat, aventurierule![ENTER]\206\254i voi fi recunosc\227tor dac\227 vei putea s\227 \238mi[ENTER]faci o favoare. Dac\227 \238\254i dau 200 Yang, ai putea[ENTER]s\227 \238mi procuri Licoare Rosie?[ENTER]Se g\227se\186te la Vanzatoarea Magazinului General.[ENTER]M\227 aflu \238n serviciu, \186i de aceea nu pot p\227r\227si[ENTER]Centrul Satului. "
gameforge.find_squareguard._50_select = "Da"
gameforge.find_squareguard._60_sayReward = "Ai primit 200 Yang de la paznic. Cu acest mijloc[ENTER]de plat\227 po\254i s\227 \238\254i procuri obiecte de la[ENTER]magazine sau s\227 \238\254i asiguri serviciile[ENTER]me\186te\186ugarilor. La negustoreasa de diverse po\254i[ENTER]cump\227ra licoare ro\186ie."
