gameforge.find_squareguard._80_sendLetter = "Cump\227r\227 o licoare ro\186ie"
gameforge.find_squareguard._90_sayReward = "Cump\227r\227 o licoare ro\186ie de la negustoreasa de[ENTER]diverse \186i du-o paznicului centrului."
