gameforge.fortune_telling._10_npcChat = "Am auzit c\227 sunte\254i clarv\227z\227toare."
gameforge.fortune_telling._110_say = "E\186ti prea t\226n\227r pentru a ofta a\186a! Vrei s\227 ne[ENTER]uit\227m la viitorul t\227u? Ar trebui s\227 \186tii c\227 sunt[ENTER]ceva puteri car \238\254i pot da r\227spunsuri. Trebuie[ENTER]doar s\227-\254i redob\226nde\186ti speren\254a."
