gameforge.fortune_telling._180_say = "Pleci? Poate c\227 ai dreptate. Ghinionul \186i[ENTER]suferin\254a sunt parte din via\254\227. Ai grij\227 de tine.[ENTER]\206n caz c\227 te r\227zg\226nde\186ti, vorbe\186te mai t\226rziu cu[ENTER]mine."
gameforge.fortune_telling._20_say = "Fa\254a ta \238mi spune, c\227 nu te afli de prea mult[ENTER]timp pe aceast\227 lume. De ce vrei s\227 \238\254i afli[ENTER]soarta a\186a devreme? Ai necazuri? Soarta ta are[ENTER]nevoie de foarte mult antrenament. Revino mai[ENTER]t\226rziu. "
gameforge.fortune_telling._30_say = "Vrei s\227 \238\254i tr\227ie\186ti via\254a dup\227 cum a spus[ENTER]clarv\227z\227toarea? Nu ar trebui s\227 crezi \238n[ENTER]preziceri. Tot ce conteaz\227 este mintea \186i[ENTER]concep\254ia ta. Dac\227 sunt am\226ndou\227 pozitive, nu va[ENTER]merge nimic r\227u. Dac\227 dore\186ti totu\186i o prezicere,[ENTER]revino m\226ine."
gameforge.fortune_telling._40_sayTitle = "Femeia B\227tr\226na"
gameforge.fortune_telling._50_say = "Asa cum ti-am mai spus, prezicerea ta pentru ziua[ENTER]de azi spune:"
gameforge.fortune_telling._60_say = "Vei avea ghinion, \186i nu ai cump\227rat \238nc\227[ENTER]talismanul pentru \238nl\227turarea r\227ului. Dore\186ti s\227[ENTER]cumperi talismanul bog\227\254iei?"
