gameforge.ghost_story = {}
gameforge.ghost_story._010_sayTitle = "Fantoma unui Sura:"
gameforge.ghost_story._020_npcChat = "E\186ti o fantom\227?"
gameforge.ghost_story._030_say = "Nu, eu sunt Regina din Sheba... Bine\238n\254eles c\227[ENTER]sunt o fantom\227! Te-ai lovit cumva la cap c\226nd[ENTER]erai mic?"
gameforge.ghost_story._040_npcChat = "Ajutor, o fantom\227!"
gameforge.ghost_story._050_say = "Uiteee, un r\227zboinic ne\238nfricat! BOO!!!"
gameforge.ghost_story._060_npcChat = "Cine e\186ti?"
gameforge.ghost_story._070_say = "Numele meu este Akuma. Am fost odat\227 un mare[ENTER]r\227zboinic, unii spun c\227 am fost cel mai mare \238n[ENTER]timpul meu. Chiar \186i eu am crezut asta! Dar[ENTER]uit\227-te acum la mine. Uit\227-te ce a r\227mas din mine[ENTER]dup\227 ce am descoperit grota ... \186i am disp\227rut."
gameforge.ghost_story._080_npcChat = "Cuno\186ti istoria acestui loc?"
gameforge.ghost_story._090_say = "Oh, \186tiu ce s-a \238nt\226mplat atunci. Am cercetat[ENTER]mult timp \238ncerc\226nd s\227 g\227sesc \186i s\227 aflu motivul[ENTER]din spatele grotei. Iar dup\227 moartea mea am avut[ENTER]timp destul de g\226ndire. \206ntreab\227-m\227 ce vrei s\227[ENTER]afli!"
gameforge.ghost_story._100_npcChat = "Ce fel de portal e acesta?"
gameforge.ghost_story._110_say = "Acest portal duce c\227tre camera dragonilor negrii,[ENTER]c\227tre zeul c\227zut Beran-Setaou, Poate s\227 fie[ENTER]activat\227 cu ajutorul unei chei magice, cheie pe[ENTER]care doar trupele lui Beran-Setaou o poate[ENTER]procura ..."
gameforge.ghost_story._120_npcChat = "Cei Trei Zei"
gameforge.ghost_story._130_say = "Odat\227, trei zei evlavio\186i au pus bazele[ENTER]existentei.[ENTER]Zei\254a Crea\254iei, Bahar-Taraji era cea mai t\226n\227r\227[ENTER]dintre to\254i. Responsabilitatea ei era s\227 creeze[ENTER]noi fiin\254e, oriunde p\227\186ea florile \238nfloreau \186i[ENTER]via\254a devenea prosper\227."
gameforge.ghost_story._140_say = "Cel mai mare frate era Beran-Setaou. El era[ENTER]responsabil pentru sf\226r\186itul vie\254ii \186i[ENTER]dispari\254iei. Ori de c\226te ori un ciclu de viat\227[ENTER]disp\227rea, el separa corpul \186i sufletul unul de[ENTER]celalalt \186i trimitea sufletul \238n lumea de apoi.[ENTER]Astfel, a fost asigurat\227 o trecere constant\227 -[ENTER]temelia \238ntregii vie\254i."
gameforge.ghost_story._150_say = "Fratele mijlociu era Baljit-Elvedin. Ca Zeu al[ENTER]Conserv\227rii, el ac\254iona intre ceilal\254i doi fra\254i[ENTER]\186i men\254inea activ ciclul vie\254ii pentru viet\227tiile[ENTER]de pe p\227m\238nt. El era responsabil, de exemplu,[ENTER]pentru schimbarea anotimpurilor."
gameforge.ghost_story._160_npcChat = "Cearta"
gameforge.ghost_story._170_say = "In timpuri de nevoie, oamenii au cerut ajutorul[ENTER]celor trei zei. De\186i se temeau de Beran-Setaou,[ENTER]ei nu au \238n\254eles c\227 la fel cum exist\227 lumin\227 \186i[ENTER]\238ntuneric, el trebui\227 s\227 existe ca o parte la[ENTER]crea\254ie."
gameforge.ghost_story._180_say = "Pentru o perioad\227 de timp zeul a ignorat asta,[ENTER]dar cu trecerea timpului invidia cre\186tea \238n el,[ENTER]invidie care s-a transformat \238n ur\227. La \238nceput[ENTER]\238\186i canaliza furia asupra oamenilor provoc\226nd[ENTER]r\227zboaie \186i boli. Acest lucru a dus numai la[ENTER]respingerea lui iar oamenii se rugau la[ENTER]Bahar-Taraji, Zei\254a d\227t\227toare de via\254\227. \170i astfel[ENTER]a devenit cercul vicios care a condus \238n cele din[ENTER]urm\227 la ruin\227."
gameforge.ghost_story._190_say = "\170i cum m\226nia zeului a devenit at\226t de intens\227[ENTER]\238nc\226t acesta nu mai putea s\227 o controleze, s-a[ENTER]\238nt\226mplat ceva de necrezut: El \186i-a ucis sora,[ENTER]iubita na\254iunii. Aceast\227 fapt\227 nu a fost una[ENTER]premeditat\227, c\227ci \238n acea zi zei\254a l-a tratat pe[ENTER]fratele ei cu aceea\186i dragoste \186i \238ncredere pe[ENTER]care o avea \238n fiecare zi. Dar el s-a uitat \238n[ENTER]ochii ei senini \186i i-a luat via\254a f\227r\227 mil\227."
gameforge.ghost_story._200_npcChat = "Consecin\254a"
gameforge.ghost_story._210_say = "Moartea lui Bahar-Taraji a avut consecin\254e grave[ENTER]at\226t pentru lumea zeilor c\226t \186i pentru cea a[ENTER]oamenilor. A venit o iarn\227 crunt\227 ce a omor\226t[ENTER]creaturile m\227rii \186i ale uscatului. P\227m\226ntul a[ENTER]\238nghe\254at at\226t de tare \238nc\226t pietrele cr\227pau iar[ENTER]cei mai vechi \186i rezisten\254i copaci au c\227zut la[ENTER]p\227m\226nt."
gameforge.ghost_story._220_say = "Oameni tineri \186i animale au murit iar odat\227 cu[ENTER]\238nc\227lzirea p\227m\238ntului rata natalit\227\254ii se[ENTER]mic\186ora. Tarile slabe nu d\227deau randament destul[ENTER]pentru a tine popula\254ia intacta. Speran\254a a murit[ENTER]\186i ea."
gameforge.ghost_story._230_say = "Chiar \186i zeii aveau de suferit, timpul se scurgea[ENTER]mai greu \238n compara\254ie cu cel al oamenilor.[ENTER]Beran-Setaou s-a retras \186i a c\227utat singur\227tatea[ENTER]dup\227 ce a devenit con\186tient de ceea ce f\227cuse.[ENTER]Regrete devastatoare i-au cople\186it mintea - p\226n\227[ENTER]\238ntr-un final c\226nd a c\226\186tigat aceast\227 b\227t\227lie[ENTER]psihic\227. Inima lui s-a transformat \238n gheat\227 iar[ENTER]Zeul Dizolv\227rii a devenit Zeul \206nghe\254ului \186i al[ENTER]Frigului, al Urii \186i al Fricii."
gameforge.ghost_story._240_npcChat = "B\227t\227lia"
gameforge.ghost_story._250_say = "Zeul Conserv\227rii, Baljit-Elvedin, a fost[ENTER]\238ndurerat dup\227 sora sa pentru o perioad\227 lung\227 de[ENTER]timp ca \238ntr-un final s\227 mearg\227 \238n c\227utarea[ENTER]fratelui sau."
gameforge.ghost_story._260_say = "Dup\227 c\227ut\227ri lungi \186i-a g\227sit fratele \238ntr-o[ENTER]cavern\227 de ghea\254\227, plin de ur\227 \186i singur, departe[ENTER]de orice semn de via\254\227, de civiliza\254ie.[ENTER]Baljit-Elvedin a f\227cut ceea ce trebuia s\227 fac\227,[ENTER]chiar dac\227 a crestat \238nc\227 o ran\227 \238n inima lui:[ENTER]l-a provocat pe fratele s\227u la un duel.[ENTER]Beran-Setaou a deviat de la calea cea dreapt\227[ENTER]\238nc\226t n-a ezitat nicio secund\227..."
gameforge.ghost_story._270_say = "Se pare ca b\227t\227lia a \238ntrecut orice imagina\254ie,[ENTER]Baljit-Elvedin c\238\186tig\238nd. \222in\238ndu-se de cuv\238nt,[ENTER]nu \186i-a ucis fratele dar i-a luat puterile[ENTER]\238nchiz\238ndu-l \238n grot\227 r\227m\238n\238nd acolo cu[ENTER]creaturile pe care le-a creat cu secole \238n urm\227[ENTER]..."
gameforge.ghost_story._280_npcChat = "Am auzit destul."
gameforge.ghost_story._290_say = "Fie ca soarta ta s\227 fie diferit\227 de a mea. Mult[ENTER]noroc!"
gameforge.ghost_story._300_sayTitle = "Fantoma unui r\227zboinic:"
gameforge.ghost_story._310_npcChat = "De ce e\186ti transparent?"
gameforge.ghost_story._320_say = "Ce crezi? Sunt o fantom\227 \186i am fost prins\227 \238n[ENTER]aceast\227 piatr\227 pentru 1000 de ani ..."
gameforge.ghost_story._330_say = "Ajutor, o fantom\227!"
gameforge.ghost_story._340_say = "Da, o fantom\227. Fugi, ascunde-te c\227 dac\227 nu te voi[ENTER]manca de viu!"
gameforge.ghost_story._350_npcChat = "Cine e\186ti?"
gameforge.ghost_story._360_say = "Am fost odat\227 un mercenar, un simplu om. P\227rintii[ENTER]mei erau fermieri. Cum nu am vrut s\227 ajung[ENTER]fermier m-am \238nrolat \238n armat\227."
gameforge.ghost_story._370_npcChat = "Cuno\186ti povestea grotei?"
gameforge.ghost_story._380_say = "Nu, nu cunosc. Dup\227 ce am dezertat am fugit s\227 m\227[ENTER]ascund \238n mun\254i \186i am dat peste aceast\227 grot\227.[ENTER]C\238teva zile mai t\238rziu am devenit martor \186i[ENTER]victim\227 la o b\227t\227lie. Dac\227 vrei \238\254i pot povesti[ENTER]mai multe."
gameforge.ghost_story._390_npcChat = "\206nceputul b\227t\227liei"
gameforge.ghost_story._400_say = "\206ntr-o zi - str\226ngem r\227d\227cini de la poalele[ENTER]mun\254ilor - un dragon de argint a ap\227rut din[ENTER]ceruri. Credeam c\227 m\227 urm\227rea dar nici m\227car nu[ENTER]m-a v\227zut - era complet concentrat asupra[ENTER]intr\227rii \238n grot\227."
gameforge.ghost_story._410_say = "Apoi am devenit t\227cut pentru o perioad\227 de timp[ENTER]\186i nu \186tiam ce s\227 fac. Tot echipamentul meu era[ENTER]\238n grot\227 dar bine\238n\254eles nu \238ndr\227zneam s\227 intru[ENTER]din cauza dragonului. Dintr-o dat\227 p\227m\238ntul a[ENTER]\238nceput s\227 se cutremure \186i ni\186te sunete se auzeau[ENTER]din grot\227, spre disperarea mea se auzeau doua[ENTER]voci din grot\227. Apoi doi dragoni au ie\186it din[ENTER]grota - unul argintiu urmat de altul albastru."
gameforge.ghost_story._420_say = "Apoi o b\227t\227lie a izbucnit intre cei doi dragoni."
gameforge.ghost_story._430_npcChat = "Sf\226r\186itul b\227t\227liei"
gameforge.ghost_story._440_say = "Ambii dragoni s-au pr\227bu\186it peste mun\254i ca un[ENTER]fulger, provoc\226nd distrugeri imense. Arsuri se[ENTER]vedeau pe dragonul albastru \186i gheat\227 pe aripile[ENTER]dragonului argintiu. Crusta groas\227 de ghea\254\227 care[ENTER]acoperise p\227m\226ntul de ani de zile s-a topit sub[ENTER]acest atac \186i a l\227sat \238n urm\227 numai noroi. A\186a c\227[ENTER]m-am ascuns dup\227 o st\226nc\227, plin de groaz\227 dar[ENTER]neput\226nd ignora priveli\186tea m\227rea\254\227 din fa\254a mea."
gameforge.ghost_story._450_say = "Au trecut ore bune p\226na c\226nd puterile i-au[ENTER]p\227r\227sit. Apoi, \238n cele din urm\227 mi-am v\227zut[ENTER]\186ansa, am plecat departe de scen\227 \186i am alergat[ENTER]\238n vale pentru a-mi scoate echipamentul din[ENTER]pe\186ter\227. \170i \238n felul acesta mi-am ales destinul.[ENTER]Eram pe drumul de \238ntoarcere c\226nd cei doi dragoni[ENTER]au ap\227rut din mun\254i, cel albastru urmat de cel[ENTER]argintiu. Se vedeau r\227ni ad\226nci."
gameforge.ghost_story._460_say = "\206nainte ca dragonul argintiu sa intre \238n grota[ENTER]ceva ciudat s-a \238nt\238mplat: cerul a \238nceput sa[ENTER]p\238lp\238ie iar un vortex de energie s-a creat,[ENTER]vortex care l-a prins in el pe dragonul albastru."
gameforge.ghost_story._470_say = "\206ntr-un final dragonul argintiu l-a eliberat pe[ENTER]celalalt dragon \238n grot\227. Cu puterile sc\227zute,[ENTER]pierzatorul s-a tarat \238n mun\254i. Dragonul argintiu[ENTER]a eliberat o energie care a sigilat intrarea \238n[ENTER]grot\227. Dragonul negru \186i eu am fost prin\186i[ENTER]\238nauntru condamnat la o moarte mizerabil\227 ..."
gameforge.ghost_story._480_npcChat = "Am auzit destul."
gameforge.ghost_story._490_say = "Mul\254umesc pentru c\227 ai ascultat. In ultimii 1000[ENTER]de ani am fost singur ..."
gameforge.goldbar = {}
gameforge.goldbar._100_say = "\206nainte de a sc\227pa de v\226ntul negru, am putut afla[ENTER]unde \238\186i ascunde aurul. Avea la ei o gr\227mad\227 de[ENTER]lingouri de aur! Nici nu \186i-ar da seama dac\227[ENTER]lipsesc c\226teva. A\186a de pro\186ti sunt. Dac\227 m\227[ENTER]pl\227te\186ti, merg \186i \238\254i aduc lingouri.[ENTER]\206ns\227 nu pot aduce mai mult de un lingou[ENTER]deodat\227. "
gameforge.goldbar._104_say = "Timp"
gameforge.goldbar._108_say = "Minut(e)"
gameforge.goldbar._10_npcChat = "O victima a Bandei Vant Negru"
gameforge.goldbar._110_say = "Dureaz\227 cam %s %s pentru a aduce un lingou \238napoi. "
gameforge.goldbar._120_say = "Spune-mi dac\227 e\186ti interesat. "
gameforge.goldbar._130_say = "Serios? Atunci batem palma?[ENTER]Trebuie doar s\227 spui ceva, \186i eu \238\254i aduc[ENTER]unul! "
