gameforge.goldbar._160_say = "Ce? Vrei s\227 cumperi lingouri de aur?[ENTER]Nu, nu acum! V\226ntul negru pare s\227 fie suspicios.[ENTER]\206mi risc via\254a dac\227 nu sunt atent![ENTER]Vom \238ncerca dinnou c\226nd s-a mai lini\186tit[ENTER]situa\254ia. "
gameforge.goldbar._170_sayReward = "Nu po\254i cump\227ra acum lingouri de aur."
gameforge.goldbar._180_say = "Nu am reu\186it s\227 iau niciun lingou."
gameforge.goldbar._190_say = "Trebuie s\227 a\186tept\227m cam %s %s."
gameforge.goldbar._200_say = "Am adus un lingou de aur. Te cost\227 2,2 Mil Yang.[ENTER]Cei 200.000 Yang sunt comision. Deci? Vrei s\227[ENTER]cumperi unul? "
gameforge.goldbar._20_sayTitle = "Tr\227d\227torul Balso:"
