gameforge.goldbar._230_say = "De ce e\186ti aici dac\227 nu vrei s\227 cumperi nimic?[ENTER]Mi-ai irosit timpul. "
gameforge.goldbar._240_npcChat = "GM: Reseteaz\227 timp v\226nzare Lingou de Aur"
