gameforge.goldbar._270_say = "Ce vorbe\186ti? Nu \186tiu nimic despre asta."
gameforge.goldbar._280_say = "Ce? Vrei s\227 vinzi lingoul de aur? Nu ai auzit c\227[ENTER]lupt\227torii v\226ntului negru au devenit suspicio\186i?[ENTER]Dac\227 vinzi lingoul de aur acum, nu vei mai tr\227i[ENTER]mult. Cel mai bine e s\227 \238l la\186i acolo unde este.[ENTER]Ascunde-l bine! "
gameforge.goldbar._290_sayReward = "Nu po\254i vinde lingouri de aur acum."
gameforge.goldbar._300_say = "Dac\227 vrei s\227 duci lingoul de aur \238napoi,"
gameforge.goldbar._30_say = "Ce? O victim\227 a v\226ntului negru? Ha, ha, ha! E\186ti[ENTER]\238nc\227 un copil. Unde ai auzit asta? Du-te \186i te[ENTER]joac\227 cu c\226inii s\227lbatici! "
gameforge.goldbar._310_say = "trebuie s\227 a\186tep\254i aproximativ %s %s."
gameforge.goldbar._320_say = "Nu ai lingouri de aur.[ENTER]Dac\227 \238mi aduci lingouri \238\254i voi oferi Yang \238n[ENTER]schimbul lor. "
gameforge.goldbar._330_say = "Ce?[ENTER]Vrei s\227 \238napoiezi lingoul de aur? De ce, pentru[ENTER]Dumnezeu, l-ai cump\227rat atunci? Dac\227 vrei[ENTER]neap\227rat s\227 \238l \238napoiezi, sunt de acord. V\226ntul[ENTER]negru st\227 de paz\227, nu pot face asta prea des.[ENTER]Vrei s\227 \238l dai \238napoi totu\186i? "
gameforge.goldbar._340_select = "Inapoiaza"
gameforge.goldbar._350_select = "Nu inapoia."
gameforge.goldbar._360_say = "Poftim Yang.[ENTER]La naiba! Acum trebuie s\227 \238l duc[ENTER]\238napoi! "
gameforge.goldbar._370_say = "Ai un lingou de aur cu adev\227rat?[ENTER]Sunt foarte ocupat. Nu veni la mine dac\227 nu vrei[ENTER]s\227 faci afaceri. "
gameforge.goldbar._40_sayReward = "Victimei rezultate din comanda V\226ntului negru \238i[ENTER]sunt accesibile numai caractere cu nivelul 30 sau[ENTER]superior"
gameforge.goldbar._50_say = "Fii precaut! R\227zboinicii v\226ntului negru sunt[ENTER]suspicio\186i.[ENTER]Cel mai bine e s\227 te por\254i foarte lini\186tit.[ENTER]Cu bine. "
gameforge.goldbar._60_sayReward = "Una dintre victimele rezultate din comanda[ENTER]v\226ntului negru, nu este momentan disponibil\227"
gameforge.goldbar._70_say = "Pssst![ENTER]Aici se poate s\227 se fi ascuns r\227zboinici ai[ENTER]v\226ntului negru.[ENTER]Unde ai auzit a\186a ceva?[ENTER]Nu, e \238n ordine. Nu e a\186a important.[ENTER]\170tii aproximativ, despre ce e[ENTER]vorba? "
