gameforge.guild_building._10_sayTitle = "Administratorul terenului :"
gameforge.guild_building._110_say = "Revino c\226nd te vei fi r\227zg\226ndit. Cine vine[ENTER]primul, macin\227 primul."
gameforge.guild_building._20_say = "Sunt administrator de teren \186i m\227 ocup de[ENTER]v\226nzarea parcelelor. \206nainte ca mon\186trii s\227[ENTER]cucereasc\227 \254ara din mijlocul continentului, aveam[ENTER]p\227m\226nt pentru to\254i \186i tuturor ne mergea bine.[ENTER]Acum mai v\226nd doar conduc\227torilor breslelor, care[ENTER]\238l folosesc ca p\227m\226nt al breslei.[ENTER]Vrei s\227 cumperi acest teren?"
