gameforge.guild_building_npc._10_sayTitle = "Fierar Arme"
gameforge.guild_building_npc._20_say = "Oh, e\186ti membru al breslei mele! Dac\227 vrei s\227-\254i[ENTER]\238mbun\227t\227\254e\186ti armele le aduci la mine, nu te duci[ENTER]la acei amatori din ora\186. Rata mea de succes este[ENTER]cu 10% mai mare. Membrii breslei au o reducere de[ENTER]5%. Doar d\227-mi arma pe care dore\186ti s-o[ENTER]\238mbun\227t\227\254e\186ti ca s\227 pot \238ncepe."
