gameforge.guild_building_npc._50_say = "Oh, e\186ti membru al breslei mele! Asta \238nseamn\227 c\227[ENTER]po\254i s\227-mi dai armura, scutul, pantofii sau[ENTER]coiful pentru \238mbun\227t\227\254ire. Rata mea de succes[ENTER]este cu 10% mai mare dec\226t a fierarului din ora\186![ENTER]De asemenea membrii breslei mele au o reducere de[ENTER]5%. Doar d\227-mi echipamentul pe care dore\186ti s\227-l[ENTER]\238mbun\227t\227\254e\186ti."
gameforge.guild_building_npc._60_say = "M\227 numesc Stanton. M\227 ocup cu \238mbun\227t\227\254irea[ENTER]armurilor. Sunt mult mai bun dec\226t fierarul din[ENTER]ora\186: rata de succes este cu 10% mai mare. D\227-mi[ENTER]armura pe care dore\186ti s-o \238mbun\227t\227\254e\186ti."
gameforge.guild_building_npc._70_sayTitle = "Bijutier:"
gameforge.guild_building_npc._80_say = "Oh, e\186ti membru al breslei mele![ENTER]Rata ta de succes va cre\186te cu 10%, dac\227 m\227 la\186i[ENTER]s\227 \238\254i \238mbun\227t\227\254esc bijuteriile.[ENTER]Iar pentru membrii breslei mele ofer 5% reducere.[ENTER][ENTER]Pot s\227 \238mbun\227t\227\254esc br\227\254\227ri, cercei \186i coliere.[ENTER]D\227-mi accesoriul care trebuie[ENTER]\238mbun\227t\227\254it! "
