gameforge.heavens_cave_keyquest._030_say = "Ascult\227 cu aten\254ie! \206\254i voi spune povestea doar[ENTER]odat\227 ..."
gameforge.heavens_cave_keyquest._040_say = "Ascult\227 cu aten\254ie fata mea! \206\254i voi spune[ENTER]povestea doar odat\227 ..."
gameforge.heavens_cave_keyquest._050_say = "\206n zilele noastre vener\227m Zeul Dragon, \238ns\227[ENTER]odat\227, \238n timpuri str\227vechi, trei zei ne vegheau.[ENTER]Oricum, Bahar-Taraji, zei\254a crea\254iei a fost ucis\227[ENTER]de c\227tre fratele ei invidios Beran-Setaou. Iar al[ENTER]treilea zeu, Baljit-Elvedin, pe care \238l \186tim azi[ENTER]ca Zeul Dragon, a jelit mult timp dup\227 sora lui."
gameforge.heavens_cave_keyquest._060_say = "O b\227t\227lie a \238nceput intre cei doi fra\254i pe care[ENTER]Zeul Dragon a c\238\186tigat-o. Se zvone\186te c\227 la locul[ENTER]b\227t\227liei \238nc\227 se mai vad urmele alterca\254iei.[ENTER]Beran-Setaou a fost \238nchis in caverna pentru[ENTER]\238nfr\238ngerea suferita care apoi a devenit[ENTER]cunoscuta ca \186i Grota Exilului."
gameforge.heavens_cave_keyquest._070_say = "Aceast\227 grot\227 este sigilat\227 \186i p\227zit\227 de membrii[ENTER]ordinului Baljit-Elvedin. Trebuie s\227 oferi o[ENTER]Piatra Ins\226ngerat\227 pentru a putea intra. \170tiu cum[ENTER]sa produc aceste pietre, dar nu este u\186or."
gameforge.heavens_cave_keyquest._080_say = "Totul a \238nceput atunci c\226nd Zeul Dragon a pl\226ns[ENTER]dup\227 sora lui, lacrimile sale devenind pietre[ENTER]care au c\227zut pe p\227m\226nt. Ast\227zi le po\254i g\227si \238n[ENTER]\222ara de Foc, Doyyumhwan. Adu-mi \186apte lacrimi \186i[ENTER]patru buc\227\254i de Obsidian de la Fl\227c\227rile care[ENTER]tr\227iesc acolo."
gameforge.heavens_cave_keyquest._090_say_reward = "Str\238nge 7 Lacrimi Fosilizate \186i 4 buc\227\254i de[ENTER]Obsidian din Doyyumhwan(\222ara de Foc)."
gameforge.heavens_cave_keyquest._100_say = "Mai ai nevoie de Piatr\227 \206ns\226ngerat\227 pentru a[ENTER]trece de Gardianul Ordinului? \206n acest caz[ENTER]str\226nge alte \186apte Lacrimi Fosilizate \186i patru[ENTER]buc\227\254i de Obsidian din Doyyumhwan (\222ara de foc)."
gameforge.heavens_cave_keyquest._110_say = "Ai nevoie de \238nc\227 o Piatr\227 \206ns\226ngerat\227? Koe-Pung[ENTER]nu este cel mai de\186tept, dar trebuie sa a\186tep\254i[ENTER]pu\254in, \238n caz contrar ar putea observa c\227 nu faci[ENTER]parte din ordinul lui."
gameforge.heavens_cave_keyquest._120_say = "C\238teva ore, aproximativ %s"
