gameforge.heavens_cave_keyquest._220_say = "Mergi \238n Doyyumhwan (\222ara de foc) \186i caut\227[ENTER]lacrimile fosilizate ale lui Baljit Elvedin, Zeul[ENTER]Dragon. Trebuie sa str\238ngi \186i Obsidian ucig\238nd[ENTER]Fl\227c\227ri(creaturi ale focului)."
