gameforge.heavens_cave_keyquest._280_say = "\206ntoarce-te la Seon-Hae cu lacrimile \186i Obsidian."
gameforge.heavens_cave_keyquest._290_say = "Seon-Hae se afl\227 \238n: %s"
gameforge.heavens_cave_keyquest._300_say = "Lacrimile lui Baljit-Elvedin! Le voi schimba[ENTER]\238napoi \238n forma lor lichid\227 \186i le voi introduce[ENTER]\238n Obsidian. Puterea lor \238\254i va permite s\227 o[ENTER]chemi pe zei\254a Bahar-Taraji!"
gameforge.heavens_cave_keyquest._310_say = "Spiritul ei \238nc\227 se plimb\227 pe p\227m\226nt. Vei putea[ENTER]auzi vocea ei at\226ta timp c\226t ai la tine[ENTER]lacrimile. O po\254i g\227si \238n P\227durea Ro\186ie, Lungsam."
gameforge.heavens_cave_keyquest._320_say = "Poftim, ia aceast\227 vaz\227 cu tine \186i caut\227 vocea[ENTER]lui Bahar-Taraji."
gameforge.heavens_cave_keyquest._330_say = "Caut\227 vocea lui Bahar-Taraji \238n Lungsam, \238n[ENTER]\254inutul din P\227durea Ro\186ie. Chiar dac\227 nu po\254i[ENTER]vedea spiritul zei\254ei, po\254i sim\254i prezenta ei."
gameforge.heavens_cave_keyquest._335_say = "O voce \238nceat\227 \238\254i zice: Mergi \238ntr-un loc sigur[ENTER]... Nu putem vorbi aici ...[ENTER]Face\254i clic pe c\227utarea de parcurgere pentru a[ENTER]vorbi cu fantoma."
gameforge.heavens_cave_keyquest._340_say = "\206n dep\227rtare se aude vocea zei\254ei ucise,[ENTER]Bahar-Taraji..."
gameforge.heavens_cave_keyquest._350_say = "Lacrimile fratelui meu care a jelit dup\227 mine[ENTER]mult timp \186i \238nc\227 nu a reu\186it sa-l pedepseasc\227 pe[ENTER]Beran-Setaou pentru crimele s\227v\238r\186ite."
gameforge.heavens_cave_keyquest._360_say = "Nu a putut sa-l \238nfrunte pe fratele sau,[ENTER]Beran-Setaou, distrug\227torul, de care to\254i se tem."
gameforge.heavens_cave_keyquest._370_say = "Dar tu ... Cine e\186ti? E\186ti diferit! \222ie nu \238\254i[ENTER]este fric\227 de el. Contrariu, observ ca e\186ti \238n[ENTER]c\227utare de batalii."
gameforge.heavens_cave_keyquest._380_say = "%s! Accepta aceste pic\227turi din s\226ngele meu. F\227 o[ENTER]Piatr\227 \206ns\226ngerat\227 cu ele \186i pedepse\186te-l pe[ENTER]Beran-Setaou pentru crimele sale. Grota Exilului[ENTER]nu este departe de aici."
gameforge.heavens_cave_keyquest._390_say = "\206n dep\227rtare se aude vocea zei\254ei ucise,[ENTER]Bahar-Taraji..."
gameforge.heavens_cave_keyquest._400_say = "%s! Te recunosc!"
gameforge.heavens_cave_keyquest._410_say = "Ai adus lacrimile fratelui meu pentru a m\227[ENTER]consola, drept recompens\227 \238\254i dau s\226ngele meu[ENTER]pentru a putea lupta \238n continuare."
gameforge.heavens_cave_keyquest._420_say = "\206ntoarce-te la Seon-Hae cu s\226ngele lui[ENTER]Bahar-Taraji."
gameforge.heavens_cave_keyquest._430_say = "Ochii lui Seon-Hae au devenit str\227lucitori c\226nd a[ENTER]luat pic\227turile de s\226nge..."
gameforge.heavens_cave_keyquest._440_say = "S\226ngele unei zei\254e reale! Repede, s\227 m\227 gr\227besc[ENTER]s\227 fac o Piatr\227 \206ns\226ngerat\227."
gameforge.heavens_cave_keyquest._450_say = "Gardianul Koe-Pung te va las\227 s\227 folose\186ti[ENTER]portalul care te duce c\227tre Grota Exilului, asta[ENTER]doar dac\227 ai o Piatr\227 \206ns\226ngerat\227. Doar odat\227[ENTER]po\254i face acest pas. Dac\227 ai nevoie de mai multe[ENTER]pietre \238ntoarce-te \186i viziteaz\227-ma. Din p\227cate[ENTER]pot produce doar 1 piatr\227 pe zi pentru a nu[ENTER]atrage m\226nia ordinului."
gameforge.heavens_cave_keyquest._460_say_reward = "Seon-Hae poate produce mai multe pietre dar c\238te[ENTER]1 pe zi."
gameforge.heavens_cave_keyquest._470_say = "Voi transforma s\226ngele lui Bahar-Taraji \238n Piatr\227[ENTER]\206ns\226ngerat\227. S\227-\254i foloseasc\227 cu bine."
gameforge.heavens_cave_keyquest._480_say_reward = "\206\254i pot face doar o Piatr\227 \206ns\226ngerat\227 pe zi,[ENTER]altfel Koe-Pung devine suspicios."
