gameforge.locale.bookworm.accept_failure_say_2 = "Orice-a\186 face, nu pot g\227si cartea Milgyo.[ENTER]Ar trebui s\227 m\227 \238ntorc \238n sat.[ENTER]Dar ce \238i spun lui Soon?"
gameforge.locale.bookworm.accept_success_info_label = "Procur\227 cartea Milgyo pentru Soon."
gameforge.locale.bookworm.accept_success_info_text_1 = "Procur\227 cartea Milgyo pentru Soon."
gameforge.locale.bookworm.accept_success_info_text_2 = "\206ntoarce-te \238n sat, d\227-i cartea lui Soon \186i[ENTER]\238ncaseaz\227-\254i recompensa."
gameforge.locale.bookworm.accept_success_say_1 = "Aici este cartea Milgyo!"
gameforge.locale.bookworm.accept_success_say_2 = "Aceasta este cartea Milgyo.[ENTER]Du-o lui Soon \238n sat."
gameforge.locale.bookworm.aranyeo_complete_say = "Care prost i-a dat acea cartea ciudata sotului[ENTER]meu? Sta toata ziua si se holbeaza la ea, recita[ENTER]incantatii si bolboroseste tot felul de lucruri.[ENTER]Nu a mai miscat un deget! O sa-i rup osisor cu[ENTER]osisor atunci cand voi pune mana pe el!"
gameforge.locale.bookworm.aranyeo_complete_say2 = "Aranyeo: Ce s-a \238nt\226mplat? De unde acest acces de[ENTER]sudoare rece?"
gameforge.locale.bookworm.aranyeo_start_say = "Unde s-a dus? Atitudinea lui ma calca pe nervi![ENTER]Isi iroseste zilele citind carti fara sa castige[ENTER]un Yang. Si nici macar nu-i este rusine ca este[ENTER]un exemplu prost pentru copii."
gameforge.locale.bookworm.aranyeo_start_say2 = "Pot cartile sa-ti puna mancare pe masa sau sa te[ENTER]imbrace? O sa-i rup toate oasele cand pun mana pe[ENTER]el!"
gameforge.locale.bookworm.aranyeo_talk = "Vorbe\186te."
gameforge.locale.bookworm.complete_say = "Soon: Oha! O v\227d! O v\227d! V\227d lumea nou\227!"
gameforge.locale.bookworm.do_you_find_the_book = "Ai g\227sit cartea Milgyo?"
gameforge.locale.bookworm.do_you_mean_this_book = "Te referi la cartea aceasta?"
gameforge.locale.bookworm.etc_shop_start_say = "A venit ieri aici si a intrebat de cartea lui[ENTER]Milgyo. Nu avea Yang dar totusi a intrebat de ea.[ENTER]Poate Milgyo are de-a face cu aceste creaturi[ENTER]brutale din Valea Seungryong. Nu stiu de ce[ENTER]dintr-o data are atata interes pentru aceste[ENTER]bestii."
gameforge.locale.bookworm.etc_shop_start_say2 = "Negustoarea de diverse: Aranyeo trebuie[ENTER]comp\227timit\227. De ce oare \254ine o c\227snicie cu o[ENTER]astfel de persoan\227? (suspin\227)"
gameforge.locale.bookworm.etc_shop_talk_about_bookworm = "Despre \238nv\227\254atul Soon."
gameforge.locale.bookworm.order_accept = "Bine! Am s\227 \254i-o procur!"
gameforge.locale.bookworm.order_accept_answer = "Soon: Mul\254umesc! M\227 bazez pe tine."
gameforge.locale.bookworm.order_find_book_label = "Ucide ucenicul lui Milgyo!"
gameforge.locale.bookworm.order_find_book_text_1 = "Ucide ucenicul lui Milgyo!"
gameforge.locale.bookworm.order_find_book_text_2 = "Ia cartea lui Milgyo de la ucenicul acestuia."
gameforge.locale.bookworm.order_refuse = "Ar trebui s\227 fie destul de greu."
gameforge.locale.bookworm.order_refuse_answer = "Soon: De ce nu \238ncerci? \170tiu c\227 e\186ti \238n stare!"
gameforge.locale.bookworm.order_say1 = "Soon: Vrei s\227 auzi ceva de\186ucheat? Eu pot s\227 spun[ENTER]despre mine c\227 am citit toate c\227r\254ile din lume.[ENTER]Momentan studiez c\227r\254ile sfinte, care au fost[ENTER]concepute de c\227tre sfin\254i. Se zvone\186te c\227 \238n[ENTER]cartea Milgyo sunt \238ncifrate informa\254ii secrete[ENTER]\186i indica\254ii privitoare la cum po\254i deveni un[ENTER]sf\226nt adev\227rat."
gameforge.locale.bookworm.order_say2 = "Soon: Vreau s\227 am aceast\227 carte \186i s\227 o citesc!![ENTER]Ce crezi? Po\254i s\227 mi-o procuri? Dac\227 \238mi procuri[ENTER]aceast\227 carte, te voi r\227spl\227ti. Chiar de va[ENTER]trebui s\227-mi v\226nd casa pentru aceasta, te voi[ENTER]r\227spl\227ti!"
gameforge.locale.bookworm.order_too_late = "Soon: Cineva mi-a adus deja cartea Milgyo. Nu mai[ENTER]trebuie s\227 o faci tu."
gameforge.locale.bookworm.start_find_bookworm_label = "Mergi la Soon"
gameforge.locale.bookworm.start_find_bookworm_text_1 = "Mergi la Soon"
gameforge.locale.bookworm.start_find_bookworm_text_2 = "Du-te la Soon \186i \238ntreaba-l de cartea Milgyo."
gameforge.locale.bookworm.start_say = "Poti deslusi misterioasa intelepciune din acest[ENTER]document? Cuvintele individuale din propozitii si[ENTER]cum au creat ele o frumoasa poveste. Ar trebui sa[ENTER]te obisnuiesti ca imaginatia celorlalti oameni sa[ENTER]te conduca si desi nu este cel mai placut lucru,[ENTER]mie imi place."
gameforge.locale.bookworm.start_say2 = "Cu c\226t ai mai mult, cu at\226t prime\186ti mai mult.[ENTER]Cu c\226t \186tii mai mult, cu at\226t de distrezi mai[ENTER]mult \238n via\254\227.[ENTER]Ehe, dac\227 a\186 fi putut s\227 citesc c\227r\254i toat\227[ENTER]via\254\227..."
