gameforge.locale.forked_open_gate = "Poarta care a fost inchisa pana acum, s-a[ENTER]deschis. Sa mergem pe taramuri noi! Mergem sa le[ENTER]cucerim! Toata lumea va fi transportata pe pamant[ENTER]sfant."
gameforge.locale.forked_rule = "Reguli pentru participarea la B\227t\227lia Regatelor:[ENTER]1. Oricine moare \238n acest \254inut va fi trimis \238n[ENTER]ora\186. Dar, cu ajutorul Administratorului, va[ENTER]ajunge imediat \238napoi.[ENTER]2. Odat\227 ce se deschid por\254ile c\227tre P\227m\226ntul[ENTER]Sf\226nt, \254inutul se \238nchide.[ENTER]3. Pentru a intra pe P\227m\226ntul Sf\226nt, trebuie[ENTER]g\227sit\227 cheia potrivit\227."
gameforge.locale.forked_rule_sungzi = "Reguli \238n B\227t\227lia Regatelor:[ENTER]1. Regatul cu cel mai mic num\227r de victorii[ENTER]\238mpotriva altui regat va fi eliminat primul.[ENTER]2. Mon\186tri inamici vor \238ncepe s\227 apar\227. Primul[ENTER]regat, care omoar\227 cel mai mare num\227r de mon\186tri,[ENTER]c\226\186tig\227.[ENTER]3. Dac\227 Nou\227 Cozi va fi ucis\227 dup\227 asta, b\227t\227lia[ENTER]se termin\227.[ENTER]4. \206n timpul b\227t\227liei nu va fi drop de obiecte.[ENTER]5. Oricine moare de trei ori pe P\227m\226ntul Sf\226nt,[ENTER]este trimis \238n ora\186 \186i eliminat din B\227t\227lia[ENTER]Regatelor."
gameforge.locale.fortune_words_1_body = "\206ntr-adev\227r! Doamna norocului \238\254i este doar \254ie[ENTER]credincioas\227![ENTER]\206ntinde-te \186i simte cum trece prin corpul t\227u![ENTER]Ast\227zi ai \"Foarte mare noroc\"![ENTER]Mul\254umit\227 valurilor armonioase de Chi \254i se va[ENTER]\238nt\226mpla ceva bun ast\227zi!"
gameforge.locale.fortune_words_1_title = "Mult, mult noroc!"
gameforge.locale.fortune_words_2_body = "Este bine. Cum se spune? Cum iti asterni asa[ENTER]dormi. Astazi vei avea \"Noroc\"! Ma bucur pentru[ENTER]tine. Cu putin efort din partea ta vei primi mai[ENTER]mult decat pana acum!"
gameforge.locale.fortune_words_2_title = "Mult noroc!"
gameforge.locale.fortune_words_3_body = "Nu e atat de rau. Astazi vei avea \"Ceva Noroc\".[ENTER]Ziua ta va fi mai buna decat de obicei dar nu te[ENTER]astepta la nimic spectaculos!"
gameforge.locale.fortune_words_3_title = "Ceva noroc."
gameforge.locale.fortune_words_4_body = "Nimic nu pare in neregula dar nici extraordinar[ENTER]de bine! Astazi vei fi \"Cat de Cat Norocos\". Nu[ENTER]te va ajuta foarte mult insa nici nu vei pierde[ENTER]mare lucru. Zilele normale nu sunt ceva special!"
gameforge.locale.fortune_words_4_title = "Noroc normal."
gameforge.locale.fortune_words_5_body = "Norocul nu este cu tine ast\227zi.[ENTER]Dac\227 arunci plasa vrei prinde pu\254ini pe\186ti \186i va[ENTER]trebui s\227 r\227bda\254i pu\254in de foame.[ENTER]Ast\227zi ai \"Ceva ghinion![ENTER]Nimic nu este \238ns\227 mai bun, dec\226t s\227 fii[ENTER]preg\227tit. Dac\227 vrei, \238\254i scriu un Talisman, care[ENTER]poate alunga ce e mai r\227u.[ENTER]Vrei s\227 cumperi un Talisman?"
gameforge.locale.fortune_words_5_title = "Ceva ghinion."
gameforge.locale.fortune_words_6_body = "Astazi e o zi proasta. O zi in care tot ce vei[ENTER]face va fi egal cu zero. Astazi vei avea[ENTER]\"Ghinion\" si ai grija pe unde mergi si ce faci.[ENTER]Te-as putea ajuta vanzandu-ti un Talisman pentru[ENTER]a te feri de rele. Esti interesat?"
gameforge.locale.fortune_words_6_title = "Ghinion."
gameforge.locale.fortune_words_7_body = "Aceasta este una dintre cele mai proaste zile din[ENTER]via\254a ta. To\254i Zeii Cerului \186i ai P\227m\226ntului[ENTER]arunc\227 cu blesteme asupra ta. Indiferent ce vei[ENTER]face ast\227zi nu-\254i va merge bine. Dac\227 vrei s\227[ENTER]aprinzi un foc va ploua, dac\227 \238\254i va fi sete[ENTER]soarele va dogor\238 asupra ta. Vei munci la fel de[ENTER]mult ca \186i ceilal\254i dar nu te vei alege cu nimic.[ENTER]E\186ti pe cale s\227 ai parte de \132foarte mare[ENTER]ghinion\147![ENTER]F\227r\227 un Talisman vei avea vremuri grele.[ENTER]Dore\186ti s\227 cumperi unul?"
gameforge.locale.fortune_words_7_title = "Mare ghinion."
