gameforge.locale.monster_chat_11004_8 = "Ninja poate fi un adversar extrem de periculos atunci cand invata lupta cu sabia!"
gameforge.locale.monster_chat_11004_9 = "Dac\227 vrei s\227 ai control asupra luptelor ca \186i un r\227zboinic al Zeului Dragon, alege Puterea Dragonului!"
gameforge.locale.monster_chat_1105_1 = "Starea de \238nghe\254are este bun\227."
gameforge.locale.monster_chat_1105_2 = "Muntele Sohan este cu siguran\254\227 cel mai bun."
gameforge.locale.monster_chat_1105_3 = "Ce vreme frumoas\227."
gameforge.locale.monster_chat_1105_4 = "Am s\227 te fac identic cu mine."
gameforge.locale.monster_chat_1105_5 = "Po\254i tr\227i la nesf\226r\186it, \238nainte ca ghea\254a s\227 se topeasc\227."
gameforge.locale.monster_chat_1105_6 = "Cum crezi ca o sa te simti atunci cand am sa te transform incet intr-o bucata de gheata?"
gameforge.locale.monster_chat_1106_1 = "Oameni...aici?!"
gameforge.locale.monster_chat_1106_2 = "Obosit...dar destul de treaz pentru tine..."
gameforge.locale.monster_chat_1106_3 = "Cineva pe meleagurile mele? "
gameforge.locale.monster_chat_1106_4 = "Nu aparti acestui loc!"
gameforge.locale.monster_chat_1106_5 = "Mai bine te-ai retrage!"
gameforge.locale.monster_chat_1106_6 = "Ciudat...atat de singur?"
gameforge.locale.monster_chat_1191_1 = "A trecut ceva timp de cand nu am mai vazut un luptator experimentat pe aici."
gameforge.locale.monster_chat_1191_2 = "Nimic altceva de facut decat sa-ti ascuti armele..."
gameforge.locale.monster_chat_1191_3 = "Oare ar trebui s\227 lucrez la ele?"
gameforge.locale.monster_chat_1191_4 = {}
gameforge.locale.monster_chat_1191_5 = "Ceva lipse\186te. Nu sunt mul\254umit."
gameforge.locale.monster_chat_1191_6 = "Am s\227 pun repede cap\227t suferin\254ei tale. Acesta ar fi ultimul."
gameforge.locale.monster_chat_1301_1 = "Gat alungit...!"
gameforge.locale.monster_chat_1301_2 = "Culoare pielii iti va palii si mai mult intr-un minut."
gameforge.locale.monster_chat_1301_3 = "Vrei sa ma provoci? OK!"
gameforge.locale.monster_chat_1301_4 = "M-ai atacat! Pweck! Nu po\254i supravie\254ui."
gameforge.locale.monster_chat_1301_5 = "Oameni slabi, slabi!"
gameforge.locale.monster_chat_1301_6 = "Sa vedem cat poti rezista!"
gameforge.locale.monster_chat_1302_1 = "Vrei sa scapi? Nici sa nu te gandesti."
gameforge.locale.monster_chat_1302_2 = "A\186a. Vino mai aproape. Pwiehk!"
gameforge.locale.monster_chat_1302_3 = "Sabia tremur\227 \238n m\226na mea. Pwiehk!"
gameforge.locale.monster_chat_1302_4 = "Nu vei supravietui acestei incercari!"
gameforge.locale.monster_chat_1302_5 = "Aici vine sabia mea!"
gameforge.locale.monster_chat_1302_6 = "Dureros, nu? (R\226s)"
gameforge.locale.monster_chat_1303_1 = "Chiar \186i iarba c\227lcat\227 din gre\186eal\227 poate ucide."
gameforge.locale.monster_chat_1303_2 = "Aten\254ie la iarb\227."
gameforge.locale.monster_chat_1303_3 = "A\186a. Vino frumos la mine. (R\226s)"
gameforge.locale.monster_chat_1303_4 = "Indraznesti sa te apropii de mine? Bine... atunci trebuie sa suporti consecintele!"
gameforge.locale.monster_chat_1303_5 = "Mori! Mori!"
gameforge.locale.monster_chat_1303_6 = "Regre\254i c\227 ai venit?"
gameforge.locale.monster_chat_1305_1 = "Tu? Vrei s\227 lup\254i?"
gameforge.locale.monster_chat_1305_2 = "Tu? Vrei s\227 lup\254i?"
gameforge.locale.monster_chat_1305_3 = "Vino dac\227 vrei!"
gameforge.locale.monster_chat_1305_4 = "Te gandeai sa fugi, nu-i asa?"
gameforge.locale.monster_chat_1305_5 = "Ai subestimat valoarea sabiei mele."
gameforge.locale.monster_chat_1305_6 = "\222i-e fric\227? (R\226s)"
gameforge.locale.monster_chat_1901_1 = "Cred ca o sa mori in mainile mele azi."
gameforge.locale.monster_chat_1901_2 = "Oh, \238mi place de tine."
gameforge.locale.monster_chat_1901_3 = "Cum arat\227? Schimbarea mea drag\227."
gameforge.locale.monster_chat_1901_4 = "Hei! Sa fugi ca un las nu te va ajuta cu nimic."
gameforge.locale.monster_chat_1901_5 = "Aspectul meu ti-a provocat fiori pe sira spinarii?"
gameforge.locale.monster_chat_1901_6 = "Nu vrei s\227 mai strigi ceva? (R\226s)"
gameforge.locale.monster_chat_20001_1 = "Pari nervos... Nu te ingrijora, nu va exploda nimic."
gameforge.locale.monster_chat_20001_2 = "Din c\226nd \238n c\226nd a\186 vrea s\227 merg la plimbare."
gameforge.locale.monster_chat_20001_3 = "E a\186a de plictisitor. Nici m\227care nepo\254ii mei nu m\227 mai viziteaz\227."
gameforge.locale.monster_chat_20001_4 = "C\226nd e\186ti b\227tr\226n ai nevoie de companie."
gameforge.locale.monster_chat_20001_5 = "Zilele mele de glorie au apus."
gameforge.locale.monster_chat_20002_1 = "Soarele este a\186a de cald."
gameforge.locale.monster_chat_20002_2 = "Minunat\227 vreme pentru a usca o p\226nz\227 ud\227, nu-i a\186a?"
gameforge.locale.monster_chat_20002_3 = "Unde mi-o fi neispr\227vitul de b\227rbat?"
gameforge.locale.monster_chat_20002_4 = "\206\186i spune tat\227, \186i nici m\227car nu se ru\186ineaz\227 \238n fa\254a copiilor din cauza marionetei sale!"
gameforge.locale.monster_chat_20002_5 = "C\227r\254ile sunt c\227r\254i. Lucreaz\227 \186i nu c\226\186tig\227 nimic. Cite\186te doar!"
gameforge.locale.monster_chat_20003_1 = "Oh, dududu, drag\227. Ai dormit bine?"
gameforge.locale.monster_chat_20003_2 = "Z\226mbe\186ti ca un \238ngera\186."
gameforge.locale.monster_chat_20003_3 = "Mama ta se bucur\227 c\227 e\186ti a\186a s\227n\227tos."
gameforge.locale.monster_chat_20003_4 = "Iar\227 vrei aten\254ie? \222i-e foame?"
gameforge.locale.monster_chat_20003_5 = "Copil cuminte, copilul nostru. Dormi, copilule, dormi."
gameforge.locale.monster_chat_20004_1 = "Pur \186i simplu o nou\227 zi."
gameforge.locale.monster_chat_20004_2 = "Unde pot m\226nca ast\227zi ceva?"
gameforge.locale.monster_chat_20004_3 = "Intotdeauna este la fel cu spadasinii astia."
gameforge.locale.monster_chat_20004_4 = "Ia sa vedem...Poate ar trebui sa merg la Octavio la restaurant."
gameforge.locale.monster_chat_20004_5 = "Ah da, se spune c\227 nu va mai fi r\227zboi..."
gameforge.locale.monster_chat_20005_1 = "Sufletul unui maestru in olarit se afla in varful degetelor sale."
gameforge.locale.monster_chat_20005_2 = "De c\226nd \254ara a fost cuprins\227 de haos, vezi peste tot numai lupt\227tori."
gameforge.locale.monster_chat_20005_3 = "To\254i vor s\227 se lutpe mereu."
gameforge.locale.monster_chat_20005_4 = "Eu m\227 rog pentru o lume lini\186tit\227 \186i \238mp\227cat\227."
gameforge.locale.monster_chat_20005_5 = "Hei, tu acolo! Ia-\254i m\227car pu\254in timp s\227 te relaxezi \186i s\227 cuge\254i."
gameforge.locale.monster_chat_20006_1 = "Ahhh, ce fac oare?"
gameforge.locale.monster_chat_20006_2 = "Nu dau de urma fratelui meu. Zicea c\227 vrea s\227 vin\227."
gameforge.locale.monster_chat_20006_3 = "Iar acum nu v\227d dec\226t ace\186ti lupt\227tori cu s\227biile lor."
gameforge.locale.monster_chat_20006_4 = "Mi-e dor de fratele meu."
gameforge.locale.monster_chat_20006_5 = "L-a v\227zut cineva pe fratele meu?"
gameforge.locale.monster_chat_20007_1 = "Mmmmmh, carnea aceasta este proasp\227t\227!"
gameforge.locale.monster_chat_20007_2 = "Ce bine c\227 oamenii m\227n\226nc\227 din nou mai mult\227 carne."
gameforge.locale.monster_chat_20007_3 = "Afacerea \238nflore\186te, dar carnea e cam pu\254in\227."
gameforge.locale.monster_chat_20007_4 = "C\226nd ajunge carnea pe care am comandat-o?"
gameforge.locale.monster_chat_20007_5 = "Dac\227 nu vine la timp trebuie s\227 mergem la v\226n\227toare."
gameforge.locale.monster_chat_20008_1 = "Sper c\227 pe a\186a o vreme, clien\254ii ne vor n\227v\227li \238n cas\227."
gameforge.locale.monster_chat_20008_2 = "Oh! C\226inele lene\186 va veni sigur \238n cur\226nd \186i va vrea s\227 m\227n\226nce ceva."
gameforge.locale.monster_chat_20008_3 = "Na, ce am\227r\226t!"
gameforge.locale.monster_chat_20008_4 = "Mai demult era un r\227zboinic foarte bun."
gameforge.locale.monster_chat_20008_5 = "M\227 \238ntreb, de ce nu mai lupt\227?"
gameforge.locale.monster_chat_20009_1 = "Tinerii \227\186tia...at\226t de plini de via\254\227 \186i imaturi!"
gameforge.locale.monster_chat_20009_2 = "Lupt\227torii arat\227 mult mai bine c\226nd poart\227 arme."
gameforge.locale.monster_chat_20009_3 = "Acest spirit criminal \238mpline\186te pe fiecare."
gameforge.locale.monster_chat_20009_4 = "Asculta-ti inima, concentreaza-te si elibereaza-ti sufletul."
gameforge.locale.monster_chat_20009_5 = "Nu exista reteta pentru fericire insa, iti pot da cateva sfaturi pe cate te poti axa."
gameforge.locale.monster_chat_20010_1 = "Am adus un obiect bun!"
gameforge.locale.monster_chat_20010_2 = "Bunuri din tinuturi indepartate! Nemaipomenit, lucruri pretioase!"
gameforge.locale.monster_chat_20010_3 = "Veni\254i \238ncoace, veni\254i cu to\254ii \238ncoace!"
gameforge.locale.monster_chat_20010_4 = "Cump\227ra\254i, cump\227ra\254i at\226ta timp c\226t mai este. A\186a ceva nu se g\227se\186te peste tot \186i oric\226nd!"
gameforge.locale.monster_chat_20010_5 = "Sunt prea mul\254i t\226lhari pe aici. Ar trebui s\227 stea departe de bunurile mele!"
gameforge.locale.monster_chat_20011_1 = "Acum este foarte uscat aici."
gameforge.locale.monster_chat_20011_2 = "Recolta de gr\226ne nu este a\186a de bun\227 ca mai demult."
gameforge.locale.monster_chat_20011_3 = "Ce \238mpiedic\227 dezvoltarea pe c\226mpii?"
gameforge.locale.monster_chat_20011_4 = "Cerealele sunt sfaramicioase si au gust de putred."
gameforge.locale.monster_chat_20011_5 = "Semn r\227u. Agricultura este baza tuturor lucrurilor."
gameforge.locale.monster_chat_20012_1 = "Placinta cu orez! Delicioasa placinta cu orez!"
gameforge.locale.monster_chat_20012_2 = "Vand prajituri de orez dulce!"
gameforge.locale.monster_chat_20012_3 = "Oh! Afacerea merge prost."
gameforge.locale.monster_chat_20012_4 = "Ar trebui s\227 \238ncerc \238n alt ora\186."
gameforge.locale.monster_chat_20012_5 = "Dar exista asa multe animale salbatice de prada pe aici..."
gameforge.locale.monster_chat_20013_1 = "\206ntr-o astfel de zi, cel mai bine este \238n barc\227."
gameforge.locale.monster_chat_20013_2 = "Vreme perfect\227 de pescuit."
gameforge.locale.monster_chat_20013_3 = "Acum un al nod...Perfect! Nici un peste nu o sa scape din acest carlig!"
gameforge.locale.monster_chat_20013_4 = "Acest urs blestemat mi-a distrus undi\254a."
gameforge.locale.monster_chat_20013_5 = "Ar trebui sa repar din nou plasele."
gameforge.locale.monster_chat_20014_1 = "Hu!"
gameforge.locale.monster_chat_20014_2 = "Nu \238\254i face griji din cauza mea. A\186a sunt eu."
gameforge.locale.monster_chat_20014_3 = "Haaaaa!"
gameforge.locale.monster_chat_20014_4 = "Ce ar trebui sa fac ca sa... Offf, ce am mai spus acum?"
gameforge.locale.monster_chat_20014_5 = "Nu pot fi curajos. Hu!"
gameforge.locale.monster_chat_20015_1 = "De 20 de ani aceast\227 secure \238mi serve\186te cu \238ncredere."
gameforge.locale.monster_chat_20015_2 = "Este \238nc\227 ascu\254it\227, dar nu a\186a ca mai demult."
gameforge.locale.monster_chat_20015_3 = "A\186 vrea s\227 o \238nt\227resc, prin folosirea ei \186i prin faptul c\227 lovesc cu ea."
gameforge.locale.monster_chat_20015_4 = "Dar pentru asta am nevoie de ni\186te pietre bogate \238n minerale."
gameforge.locale.monster_chat_20015_5 = "Dar cum s\227 mi le procur? "
gameforge.locale.monster_chat_20016_1 = "Clien\254ii \238mi n\227v\227lesc pe u\186\227."
gameforge.locale.monster_chat_20016_2 = "Sper sa termin totul la timp."
gameforge.locale.monster_chat_20016_3 = "Lovitura dupa lovitura si nicio plangere..."
gameforge.locale.monster_chat_20016_4 = "Asa trebuie sa sune lovitura de ciocan!"
gameforge.locale.monster_chat_20016_5 = "Cam cald aici."
gameforge.locale.monster_chat_20017_1 = "Nu \238mi vine s\227 c\226nt la un instrument."
gameforge.locale.monster_chat_20017_2 = "Instrumentul meu se afl\227 \238ntr-o stare \238ngrozitoare."
gameforge.locale.monster_chat_20017_3 = "Poate ca ar trebui sa-mi cumpar un instrument nou?"
gameforge.locale.monster_chat_20017_4 = "Instrumentul meu este vechi si uzat... iubesc lucrurile vechi!"
gameforge.locale.monster_chat_20017_5 = "Imi trebuie urgent ceva sa inlocuiesc corzile."
gameforge.locale.monster_chat_20018_1 = "Sunt a\186a de ocupat!"
gameforge.locale.monster_chat_20018_2 = "\206n fiecare zi vin al\254i r\227ni\254i."
gameforge.locale.monster_chat_20018_3 = "Nu avem timp de distractie!"
gameforge.locale.monster_chat_20018_4 = "Iar medicamentele se termin\227."
gameforge.locale.monster_chat_20018_5 = "Ar fi bine dac\227 cineva ar putea procura ingredientele pentru medicamente."
gameforge.locale.monster_chat_20019_1 = "De 30 de ani str\227bat mun\254ii cu arcul."
gameforge.locale.monster_chat_20019_2 = "Astfel mi-am hr\227nit so\254ia \186i am pl\227tit pentru educa\254ia celor 3 copii."
gameforge.locale.monster_chat_20019_3 = "A fost greu, dar a meritat."
gameforge.locale.monster_chat_20019_4 = "Dar acum s-a rupt coarda arcului. \206nseamn\227 c\227 acum sunt \186i eu b\227tr\226n?"
gameforge.locale.monster_chat_20019_5 = "Daca nu-mi pot repara arcul trebuie sa cumpar unul nou, dar nu am suficienti bani pentru asta."
gameforge.locale.monster_chat_20020_1 = "Hei! La ce te ui\254i?"
gameforge.locale.monster_chat_20020_2 = "Nu te apropia!"
gameforge.locale.monster_chat_20020_3 = "Oh, c\226t va trebui s\227 m\227 mai ascund \238n acest hal?"
gameforge.locale.monster_chat_20020_4 = "Voi muri uitat \238ntr-un col\254?"
gameforge.locale.monster_chat_20020_5 = "Ahhhhh, sper s\227 m\227 ajute cineva!"
gameforge.locale.monster_chat_20021_1 = "Aceast\227 zi se va sf\226r\186i ca oricare alta."
gameforge.locale.monster_chat_20021_2 = "Ce pot s\227 fac? Hm?"
gameforge.locale.monster_chat_20021_3 = "Nu am crezut niciodat\227 c\227 voi sf\226r\186i a\186a."
gameforge.locale.monster_chat_20021_4 = "Nu-mi vine sa cred ca el nu mai este aici."
gameforge.locale.monster_chat_20021_5 = "El nu merita asta."
gameforge.locale.monster_chat_20022_1 = "\170i dinnou o zi bun\227."
gameforge.locale.monster_chat_20022_2 = "Sotul lui Ariyoung a disparut."
gameforge.locale.monster_chat_20022_3 = "Am vrut s\227 ajut, dar aceast\227 \238nc\227p\227\254\226nare..."
gameforge.locale.monster_chat_20022_4 = "Dac\227 s-ar fi c\227s\227torit cu mine, ar fi putut renun\254a la via\254a ei plictisitoare."
gameforge.locale.monster_chat_20022_5 = "Poate ar fi trebuit s\227 \238i ar\227t mai bine sentimentele mele."
gameforge.locale.monster_chat_20023_1 = "Oh nu! Ce m\227 fac dac\227 afl\227 so\254ia mea?"
gameforge.locale.monster_chat_20023_2 = "Dac\227 a\186 putea tr\227i din cititul c\227r\254ilor!"
gameforge.locale.monster_chat_20023_3 = "C\227r\254ile sunt at\226t de misterioase!"
gameforge.locale.monster_chat_20023_4 = "Nu pot tr\227i a\186a la nesf\226r\186it, dar..."
gameforge.locale.monster_chat_20023_5 = "Sper c\227 pot face ceva pentru so\254ia mea, dar..."
gameforge.locale.monster_chat_20024_1 = "Haide, pune mai mult efort!"
gameforge.locale.monster_chat_20024_2 = "Ce faci acolo, b\227iete? Nu merge mai repede?"
gameforge.locale.monster_chat_20024_3 = "Doar imagineaz\227-\254i un r\227zboinic m\226nuind o sabie \186i f\227 la fel!"
gameforge.locale.monster_chat_20024_4 = "Unde e prostul \227sta? Unde e?"
gameforge.locale.monster_chat_20024_5 = "Acest fiu de c\227\254ea! Tu nu e\186ti b\227rbat. Ha!"
gameforge.locale.monster_chat_2091_1 = "Taie, taie... parul, gatul..."
gameforge.locale.monster_chat_2091_2 = "Am ceva pentru tine: somnul de veci!"
gameforge.locale.monster_chat_2091_3 = "Trage aer in piept. Nu te ingrijora, este doar otrava!"
gameforge.locale.monster_chat_2091_4 = "Iti voi lasa doar fata! Vei arata ca un ornament dragut..."
gameforge.locale.monster_chat_2091_5 = {}
gameforge.locale.monster_chat_2091_6 = "Infasurat in matase vei arata ca un aperitiv elegant mai tarziu..."
gameforge.locale.monster_chat_2092_1 = "Nu au mai ramas multi dintre noi."
gameforge.locale.monster_chat_2092_2 = "Ei nu sunt creaturile cu doua picioare care se presupune ca ar conduce aici."
gameforge.locale.monster_chat_2092_3 = "Oh!? Se pare c\227 s-a prins cineva \238n p\226nza de p\227ianjen."
gameforge.locale.monster_chat_2092_4 = "Sunt o persoana pasnica. Doar ca nu-mi place sa fiu iritat."
gameforge.locale.monster_chat_2092_5 = "Asta este tot ce poti face?"
gameforge.locale.monster_chat_2092_6 = "Nimeni nu se poate pune cu mine!"
gameforge.locale.monster_chat_2104_1 = "De ce oamenii sunt asa aposi pe dinauntru? Imi rugineste sabia!"
gameforge.locale.monster_chat_2104_2 = "Inca nu si-a facut efectul otrava?"
gameforge.locale.monster_chat_2104_3 = "Cum st\227 treaba cu luptatul?"
gameforge.locale.monster_chat_2104_4 = "Deja obosit de la ar\186i\254\227? "
gameforge.locale.monster_chat_2104_5 = "Las cu pl\227cere pe cineva \238n urm\227 \238n de\186ert."
gameforge.locale.monster_chat_2104_6 = "S\227racul, pur \186i simplu \238ngropat \238n de\186ert."
gameforge.locale.monster_chat_2105_1 = "\206\254i spun un secret. Ur\227sc mizeria."
gameforge.locale.monster_chat_2105_2 = "Este foarte cald, nu?"
gameforge.locale.monster_chat_2105_3 = "Acest loc este periculos."
gameforge.locale.monster_chat_2105_4 = {}
gameforge.locale.monster_chat_2105_5 = "Te nimeresc \238ntre spr\226ncene."
gameforge.locale.monster_chat_2106_1 = "Se pare ca acolo este cineva pe care am sa-l pun la pamant."
gameforge.locale.monster_chat_2106_2 = "Oh da, imi vad urmatoarea osanda."
gameforge.locale.monster_chat_2106_3 = "(R\226s) \206mi place, \238mi place foarte mult!"
gameforge.locale.monster_chat_2106_4 = "Acela de acolo gras si frumos. E al meu!"
gameforge.locale.monster_chat_2106_5 = {}
gameforge.locale.monster_chat_2106_6 = "Iubesc mirosul de s\226nge."
gameforge.locale.monster_chat_2107_1 = "(V\226ntur\227) \206n ziua de azi e pu\254in de lucru. (V\226ntur\227)"
gameforge.locale.monster_chat_2107_2 = "Hei! Sunt chiar grase!"
gameforge.locale.monster_chat_2107_3 = "Coducatorul va fi incantat..."
gameforge.locale.monster_chat_2107_4 = {}
gameforge.locale.monster_chat_2107_5 = "S\227 mai v\226ntur\227m odat\227 piciorul!"
gameforge.locale.monster_chat_2107_6 = "Aceasta sageata este numai pentru tine."
gameforge.locale.monster_chat_2108_1 = "Dac\227 \238l nimeresc pe vreunul, atunci... "
gameforge.locale.monster_chat_2108_2 = "Hei, de ce te ui\254i?"
gameforge.locale.monster_chat_2108_3 = "Crezi c\227 sunt u\186or de \238nvins? Hm?"
gameforge.locale.monster_chat_2108_4 = "A\186a un ghinion, s\227 m\227 prind\227 aici \238n de\186ert!"
gameforge.locale.monster_chat_2108_5 = "Ah, sentimentul \227sta!! O s\227 m\227 bucur de el la nesf\226r\186it!"
gameforge.locale.monster_chat_2108_6 = "Mul\254umesc!"
gameforge.locale.monster_chat_2191_1 = "Simt miros de oameni. Ce miros delicios!"
gameforge.locale.monster_chat_2191_2 = "Bine. Veni\254i la mine."
gameforge.locale.monster_chat_2191_3 = {}
gameforge.locale.monster_chat_2191_4 = "Ce ma bucur ca te-ai ratacit si ai ajuns pe aici!"
gameforge.locale.monster_chat_2191_5 = "R\227m\226i pe loc! Kkkkkkk!"
gameforge.locale.monster_chat_2191_6 = "Muscatura cu muscatura o sa te las fara carne..."
gameforge.locale.monster_chat_2202_1 = "Apropie-te ca sa-ti smulg pielea."
gameforge.locale.monster_chat_2202_2 = "Stii cate dureri ti-ar putea provoca o temperatura atat de ridicata?"
gameforge.locale.monster_chat_2202_3 = "Poate ar trebui sa-mi sting arsurile cu niste sange proaspat."
gameforge.locale.monster_chat_2202_4 = "Sangele tau...lasa-ma sa-l gust."
gameforge.locale.monster_chat_2202_5 = "Nu exista niciun motiv pentru a incepe o lupta."
gameforge.locale.monster_chat_2202_6 = "Poti deveni ca mine! Numai flacari si groaza."
gameforge.locale.monster_chat_2204_1 = "At\226ta timp c\226t sunt eu aici, nu intr\227 nimeni!"
gameforge.locale.monster_chat_2204_2 = "Dintr-un oarecare motiv \238mi devii o povar\227."
gameforge.locale.monster_chat_2204_3 = {}
gameforge.locale.monster_chat_2204_4 = "Kwuuh, \186tii unde e\186ti?"
gameforge.locale.monster_chat_2204_5 = {}
gameforge.locale.monster_chat_2204_6 = "Esti cel mai patetic oponent al meu!"
gameforge.locale.monster_chat_2205_1 = "O sabie \238\186i \238ndepline\186te rolul doar \238n m\226na unui r\227zboinic."
gameforge.locale.monster_chat_2205_2 = "\222ine sabia tot timpul \238n m\226n\227."
gameforge.locale.monster_chat_2205_3 = "R\227zboiul bate la u\186\227."
gameforge.locale.monster_chat_2205_4 = "\170i acum lupt\227m p\226n\227 la moarte!"
gameforge.locale.monster_chat_2205_5 = "Vrei s\227 rezi\186ti mai departe atacurilor?"
gameforge.locale.monster_chat_2205_6 = "Da, nu ar trebui s\227 mori a\186a repede."
gameforge.locale.monster_chat_2206_1 = "Lava este elixirul vie\254ii."
gameforge.locale.monster_chat_2206_2 = "Lava m\227 \254ine \238n via\254\227 iar pe tine te va ucide!"
gameforge.locale.monster_chat_2206_3 = "Nu este minunata aceasta lume care clocoteste in lava?"
gameforge.locale.monster_chat_2206_4 = "Indraznesti sa ma deranjezi?"
gameforge.locale.monster_chat_2206_5 = "Ar trebui s\227 pleci dac\227 \238\254i pas\227 de via\254a ta."
gameforge.locale.monster_chat_2206_6 = "Vei regreta prezenta mea aici."
gameforge.locale.monster_chat_2291_1 = "Este o zi frumoasa. Tot ce as vrea ar fi sa am putina liniste."
gameforge.locale.monster_chat_2291_2 = "Nimic nu se poate m\227sura cu \254ara lui Doyyumhwan."
gameforge.locale.monster_chat_2291_3 = "Putin sange proaspat ar fi o schimbare placuta."
gameforge.locale.monster_chat_2291_4 = "Se pare ca-ti cauti moartea, altfel nu m-ai fi deranjat. "
gameforge.locale.monster_chat_2291_5 = "Deja regreti ca ai ajuns aici?"
gameforge.locale.monster_chat_2291_6 = "Prea tarziu sa mai fugi. Infrunta-ti temerile."
gameforge.locale.monster_chat_301_1 = "Aceste vremuri tensionate ma fac sa-mi pierd rabdarea."
gameforge.locale.monster_chat_301_2 = "Acum doua zile o fata tanara a fost mutilata de animalele din aceasta zona."
gameforge.locale.monster_chat_301_3 = "Animalele salbatice devin din ce in ce mai agresive. Trebuie sa omoram cat de multe putem."
gameforge.locale.monster_chat_301_4 = "Azi nu sunt intr-o dispozitie buna. Strainii ar trebui sa stea departe de mine."
gameforge.locale.monster_chat_301_5 = "Ultimul r\227zboinic pe care l-am omor\226t m\227 implora pentru via\254a lui."
gameforge.locale.monster_chat_302_1 = "Cineva trebuie sa faca ceva cu aceste pietre."
gameforge.locale.monster_chat_302_2 = "Nu am incredere in dimineata asta linistita."
gameforge.locale.monster_chat_302_3 = "Presiunea atmosferica imi da o stare de inconfort."
gameforge.locale.monster_chat_302_4 = "Aceste sageti au fost ascutite foarte bine."
gameforge.locale.monster_chat_302_5 = "Daca as fi in locul tau as avea grija. Sageata se indreapta chiar spre inima ta."
gameforge.locale.monster_chat_302_6 = "Ar trebui sa merg acolo si sa ucid cateva dintre acele bestii."
gameforge.locale.monster_chat_303_1 = "\206nv\227\254\227tura artelor mar\254iale este esen\254ial\227 \238n aceste vremuri."
gameforge.locale.monster_chat_303_2 = "Ce se \238nt\226mpl\227 dac\227 deodat\227 dau buzna solda\254i ai guvernului?"
gameforge.locale.monster_chat_303_3 = "De ce te ui\254i a\186a la mine? "
gameforge.locale.monster_chat_303_4 = "Lasii au o sansa mica de supravietuire."
gameforge.locale.monster_chat_303_5 = "Nu te supraestima."
gameforge.locale.monster_chat_303_6 = "Se pare ca cineva te-a antrenat foarte bine."
gameforge.locale.monster_chat_304_1 = "Chiar si stramosii mei au reusit sa se afirme in lupta pe aceste teritorii."
gameforge.locale.monster_chat_304_2 = "Trebuie sa stai in alerta si bine pregatit pe aici."
gameforge.locale.monster_chat_304_3 = "Nici sa nu te gandesti sa ma faci sa-mi pierd timpul."
gameforge.locale.monster_chat_304_4 = "Deci, cum te sim\254i c\226nd via\254a ta este \238n pericol?"
gameforge.locale.monster_chat_304_5 = "Oh nu! Renun\254i deja? "
gameforge.locale.monster_chat_304_6 = "Durerea vine foarte repede."
gameforge.locale.monster_chat_305_1 = "Oh doamne! Sabia arat\227 grozav!"
gameforge.locale.monster_chat_305_2 = "M\227re\186te-\254i \238nc\227p\227\254\226narea, puterea ta!"
gameforge.locale.monster_chat_305_3 = "Crezi c\227 po\254i deveni a\186a puternic ca mine?"
gameforge.locale.monster_chat_305_4 = "Bine. De ce s\227 nu juc\227m serios atunci?"
gameforge.locale.monster_chat_305_5 = "Vai de mine! Eu sunt doar o femeie slab\227!"
gameforge.locale.monster_chat_305_6 = "Pari obosit. De ce nu renun\254i? Ho, ho, ho!"
gameforge.locale.monster_chat_306_1 = "Oare ce va face Serangyi ast\227zi?"
gameforge.locale.monster_chat_306_2 = "M\227 plictisesc. Joac\227-te cu mine!"
gameforge.locale.monster_chat_306_3 = "Eu \238l prefer pe tipul Sura."
gameforge.locale.monster_chat_306_4 = "He! Cum ar fi o lupt\227?"
gameforge.locale.monster_chat_306_5 = "Nu m\227 subestima doar pentru c\227 sunt femeie!"
gameforge.locale.monster_chat_306_6 = "Durerea dureaz\227 doar un moment."
gameforge.locale.monster_chat_307_1 = "Vreau cu orice pre\254 s\227 scap de aici."
gameforge.locale.monster_chat_307_2 = "C\226t de sigure sunt coifurile membrilor? Bine?"
gameforge.locale.monster_chat_307_3 = "Voi fetelor, t\227ce\254i din gur\227!"
gameforge.locale.monster_chat_307_4 = "Las\227-m\227 s\227 te lichidez dintr-o lovitur\227."
gameforge.locale.monster_chat_307_5 = "Nici s\227 nu te g\226nde\186ti s\227 fugi."
gameforge.locale.monster_chat_307_6 = "Deci, de ce nu \238ncepem?"
gameforge.locale.monster_chat_394_1 = "Nu uita: To\254i b\227rba\254ii sunt inamici."
gameforge.locale.monster_chat_394_2 = "Dac\227 o persoan\227 are o fa\254\227 dr\227gu\254\227, putem fi mai bl\226nzi."
gameforge.locale.monster_chat_394_3 = "Ce, vrei s\227 lup\254i?"
gameforge.locale.monster_chat_394_4 = "Nu va dura mult, dar va durea."
gameforge.locale.monster_chat_394_5 = "Ah, pare c\227 ai cu adev\227rat dureri."
gameforge.locale.monster_chat_394_6 = "Adio, merge\254i \238n iad!"
gameforge.locale.monster_chat_401_1 = "\170i, ce fac ei \238n armata alb\227?"
gameforge.locale.monster_chat_401_2 = "Unde mergi?"
gameforge.locale.monster_chat_401_3 = "Hei! Vrei s\227 lup\254i?"
gameforge.locale.monster_chat_401_4 = "Ha, ha, ha! Evi\254i loviturile mele."
gameforge.locale.monster_chat_401_5 = "Crezi c\227 po\254i s\227 scapi?"
gameforge.locale.monster_chat_401_6 = "Vine lovitura mea!"
gameforge.locale.monster_chat_402_1 = "Doamne, sunt atat de obosit!"
gameforge.locale.monster_chat_402_2 = "Hei! Frumoas\227 armur\227. Te-a costat mult? "
gameforge.locale.monster_chat_402_3 = "Dar este vreme bun\227."
gameforge.locale.monster_chat_402_4 = "Oh! Se pare c\227 te-ai antrenat mult. Grozav!"
gameforge.locale.monster_chat_402_5 = "Cum \254i se par capacit\227\254ile mele? Bune, nu? Ha, ha, ha!"
gameforge.locale.monster_chat_402_6 = "Ce se \238nt\226mpl\227? Normal! E viteza asta nebun\227!"
gameforge.locale.monster_chat_403_1 = "De ce nu merg oare la v\226n\227toare?"
gameforge.locale.monster_chat_403_2 = "Ast\227zi nu ne atac\227 nimeni satul."
gameforge.locale.monster_chat_403_3 = "Lupt\227, dac\227 vrei s\227 lup\254i! Bastardule!"
gameforge.locale.monster_chat_403_4 = "Ha, ha, ha! E\186ti totu\186i doar un amator!"
gameforge.locale.monster_chat_403_5 = "S\227 te nimeresc \238nt\226i \238n picior sau \238n bra\254?"
gameforge.locale.monster_chat_403_6 = "Uite s\227geata mea!"
gameforge.locale.monster_chat_404_1 = "\206n cur\226nd trebuie s\227 merg \238n sat s\227 m\227 antrenez."
gameforge.locale.monster_chat_404_2 = "M\227 simt \238n\254epenit."
gameforge.locale.monster_chat_404_3 = "Ce avem ast\227zi de m\226ncare?"
gameforge.locale.monster_chat_404_4 = "M\227 uit, a\186a c\227 strig\227 c\226t pofte\186ti."
gameforge.locale.monster_chat_404_5 = "Prea mult a\186teptat? S\227 v\226ntur\227m odat\227 sabia!"
gameforge.locale.monster_chat_404_6 = "Sabia sun\227 a\186a provocator! "
gameforge.locale.monster_chat_405_1 = "Sabia aceasta e preg\227tit\227 s\227 \238nceap\227!"
gameforge.locale.monster_chat_405_2 = "S\227 vedem pe cine va ucide sabia primul!"
gameforge.locale.monster_chat_405_3 = "Hei! La ce te ui\254i?"
gameforge.locale.monster_chat_405_4 = "\206nt\226i burta!"
gameforge.locale.monster_chat_405_5 = "Teaca nu este standard pentru un lupt\227tor cu sabia?"
gameforge.locale.monster_chat_405_6 = "\206mi place s\227 am pe cineva ca tine \238n loc de teac\227."
gameforge.locale.monster_chat_406_1 = "Fl\227m\226nzesc!"
gameforge.locale.monster_chat_406_2 = "Avem ceva de m\226ncare?"
gameforge.locale.monster_chat_406_3 = "De ce oare mi-e \238nc\227 foame, dup\227 ce am m\226ncat at\226ta?"
gameforge.locale.monster_chat_406_4 = "Waaah, mori!"
gameforge.locale.monster_chat_406_5 = "Stomacul meu va decide aceast\227 lupt\227!"
gameforge.locale.monster_chat_406_6 = "Este alegerea \238ntre cer \186i iad!"
gameforge.locale.monster_chat_491_1 = "Nu mai suport! M\227 furnic\227 \238n tot corpul."
gameforge.locale.monster_chat_491_2 = "Oh da. V\227d acolo c\226\254iva porci."
gameforge.locale.monster_chat_491_3 = "La p\227m\226nt?"
gameforge.locale.monster_chat_491_4 = "Te lichidez dintr-o lovitur\227."
gameforge.locale.monster_chat_491_5 = "Aceasta va fi o amintire memorabila!"
gameforge.locale.monster_chat_491_6 = "Mori!"
gameforge.locale.monster_chat_492_1 = "Corpul meu este sl\227bit."
gameforge.locale.monster_chat_492_2 = "Oare de ce nu mai exersez?"
gameforge.locale.monster_chat_492_3 = "Fric\227? Hm?"
gameforge.locale.monster_chat_492_4 = "Ah, doar o nou\227 victim\227 a armei mele v\226j\226itoare!"
gameforge.locale.monster_chat_492_5 = "Poti vedea stilul meu de atac? Nu? Pierderea ta!"
gameforge.locale.monster_chat_492_6 = "Chiar \186i o t\227ietur\227 mic\227 d\227uneaz\227 s\227n\227t\227\254ii, \186tiai?"
gameforge.locale.monster_chat_493_1 = "La naiba, e a\186a de incomod s\227 ai a\186a o m\226n\227."
gameforge.locale.monster_chat_493_2 = "La ce te ui\254i? Nu ai mai v\227zut pe cineva cu a\186a o m\226n\227?"
gameforge.locale.monster_chat_493_3 = "Voi chiar m\227 c\227lca\254i pe nervi."
gameforge.locale.monster_chat_493_4 = "S\227 te bat m\227r? Dac\227 nu vrei asta, atunci pleac\227 acum, bine?"
gameforge.locale.monster_chat_493_5 = "Acum v\227 ar\227t lovitura mea mare!"
gameforge.locale.monster_chat_493_6 = "\170tiu c\227 te holbezi la m\226na mea!"
gameforge.locale.monster_chat_494_1 = "Hei, tu acolo! Dac\227 vrei s\227 lup\254i, vino \238ncoace!"
gameforge.locale.monster_chat_494_2 = "M\227 cred destul de interesant."
gameforge.locale.monster_chat_494_3 = "De ce nu intreprindem ceva?"
gameforge.locale.monster_chat_494_4 = "Nu, s\227 ie\186im nu avem \238nc\227 voie. Lupt\227!"
gameforge.locale.monster_chat_494_5 = "Bine, uite!"
gameforge.locale.monster_chat_494_6 = "E\186ti aproape mort."
gameforge.locale.monster_chat_501_1 = "Joac\227-te cu mine! R\227m\226i aici!"
gameforge.locale.monster_chat_501_2 = "As putea sculpta ceva frumos din oasele tale..."
gameforge.locale.monster_chat_501_3 = "Nu am exersat \238nc\227."
gameforge.locale.monster_chat_501_4 = "Oh, ce armur\227 frumoas\227! Pe aia o vreau."
gameforge.locale.monster_chat_501_5 = "De acum \238\254i va fi greu s\227 \238mi ignori atacul!"
gameforge.locale.monster_chat_501_6 = "Ha, ha, ha! Surprins, nu?"
gameforge.locale.monster_chat_502_1 = "Frumusetea nu e totul."
gameforge.locale.monster_chat_502_2 = "Nu te holba, lupt\227!"
gameforge.locale.monster_chat_502_3 = "Nu \238mi place cum te holbezi la mine. Vino \238ncoace!"
gameforge.locale.monster_chat_502_4 = "Este o onoare s\227 mori din sabia mea!!"
gameforge.locale.monster_chat_502_5 = {}
gameforge.locale.monster_chat_502_6 = "Excelent!"
gameforge.locale.monster_chat_503_1 = "Hei! Nu atinge!"
gameforge.locale.monster_chat_503_2 = "Se pare c\227 mi s-a rupt coarda arcului."
gameforge.locale.monster_chat_503_3 = "La naiba! Au venit idio\254ii \227\186tia."
gameforge.locale.monster_chat_503_4 = "Nu-i r\227u. Dar totu\186i ai s\227 mori!"
gameforge.locale.monster_chat_503_5 = "E\186ti de acord cu asta? E divin!"
gameforge.locale.monster_chat_503_6 = "Uite s\227geata!"
gameforge.locale.monster_chat_504_1 = "Veni\254i to\254i \238ncoace!"
gameforge.locale.monster_chat_504_2 = "La, lala, fredonez un cantec..."
gameforge.locale.monster_chat_504_3 = "Ce vreme frumoas\227."
gameforge.locale.monster_chat_504_4 = {}
gameforge.locale.monster_chat_504_5 = "Bine! \206\254i apreciez dorin\254a de lupt\227!"
gameforge.locale.monster_chat_504_6 = "Veniti aici! Toata lumea la mine!"
gameforge.locale.monster_chat_601_1 = "Sunt a\186a fl\227m\226nd!"
gameforge.locale.monster_chat_601_2 = "A\186 vrea s\227 m\227n\226nc fructe."
gameforge.locale.monster_chat_601_3 = "Ei bine, saramura facem. La atac!"
gameforge.locale.monster_chat_601_4 = "Nu fugi! Stai pe loc!"
gameforge.locale.monster_chat_601_5 = "Am c\226\186tigat! Este evident!"
gameforge.locale.monster_chat_601_6 = "Vezi? Ai ratat!"
gameforge.locale.monster_chat_601_7 = "Trebuie sa ai grija, haha!"
gameforge.locale.monster_chat_602_1 = "Unde sunt?"
gameforge.locale.monster_chat_602_2 = "Frumoas\227 vreme. "
gameforge.locale.monster_chat_602_3 = "Vii s\227 m\227 v\226nezi? Ridicol!"
gameforge.locale.monster_chat_602_4 = "Tu e\186ti prada mea. "
gameforge.locale.monster_chat_602_5 = "Ce teroare, hm? Bine, las\227-m\227 s\227 te lichidez!"
gameforge.locale.monster_chat_602_6 = "Uite cat de tare sunt: pot invarti acest ciomag gigant!"
gameforge.locale.monster_chat_603_1 = "Plictisitor!"
gameforge.locale.monster_chat_603_2 = "M\227 furnic\227 \238n tot corpul."
gameforge.locale.monster_chat_603_3 = "Cine reu\186e\186te primul."
gameforge.locale.monster_chat_603_4 = "Tu m-ai nimerit primul? Am s\227 te alung."
gameforge.locale.monster_chat_603_5 = "Odat\227 ce ai intrat, nu mai po\254i ie\186i. Fuga este de prisos acum!"
gameforge.locale.monster_chat_603_6 = "Aceasta va fi ultima lovitur\227. Te lichidez!"
gameforge.locale.monster_chat_604_1 = "Am facut o noua otrava . Doresti sa gusti?"
gameforge.locale.monster_chat_604_2 = "Vreau sa vad cum merge! Poftim, ia-o!"
gameforge.locale.monster_chat_604_3 = "Hei, tu de acolo! Vino aici, vrei sa te fac cobaiul meu?"
gameforge.locale.monster_chat_604_4 = "Te otr\227vesc! "
gameforge.locale.monster_chat_604_5 = "Oh, ce bine! Un \186oarece de laborator!"
gameforge.locale.monster_chat_604_6 = "Nu e distractiv daca renunti asa repede! Haide, apara-te!"
gameforge.locale.monster_chat_631_1 = "Asteapta un moment. Caut ceva sa vanez."
gameforge.locale.monster_chat_631_2 = "Nu ajuta cu nimic daca te misti atat de incet Misca!"
gameforge.locale.monster_chat_631_3 = "Mi-e a\186a de foame!"
gameforge.locale.monster_chat_631_4 = "Este nemaipomenit ca am gasit ce sa vanez!"
gameforge.locale.monster_chat_631_5 = "Toti speram sa supravietuim! Tu nu vei supravietui!"
gameforge.locale.monster_chat_631_6 = "Acum vei afla ce inseamna cu adevarat durerea!"
gameforge.locale.monster_chat_632_1 = "Plictisitoooor!"
gameforge.locale.monster_chat_632_2 = "Exist\227 vreo momeal\227 bun\227?"
gameforge.locale.monster_chat_632_3 = "Vino \186i lupt\227 dac\227 vrei!"
gameforge.locale.monster_chat_632_4 = "Te crezi r\227zboinic? Atunci arat\227 ce po\254i!"
gameforge.locale.monster_chat_632_5 = {}
gameforge.locale.monster_chat_632_6 = "Fugi \238n sat dac\227 vrei s\227 r\227m\226i \238n via\254\227!"
gameforge.locale.monster_chat_633_1 = "Doare s\227 fl\227m\226nze\186ti."
gameforge.locale.monster_chat_633_2 = "Oh, vin spre noi."
gameforge.locale.monster_chat_633_3 = "Cum ar fi cu un duel?"
gameforge.locale.monster_chat_633_4 = "Nu m\227 compara cu ace\186ti bastarzi!"
gameforge.locale.monster_chat_633_5 = "Acum vine lovitura mea de tunet!"
gameforge.locale.monster_chat_633_6 = "Cei care fug nu sunt r\227zboinici adev\227ra\254i!"
gameforge.locale.monster_chat_634_1 = "De data aceasta otrava trebuie s\227 fie cu adev\227rat bun\227!"
gameforge.locale.monster_chat_634_2 = "C\226nd \254i-e foame, liliecii sunt o delicates\227!"
gameforge.locale.monster_chat_634_3 = "Cum ar fi cu o lupt\227?"
gameforge.locale.monster_chat_634_4 = "Dup\227 ce otrava mea a ajuns \238n corp, nu mai exist\227 vindecare."
gameforge.locale.monster_chat_634_5 = "Magia mea va arde totul imprejur, hehehe!"
gameforge.locale.monster_chat_634_6 = "Arzi! Ha, ha!"
gameforge.locale.monster_chat_635_1 = "Nu uita niciodata sa-ti ascuti sabia. Urmatoarea lupta e mai devreme decat crezi."
gameforge.locale.monster_chat_635_2 = "Le\186in?"
gameforge.locale.monster_chat_635_3 = "Mori \186i re\238nvie \238n alt\227 via\254\227!"
gameforge.locale.monster_chat_635_4 = "Pe mine s\227 m\227 \238nfr\226ngi? Serios?"
gameforge.locale.monster_chat_635_5 = "Lupt\227 ca un r\227zboinic!"
gameforge.locale.monster_chat_635_6 = "Haide, inca putin de tot."
gameforge.locale.monster_chat_636_1 = "Ha, caut o lupta frumoasa."
gameforge.locale.monster_chat_636_2 = "Lupta e distractiv\227. (R\226s)"
gameforge.locale.monster_chat_636_3 = "A\186 dori s\227 lupt \238n continuu!"
gameforge.locale.monster_chat_636_4 = "Foarte bine! Incearca din nou!"
gameforge.locale.monster_chat_636_5 = "Uita-te cum imi vantur sabia!"
gameforge.locale.monster_chat_636_6 = "O s\227 \238\254i par\227 r\227u c\227 m-ai nimerit!"
gameforge.locale.monster_chat_636_7 = "Asa de slab! Cat de ridicol!"
gameforge.locale.monster_chat_637_1 = "Nu vreau s\227 fiu deranjat."
gameforge.locale.monster_chat_637_2 = "Mergi la culcare. Pentru totdeauna!"
gameforge.locale.monster_chat_637_3 = "Nu ai adormit \238nc\227?"
gameforge.locale.monster_chat_637_4 = "Sunt atat de multe de facut! Sa terminam cu ele!"
gameforge.locale.monster_chat_637_5 = "Nu te mira de puterea mea!"
gameforge.locale.monster_chat_637_6 = "Te pulverizez!"
gameforge.locale.monster_chat_691_1 = "Grozav, oponentii puternici rezista mai mult! Apara-te!"
gameforge.locale.monster_chat_691_2 = "Ce? Cum ar\227t?"
gameforge.locale.monster_chat_691_3 = "Nu m\227 compara cu acest neputiincios."
gameforge.locale.monster_chat_691_4 = "Nici el nu te place iar eu nici atat!"
gameforge.locale.monster_chat_691_5 = "Sa luptam."
gameforge.locale.monster_chat_691_6 = "Pana la moarte!"
gameforge.locale.monster_chat_701_1 = "Uite, un fluturas! Cat de frumos!"
gameforge.locale.monster_chat_701_2 = "Nu vezi adev\227rul cerululi \186i al p\227m\226ntului?"
gameforge.locale.monster_chat_701_3 = "Mai \238ncolo va fi prea t\226rziu. Crezi deja de pe acum!"
gameforge.locale.monster_chat_701_4 = "Crezi \238n \238nv\227\254\227tura esotericilor!"
gameforge.locale.monster_chat_701_5 = "Scepticii vor fi uci\186i!"
gameforge.locale.monster_chat_701_6 = "Ilumineaz\227-te prin \238mbr\227\254i\186area mor\254ii!"
gameforge.locale.monster_chat_702_1 = "Adevarul despre credinta esoterica salasuieste in puterea cerului."
gameforge.locale.monster_chat_702_2 = "Filosofia credin\254ei esoterice este ordinea cerului."
gameforge.locale.monster_chat_702_3 = "Adev\227rul esoteric, adev\227rul zeului tigru, Sabaha Sabah."
gameforge.locale.monster_chat_702_4 = "\206ndr\227zne\186ti s\227 pui sub semnul \238ntreb\227rii adev\227rul cerului \186i al p\227m\226ntului?"
gameforge.locale.monster_chat_702_5 = {}
gameforge.locale.monster_chat_702_6 = "Simte-mi clestii!"
gameforge.locale.monster_chat_703_1 = "C\226nd va fi c\226ntat adev\227rul zeului tigru, atunci va sf\226r\186i suferin\254a."
gameforge.locale.monster_chat_703_2 = "Adevarul despre credinta esoterica salasuieste in puterea cerului."
gameforge.locale.monster_chat_703_3 = "Sabaha Sabaha. Trimite-ne \238n\254elegere."
gameforge.locale.monster_chat_703_4 = "Nu \186ov\227i!"
gameforge.locale.monster_chat_703_5 = "Prime\186te tunetul cerurilor!"
gameforge.locale.monster_chat_703_6 = "Cicatricea tribunalului!"
gameforge.locale.monster_chat_704_1 = "Adevarul despre credinta esoterica salasuieste in puterea cerului."
gameforge.locale.monster_chat_704_2 = "Adev\227rul esoteric, adev\227rul zeului tigru, Sabaha Sabah."
gameforge.locale.monster_chat_704_3 = "Crezi ca sunt clovn, nu-i asa? Nu pentru mult timp!"
gameforge.locale.monster_chat_704_4 = "Conduc\227torul sectei este un sf\226nt \186i se afl\227 deasupra tuturor creaturilor!"
gameforge.locale.monster_chat_704_5 = "Ia flac\227ra iadului!"
gameforge.locale.monster_chat_704_6 = "Pariez ca nu ai mai vazut niciodata o furca atat de mare, nu-i asa?"
gameforge.locale.monster_chat_705_1 = "Adev\227rul esoteric, adev\227rul zeului tigru, Sabaha Sabah."
gameforge.locale.monster_chat_705_2 = "Adevarul despre credinta esoterica salasuieste in puterea cerului."
gameforge.locale.monster_chat_705_3 = "Doar pentru ca sunt mai mic decat fratele meu nu inseamna ca trebuie sa am grija de toate!"
gameforge.locale.monster_chat_705_4 = "Te asteapta suferinta eterna si intunericul!"
gameforge.locale.monster_chat_705_5 = {}
gameforge.locale.monster_chat_705_6 = "Acesta nu este sf\226r\186itul. Va veni drumul mai bun."
gameforge.locale.monster_chat_706_1 = "Ne rug\227m pentru pace \186i lini\186te! Te rog!"
gameforge.locale.monster_chat_706_2 = "C\226nd domne\186te frica, ne ajut\227 adev\227rul zeului tigru."
gameforge.locale.monster_chat_706_3 = "Adev\227rul credin\254ei esoterice este ordinea \186i \238n\254elegerea cerului."
gameforge.locale.monster_chat_706_4 = "S\227 mergem to\254i \238n iad!"
gameforge.locale.monster_chat_706_5 = "Nu te las s\227 pleci!"
gameforge.locale.monster_chat_706_6 = "Am s\227 \238\254i dau tot ce am!"
gameforge.locale.monster_chat_707_1 = "Te implor. Salveaz\227-ne!"
gameforge.locale.monster_chat_707_2 = "Adevarul despre credinta esoterica salasuieste in puterea cerului."
gameforge.locale.monster_chat_707_3 = "Adev\227rul esoteric, adev\227rul zeului tigru, Sabaha Sabah."
gameforge.locale.monster_chat_707_4 = "(R\226s tare) Poarta iadului este deschis\227. Mori!"
gameforge.locale.monster_chat_707_5 = "Te avertizez: Nu ma forta sa folosesc scandura!"
gameforge.locale.monster_chat_707_6 = "\206\254i v\227d deja moartea!"
gameforge.locale.monster_chat_791_1 = "Cum s\227 \238\254i povestesc pe scurt adev\227rul despre ordinea cerului \186i a universului?"
gameforge.locale.monster_chat_791_2 = "Aud c\226ntecele credincio\186ilor."
gameforge.locale.monster_chat_791_3 = "Este adev\227rat! C\227ie\186te-te. Vei fi salvat."
gameforge.locale.monster_chat_791_4 = "Suferi de durere etern\227 pentru c\227 pui sub semnul \238ntreb\227rii adev\227rata \238nv\227\254\227tur\227."
gameforge.locale.monster_chat_791_5 = "Las\227-m\227 s\227 te intruiesc mai departe."
gameforge.locale.monster_chat_791_6 = "Nu ai voie s\227 o vezi ca pe o suferin\254\227. Este o indica\254ie."
gameforge.locale.monster_chat_901_1 = "Poate ca nu sunt asa dragut dar sunt extraordinar de amuzant, hihihi!"
gameforge.locale.monster_chat_901_2 = "Trebuie s\227 devii ca noi!"
gameforge.locale.monster_chat_901_3 = "Vino la noi, hihi!"
gameforge.locale.monster_chat_901_4 = "Haaa, haha!"
gameforge.locale.monster_chat_901_5 = "\206ncepe!"
gameforge.locale.monster_chat_903_1 = "Aici este iadul!"
gameforge.locale.monster_chat_903_2 = "Ahhhhh!."
gameforge.locale.monster_chat_903_3 = "Nu putem rezista singuri! Nu!"
gameforge.locale.monster_chat_903_4 = "\170i tu trebuie s\227 gu\186ti aceast\227 suferin\254\227!"
gameforge.locale.monster_chat_903_5 = "Ce spui de un schimb? Imi dai sufletul tau pe suferinta mea!"
gameforge.locale.monster_chat_903_6 = "Vei afla \238n cur\226nd pacea etern\227!"
gameforge.locale.monster_chat_904_1 = "Doare! Doare!"
gameforge.locale.monster_chat_904_2 = "Ahhh, la naiba! Mana mea arde!"
gameforge.locale.monster_chat_904_3 = "De ce trebuie s\227 suferim? De ce?"
gameforge.locale.monster_chat_904_4 = "Nu este a\186a de r\227u s\227 suferi de misterioasa boal\227!"
gameforge.locale.monster_chat_904_5 = {}
gameforge.locale.monster_chat_904_6 = "Ahhhh!"
gameforge.locale.monster_chat_905_1 = "Ahhhhh!."
gameforge.locale.monster_chat_905_2 = "Te omooooooooor."
gameforge.locale.monster_chat_905_3 = "Nu te uita doar. Particip\227!"
gameforge.locale.monster_chat_905_4 = "Hai s\227 fim prieteni!"
gameforge.locale.monster_chat_905_5 = "Te-ai molipsit deja."
gameforge.locale.monster_chat_905_6 = "Acum e\186ti prietenul meu."
gameforge.locale.monster_chat_906_1 = "Hihihi!"
gameforge.locale.monster_chat_906_2 = "Vine \186i \238nfige-te \238n s\227geata mea."
gameforge.locale.monster_chat_906_3 = "M\227 calci pe nervi."
gameforge.locale.monster_chat_906_4 = "Am s\227 te molipsesc de boala misterioas\227."
gameforge.locale.monster_chat_906_5 = "Delicios miros!"
gameforge.locale.monster_chat_906_6 = "Mori!"
gameforge.locale.monster_chat_907_1 = "\170i c\226nd g\227sesc alt\227 cauz\227..."
gameforge.locale.monster_chat_907_2 = "(R\226s) Va fi o distrac\254ie."
gameforge.locale.monster_chat_907_3 = "Hmm, biciuit sau sfartecat...?"
gameforge.locale.monster_chat_907_4 = "Ahhhhh, daaaaaa!"
gameforge.locale.monster_chat_907_5 = "Las\227-m\227 s\227 \238\254i transmit cauza!"
gameforge.locale.monster_chat_907_6 = "Aceast\227 cauz\227 \238nc\227p\227\254\226nat\227 a misterioasei boli!"
