gameforge.locale.old_pirate.baekgo_accept_ask = "Baek-Go:[ENTER]Nu ai g\227sit \238nc\227 nimic?[ENTER]Trebuie s\227 oprim boala, \238nainte s\227 se extind\227 \238n[ENTER]tot satul! Gr\227be\186te-te!"
