gameforge.locale.old_pirate.baekgo_accept_success_info_label = "Du-i mostra lui Baek-Go"
gameforge.locale.old_pirate.baekgo_accept_success_info_text_1 = "Du-i mostra pentru cauza misterioasei boli lui[ENTER]Baek-Go."
gameforge.locale.old_pirate.baekgo_accept_success_info_text_2 = "D\227-i mostra pentru cauza misterioasei boli \186i[ENTER]prime\186te medicamentul pentru b\227tr\226nul pirat."
gameforge.locale.old_pirate.baekgo_accept_success_say_1 = "Am o mostr\227 pentru cauza misterioasei boli."
gameforge.locale.old_pirate.baekgo_accept_success_say_2 = "Am o mostra din virusul misterios. Ar trebui dusa[ENTER]la Baek-Go."
gameforge.locale.old_pirate.baekgo_do_you_get_the_virus = "Nu \186tiu \238nc\227 ce se ascunde \238n spatele[ENTER]misterioasei boli."
gameforge.locale.old_pirate.baekgo_iv_got_the_virus = "Am descoperit cauza misterioasei boli."
gameforge.locale.old_pirate.baekgo_order_find_virus_label = "Ucide toate persoanele infectate"
gameforge.locale.old_pirate.baekgo_order_find_virus_text_1 = "Ucide-i pe to\254i care s-au molipsit de misterioasa[ENTER]boal\227!"
gameforge.locale.old_pirate.baekgo_order_find_virus_text_2 = "Ucide-i pe care care poart\227 cauza misterioasei[ENTER]boli \186i adu o mostr\227 la Baek-Go.[ENTER]El va produce un medicament pentru b\227tr\226nul pirat."
gameforge.locale.old_pirate.baekgo_order_too_late = "Baek-Go:[ENTER]Altcineva mi-a adus deja o mostr\227 pentru cauza[ENTER]bolii. I-am trimis piratului medicamentul; ar[ENTER]trebui s\227 \238i mearg\227 mai bine."
gameforge.locale.old_pirate.baekgo_start_say = "Baek-Go:[ENTER]A avut doar o dat\227 contact cu o persoan\227 bolnav\227[ENTER]\186i de atunci rana lui a \238nceput s\227 supureze \186i s\227[ENTER]\238l m\227n\226nce?!"
gameforge.locale.old_pirate.baekgo_start_say2 = "Baek-Go:[ENTER]Vai de mine![ENTER]Sunt aproape sigur c\227 sufer\227 de misterioasa[ENTER]boal\227! Dac\227 nu va fi tratat, boala se va extinde[ENTER]\238n tot satul!"
gameforge.locale.old_pirate.baekgo_start_say3 = "Baek-Go:[ENTER]Nu trebuie sa molipseasca pe nimeni! Trebuie sa-l[ENTER]vindeci imediat. Pentru asta avem nevoie de o[ENTER]mostra din virusul bolii misterioase. Poti lua[ENTER]aceasta mostra de la o persoana bolnava. Gasesti[ENTER]multi in Nordul Muntelui Sohan."
gameforge.locale.old_pirate.baekgo_success_say = "Baek-Go:[ENTER]Ai reu\186it! A\186teapt\227 un moment dup\227 medicament![ENTER][DELAY value;1000] [/DELAY][ENTER][ENTER]L-am produs a\186a repede, c\227 nu \186tiu dac\227 \238\186i va[ENTER]face efectul, cel pu\254in \238i va merge mai bine.[ENTER]Du-i medicamentul c\226t mai repede."
gameforge.locale.old_pirate.baekgo_talk = "M-a trimis Batranul Pirat."
gameforge.locale.old_pirate.baekgo_talk_about_old_pirate = "Boala Batranului Pirat"
gameforge.locale.old_pirate.complete_say = "B\227tr\226nul pirat:[ENTER]\206nc\227 m\227 m\227n\226nc\227. Dar m\227 simt mult mai bine. A\186a[ENTER]pot tr\227i mai departe."
gameforge.locale.old_pirate.do_you_get_the_medicine = "\206nc\227 nu am medicamentul."
gameforge.locale.old_pirate.do_you_mean_this_medicine = "Aici este leacul!"
gameforge.locale.old_pirate.etc_shop_start_say = "Negustoreasa de diverse:[ENTER]B\227tr\226nul pirat? Sigur c\227 \238l cunosc. Te referi la[ENTER]tipul \227la care \238njur\227 permanent, \186i se scarpin\227[ENTER]tot timpul, nu-i a\186a? Vine des pe aici, s\227[ENTER]cumpere un lichid de vindecare. A cheltuit deja[ENTER]multe mii de Yang pe lichidul acela ro\186u."
gameforge.locale.old_pirate.etc_shop_start_say2 = "Vanzatoarea de la magazinul General:[ENTER]Unde pe pamant s-a mai pomenit sa ai atat de[ENTER]multi bani fara sa muncesti?! L-am rugat de[ENTER]atatea ori sa consulte un doctor dar niciodata nu[ENTER]m-a ascultat.[ENTER]Licoarea rosie doar amelioreaza simptomele dar nu[ENTER]vindeca si boala. Din pacate nu cred sa se[ENTER]termine cu bine pentru el."
gameforge.locale.old_pirate.etc_shop_talk_about_old_pirate = "Il cunosti pe Batranul Pirat?"
gameforge.locale.old_pirate.order_accept = "Te ajut."
gameforge.locale.old_pirate.order_accept_answer = "B\227tr\226nul pirat:[ENTER]Grozav. Mult noroc![ENTER]Doctorul este probabil \238n ora\186."
gameforge.locale.old_pirate.order_find_medicine_label = "Medicamentul pentru Batranul Pirat"
gameforge.locale.old_pirate.order_find_medicine_text_1 = "Procura medicamentul pentru Batranul Pirat."
gameforge.locale.old_pirate.order_find_medicine_text_2 = "Mergi \238n ora\186 la Baek-Go \186i \238ntreab\227-l de[ENTER]medicamentul B\227tr\226nului Pirat."
gameforge.locale.old_pirate.order_refuse = "Imi pare rau, nu pot."
gameforge.locale.old_pirate.order_refuse_answer = "B\227tr\226nul pirat:[ENTER]Atunci nu mai am ce s\227 \238\254i spun!"
gameforge.locale.old_pirate.order_say1 = "B\227tr\226nul pirat:[ENTER]La naiba! Ce vrei de la mine? V\226nz\227toarea asta de[ENTER]prostii \254i-a povestit ceva, hm? Da, are dreptate.[ENTER]Dar nu am timp s\227 merg la doctor. Am a\186a mul\254i[ENTER]inamici!"
gameforge.locale.old_pirate.order_say2 = "B\227tr\226nul pirat:[ENTER]Nu \186tii niciodat\227, c\226nd te treze\186ti cu a\186a un[ENTER]bastard care te atac\227! Dar m\227 m\227n\226nc\227 \238n a\186a hal,[ENTER]c\227 nu mai suport! Deci, po\254i merge la doctor[ENTER]pentru mine s\227 procuri un medicament \238mpotriva[ENTER]m\226nc\227rimilor? Dac\227 \238mi faci rost de medicament,[ENTER]am s\227 te r\227spl\227tesc din greu."
gameforge.locale.old_pirate.order_too_late = "B\227tr\226nul pirat:[ENTER]Altcineva mi-a procurat deja medicamentul. A\186a c\227[ENTER]nu prime\186ti nicio recompens\227."
gameforge.locale.old_pirate.start_find_old_pirate_label = "Mergi la b\227tr\226nul pirat."
gameforge.locale.old_pirate.start_find_old_pirate_text_1 = "Mergi la b\227tr\226nul pirat."
gameforge.locale.old_pirate.start_find_old_pirate_text_2 = "Mergi la b\227tr\226nul pirat \186i \238ntreab\227-l, de ce nu[ENTER]merge la doctor."
gameforge.locale.old_pirate.start_say = "B\227tr\226nul pirat:[ENTER]M\227 m\227n\226nc\227 peste tot! Nu ar fi trebuit s\227 intru[ENTER]\238n contact cu individul \227la. A fost doar o[ENTER]atingere![ENTER]De atunci supureaz\227 rana \186i m\227 m\227n\226nc\227 tot[ENTER]corpul! M\227 simt de parc\227 a\186 putrezi de viu.[ENTER]Nenorocitul!"
gameforge.locale.old_pirate.success_thanks = "Pirat B\227tr\226n:[ENTER]Poftim? M-am \238mboln\227vit de o boal\227 misterioas\227?![ENTER]Iar acesta este medicamentul potrivit? Mul\254umesc[ENTER]mult, mult de tot! Probabil mi-ai salvat via\254a.[ENTER]Apreciez."
