gameforge.locale.questscroll5.mission_10_hunt = "Mar\186ul ur\186ilor fl\227m\226nzi"
gameforge.locale.questscroll5.mission_10_mis = "Ucide 25 Urs Grizzly si 25 Urs Negru."
gameforge.locale.questscroll5.mission_10_text = "Oh, ajuta-ne te rugam. In ultimul timp un numar[ENTER]tot mai mare de Ursi Grizzly si Ursi Negri ne[ENTER]distrug stupii si plantatiile. Te rugam sa ne[ENTER]ajuti si sa omori aceste bestii, altfel o sa[ENTER]murim de foame!"
gameforge.locale.questscroll5.mission_11_hunt = "Asaltul lupilor alba\186tri"
gameforge.locale.questscroll5.mission_11_mis = "Ucide 35 de lupi alba\186tri \186i 25 de lupi alfa[ENTER]alba\186tri."
gameforge.locale.questscroll5.mission_11_text = "Ai auzit deja de asaltul lupilor alba\186tri?[ENTER]Este vorba de faptele rele ale lupilor alba\186tri[ENTER]din ultima vreme. Distrug tot ce le st\227 \238n cale,[ENTER]ca o furtun\227 de blan\227 \186i col\254i. Po\254i opri acest[ENTER]asalt al lupilor alba\186tri?"
gameforge.locale.questscroll5.mission_12_hunt = "Alung\227 armata alb\227"
gameforge.locale.questscroll5.mission_12_mis = "Ucide 20 de comandante ale jur\227m\226ntului alb."
gameforge.locale.questscroll5.mission_12_text = "\206n ultima vreme, armata alb\227 a f\227cut multe[ENTER]pagube. R\227pe\186te adesea negustori ambulan\254i \186i[ENTER]face dezastre \238n sat. Opre\186te armata alb\227.[ENTER]Anihileaz\227 membri ai armatei albe \186i conduc\227torii[ENTER]lor."
gameforge.locale.questscroll5.mission_13_hunt = "V\226nt negru nelini\186tit"
gameforge.locale.questscroll5.mission_13_mis = "Ucide 25 de Jak-To \186i 25 de To-Su ai bandei[ENTER]v\226ntului negru."
gameforge.locale.questscroll5.mission_13_text = "Se spune mai nou c\227 banda v\226ntului negru se[ENTER]preg\227te\186te s\227 preia conducerea \254\227rii dintr-o[ENTER]lovitur\227. Ar trebui s\227 anihilam conduc\227torii,[ENTER]\238nainte ca trupele lor s\227 se \238nt\227reasc\227. Te rog,[ENTER]anihileaz\227-i."
gameforge.locale.questscroll5.mission_14_hunt = "Mare r\227scoal\227 a orcilor 1"
gameforge.locale.questscroll5.mission_14_mis = "Ucide 30 de orci m\226ndri \186i 30 de spioni-orc[ENTER]m\226ndri."
gameforge.locale.questscroll5.mission_14_text = "Informa\254ii secrete spun c\227 conduc\227tori ai orcilor[ENTER]\238n valea Seungryong, \238n zona neutr\227, pun la cale[ENTER]cucerirea lumii.[ENTER]Te \238ns\227rcinez cu verificarea acestui zvon. \170i[ENTER]dac\227 tot vei fi acolo, ai putea s\227 le mai r\227re\186ti[ENTER]num\227rul."
gameforge.locale.questscroll5.mission_15_hunt = "Atac al s\227lbaticilor"
gameforge.locale.questscroll5.mission_15_mis = "Ucide 30 Infanterist Salbatic si 30 Salbatic[ENTER]Devotat."
gameforge.locale.questscroll5.mission_15_text = "Am stors ni\186te informa\254ii de la un spion[ENTER]s\227lbatic. S\227lbaticii se g\226ndesc s\227 atace regatul.[ENTER]Trebuie s\227 atac\227m \238naintea lor. Arat\227-\254i[ENTER]devotamentul fa\254\227 de regat."
gameforge.locale.questscroll5.mission_16_hunt = "Distruge Metinul Intunericului"
gameforge.locale.questscroll5.mission_16_mis = "Distruge 3 metin ai \238ntunericului."
gameforge.locale.questscroll5.mission_16_text = "De pu\254in timp plou\227 cu pietre cu Chi negativ \238n[ENTER]apropierea ora\186ului. Cercet\227ri arat\227, c\227 Chi-ul[ENTER]face animalele s\227 turbeze. Distruge aceste[ENTER]pietre. Te rog. Vei fi cu siguran\254\227 r\227spl\227tit."
gameforge.locale.questscroll5.mission_17_hunt = "Distruge Metinul Amarului"
gameforge.locale.questscroll5.mission_17_mis = "Distruge 2 Metin al Amarului"
gameforge.locale.questscroll5.mission_17_text = "De pu\254in timp plou\227 cu pietre cu Chi negativ \238n[ENTER]apropierea ora\186ului. Cercet\227ri arat\227, c\227 Chi-ul[ENTER]face animalele s\227 turbeze. Distruge aceste[ENTER]pietre. Te rog. Vei fi cu siguran\254\227 r\227spl\227tit."
gameforge.locale.questscroll5.mission_18_hunt = "Atacul Se-Rang"
gameforge.locale.questscroll5.mission_18_mis = "Ucide 10 grade Se ale armatei albe."
gameforge.locale.questscroll5.mission_18_text = "R\227zboinici, am primit noi informa\254ii despre[ENTER]armata alb\227. Ca reac\254ie la presiunile noastre,[ENTER]Se-Rang, conduc\227toarele armatei albe, au pornit[ENTER]un contraatac. F\227 ceva \238mpotriva Se-Rang. Trebuie[ENTER]s\227 le prindem pe conduc\227toare pentru a le da[ENTER]planurile peste cap."
gameforge.locale.questscroll5.mission_19_hunt = "Marea r\227scoal\227 a orcilor 2"
gameforge.locale.questscroll5.mission_19_mis = "Ucide 20 de lupt\227tori-orc m\226ndri \186i 15[ENTER]vr\227jitori-orc m\226ndri."
gameforge.locale.questscroll5.mission_19_text = "Informa\254ii secrete spun c\227 conduc\227tori ai orcilor[ENTER]\238n valea Seungryong, \238n zona neutr\227, pun la cale[ENTER]cucerirea lumii.[ENTER]Te \238ns\227rcinez cu verificarea acestui zvon. \170i[ENTER]dac\227 tot vei fi acolo, ai putea s\227 le mai r\227re\186ti[ENTER]num\227rul."
gameforge.locale.questscroll5.mission_1_hunt = "Distruge Metinul Luptei"
gameforge.locale.questscroll5.mission_1_mis = "Distruge 3 metin ai luptei."
gameforge.locale.questscroll5.mission_1_text = "De pu\254in timp plou\227 cu pietre cu Chi negativ \238n[ENTER]apropierea ora\186ului. Cercet\227ri arat\227, c\227 Chi-ul[ENTER]face animalele s\227 turbeze. Distruge aceste[ENTER]pietre. Te rog. Vei fi cu siguran\254\227 r\227spl\227tit."
gameforge.locale.questscroll5.mission_20_hunt = "Misterul maimu\254elor normale1"
gameforge.locale.questscroll5.mission_20_mis = "Ucide 30 de solda\254i maimu\254\227 \186i 30 de arunc\227tori[ENTER]maimu\254\227."
gameforge.locale.questscroll5.mission_20_text = "Am gasit in cele din urma Pestera Maimutei[ENTER]normale, care se afla in desert. In mod normal[ENTER]maimutele care locuiesc acolo sunt inofensive,[ENTER]dar cand sunt toate la un loc reprezinta o mare[ENTER]amenintare pentru regat. Mergi in Pestera[ENTER]Maimutei usoare si verifica ce se petrece acolo."
gameforge.locale.questscroll5.mission_21_hunt = "Misterul maimu\254elor u\186oare1"
gameforge.locale.questscroll5.mission_21_mis = "Ucide 30 de solda\254i maimu\254\227 slabi \186i 30 de[ENTER]arunc\227tori maimu\254\227 slabi."
gameforge.locale.questscroll5.mission_21_text = "Locatia Garnizoanei Maimutelor mici a fost[ENTER]descoperita in desert. In mod normal, ele nu[ENTER]reprezinte o amenintare, dar stranse laolalta pot[ENTER]reprezenta o amenintare pentru Regatul nostru.[ENTER]Mergi la Garnizoana Maimutelor mici si descopera[ENTER]ce se intampla."
gameforge.locale.questscroll5.mission_22_hunt = "Cine seam\227n\227 v\226nt, culege furtun\227"
gameforge.locale.questscroll5.mission_22_mis = "Ucide 4 Chuong ai bandei v\226ntului negru."
gameforge.locale.questscroll5.mission_22_text = "Chuong, conduc\227torii bandei v\226ntului negru, au[ENTER]\238nceput atacul. Ca mae\186tri ai luptei cu sabia, au[ENTER]provocat al\254i r\227zboinici, pentru a se distra.[ENTER]Anihileaz\227-i \238nainte ca ei s\227 \238ncurajeze banda[ENTER]v\226ntului negru."
