gameforge.locale.questscroll5.mission_23_text = "De pu\254in timp plou\227 cu pietre cu Chi negativ \238n[ENTER]apropierea ora\186ului. Cercet\227ri arat\227, c\227 Chi-ul[ENTER]face animalele s\227 turbeze. Distruge aceste[ENTER]pietre. Te rog. Vei fi cu siguran\254\227 r\227spl\227tit."
