gameforge.locale.questscroll5.mission_27_mis = "Ucide 40 de p\227ianjeni pui."
gameforge.locale.questscroll5.mission_27_text = "P\227ianjeni, care de obicei tr\227iesc \238n pace \238n[ENTER]de\186ertul Yongbi, au \238nceput s\227 atace \186i s\227 omoare[ENTER]c\227l\227tori. Aceasta d\227uneaz\227 economiei regatului.[ENTER]Anihileaz\227, te rog, ace\186ti p\227ianjeni."
