gameforge.locale.questscroll5.mission_33_mis = "Ucide 35 de p\227ianjeni otr\227vitori pui \186i 35 de[ENTER]p\227ianjeni otr\227vitori mortali."
gameforge.locale.questscroll5.mission_33_text = "S-a descoperit un sistem de pe\186teri, despre care[ENTER]se crede c\227 serve\186te ca ad\227post p\227ianjenilor din[ENTER]de\186ertul Yongbi. Nu avem informa\254ii exacte despre[ENTER]aceste pe\186teri. Se \186tie \238ns\227 c\227 sunt foarte[ENTER]periculoase. Opre\186te \238nmul\254irea p\227ianjenilor \186i[ENTER]mai omoar\227 din ei."
