gameforge.locale.questscroll5.mission_41_hunt = "Misterul maimu\254elor grele2"
gameforge.locale.questscroll5.mission_41_mis = "Ucide 15 Gorila Luptator \186i 15 Gorila General"
gameforge.locale.questscroll5.mission_41_text = "Locatia Garnizoanei Maimutelor mari a fost[ENTER]descoperita in desert. In mod normal, ele nu[ENTER]reprezinte o amenintare, dar stranse laolalta pot[ENTER]reprezenta o amenintare pentru Regatul nostru.[ENTER]Mergi la Garnizoana Maimutelor mari si descopera[ENTER]ce se intampla."
gameforge.locale.questscroll5.mission_42_hunt = "Ghea\254a se va topi"
gameforge.locale.questscroll5.mission_42_mis = "Ucide 25 de golem de ghea\254\227 pe muntele Sohan."
gameforge.locale.questscroll5.mission_42_text = "Stii Muntele Sohan, cel acoperit permanent de[ENTER]gheata? Multi exploratori si luptatori au plecat[ENTER]acolo dar nu s-au mai intors. Afla care este[ENTER]motivul si daca au fost atacati. Poate poti afla[ENTER]ceva daca vanezi monstri acolo."
gameforge.locale.questscroll5.mission_43_hunt = "Misterul maimu\254elor grele1"
gameforge.locale.questscroll5.mission_43_mis = "Ucide 30 Gorila Soldat si 30 Gorila Grenadier."
gameforge.locale.questscroll5.mission_43_text = "Locatia Garnizoanei Maimutelor mari a fost[ENTER]descoperita in desert. In mod normal, ele nu[ENTER]reprezinte o amenintare, dar stranse laolalta pot[ENTER]reprezenta o amenintare pentru Regatul nostru.[ENTER]Mergi la Garnizoana Maimutelor mari si descopera[ENTER]ce se intampla."
gameforge.locale.questscroll5.mission_44_hunt = "Spiritul tigrului galben"
gameforge.locale.questscroll5.mission_44_mis = "Ucide 30 de Generali Broasca Taur."
gameforge.locale.questscroll5.mission_44_text = "Spiritul tigrului galben, regele creaturilor de[ENTER]pe acest continent, a mobolizat de cur\226nd[ENTER]animalele. Serviciul secret al regatului[ENTER]presupune c\227 de aceea au devenit animalele at\226t[ENTER]de s\227lbatice. E nevoie s\227 se reduc\227 trupele[ENTER]spiritului tigrului galben. Anihileaz\227[ENTER]conduc\227torii, care \238i servesc ca m\226n\227 dreapt\227."
gameforge.locale.questscroll5.mission_45_hunt = "Proprietar al muntelui Sohan?"
gameforge.locale.questscroll5.mission_45_mis = "Ucide 35 Om Inghetat si 30 Yeti."
gameforge.locale.questscroll5.mission_45_text = "9-cozi, st\227p\226nul muntelui Sohan, adun\227 acolo[ENTER]demoni \238n jurul s\227u. \206nainte ca el s\227 \238\186i adune[ENTER]trupele, trebuie s\227 ucidem oamenii de ghea\254\227 \186i[ENTER]Yeti, spinarea trupelor sale. Ajut\227-ne, te rog.[ENTER]Vrei fi r\227spl\227tit generos."
gameforge.locale.questscroll5.mission_46_hunt = "Chunwa Bong-ki"
gameforge.locale.questscroll5.mission_46_mis = "Ucide 45 Soldat Brotac \186i 35 de General Brotac."
gameforge.locale.questscroll5.mission_46_text = "Spiritul Tigrului Galben se pare ca a pus ceva la[ENTER]cale cu Brotacii Monstri. Strica-le planurile[ENTER]imediat. Daca ignori asta intreg regatul va avea[ENTER]de suferit!"
gameforge.locale.questscroll5.mission_47_hunt = "Mon\186trii de ghea\254\227! Adev\227rata lor fiin\254\227"
gameforge.locale.questscroll5.mission_47_mis = "Ucide 45 Gheata Fermecata."
gameforge.locale.questscroll5.mission_47_text = "Am aflat cum comunica intre ei acesti Monstri de[ENTER]Gheata de pe Muntele Sohan: Ei raspandesc[ENTER]informatiile prin indermediul cioburilor de[ENTER]gheata pe care le gasesti plutind pretutindeni.[ENTER]Pentru a reduce numarul lor, din acest tinut[ENTER]inghetat, trebuie sa oprim comunicarea dintre[ENTER]ele. Asa ca te rog : Omoara Gheata Fermecata!"
gameforge.locale.questscroll5.mission_48_hunt = "Secretul Turnului Demonilor"
gameforge.locale.questscroll5.mission_48_mis = "Ucide 45 de Luptatori Spirit."
gameforge.locale.questscroll5.mission_48_text = "Exista zvonuri cum ca Luptatorii cu Sulita din[ENTER]Turnul Demonilor sunt invincibili. De fapt chiar[ENTER]au reaparut de fiecare data dupa ce au fost[ENTER]ucisi. Daca este adevarat ne asteapta vremuri[ENTER]intunecate. Afla despre ce este vorba!"
gameforge.locale.questscroll5.mission_49_hunt = "Stapanul Turnului Demonilor"
gameforge.locale.questscroll5.mission_49_mis = "Ucide 60 de Samani Demon."
gameforge.locale.questscroll5.mission_49_text = "Dupa cercetari atente, am descoperit ca Soldatii[ENTER]Stafie sunt mereu reinviati. Trebuie sa eliminam[ENTER]Spirit Saman Comun pentru a impiedica asta."
gameforge.locale.questscroll5.mission_4_hunt = "Apari\254ia lupilor gri 1"
gameforge.locale.questscroll5.mission_4_mis = "Ucide 35 de lupi gri."
gameforge.locale.questscroll5.mission_4_text = "Ai auzit de lupii gri?[ENTER]Umblau mai mult singuri, dar din cauza Chi-ului[ENTER]au \238nceput s\227 atace \238n haite c\227l\227torii. Po\254i s\227[ENTER]anihilezi ace\186ti lupi gri? Vei fi cu siguran\254\227[ENTER]r\227spl\227tit."
gameforge.locale.questscroll5.mission_50_hunt = "Mergi in Doyyumhwan"
gameforge.locale.questscroll5.mission_50_mis = "Ucide 45 Tigru Luptator Dur."
gameforge.locale.questscroll5.mission_50_text = "Doyyumhwan este un taram pe care clocoteste lava[ENTER]si traiesc creaturi ingrozitoare, i se mai spune[ENTER]si Tara de Foc. Trebuie sa cercetam zona.[ENTER]Ne poti ajuta?"
gameforge.locale.questscroll5.mission_51_hunt = "Spiritul Focului! Identitatea sa"
gameforge.locale.questscroll5.mission_51_mis = "Ucide 45 Spiritul Focului."
gameforge.locale.questscroll5.mission_51_text = "Grupul care trebuia sa invinga Tigrii Luptatori a[ENTER]fost eliminat de inamici necunoscuti. Zvonurile[ENTER]spun ca acesti inamici arata ca niste \"fete in[ENTER]flacari\". Afla adevarul."
gameforge.locale.questscroll5.mission_52_hunt = "Omoara Tigri Luptatori"
gameforge.locale.questscroll5.mission_52_mis = "Ucide 60 Tigru Luptator Dur si 40 Tigru Luptator."
gameforge.locale.questscroll5.mission_52_text = "Acum ca putem lupta contra acestor Spirite ale[ENTER]Focului, trebuie ucise pana la ultimul. Astfel de[ENTER]misiuni sunt rezolvate de armata, dar pentru a[ENTER]obtine putere maxima contra acestora, ne trebuie[ENTER]o strategie buna. Te rog sa omori acesti Tigri[ENTER]Luptatori pentru a nu mai sta in calea noastra."
gameforge.locale.questscroll5.mission_53_hunt = "Cerceteaz\227 Flacarile"
gameforge.locale.questscroll5.mission_53_mis = "Ucide 40 Flacara."
gameforge.locale.questscroll5.mission_53_text = "Flacarile sunt incredibil de brutale. Se bucura[ENTER]de durerea oamenilor cand le devoreaza pielea.[ENTER]Inca nu stim cum pot fi omorate. Ai putea afla[ENTER]mai multe despre aceste Flacari?"
gameforge.locale.questscroll5.mission_54_hunt = "R\227zboinic al focului"
gameforge.locale.questscroll5.mission_54_mis = "Ucide 60 de r\227zboinici ai focului."
gameforge.locale.questscroll5.mission_54_text = "De cur\226nd a fost ucis copilul unui nobil, care se[ENTER]plimba \238n \222ara de Foc, de c\227tre un lupt\227tor al[ENTER]focului. Dac\227 ucizi lupt\227torii focului vei primi[ENTER]o recompens\227. De ce nu \238i provoci?"
gameforge.locale.questscroll5.mission_55_hunt = "Cerceteaza Copacii Fantoma"
gameforge.locale.questscroll5.mission_55_mis = "Distruge 30 de Copaci Fantoma."
gameforge.locale.questscroll5.mission_55_text = "Arata ca niste copaci, dar dintr-o data ataca[ENTER]animalele si oamenii. Numarul lor este in[ENTER]crestere. Afla cum putem distruge Copacii Fantoma"
gameforge.locale.questscroll5.mission_56_hunt = "Misterul Padurii Fantoma"
gameforge.locale.questscroll5.mission_56_mis = "Ucide 40 Buturuga Fantoma si 30 Driade."
gameforge.locale.questscroll5.mission_56_text = "Cercetarile au aratat ca Padurea Fantoma este un[ENTER]tinut populat de Buturuga Fantoma si Driade.[ENTER]Elimina-le si poate vei putea opri raspandirea[ENTER]Copacilor Fantoma."
gameforge.locale.questscroll5.mission_5_hunt = "Ai grij\227 de sate"
gameforge.locale.questscroll5.mission_5_mis = "Ucide 40 Mistre\254i."
gameforge.locale.questscroll5.mission_5_text = "\206n ultimele s\227pt\227m\226ni temerile localnicilor din[ENTER]jurul ora\186ului au reap\227rut. Mistre\254ii, care \238n[ENTER]trecut atacau numai animale mici \238n mun\254i, au[ENTER]devenit foarte agresivi.[ENTER]Au \238nceput s\227 \238ntre \238n gospod\227riile \254\227ranilor \186i[ENTER]s\227-i atace. Po\254i alunga Mistre\254ii de aici?"
gameforge.locale.questscroll5.mission_6_hunt = "Tigri si Ursi"
gameforge.locale.questscroll5.mission_6_mis = "Ucide 25 de tigri \186i 30 de ur\186i."
gameforge.locale.questscroll5.mission_6_text = "Ai auzit? Dac\227 tigrii \186i ur\186ii m\227n\226nc\227 timp de[ENTER]100 de zile doar usturoi \186i ceap\227, se transform\227[ENTER]\238n tigrii mari \186i ur\186i de foc.[ENTER]Asta nu se va \238nt\226mpla, dar nu stric\227 s\227 verifici[ENTER]acest zvon. Verific\227-l prin uciderea de tigri \186i[ENTER]ur\186i."
gameforge.locale.questscroll5.mission_7_hunt = "Distruge Metinul Lacomiei"
gameforge.locale.questscroll5.mission_7_mis = "Distruge 2 metin ai l\227comiei."
gameforge.locale.questscroll5.mission_7_text = "De pu\254in timp plou\227 cu pietre cu Chi negativ \238n[ENTER]apropierea ora\186ului. Cercet\227ri arat\227, c\227 Chi-ul[ENTER]face animalele s\227 turbeze. Distruge aceste[ENTER]pietre. Te rog. Vei fi cu siguran\254\227 r\227spl\227tit."
gameforge.locale.questscroll5.mission_8_hunt = "Sparge Piatra Metin a Bataliei"
gameforge.locale.questscroll5.mission_8_mis = "Distruge 2 Pietre Metin ale Bataliei"
gameforge.locale.questscroll5.mission_8_text = "De pu\254in timp plou\227 cu pietre cu Chi negativ \238n[ENTER]apropierea ora\186ului. Cercet\227ri arat\227, c\227 Chi-ul[ENTER]face animalele s\227 turbeze. Distruge aceste[ENTER]pietre. Te rog. Vei fi cu siguran\254\227 r\227spl\227tit."
gameforge.locale.questscroll5.mission_9_hunt = "Ai grij\227 de sate 2"
gameforge.locale.questscroll5.mission_9_mis = "Ucide 30 Mistre\254i Ro\186ii."
gameforge.locale.questscroll5.mission_9_text = "De ceva timp, Mistre\254ii condu\186i de liderii lor,[ENTER]Mistre\254ii Ro\186ii, atac\227 locuitorii din[ENTER]\238mprejurimile ora\186ului. Guvernatorul a dat ordin[ENTER]ca ace\186tia s\227 fie uci\186i. Fiecare r\227zboinic s\227[ENTER]ucid\227 c\226te 30 de Mistre\254i Ro\186ii. Ajut\227-ne \186i tu."
gameforge.locale.questscroll_10_hunt = "Solda\254i oamenii \186arpe"
gameforge.locale.questscroll_10_mis = "Ucide solda\254ii, jum\227tate om, jum\227tate \186arpe."
gameforge.locale.questscroll_10_text = "Nu pot fi numi\254i oameni. Dar la fel de gre\186it ar[ENTER]fi s\227 spui c\227 nu sunt oameni. Arat\227 ca oamenii,[ENTER]dar capul, pielea \186i comportamentul sunt de \186arpe[ENTER]otr\227vitor. Str\227bat de\186ertul \186i atac\227 negustori.[ENTER][ENTER]Ucide 20 de astfel de solda\254i, jum\227tate om,[ENTER]jum\227tate \186arpe. Dac\227 \238i ucizi vei primi[ENTER]urm\227toarea recompens\227:"
gameforge.locale.questscroll_11_hunt = "Arca\186i oamenii \186arpe"
gameforge.locale.questscroll_11_mis = "Ucide arca\186ii, jum\227tate om, jum\227tate \186arpe."
gameforge.locale.questscroll_11_text = "Sunt la fel de inteligen\254i ca oamenii. Sunt[ENTER]\186ire\254i \186i se pricep de minune la m\226nuirea[ENTER]armelor. Arca\186i, jum\227tate om, jum\227tate \186arpe,[ENTER]atac\227 negustorii de la distan\254\227.[ENTER]Mul\254i negustori au murit astfel.[ENTER][ENTER]Ucide 20 de arca\186i, jum\227tate om, jum\227tate \186arpe.[ENTER]Dac\227 \238ndepline\186ti aceast\227 sarcin\227, prime\186ti[ENTER]urm\227toarea recompens\227:"
gameforge.locale.questscroll_12_hunt = "T\226lhari de De\186ert"
gameforge.locale.questscroll_12_mis = "Ucide T\226lhari de De\186ert."
gameforge.locale.questscroll_12_text = "\206n de\186ertul Yongbi tr\227iesc creaturi malefice.[ENTER]Sunt cunoscute sub numele de t\226lhari de tuf\227 de[ENTER]de\186ert, iar faptele lor sunt strig\227toare la cer.[ENTER]T\226lh\227resc \186i ucid negustori din pl\227cere. Au[ENTER]distrus satele din de\186ert."
gameforge.locale.questscroll_13_hunt = "Tigri Luptatori"
gameforge.locale.questscroll_13_mis = "Ucide Tigrii Luptatori."
gameforge.locale.questscroll_13_text = "Acolo sunt niste creaturi care se numesc Tigri[ENTER]Luptatori. Au sange de foc si corpuri formate din[ENTER]granit vulcanic. Sunt incredibil de puternici! Se[ENTER]hranesc cu lava si focul vulcanului. Cateodata,[ENTER]coboara de pe vulcan, ataca oameni si ii[ENTER]mananca... Omoara 20 de Tigri Luptatori. Dupa ce[ENTER]termini aceasta misiune, vei primi urmatoarea[ENTER]recompensa:"
gameforge.locale.questscroll_14_hunt = "O\186tirea r\227zboinicilor"
gameforge.locale.questscroll_14_mis = "\206nfr\226ngerea o\186tirii r\227zboinicilor"
gameforge.locale.questscroll_14_text = "Doyyumhwan este mare \186i fierbinte \186i ad\227poste\186te[ENTER]fiare s\227lbatice. Acolo se \238nt\226lnesc r\227zboinicii[ENTER]din Chunjo, Jinno \186i Shinsoo. Mon\186trii puternici[ENTER]\186i \238nsp\227im\226nt\227tori \238i a\186teapt\227 acolo pe[ENTER]r\227zboinici. O\186tirea r\227zboinicilor (Kriegsmanii)[ENTER]sunt st\227p\226nitorii Doyyumhwan-ului."
gameforge.locale.questscroll_15_hunt = "R\227zboinic Taehwa"
gameforge.locale.questscroll_15_mis = "\206nvinge r\227zboinicul Taehwa."
gameforge.locale.questscroll_15_text = "Asculta\254i, voi, cei care v\227 crede\254i lupt\227tori[ENTER]puternici! Acesta este frontul focului, al[ENTER]lacrimilor, al durerii, al luptei \186i al mor\254ii![ENTER]Eu tr\227iesc aici \238mpreun\227 cu mul\254i mon\186tri \186i[ENTER]r\227uf\227c\227tori! Cine \238\186i permite s\227 m\227 provoace? Se[ENTER]g\227se\186te cineva care s\227 \238mi p\227\186easc\227 \238nainte cu[ENTER]sabia \238n m\226n\227?[ENTER][ENTER]Dac\227 te \238ncrezi \238n bra\254ul t\227u, ie\186i \186i[ENTER]provoac\227-m\227! Dac\227 m\227 vei birui pe mine \186i pe cei[ENTER]12 colegi ai mei, vei primi urm\227toarea[ENTER]recompens\227:"
gameforge.locale.questscroll_16_hunt = "Ur\186i \238ntuneca\254i"
gameforge.locale.questscroll_16_mis = "Ucide ur\186ii \238ntuneca\254i."
gameforge.locale.questscroll_16_text = "Mi-e team\227 c\227 sf\226r\186esc aici. \206ns\227 mai las\227-m\227[ENTER]doar s\227 povestesc o \238nt\226mplare. C\226nd vei citi[ENTER]aceast\227 scrisoare, eu voi fi mort sau disp\227rut.[ENTER]Tr\227iam \238n valea Seungryong, unde adunam plante[ENTER]medicinale. Dar mon\186trii, numi\254i ur\186i \238ntuneca\254i,[ENTER]au \238nceput s\227 fac\227 crime. Mi-au r\227pus familia.[ENTER][ENTER]V\227 rog, r\227zbuna\254i-m\227 pe mine \186i familia mea. Dac\227[ENTER]ucizi 25 de ur\186i \238ntuneca\254i, vei primi urm\227toarea[ENTER]recompens\227:"
gameforge.locale.questscroll_17_hunt = "Ur\186i \238ntuneca\254i uria\186i"
gameforge.locale.questscroll_17_mis = "Ucide ur\186ii \238ntuneca\254i uria\186i."
gameforge.locale.questscroll_17_text = "Mon\186trii urs au creat un nou monstru prin[ENTER]\238mperecherea cu mon\186tri \186i mai malefici. Este[ENTER]vorba despre ur\186ii \238ntuneca\254i uria\186i, mai mari \186i[ENTER]mai puternici dec\226t p\227rin\254ii lor \186i de o[ENTER]incredibil\227 r\227utate. At\226ta timp c\226t ei vor fi \238n[ENTER]valea Seungryong, oamenii vor avea de suferit.[ENTER][ENTER]Ucide 20 de ur\186i \238ntuneca\254i uria\186i \186i vei primi[ENTER]urm\227toarea recompens\227:"
gameforge.locale.questscroll_18_hunt = "Solda\254i care sufer\227 de misterioasa boal\227"
gameforge.locale.questscroll_18_mis = "Ucide solda\254ii care sufer\227 de misterioasa boal\227."
gameforge.locale.questscroll_18_text = "Satul a fost \186ters de pe fa\254a p\227m\226ntului. Cei[ENTER]care sufer\227 de misterioasa boal\227 \238i atac\227 pe[ENTER]nenoroco\186ii care trec pe aici. Atac\227 negustorti[ENTER]ambulan\254i \186i m\227n\226nc\227 oameni. Sunt extrem de[ENTER]periculo\186i.[ENTER][ENTER]Ucide 35 de solda\254i suferinzi de misterioasa[ENTER]boal\227 \186i vei primi urm\227toarea recompens\227:"
gameforge.locale.questscroll_19_hunt = "Arca\186i care sufer\227 de misterioasa boal\227"
gameforge.locale.questscroll_19_mis = "Ucide arca\186ii care sufer\227 de misterioasa boal\227."
gameforge.locale.questscroll_19_text = "Misterioasa boal\227 este cauza pagubelor, provocate[ENTER]de cei care sufer\227 de ea. Dar cei mai de temut[ENTER]sunt arca\186ii lovi\254i de boal\227. Ei trag cu s\227ge\254i[ENTER]otr\227vite care paralizeaz\227 c\227l\227torii, astfel \238nc\226t[ENTER]s\227 fie prin\186i \186i r\227pi\254i.[ENTER][ENTER]Ucide 25 de arca\186i bolnavi \186i vei primi[ENTER]urm\227toarea recompens\227:"
gameforge.locale.questscroll_1_hunt = "Ur\186i de foc"
gameforge.locale.questscroll_1_mis = "Ucide 25 de ur\186i de foc."
gameforge.locale.questscroll_1_text = "Ur\186ii de foc sunt \238nt\226lni\254i adesea \238n apropierea[ENTER]capitalei. Ei str\227bat preeria \186i str\227zile late[ENTER]ale oamenilor. Sunt din ce \238n ce mai multe[ENTER]victime. Unii oameni au fost omor\226\254i.[ENTER][ENTER]V\226neaz\227 ace\186ti ur\186i. Dac\227 ucizi 25 dintre ei vei[ENTER]primi urm\227toarea recompens\227:"
gameforge.locale.questscroll_20_hunt = {}
gameforge.locale.questscroll_20_mis = "Ucide 4 inamici."
gameforge.locale.questscroll_20_text = "M\227 tem c\227 voi sf\226r\186i! Privirea mi-e[ENTER]\238mp\227ienjenit\227. C\226nd vei citi aceast\227 scrisoare,[ENTER]corpul meu va putrezi deja. Porcii m-au prins \186i[ENTER]r\227pit. Am reu\186it s\227 scap, dar rana era at\226t de[ENTER]ad\226nc\227, c\227 am cedat. Nu te cunosc. Dar te rog,[ENTER]r\227zbun\227-m\227![ENTER]Ucide 4 inamici la locul luptei. Dac\227 vei reu\186i,[ENTER]vei primi urm\227toarea recompens\227:"
gameforge.locale.questscroll_2_hunt = "Tigru mare"
gameforge.locale.questscroll_2_mis = "Ucide 20 de tigri mari."
gameforge.locale.questscroll_2_text = "Numele r\227ut\227\254ii, tigrul mare, str\227punge aerul.[ENTER]Ace\186ti tigri se afl\227 de obicei \238n jurul[ENTER]capitalei. Ei atac\227 oameni \186i m\227n\226nc\227 cadavrele[ENTER]negustorilor. Victimele lor sunt nenum\227rate.[ENTER][ENTER]V\226neaz\227 tigrii mari. Dac\227 vei ucide 20 dintre ei,[ENTER]vei primi urm\227toarea recompens\227:"
gameforge.locale.questscroll_3_hunt = "Zeul c\226ine al muntelui"
gameforge.locale.questscroll_3_mis = "Ucide zeul c\227ine al muntelui."
gameforge.locale.questscroll_3_text = "Zeul c\226ine al muntelui se afl\227 \238n fruntea unei[ENTER]haite de mon\186tri c\226ini, \186i o conduce \238ncoace. El[ENTER]este puternic \186i s\227lbatic. De cur\226nd a ap\227rut \238n[ENTER]apropierea satului \186i a \238nceput s\227 atace[ENTER]negustori. Mul\254i i-au c\227zut deja prad\227. Crimele[ENTER]sale nu mai pot fi ignorate.[ENTER][ENTER]Ucide zeul c\226ine al muntelui. Dac\227 vei reu\186i, vei[ENTER]primi urm\227toarea recompens\227."
gameforge.locale.questscroll_4_hunt = "Zeul porc"
gameforge.locale.questscroll_4_mis = "Ucide zeul porc."
gameforge.locale.questscroll_4_text = "\206n perioada aceasta a anului lanurile sunt[ENTER]\238nc\227rcate cu gr\226ne coapte. Este timpul recoltei,[ENTER]timpul ca \254\227ranii s\227 adune roadele muncii lor.[ENTER]\206ns\227 zeul porc \186i tovar\227\186ii s\227i m\227n\226nc\227 toate[ENTER]gr\226nele. Deoarece ei amenin\254\227 via\254a \254\227ranilor,[ENTER]trebuie s\227 \238i omor\226m.[ENTER][ENTER]Ucide zeul porc. El se afl\227 de obicei \238n jurul[ENTER]capitalei. Dac\227 reu\186e\186ti, vei primi urm\227toarea[ENTER]recompens\227:"
gameforge.locale.questscroll_5_hunt = "Zeul urs"
gameforge.locale.questscroll_5_mis = "Ucide zeul urs."
gameforge.locale.questscroll_5_text = "\206n mediul s\227u natural, zeul urs era cuminte. \206ns\227[ENTER]de pu\254in timp apare \238n jurul capitalei \186i atac\227[ENTER]oameni. Tot mai mul\254i \238i cad victim\227. C\226\254i au[ENTER]murit deja aproape c\227 nu se mai \186tie. Trebuie s\227[ENTER]dispar\227 de aici.[ENTER][ENTER]Ucide zeul urs \186i vei primi urm\227toarea recompens\227:"
gameforge.locale.questscroll_6_hunt = "Zeul tigru"
gameforge.locale.questscroll_6_mis = "Ucide zeul tigru."
gameforge.locale.questscroll_6_text = "Nu \238mi vine s\227 cred. Cum a putut face zeul tigru[ENTER]a\186a ceva? Eu sunt o femeie simpl\227, care am[ENTER]respectat zi de zi pe zeul tigru, care trecea din[ENTER]c\226nd \238n c\226nd pe potecile de munte. \206ns\227 \238ntr-o[ENTER]bun\227 zi zeul tigru \186i adep\254ii s\227i mi-au atacat[ENTER]familia! To\254i au murit, iar eu am pierdut un[ENTER]bra\254.[ENTER]Te rog, r\227zbun\227-mi familia. Dac\227 vei reu\186i, vei[ENTER]primi urm\227toarea recompens\227:"
gameforge.locale.questscroll_7_hunt = "Conduc\227toare a armatei albe"
gameforge.locale.questscroll_7_mis = "Ucide conduc\227toarea armatei albe."
gameforge.locale.questscroll_7_text = "Armata alb\227 este un grup de femei, care au fost[ENTER]p\227r\227site de b\227rba\254i \186i de toat\227 lumea. Or fi ele[ENTER]s\227race, dar cum \238i chinuie pe locuitorii satului[ENTER]este de necrezut. O femeie a fost omor\226t\227 cu[ENTER]pietre c\226nd a venit \238n sat. Nu putem accepta s\227[ENTER]vin\227 \238n sat \186i s\227 atace s\227tenii.[ENTER][ENTER]Ucide 20 de conduc\227toare ale armatei albe. Dac\227[ENTER]vei \238ndeplini cu succes aceast\227 sarcin\227, vei[ENTER]primi urm\227toarea recompens\227:"
gameforge.locale.questscroll_8_hunt = "Conduc\227tor al bandei v\226ntului negru"
gameforge.locale.questscroll_8_mis = "Ucide conduc\227torul bandei v\226ntului negru."
gameforge.locale.questscroll_8_text = "T\226lharii bandei v\226ntului negru se leag\227 demult de[ENTER]negustorii c\227l\227tori. Sunt at\226t de temu\254i, \238nc\226t[ENTER]nimeni nu cuteaz\227 s\227 loveasc\227 \238napoi. Nu mai[ENTER]poate continua a\186a, c\227ci fac pagube[ENTER]insuportabile.[ENTER]Ucide 20 de conduc\227tori ai bandei v\226ntului negru[ENTER]\186i vei primi urm\227toarea recompens\227:"
gameforge.locale.questscroll_9_hunt = "C\227petenia barbarilor"
gameforge.locale.questscroll_9_mis = "Ucide c\227petenia barbarilor."
gameforge.locale.questscroll_9_text = "A trecut deja ceva timp de c\226nd barbarii au[ENTER]dep\227\186it grani\254ele \186i au atacat satul. Num\227rul[ENTER]victimelor a fost de ordinul sutelor. Num\227rul[ENTER]p\227gubi\254ilor este \238ns\227 cu mult mai mare. Barbarii[ENTER]sunt at\226t de cruzi, \238nc\226t nimeni nu a cutezat s\227[ENTER]se r\227zbune. \206ns\227 nu mai putem suporta.[ENTER][ENTER]Ucide 25 de c\227petenii barbare. Dac\227 vei reu\186i,[ENTER]vei primi urm\227toarea recompens\227:"
