gameforge.locale.skeleton_gem.order_say = "Negustorul ambulant:[ENTER]Acum totul s-a terminat. Nu mai este nimic de[ENTER]facut decat sa astept moartea. Daca hotii nu m-ar[ENTER]fi atacat, nu mi-as fi pierdut bunurile. De ce a[ENTER]trebuit sa mi se intample asa ceva?"
gameforge.locale.skeleton_gem.order_say2 = "Negustorul ambulant:[ENTER]Te rog, ajut\227-m\227.[ENTER]Dac\227 po\254i lua piatra pre\254ioas\227+ a demonilor de la[ENTER]magicianul demon, am s\227 te r\227spl\227tesc generos."
gameforge.locale.skeleton_gem.order_too_late = "Negustorul ambulant:[ENTER]Altcineva mi-a adus piatra. Nu mai trebuie s\227 te[ENTER]ocupi tu de asta."
