gameforge.locale.skeleton_gem.success_say = "Negustorul ambulant:[ENTER]Chiar te-ai descurcat? Vino la mine piatra mea[ENTER]draga! Multumesc. Nu-ti poti imagina cat de bine[ENTER]ma simt."
