gameforge.locale.skill_group = {}
gameforge.locale.skill_group.board = "\206n ghidul de informare scrie:[ENTER]Recrut\227m femei \186i b\227rba\254i curajo\186i preg\227ti\254i s\227[ENTER]lupte pentru pacea regatului \186i a locuitorilor[ENTER]s\227i![ENTER][ENTER]Condi\254ii de \238nrolare \238n armat\227: Minim nivelul 5."
gameforge.locale.skill_group.dialog_assassin_1 = "Aici sunt antrenati Ninja care stapanesc arta[ENTER]camuflajului si a ambuscadei. Se concentreaza pe[ENTER]folosirea pumnalelor si a otravii. Doar Ninja[ENTER]peste level 5 pot participa. Cand ajungi la acest[ENTER]nivel vei primi o scrisoare de recrutare. Daca[ENTER]esti pregatit sa te furisezi prin colturile[ENTER]intunecate ale lumii te astept la mine. Atunci[ENTER]discutam mai departe."
gameforge.locale.skill_group.dialog_assassin_2 = "Aici sunt antrenati Ninja care stapanesc arta[ENTER]camuflajului si a ambuscadei. Se concentreaza pe[ENTER]folosirea pumnalelor si a otravii. Daca esti[ENTER]pregatit sa te furisezi prin colturile intunecate[ENTER]ale lumii te astept la mine. Atunci discutam mai[ENTER]departe."
gameforge.locale.skill_group.dialog_assassin_3 = "Aici sunt antrenati Ninja care stapanesc manuirea[ENTER]arcului. Ei isi concentreaza reflexele pe[ENTER]aruncarea sagetilor, intr-o ploaie de foc, de la[ENTER]distanta. Doar Ninja peste level 5 pot participa.[ENTER]Cand ajungi la acest level vei primi o scrisoare[ENTER]de recrutare. Daca esti pregatit sa te furisezi[ENTER]prin colturile intunecate ale lumii te astept la[ENTER]mine. Daca esti interesat, cauta-ma."
gameforge.locale.skill_group.dialog_assassin_4 = "Aici sunt antrenati Ninja care stapanesc manuirea[ENTER]arcului. Ei isi concentreaza reflexele pe[ENTER]aruncarea sagetilor, intr-o ploaie de foc, de la[ENTER]distanta. Urmeaza-ma. Te voi face maestru in[ENTER]manuirea arcului."
gameforge.locale.skill_group.dialog_assassin_5 = "Alege intre Lupta cu Sabia si Lupta cu Arcul si[ENTER]vei primi abilit\227\254ile dorite."
gameforge.locale.skill_group.dialog_shaman_1 = "Aici este locul in care Samanii urmeaza calea[ENTER]Dragonului. Ei invata cum sa foloseasca amuletele[ENTER]impotriva puterii tale mentale, iar acest lucru,[ENTER]pentru Samani este o tehnica de exceptie. De[ENTER]asemenea, ei isi cresc valoarea apararii singuri,[ENTER]prin protectia sfanta, atat a lor cat si a celor[ENTER]din grup. Doar Samanii incepand cu level 5 pot[ENTER]participa. De indata ce ai ajuns la acest level[ENTER]vei primi o scrisoare de recrutare. Cand esti[ENTER]pregatit sa inveti Puterea Dragonului, te astept[ENTER]la mine."
gameforge.locale.skill_group.dialog_shaman_2 = "Aici este locul in care Samanii urmeaza calea[ENTER]Dragonului. Ei invata cum sa foloseasca amuletele[ENTER]impotriva puterii tale mentale, iar acest lucru,[ENTER]pentru Samani este o tehnica de exceptie. De[ENTER]asemenea, ei isi cresc valoarea apararii singuri,[ENTER]prin protectia sfanta, atat a lor cat si a celor[ENTER]din grup. Crezi ca esti pregatit sa inveti[ENTER]alaturi de mine despre Puterea Dragonului? Un[ENTER]umil credincios este intotdeauna binevenit."
gameforge.locale.skill_group.dialog_shaman_3 = "Samanii isi aduna in acest loc luminile si[ENTER]fortele naturii. Farmecele lor sunt conectate la[ENTER]fulgere, tunete si furtuni dar si la puterea[ENTER]vindecarii. Samanii care invata Vindecare[ENTER]lucreaza in grup pentru a le oferi suport[ENTER]celorlalti. Doar Samanii care au atins level 5[ENTER]pot invata. De indata ce ai atins acest level vei[ENTER]primi o scrisoare de recrutare. Te vom astepta."
gameforge.locale.skill_group.dialog_shaman_4 = "Samanii isi aduna in acest loc luminile si[ENTER]fortele naturii. Farmecele lor sunt conectate la[ENTER]fulgere, tunete si furtuni dar si la puterea[ENTER]vindecarii. Samanii care invata Vindecare[ENTER]lucreaza in grup pentru a le oferi suport[ENTER]celorlalti. Vrei sa lucrezi cu mine pentru ai[ENTER]ajuta pe ceilalti? Ajutorul tau ii va ajuta pe[ENTER]toti cei care sufera. Te rog ajuta-ma."
gameforge.locale.skill_group.dialog_shaman_5 = "Alege intre Forta Dragonului si Vindecare si vei[ENTER]primi skillurile necesare."
gameforge.locale.skill_group.dialog_sura_1 = "\206i \238nv\227\254 pe aceia care au fost binecuv\226nta\254i cu[ENTER]puterea diavoleasc\227 de a folosi magia.[ENTER]Ace\186tia \238nva\254\227 cum s\227 \238\186i vr\227jeasc\227 armele \186i[ENTER]armurile cu atribute ce cresc puterea de atac \186i[ENTER]m\227resc puterea de ap\227rare. Pe l\226ng\227 acestea mai[ENTER]\238nva\254\227 s\227 evoce spirite din Iad reduc\226ndu-le[ENTER]moralul inamicilor. Doar Sura ce au atins nivelul[ENTER]5 pot \238nv\227\254a. Odat\227 ce ai atins acest nivel vei[ENTER]primi o scrisoare de recrutare. Dac\227 e\186ti[ENTER]preg\227tit, te a\186tept\227m \238n cercul demonic."
gameforge.locale.skill_group.dialog_sura_2 = "\206i \238nv\227\254 pe aceia care au fost binecuv\226nta\254i cu[ENTER]puterea diavoleasc\227 de a folosi magia.[ENTER]Ace\186tia \238nva\254\227 cum s\227 \238\186i vr\227jeasc\227 armele \186i[ENTER]armurile cu atribute ce cresc puterea de atac \186i[ENTER]m\227resc puterea de ap\227rare. Pe l\226ng\227 acestea mai[ENTER]\238nva\254\227 s\227 evoce spirite din Iad reduc\226ndu-le[ENTER]moralul inamicilor. E\186ti preg\227tit s\227-\254i vr\227je\186ti[ENTER]sabia, armura \186i s\227 arunci cu vr\227ji \238ntunecate?[ENTER]Te pot asigura c\227 puterea g\227sit\227 aici se[ENTER]potrive\186te doar unui singur gen de oameni."
gameforge.locale.skill_group.dialog_sura_3 = "Daca esti interesat de acest loc nu vei gasi[ENTER]decat pe aceia care s-au convertit fortei[ENTER]intunecate. Ei invata cum sa stapaneasca[ENTER]spiritele, demonii si flacarile Iadului. Doar[ENTER]Sura ce au atins level 5 pot invata. De indata ce[ENTER]ai atins acest level vei primi o scrisoare de[ENTER]recrutare. Daca intunericul va fi casa ta cu[ENTER]siguranta iti vei intalni fratii si surorile[ENTER]acolo."
gameforge.locale.skill_group.dialog_sura_4 = "Dac\227 e\186ti interesat de acest loc nu \238i vei g\227si[ENTER]dec\226t pe aceia care s-au convertit for\254ei[ENTER]\238ntunecate. Ei \238nva\254\227 cum s\227 st\227p\226neasc\227[ENTER]spiritele, demonii \186i fl\227c\227rile Iadului. Dac\227[ENTER]e\186ti interesat s\227-ti faci prieteni printre[ENTER]spiritele rele care pic\227tur\227 cu pic\227tur\227 \238\254i vor[ENTER]inunda mintea, atunci vino la mine. Al\227tur\227-te[ENTER]cultului nostru \186i las\227 umanitatea \238n urm\227..."
gameforge.locale.skill_group.dialog_sura_5 = "Alege intre Arme Magice si Magie Neagra si vei[ENTER]primi abilit\227\254ile dorite."
gameforge.locale.skill_group.dialog_warrior_1 = "\170tii unde te afli? Atacatorii sunt antrena\254i[ENTER]aici, R\227zboinicii cei mai rapizi \186i mai bravi de[ENTER]peste tot. Tehnici de rapiditate, lovituri[ENTER]circulare \186i abilit\227\254i de atac sunt \238nv\227\254ate aici[ENTER]cu sabia sau suli\254a.[ENTER]Doar R\227zboinicii ce au atins nivelul 5 pot[ENTER]\238nv\227\254a. De \238ndat\227 ce ai ajuns la acest nivel vei[ENTER]primi o scrisoare de recrutare. Dac\227 vrei s\227 afli[ENTER]adev\227rata putere a corpului t\227u, vino cu mine!"
gameforge.locale.skill_group.dialog_warrior_2 = "\170tii unde te afli? Atacatorii sunt antrena\254i[ENTER]aici, R\227zboinicii cei mai rapizi \186i mai bravi de[ENTER]peste tot. Tehnici de rapiditate, lovituri[ENTER]circulare \186i abilit\227\254i de atac sunt \238nv\227\254ate aici[ENTER]cu sabia sau suli\254a.[ENTER]Ce dore\186ti s\227 faci mai departe? Vrei s\227 te[ENTER]antrenezi?"
gameforge.locale.skill_group.dialog_warrior_3 = "\206i \238nv\227\254 pe R\227zboinici cum s\227-\186i foloseasc\227[ENTER]corespunz\227tor Chi-ul.[ENTER]Acest lucru necesit\227 un mod de lupt\227 mental \186i[ENTER]epuizant. Oricum, \238n schimb vei fi capabil s\227[ENTER]love\186ti mai mul\254i oponen\254i \238n acela\186i timp. Iar[ENTER]ap\227rarea unei min\254i puternice de r\227zboinic este[ENTER]de nep\227truns \186i a devenit legendar\227. Doar[ENTER]R\227zboinicii ce au atins nivelul 5 pot \238nv\227\254a. De[ENTER]\238ndat\227 ce ai atins acest nivel vei primi o[ENTER]scrisoare de recrutare. Dac\227 e\186ti interesat, vino[ENTER]la mine."
gameforge.locale.skill_group.dialog_warrior_4 = "\206i \238nv\227\254 pe R\227zboinici cum s\227-\186i foloseasc\227[ENTER]corespunz\227tor Chi-ul.[ENTER]Acest lucru necesit\227 un mod de lupt\227 mental \186i[ENTER]epuizant. Oricum, \238n schimb vei fi capabil s\227[ENTER]love\186ti mai mul\254i oponen\254i \238n acela\186i timp. Iar[ENTER]ap\227rarea unei min\254i puternice de r\227zboinic este[ENTER]de nep\227truns \186i a devenit legendar\227. Ce s\227 fie?[ENTER]E\186ti preg\227tit s\227 dai piept cu b\227t\227liile mentale?"
gameforge.locale.skill_group.dialog_warrior_5 = "Alege intre Lupta de Corp si Lupta Mentala si vei[ENTER]primi abilit\227\254ile dorite."
gameforge.locale.skill_group.invite = "Anun\254ul recrut\227rii militare"
gameforge.locale.skill_group.lets_join_skill_group_1 = "[COLOR r;1|g;0.6|b;0.6]Anun\254 despre recrutarea[ENTER]R\227zboinicilor[/COLOR][ENTER]Dac\227 admiri R\227zboinicii pentru atacurile lor[ENTER]rapide \186i repetitive, \238\254i recomand antrenament la[ENTER]Lupt\227 de Corp.[ENTER]Dac\227 vrei s\227 devi invulnerabil \186i s\227 \238nvingi[ENTER]grupuri \238ntregi de mon\186tri dintr-un singur atac[ENTER]\238\254i recomand antrenament la Lupt\227 Mental\227.[ENTER][ENTER]Te a\186tept \238n Pia\254a Central\227."
gameforge.locale.skill_group.lets_join_skill_group_2 = "[COLOR r;1|g;0.6|b;0.6]Anunt despre recrutarea[ENTER]Ninja[/COLOR][ENTER]Daca vrei sa fi cunoscut ca un arcas remarcabil,[ENTER]poti invata Lupta cu Arcul. Daca esti pregatit sa[ENTER]ai parte de misterioasele secrete ale[ENTER]intunericului, atunci pentru Ninja cea mai buna[ENTER]alegere este Lupta cu Sabia.[ENTER][ENTER]Te astept in Piata Centrala."
gameforge.locale.skill_group.lets_join_skill_group_3 = "[COLOR r;1|g;0.6|b;0.6]Anunt despre recrutarea[ENTER]Sura[/COLOR][ENTER]Doresti sa devi un supranatural meastru al[ENTER]manuirii sabiilor si sa ii faci pe oponenti sa[ENTER]simta gustul lamelor? Atunci iti recomand sa[ENTER]inveti arta Armelor Magice. Daca doresti sa devi[ENTER]cel mai temut conducator al flacarilor si al[ENTER]magiilor atunci ar trebui sa inveti Magia Neagra.[ENTER][ENTER]Te astept in Piata Centrala."
gameforge.locale.skill_group.lets_join_skill_group_4 = "[COLOR r;1|g;0.6|b;0.6]Anun\254 pentru recrutarea[ENTER]\170amanilor[/COLOR][ENTER]Dac\227 dore\186ti s\227 readuci la via\254\227 puterea[ENTER]dragonilor \186i vrei s\227 folose\186ti suflarea lor[ENTER]fierbinte \238mpotriva inamicilor alege Puterea[ENTER]Dragonului. Totu\186i, dac\227 dori\254i s\227 ameliora\254i \186i[ENTER]s\227 vindeca\254i durerea celor care sufer\227, atunci ar[ENTER]trebui s\227 c\227uta\254i un \206nv\227\254\227tor de Vindecare[ENTER][ENTER]Te a\186tept \238n Pia\254a Central\227."
gameforge.locale.stamina_food = {}
