gameforge.locale.stamina_food.baekgo_accept_failure_info_text_1 = "\206ntoarce-te la Oakgu."
gameforge.locale.stamina_food.baekgo_accept_failure_info_text_2 = "Explic\227-i lui Oakgu c\227 nu ai putut procura carnea[ENTER]de broasc\227 verde."
gameforge.locale.stamina_food.butcher = {}
gameforge.locale.stamina_food.butcher.start_say = "B\227tr\226nul \238n restaurantul Suhpyung:[ENTER]Trupul meu nu mai este a\186a \238n form\227 ca mai[ENTER]demult. C\226nd eram t\226n\227r, puteam munci o s\227pt\227m\226n\227[ENTER]\238ntreag\227 \186i tot \238mi mai r\227m\226nea destul\227 energie[ENTER]pentru a bea seara![ENTER]\206ntre timp \238ns\227 \238mi vine greu \186i s\227 stau \238n[ENTER]picioare. \206n astfel de momente este o sup\227 de[ENTER]broasc\227 verde exact ce-mi trebuie pentru[ENTER]refacerea energiei."
gameforge.locale.stamina_food.butcher.start_say2 = "B\227tr\226nul \238n restaurantul Suhpyung:[ENTER]Vre\254i s\227 \186ti\254i ce este supa de broasc\227 verde?[ENTER]Dac\227 m\226nca\254i un castron de sup\227, nu ve\254i mai[ENTER]obosi! Chiar dac\227 ve\254i munci o s\227pt\227m\226n\227 pe c\226mp,[ENTER]ve\254i mai avea seara energie! Un prieten de-al[ENTER]meu, pe nume Oakgu, este cel mai bun buc\227tar de[ENTER]sup\227 de broasc\227 verde, pe care \238l cunosc. Dar[ENTER]dintr-un oarecare motiv nu mai face sup\227."
gameforge.locale.stamina_food.butcher.talk = "Vorbe\186te."
gameforge.locale.stamina_food.complete_say = "Oakgu:[ENTER]O ai? S\227 nu mai poveste\186ti nim\227nui despre supa de[ENTER]broasc\227 verde. \170i mai ales acestui bastard din[ENTER]restaurantul Suhpyung! Nu ajunge. Dac\227 afl\227[ENTER]oamenii despre supa de broasc\227 verde, vor da[ENTER]buzna aici \186i o vor m\226nca pe toat\227!"
gameforge.locale.stamina_food.food_manager = {}
gameforge.locale.stamina_food.food_manager.order_say = "Oakgu:[ENTER]Sup\227 de broasc\227 verde? Da! Eu o g\227team mai[ENTER]demult. Dar asta puteam face doar \238n tinere\254e. Pe[ENTER]atunci nu \238mi f\227ceam griji din cauza[ENTER]periculo\186ilor mon\186tri. Astfel puteam v\226na mereu[ENTER]broa\186te verzi."
gameforge.locale.stamina_food.food_manager.order_say2 = "Oakgu:[ENTER]Dar acum? Acum sunt b\227tr\226n \186i nu mai am energie[ENTER]pentru a\186a ceva. A\186 vrea s\227 m\227n\226nc eu \238nsumi[ENTER]ni\186te sup\227 de broasc\227 verde. Dar broa\186tele verzi[ENTER]nu sunt u\186or de prins! Dac\227 \238mi aduci ni\186te carne[ENTER]de broasc\227 verde, \238\254i voi face cea mai bun\227 sup\227[ENTER]de broasc\227 verde!"
gameforge.locale.stamina_food.food_manager.talk = "Vorbe\186te."
