gameforge.main_quest_flame_lv104._090_sayReward = "Du ben\246tigst eine Gruppe und einen Passierschein"
gameforge.main_quest_flame_lv104._100_say = "Nu va fi usoara lupta impotriva lui Razador. Dar[ENTER]nu avem alta solutie daca vrem sa oprim planurile[ENTER]Servitorilor Intunericului.[ENTER]Aduna-ti puterile si intalneste-l pe conducatorul[ENTER]focului, inainte de a fi prea tarziu!"
gameforge.main_quest_flame_lv104._110_say = "Muritorule, ascult\227-m\227 atent! Bucur\227-te de[ENTER]ultimele tale clipe de via\254\227. Nu va mai dura[ENTER]mult. Dragonul ro\186u va sc\227pa din lan\254urile sale.[ENTER]Cu ajutorul puterilor lui m\227 voi \238ntoarce \238n[ENTER]lumea ta jalnic\227 pentru a-mi continua planurile."
