gameforge.main_quest_flame_lv99._220_say = {}
gameforge.main_quest_flame_lv99._230_say = {}
gameforge.main_quest_flame_lv99._240_say = "Eine geheimnisvolle Aura die aus dem Inneren einer Festung str\246mt Interessant Schaue dich zun\228chst einmal in der n\228heren Umgebung dort um Ich habe da einen Verdacht worum es sich bei dieser Aura handeln k\246nnte Hier nimm dieses Papier und wickel es um deine Waffe Wenn sich mein Verdacht best\228tigt sollte sich das Papier schwarz f\228rben sobald du damit D\228monen t\246test die unter dem Einfluss der dunklen Aura stehen"
gameforge.main_quest_flame_lv99._250_notice = "Infrange demonii care bantuie in jurul fortaretei."
