gameforge.main_quest_lv1 = {}
gameforge.main_quest_lv1._10_sendLetter = "Bun-venit \238n Metin2"
gameforge.main_quest_lv1._20_say = "Te a\186teapt\227 incitantele aventuri din Metin2. Mai[ENTER]\238nt\226i trebuie s\227 cau\254i Gardianul Orasului.[ENTER]El \238\254i va oferi c\226teva informa\254ii de baz\227 \186i[ENTER]diverse misiuni.[ENTER][ENTER]Dac\227 dore\186ti s\227 mergi la v\226n\227toare, vei g\227si[ENTER]animale s\227lbatice la marginea hotarelor satului.[ENTER]Acestea vor fi afi\186ate pe harta mini sub form\227 de[ENTER]puncte ro\186ii. Ar trebui s\227 te concentrezi mai[ENTER]\238nt\226i pe c\226inii s\227lbatici, deoarece sunt \254intele[ENTER]cele mai u\186oare.[ENTER]Succes!"
gameforge.main_quest_lv1._30_targetVid = "G\227se\186te Gardianul Ora\186ului"
gameforge.main_quest_lv1._40_sayTitle = "G\227se\186te Gardianul Ora\186ului"
gameforge.main_quest_lv1._50_sayReward = "Vorbe\186te cu Gardianul Ora\186ului d\238nd click pe el.[ENTER]El este NPC pe care s\227geata \238l indic\227. Dac\227 nu-l[ENTER]vezi \238nseamn\227 c\227 e\186ti prea departe de el. Urmeaz\227[ENTER]cercurile care clipesc pe hart\227 p\238n\227 ajungi la[ENTER]el."
gameforge.main_quest_lv1._60_sayTitle = "Gardianul Ora\186ului:"
gameforge.main_quest_lv1._70_say = "Pari nou aici \238n localitate! Dup\227 cum v\227d, \238nc\227[ENTER]nu au f\227cut din tine un soldat. Ai \238nv\227\254at m\227car[ENTER]ceva? Uite-te la tine! Ai folosit m\227car o dat\227 \238n[ENTER]via\254\227 o arm\227?[ENTER]Ascult\227![ENTER]Trebuie s\227 fii mereu pe faz\227, dac\227 vrei s\227[ENTER]supravie\254uie\186ti r\227zboiului. P\226n\227 c\226nd vei atinge[ENTER]nivelul 10, am s\227 te ajut eu. S\227 nu crezi c\227 va[ENTER]fi u\186or![ENTER]Mi\186c\227! "
gameforge.main_quest_lv1._80_say = "Acum mergi \186i \238nva\254\227 tehnicile de baz\227 pentru[ENTER]lupte \186i v\226n\227toare! Imediat ce ai ajuns la un[ENTER]nivel mai mare \238ntoarce-te la mine. De ce mai[ENTER]e\186ti aici? Nu vei primi experien\254\227 dac\227 stai[ENTER]aici!"
gameforge.main_quest_lv10 = {}
