gameforge.main_quest_lv10._10_sendLetter = "Mergi la c\227pitan"
gameforge.main_quest_lv10._110_sayTitle = "Calificare la c\227pitan"
gameforge.main_quest_lv10._120_sayReward = "Prima misiune a C\227pitanului te va duce \238n satul[ENTER]vecin. Acolo trebuie s\227 vizitezi pe muzicianul[ENTER]Yu-Hwan \186i s\227 \238ntrebi de documentele secrete[ENTER]pentru C\227pitan."
gameforge.main_quest_lv10._130_sayTitle = "Muzicianul Yu-Hwan:"
gameforge.main_quest_lv10._140_say = "Via\254a este un vis, ca \186i totul \238n via\254\227. De unde[ENTER]venim \186i \238ncotro ne \238ndrept\227m? Lumea e plin\227 de[ENTER]g\226lceav\227. Efortul cinstit nu d\227 niciodat\227 roade.[ENTER]Ai venit s\227 \238mi ascul\254i[ENTER]c\226ntecul? "
gameforge.main_quest_lv10._150_say = "Oh, c\227pitanul te-a trimis![ENTER]Psst, vorbe\186te \238ncet...[ENTER][ENTER]Nimeni din sat nu trebuie s\227 \238mi afle adev\227rata[ENTER]identitate.[ENTER]Trebuie s\227 fi de \238ncredere dac\227 te-a trimis[ENTER]c\227pitanul![ENTER]Aici este. Documentul con\254ine informa\254iile pe[ENTER]care am putut s\227 le adun.[ENTER]Du-le la c\227pitan. "
gameforge.main_quest_lv10._160_sayTitle = "Muzicianul Yu-Hwan:"
gameforge.main_quest_lv10._170_say = "Gr\227be\186te-te \186i pleac\227. Dac\227 r\227m\226i prea mult timp[ENTER]aici, nu vei realiza nimic bun. Ce este via\254a?[ENTER]Via\254a este scurt\227. Bucur\227-te de ea atunci c\226nd[ENTER]po\254i. "
gameforge.main_quest_lv10._180_targetVid = "\206napoi la c\227pitan"
gameforge.main_quest_lv10._190_sayReward = "Muzicianul Yu-Hwan care lucreaz\227 ca \186i spion \254i-a[ENTER]dat documentele secrete. Du-le C\227pitanului \238n[ENTER]primul sat."
gameforge.main_quest_lv10._200_say = "Acesta este documentul de la muzician?[ENTER]Nu-i r\227u pentru un aventurier nou.[ENTER]Pun mari speran\254e \238n tine. Ia asta ca r\227splat\227[ENTER]pentru munca ta. \170i munce\186te mai departe cu[ENTER]acela\186i s\226rg pentru \254ar\227. "
gameforge.main_quest_lv10._20_sayReward = "Ai acumulat destul\227 experien\254\227 acum pentru a[ENTER]ap\227r\227 regatul. De acum \238nainte C\227pitanul \238\254i va[ENTER]da misiuni noi. \206l g\227se\186ti \238n primul sat. Mergi[ENTER]la el, te a\186teapt\227."
gameforge.main_quest_lv10._30_sayTitle = "C\227pitan"
gameforge.main_quest_lv10._40_say = "\206mi pari cunoscut... A da, trebuie s\227 fi auzit de[ENTER]tine.[ENTER]E\186ti noul aventurier, \186i \254i-ai demonstrat deja[ENTER]vitejia. Nu \186tiu c\226t de bine ai fost instruit,[ENTER]dar pe viitor vei primi multe[ENTER]sarcini. "
gameforge.main_quest_lv10._50_say = "Sunt lucruri importante, \186i le voi recapitula.[ENTER]Odat\227 a existat un regat unit.[ENTER]Dup\227 apari\254ia pietrelor metin a fost \238mp\227r\254it \238n[ENTER]cele trei regate: Shinsoo este regatul nego\254ului,[ENTER]Chunjo, regatul religiei, iar Jinno este regatul[ENTER]armatei. "
gameforge.main_quest_lv10._60_say = "Sunt lucruri importante, \186i le voi recapitula.[ENTER]Odat\227 a existat un regat unit.[ENTER]Dup\227 apari\254ia pietrelor metin a fost \238mp\227r\254it \238n[ENTER]cele trei regate: Shinsoo este regatul nego\254ului,[ENTER]Chunjo, regatul religiei, iar Jinno este regatul[ENTER]armatei. "
gameforge.main_quest_lv10._70_say = "Fiecare regat \238ncearc\227 s\227 se refac\227 dup\227[ENTER]nelini\186tile care au ap\227rut odat\227 cu pietrele[ENTER]metin, pentru a reuni continentul.[ENTER]Trebuie \186i tu s\227 lucrezi aspru pentru unirea[ENTER]continentului![ENTER]Este important s\227 nu ui\254i asta[ENTER]niciodat\227. "
gameforge.main_quest_lv10._80_say = "Am s\227 \238\254i dau prima sarcin\227.[ENTER]Fii lini\186tit, este o sarcin\227 relativ u\186oar\227.[ENTER]\206n satul vecin se afl\227 un muzician pe nume[ENTER]Yu-Hwan. Lumea spune c\227 a renun\254at la serviciul[ENTER]militar pentru a deveni muzician.[ENTER]Dar de fapt este spion.[ENTER]Este un document de la Yu-Hwan, de care am[ENTER]nevoie. Adu-mi-l.[ENTER]Nu uita c\227 este o sarcin\227[ENTER]secret\227. "
gameforge.main_quest_lv10._90_say = "Apas\227 pe M pentru a vedea cum ajungi \238n urm\227torul[ENTER]sat cu ajutorul h\227r\254ii. Folose\186te portalul de[ENTER]teleportare corespunz\227tor satului respectiv.[ENTER]Gr\227be\186te-te! Yu-Hwan este foarte \238nalt dar \238l[ENTER]vezi recunoa\186te dup\227 instrumentele care le poart\227[ENTER]cu el."
