gameforge.main_quest_lv14._120_say = "Bine lucrat! Ai devenit un ajutor de \238ncredere![ENTER]Acum \186tiu c\227 i\254i pot da orice sarcin\227.[ENTER]Sunt m\226ndru de tine \186i de ceea ce ai f\227cut pentru[ENTER]noi. Uite-\254i r\227splata si \254ine-o tot a\186a!"
