gameforge.main_quest_lv14._30_say = "Dac\227 nu facem ceva \238mpotriva Pietrelor Metin,[ENTER]animalele s\227lbatice vor ataca satele din nou sau[ENTER]chiar mai r\227u, eruperea unei epidemii. Te po\254i[ENTER]ocupa de pietrele care au c\227zut \238n afara satului?"
