gameforge.main_quest_lv15 = {}
gameforge.main_quest_lv15._100_say = "Regatul nostru, Jinno, a fost mereu o putere[ENTER]militar\227. \206mp\227ratul a unit continentul cu[ENTER]cavalerie puternic \238ncercat\227 \186i testat\227. Chiar[ENTER]dac\227 suntem dezbina\254i ca urmare a revoltelor[ENTER]cauzate de Pietrele Metin, regatul nostru \238nc\227[ENTER]de\254ine puterea asupra Iryung."
gameforge.main_quest_lv15._10_qSetTitle = "Situa\254ia curent\227"
gameforge.main_quest_lv15._110_say = "Inc\227 avem cea mai puternic\227 armat\227 dintre toate[ENTER]cele 3 regate, chiar dac\227 nu facem nimic[ENTER]\238mpotriva pietrelor metin. Dac\227 am vrea, am putea[ENTER]cuceri f\227r\227 probleme celelalte \254\227ri. Trebuie s\227[ENTER]te antrenezi din greu pentru a deveni un bun[ENTER]soldat!"
gameforge.main_quest_lv15._120_say = "Am s\227 \238\254i dau o sarcin\227 nou\227. Du aceast\227 muni\254ie[ENTER]la Yu-Hwan, \238n satul vecin. \222ara noastr\227 este o[ENTER]super-putere militar\227 \186i trebuie s\227 asigur\227m[ENTER]muni\254ie suficient\227.[ENTER]Dac\227 duci aceasta la Yu-Hwan vei contribui mult[ENTER]la \238narmarea satului."
gameforge.main_quest_lv15._130_sayReward = "Ai primit 36000 puncte de experien\254a.[ENTER]Ai primit 10000 Yang.[ENTER]Ai primit o Podoaba."
gameforge.main_quest_lv15._140_sayTitle = "Situa\254ia curent\227"
gameforge.main_quest_lv15._150_sayReward = "C\227pitanul \254i-a \238ncredin\254at o livrare pentru[ENTER]Yu-Hwan. Du-o lui \238n al doilea sat."
gameforge.main_quest_lv15._160_say = "\206n timpuri str\227vechi a avut loc o b\227t\227lie[ENTER]s\226ngeroas\227 intre Sung Mahi \186i Zeul Dragon. De[ENTER]atunci oamenii au fost \238mp\227r\254i\254i \238n doua tabere[ENTER]care se r\227zboiesc intre ele ... Din nou tu! Ai[ENTER]nevoie de ceva? C\227pitanul mi-a trimis ceva[ENTER]important? Mul\254umesc. \170i acum vezi de drumul t\227u[ENTER]- nu e bine ca oamenii s\227 ne vad\227 \238mpreun\227."
gameforge.main_quest_lv15._170_makequestbutton = "Vorbe\186te cu c\227pitanul"
gameforge.main_quest_lv15._175_say = "I-ai dat lui Yu-Hwan livrarea C\227pitanului. Acum[ENTER]\238ntoarce-te la C\227pitan \186i ia-\254i recompensa."
gameforge.main_quest_lv15._180_say = "Foarte bine! Daca continui tot asa vei ajunge un[ENTER]ajutor important pentru sat. Poftim recompensa."
gameforge.main_quest_lv15._20_say = "Dac\227 mergi la c\227pitan vei afla \238n ce stare se[ENTER]afl\227 cele 3 regate. Mergi repede la el."
gameforge.main_quest_lv15._30_say = "Dup\227 cum v\227d, e\186ti preg\227tit s\227 afli mai multe[ENTER]despre situa\254ia actual\227. S\227 \238ncep cu regatul[ENTER]nostru. Pentru a c\226\186tiga un r\227zboi trebuie s\227 te[ENTER]cuno\186ti \238nt\226i pe tine, pentru a putea apoi[ENTER]cunoa\186te inamicul."
gameforge.main_quest_lv15._40_say = "Shinsoo: Regatul nostru a fost dintotdeauna un[ENTER]regat al nego\254ului. Aveam rute comerciale foarte[ENTER]\238ntinse, de aceea nego\254ul \238nflorea la noi \238n[ENTER]regat. Dar de c\226nd au ap\227rut pietrele metin,[ENTER]nego\254ul s-a pr\227bu\186it iar economia noastr\227 se[ENTER]\238nr\227ut\227\254e\186te. Ca regat al comer\254ului, nu am fost[ENTER]niciodat\227 o putere militar\227 mare.[ENTER][ENTER]De aceea am angajat cu averile noastre mul\254i[ENTER]mercenari. Mercenarii sunt de n\227dejde \186i loiali,[ENTER]at\226ta timp c\226t \238i pl\227te\186ti. "
gameforge.main_quest_lv15._50_say = "Mul\254umit\227 mercenarilor, \254ara noastr\227 \186i-a[ENTER]rec\227p\227tat oarecum stabilitatea. Dar pentru a ne[ENTER]preg\227ti pentru viitoare r\227zboaie, avem nevoie de[ENTER]mai mul\254i mercenari \186i o economie puternic\227. Ne[ENTER]va costa mult pe to\254i. "
gameforge.main_quest_lv15._60_say = "Am s\227 \238\254i dau o nou\227 sarcin\227. Du aceast\227[ENTER]specialitate la Yu-Hwan, \238n satul vecin. Regatul[ENTER]nostru este un regat al comer\254ului, iar noi[ENTER]negociem cu specialit\227\254i din diferite regiuni.[ENTER]Dac\227 o duci la Yu-Hwan, aduci o mare contribu\254ie[ENTER]\238ntregului sat."
gameforge.main_quest_lv15._70_say = "Chunjo: Regatul nostru, condus de Yoon Young,[ENTER]este un regat al religiei. Datorit\227 acestul fapt[ENTER]am aflat primii de existen\254a lui Sung Mahi.[ENTER]\170amanii no\186tri ne-au preg\227tit pentru venirea[ENTER]pietrelor metin. \170amanii lucreaz\227 din greu la[ENTER]siguran\254a regatului nostru. Ei au multe calit\227\254i[ENTER]datorate credin\254ei lor. F\227r\227 ei ar fi doar o[ENTER]chestiune de timp, p\226n\227 c\226nd am fi cuceri\254i de[ENTER]alt\227 \254ar\227. "
gameforge.main_quest_lv15._80_say = "\170i locuitorii \254\227rii noastre au o credin\254\227[ENTER]puternic\227 \186i se roag\227 zilnic la zeul zmeu. Zeul[ENTER]zmeu, binef\227c\227torul nostru, ne protejeaz\227 \186i ne[ENTER]ap\227r\227 de \238nvierea lui Sung Mahi. Trebuie s\227 ne[ENTER]ap\227r\227m \238n continuare de aceste atacuri barbare \186i[ENTER]s\227 reunim continentul cu credin\254a[ENTER]noastr\227. "
gameforge.main_quest_lv15._90_say = "Am s\227 \238\254i dau o nou\227 sarcin\227. Du aceast\227 statuie[ENTER]a zeului zmeu lui Yu-Hwan, \238n satul vecin. \222ara[ENTER]noastr\227 este religioas\227 iar credin\254a ad\226nc\227 \238n[ENTER]zeul zmeu ne este foarte important\227. Dac\227 duci[ENTER]statuia la Yu-Hwan vei contribui foarte mult la[ENTER]credin\254a satului."
