gameforge.main_quest_lv32._380_sayReward = "Asta este singura noastr\227 \186ans\227 chiar dac\227 nu[ENTER]\186tim c\227 va avea succes \238ns\227 trebuie s\227 \238ncercam.[ENTER]\206nainte s\227 ne atace trebuie s\227 de\254inem[ENTER]informa\254iile despre puterea magic\227 interzis\227.[ENTER]Conform legendei putem afla informa\254ii despre[ENTER]aceasta doar \238n Valea Dragonului."
gameforge.main_quest_lv32._390_say = "Din con\254inut \238n\254eleg c\227 \238n aceast\227 \254ar\227 au[ENTER]existat credin\254e str\227vechi. \206nainte ca Lee Seop[ENTER]s\227 uneasc\227 toate teritoriile, fiecare \254ar\227 avea[ENTER]credin\254a ei. Se pare ca autorul c\227r\254ii a fost un[ENTER]om \238n\254elept \186i a f\227cut parte dintr-o breasl\227 sau[ENTER]chiar era liderul ei. Membrii unei bresle erau[ENTER]considera\254i elita societ\227\254ii."
gameforge.main_quest_lv32._400_say = "Multe pove\186ti s-au tot n\227scocit despre Valea[ENTER]Dragonului. Chiar \186i eu cunosc c\226teva. Poate c\227[ENTER]vom g\227si mai multe informa\254ii despre asta sau mai[ENTER]multe pagini din carte. Din p\227cate nu am nicio[ENTER]informa\254ie despre locul unde se afl\227.[ENTER]Mergi la v\226n\227torul Yang-Shin \238n satul vecin, el[ENTER]cunoa\186te bine \238mprejurimile locului \238n care se[ENTER]afl\227. Poate \186tie unde se afl\227 \186i Valea Dragonului[ENTER]\186i dac\227 po\254i g\227si ceva util acolo."
gameforge.main_quest_lv32._40_say = "Salutare.[ENTER]Ajutorul t\227u de ultima dat\227 a fost foarte util.[ENTER]\206nc\226t am reu\186it s\227 fac progrese foarte mari.[ENTER]Dar acum am o problem\227. \206n timp ce f\227ceam[ENTER]cercet\227ri despre meteori\254i am g\227sit o carte[ENTER]veche. Din ce am \238n\254eles \238n carte se vorbe\186te[ENTER]despre schimb\227rile ce le-a avut \254ara noastr\227 \186i[ENTER]cum a fost afectat\227 de acestea.[ENTER]Este foarte important."
gameforge.main_quest_lv32._410_say = "Excelent! \206nainte s\227 uit: poftim recompensa[ENTER]pentru prima pagin\227."
gameforge.main_quest_lv32._420_sayReward = "Ai primit 1000000 puncte de experien\254\227."
