gameforge.main_quest_lv32._470_sayTitle = "\206ntreab\227-l pe Yang-Shin despre Valea Dragonului."
gameforge.main_quest_lv32._480_say = "Pe prima pagin\227 din cartea veche se men\254ioneaz\227[ENTER]loca\254ia V\227ii Dragonului. Uriel a auzit multe[ENTER]povesti despre vale dar nu \186tie loca\254ia ei. Mergi[ENTER]\238n satul vecin \186i \238ntreab\227-l pe v\226n\227torul[ENTER]Yang-Shin dac\227 \186tie mai multe detalii."
