gameforge.main_quest_lv32._500_npcChat = "Informa\254ii despre valea zmeilor"
gameforge.main_quest_lv32._50_say = "Problema este c\227, cartea este foarte veche \186i[ENTER]deteriorat\227. Cartea a fost transmis\227 din[ENTER]genera\254ii \238n genera\254ii \186i de asta este asa[ENTER]deteriorat\227. 13 pagini lipsesc din carte. Po\254i[ENTER]face rost de ele c\227ci e posibil s\227 fie scris pe[ENTER]ele cum pot pune cap\227t r\227zboiului."
gameforge.main_quest_lv32._510_sayTitle = "Yang-Shin :"
gameforge.main_quest_lv32._520_say = "Vrei sa afli loca\254ia V\227ii Dragonului? Asta este[ENTER]denumirea veche a V\227ii Seungryong. Nu se g\227sesc[ENTER]dragoni acolo dar \238n schimb g\227se\186ti multi orci \186i[ENTER]o sect\227 secret\227. De ce vrei s\227 mergi \238ntr-un[ENTER]astfel de loc periculos? Nici eu nu merg acolo[ENTER]asa c\227 mai bine ai sta departe de acel loc."
gameforge.main_quest_lv32._530_say = "Poftim? Cau\254i paginile din cartea veche? De[ENTER]\238ndat\227 ce am aflat de la v\226n\227tori c\227 Vr\227jitorii[ENTER]Orci au \238n posesie c\238teva pagini, am \238nceput s\227[ENTER]m\227 \238ntreb dac\227 este adev\227rat.[ENTER]Dac\227 e\186ti at\226t de curios mergi acolo \186i vezi[ENTER]numai ai grij\227 c\227 este un loc periculos. Ai grija[ENTER]de tine."
gameforge.main_quest_lv32._540_sendLetter = "Caut\227 pagina a doua"
gameforge.main_quest_lv32._550_say = "Dup\227 povestirile v\226n\227torului, trebuie s\227 \238i[ENTER]g\227se\186ti pe Orcii Elite Vr\227jitori din Valea[ENTER]Dragonului. Ace\186tia ar trebui s\227 aib\227 a doua[ENTER]pagin\227 veche. Ucide-i pe Orcii Elite Vr\227jitori \186i[ENTER]ia a doua pagin\227. De \238ndat\227 ce ai luat-o, du-o la[ENTER]Uriel."
