gameforge.main_quest_lv32._580_say = "V\226n\227toarea Orcilor Elite Vr\227jitori a avut succes:[ENTER]ai g\227sit a doua pagin\227 din carte. Du-o lui Uriel."
gameforge.main_quest_lv32._590_say = "Asta este pagina a doua?[ENTER]S\227 v\227d. Hm. Nu e deloc u\186or de descifrat.[ENTER]Scrie... "
gameforge.main_quest_lv32._600_sayTitle = "Pagina a doua:"
gameforge.main_quest_lv32._60_say = "Odat\227 ce ai g\227sit vechile pagini, adu-le la mine.[ENTER]Atunci am s\227 \238ncerc s\227 le descifrez. Hmmm...[ENTER]Oare unde ar trebui \238nceput? Acum ceva timp am[ENTER]auzit de la un negustor ambulant din satul vecin,[ENTER]c\227 ar fi g\227sit o pagin\227 veche. Mergi la el \186i[ENTER]vezi dac\227 po\254i afla ceva. "
gameforge.main_quest_lv32._610_sayReward = "Adep\254ii magiei negre au fost g\227si\254i ascunz\238ndu-se[ENTER]\238n Valea Dragonului. Ei de\254in informa\254ii despre[ENTER]puterea magic\227 care a existat \238nc\227 din timpuri[ENTER]str\227vechi. A fost nevoie de timp \186i amenin\254\227ri[ENTER]pentru a-i convinge sa ne ajute, rezultatul[ENTER]fiind: ai nevoie de un loc special pentru a[ENTER]practica aceast\227 putere magic\227, locul trebuie sa[ENTER]fie plin de energie negativ\227. Timpul se scurge[ENTER]repede asa c\227 trebuie s\227 g\227sesc locul potrivit."
gameforge.main_quest_lv32._620_say = "Hmm, avem nevoie de un loc plin cu energie[ENTER]negativ\227 pentru a folosi puterea magic\227, un loc[ENTER]unde totul poate fi transformat \238n energie[ENTER]negativ\227. Unde oare putem g\227si un astfel de loc?[ENTER]\170tiu! \206n Templul Hwang. Locuitorii nu-l numesc[ENTER]degeaba Templul \206ntunericului. Este locul unde[ENTER]nimeni nu \186i-ar dori s\227 mearg\227, nici m\227car[ENTER]animalele."
gameforge.main_quest_lv32._630_say = "Mai mult, acolo se afl\227 o leg\227tur\227 intre puterea[ENTER]magic\227 interzis\227 \186i secta secret\227. Po\254i g\227si[ENTER]explica\254ia asta doar \238n Templul Hwang. Vezi ce se[ENTER]petrece \238n templu \186i \238ncearc\227 s\227 g\227se\186ti \186i alte[ENTER]pagini din carte. Uite aici recompensa pentru a[ENTER]doua pagina g\227sita ..."
