gameforge.main_quest_lv40._60_sayTitle = "Pagina a treia:"
gameforge.main_quest_lv40._70_sayReward = "Am ajuns \238ntr-un loc unde energia r\227ului a fost[ENTER]\238nvins\227. Dar asta nu este de ajuns ...[ENTER]Unde se poate practica vr\227jitoria? O informa\254ie[ENTER]recent\227 spune ca ar exista un loc ascuns \238n[ENTER]de\186ertul Yongbi. Plini de speran\254\227, s\227 ne[ENTER]teleport\227m acum \238n de\186ertul Yongbi."
gameforge.main_quest_lv40._80_say = "Deci, nu au reu\186it s\227-\186i ating\227 scopul \238n Valea[ENTER]Dragonului. Hmm ... Desertul Yongbi? Nu prea[ENTER]\238nt\226lne\186ti oameni acolo mai ales c\227 zona este[ENTER]neexploatat\227. Dar totul este complicat, unde este[ENTER]aceasta zon\227 despre care se vorbe\186te? Presupun c\227[ENTER]se refer\227 la Jungsun Dong (Temni\254a maimu\254elor[ENTER]normal). Este o pe\186ter\227 ad\226nc\227 \186i numai bun\227[ENTER]pentru colectare de energie negativ\227."
