gameforge.main_quest_lv47._160_npcChat = "Pagina a \186asea"
gameforge.main_quest_lv47._170_say = "Cum a fost \238n Temni\254a P\227ianjenilor? Ai g\227sit a[ENTER]\186asea pagin\227? Fantastic! M-am temut c\227 va fi prea[ENTER]t\226rziu. Cineva \238mi spunea mereu c\227 al\254i oameni[ENTER]caut\227 \186i ei secretele magiei negre. Se pare c\227[ENTER]informa\254ia este foarte important\227. S\227 vedem ce[ENTER]g\227sim \238n aceast\227 pagin\227."
gameforge.main_quest_lv47._180_say = "Oh, aceast\227 pagin\227 este greu de descifrat. Am[ENTER]nevoie de mai mult timp pentru a o descifra.[ENTER]\206ns\227 con\254inutul pare s\227 fie interesant. Acest[ENTER]semn simbolizeaz\227 Magia Neagr\227, suntem pe drumul[ENTER]cel bun. Vreau s\227 aflu de ce magia neagr\227 a fost[ENTER]interzis\227. Cred c\227 trebuie s\227 existe un motiv[ENTER]bun."
