gameforge.main_quest_lv47._260_say = "Muzicianul Yu-Hwan se pare ca are informa\254ii[ENTER]despre pagin\227, mergi la el \186i \238ntreab\227-l."
gameforge.main_quest_lv47._270_npcChat = "Ceva noutati?"
gameforge.main_quest_lv47._280_say = "Bucur\227-te de via\254\227 pentru ca este foarte scurt\227![ENTER]Tralalalalala ... Ah, ai revenit. Probabil te-ai[ENTER]\238ntors de la Uriel. Am aflat ca \238n toate regatele[ENTER]oamenii sunt \238n c\227utare de documente importante[ENTER]\238ns\227 nimeni nu a vrut s\227-mi zic\227 nimic despre[ENTER]a\186aceva."
gameforge.main_quest_lv47._290_say = "Este ciudat c\227 \238nc\227 aceste figuri ciudate se[ENTER]\238nv\238rt pe aici \238n timpul r\227zboiului! Cu excep\254ia[ENTER]ta, bine\238n\254eles! Am auzit c\227 beduinii au reu\186it[ENTER]s\227 ia ca prada ni\186te lucruri care pot fi[ENTER]importante pentru noi."
gameforge.main_quest_lv47._300_say = "Am auzit ca Beduinii sunt creaturi periculoase,[ENTER]asa c\227 ai grij\227. Dar cred c\227 se merit\227."
