gameforge.main_quest_lv47._310_sendLetter = "Beduinii"
gameforge.main_quest_lv47._320_sayTitle = "C\227utarea informa\254iilor secrete"
gameforge.main_quest_lv47._330_say = "Uriel are nevoie de toate informa\254iile despre[ENTER]magia neagr\227. Muzicianul Yu-Hwan a spus c\227[ENTER]Beduinii au furat ceva care poate fi de folos. Ar[ENTER]trebui s\227 merg s\227 ucid Beduini."
gameforge.main_quest_lv47._340_sendLetter = "Am g\227sit a \186aptea pagin\227"
gameforge.main_quest_lv47._350_targetVid = "C\227utarea muzicianului Yu-Hwan"
gameforge.main_quest_lv47._360_say = "Datorit\227 informa\254iilor pe care \254i le-a dat[ENTER]muzicianul Yu-Hwan ai reu\186it s\227 g\227se\186ti a \186aptea[ENTER]pagin\227 a jurnalului la Beduini. Mergi acum la[ENTER]Yu-Hwan \186i anun\254\227-l c\227 informa\254ia a fost corect\227."
gameforge.main_quest_lv47._370_say = "Ochii tai sunt frumo\186i ca lacul unui munte. Hey,[ENTER]ai revenit. Ai avut succes cu beduinii? Poftim,[ENTER]asta e tot? O bucat\227 veche de h\238rtie? Nu este[ENTER]folositoare pentru mine. Dar dac\227 te \238nc\238nt\227 ...[ENTER]Du-o lui Uriel \186i transmite-i salutari."
gameforge.main_quest_lv47._380_sendLetter = "Mergi la Uriel."
gameforge.main_quest_lv47._390_targetVid = "Mergi la Uriel."
gameforge.main_quest_lv47._400_sayTitle = "A \186aptea pagin\227"
gameforge.main_quest_lv47._40_say = "Ai g\227sit a cincea pagin\227? De necrezut! Suntem[ENTER]noroco\186i c\227 aceste pagini \238nc\227 exist\227 dup\227 at\226\254ia[ENTER]ani. E\186ti foarte eficient.[ENTER]Acum s\227 vedem ce scrie pe aceast\227 pagin\227."
gameforge.main_quest_lv47._410_say = "Ai g\227sit a \186aptea pagin\227 a jurnalului.[ENTER]Du-o lui Uriel."
gameforge.main_quest_lv47._420_say = "Salut, \238mi pare bine s\227 te rev\227d! Am ve\186ti bune:[ENTER]am reu\186it s\227 descifrez a \186asea pagin\227. Nu-i r\227u,[ENTER]a\186a-i? Trebuie s\227 m\227rturisesc c\227 sunt m\226ndru de[ENTER]mine. Ceea ce mi-a atras aten\254ia au fost acele[ENTER]caractere... Pardon? Ai g\227sit alt\227 pagin\227?[ENTER]Doamne! Chiar c\227 ai fost rapid.[ENTER]Arat\227-mi! Wow, unde ai g\227sit-o pe asta? Dac\227 nu[ENTER]m\227 \238n\186el acestea sunt caracterele folosite de[ENTER]familia regal\227."
gameforge.main_quest_lv47._430_say = "Pentru c\227 aceste caractere nu au fost folosite[ENTER]des \186i de c\227tre putini oameni, a fost foarte[ENTER]dificil s\227 le descifrez. \206ns\227 pu\254in\227 chinuial\227 nu[ENTER]stric\227, hahaha! De abia a\186tept. Beduinii au furat[ENTER]aceast\227 pagin\227 de la str\227inii misterio\186i? Hmm...[ENTER]Asta \238nseamn\227 c\227 str\227inii \238n\254elegeau caracterele?[ENTER]Devine confuz\227 toat\227 treaba asta.[ENTER]Trebuie s\227 ne asiguram c\227 nu omitem nimic."
gameforge.main_quest_lv47._440_say = "Oh da: \238nainte s\227 m\227 concentrez asupra urm\227toarei[ENTER]pagini cred c\227 ar trebui s\227-\254i zic ce se afl\227 pe[ENTER]pagina a \186asea. Hm..."
gameforge.main_quest_lv47._450_sayTitle = "Pagina a \186asea:"
gameforge.main_quest_lv47._460_sayReward = "Timpul se scurge. Am \238ncercat s\227 folosim magia[ENTER]neagr\227 \238n Temni\254a P\227ianjenilor dar nu a[ENTER]func\254ionat. Ce ne scap\227? Se pare c\227 se cer[ENTER]sacrificii mai mari. Dac\227 este adev\227rat \238nseamn\227[ENTER]c\227 este o for\254\227 imens\227."
gameforge.main_quest_lv47._470_sayReward = "Conform legendelor acest tip de magie necesit\227[ENTER]sacrificii umane. Dar dac\227 voi face aceste[ENTER]sacrificii voi fi privit cu al\254i ochi \238n r\238ndul[ENTER]oamenilor. Ne trebuie un \238nlocuitor. S\227 \238ncercam[ENTER]cu \170arpe Spadasin din de\186ert."
gameforge.main_quest_lv47._480_say = "Aha. Pentru c\227 nu au putut sacrifica vie\254i umane[ENTER]au \238ncercat cu \186erpi lupt\227tori. Nu pot spune c\227[ENTER]sunt de acord cu asta ... \238nsa s\227 nu se termine[ENTER]r\227u. Mergi \238n de\186ert \186i ucide c\238\254iva \170erpi[ENTER]Spadasini \186i \170erpi Arca\186i. Cine \186tie ce mai g\227sim[ENTER]acolo. Apropo: recompensa ta este \238n aceast\227[ENTER]pung\227."
gameforge.main_quest_lv47._490_sendLetter = "Ucide lupt\227torii \186arpe"
gameforge.main_quest_lv47._500_sayTitle = "A opta pagin\227"
gameforge.main_quest_lv47._50_sayTitle = "A cincea pagin\227:"
gameforge.main_quest_lv47._510_say = "Jurnalul spune despre sacrificarea \170erpilor[ENTER]Spadasini \186i \170erpilor Arca\186i pentru ritualul[ENTER]magiei negre. Mergi \238n desertul Yongbi \186i ucide[ENTER]\170erpi Spadasini. Si g\227se\186te \186i alte informa\254ii."
gameforge.main_quest_lv47._520_sendLetter = "Am g\227sit a opta pagin\227"
gameforge.main_quest_lv47._530_targetVid = "Mergi la \238nv\227\254atul Uriel"
gameforge.main_quest_lv47._540_say = "Ai g\227sit a opta pagin\227 din jurnal la \170erpii[ENTER]Spadasini din De\186ert. Du-o lui Uriel."
gameforge.main_quest_lv47._550_say = "Aceasta este Pagina a 8-a. Deoarece e foarte[ENTER]scurt\227, o descifrez imediat."
gameforge.main_quest_lv47._560_sayTitle = "A opta pagin\227:"
gameforge.main_quest_lv47._570_sayReward = "Victimele necesare au fost g\227site. Am fost[ENTER]noroco\186i. Ma \238ntreb dac\227 nu cumva asta este un[ENTER]semn? Avem nevoie de un clopo\254el pentru[ENTER]ceremonie. Dac\227 \238mi aduc bine aminte p\227ianjenii[ENTER]au a\186aceva."
gameforge.main_quest_lv47._580_say = "Ah, din nou Temni\254a P\227ianjenilor. Trebuie s\227[ENTER]mergi acolo \186i s\227 cau\254i clopo\254elul. Va fi o[ENTER]c\227l\227torie obositoare a\186a c\227 odihne\186te-te pu\254in \186i[ENTER]apoi revino. \206ntre timp voi traduce \186i alte[ENTER]fragmente. C\226nd te vei \238ntoarce \238\254i voi da o nou\227[ENTER]misiune. \170i stai lini\186tit, vei primi chiar acum[ENTER]\186i recompensa pentru a opta pagin\227."
gameforge.main_quest_lv47._590_sayReward = "Puncte de experien\254\227: 3.000.000 de EXP[ENTER]Yang: 70.000[ENTER]Mantia Curajului: 20[ENTER]Sfat: pentru sarcinile urm\227toare trebuie s\227 fi[ENTER]ajuns cel pu\254in la nivelul 50."
gameforge.main_quest_lv47._60_sayReward = "Lee Seop a ajuns \238n regatul Taejo \238mpreun\227 cu[ENTER]armata sa \186i se pare c\227 vrea s\227 stea acolo pentru[ENTER]o perioada de timp. Intre timp buc\227\254i mari \186i[ENTER]mici de meteori\254i cad pe p\227m\226nt produc\226nd haos,[ENTER]distrugere \186i conflicte. M\227re\254ul regat s-a[ENTER]\238mp\227r\254it \238n 3 regate mai mici care se lupt\227 intre[ENTER]ele \238n loc sa lupte \238mpotriva inamicului mai[ENTER]mare. Zeul Dragpn nu ne mai ajut\227 datorita[ENTER]acestui lucru. Uneori \238nsa ajuta pe unii \186i pe[ENTER]al\254ii nu. A\186a c\227 dezastrul devine din ce \238n ce[ENTER]mai mare ..."
gameforge.main_quest_lv47._70_sayTitle = "Uriel:"
gameforge.main_quest_lv47._80_say = "Un martor ocular al zilelor noastre. Este de[ENTER]nepre\254uit! Oh da, pl\227te\186te. Uite aici o[ENTER]recompens\227 pentru munca ta. \170i \238nc\227 ceva: cineva[ENTER]mai face investiga\254ii ca \186i noi asa c\227 nu trebuie[ENTER]s\227 pierdem timp. \206n josul paginii scrie c\227 Lee[ENTER]Seop a c\227utat energie negativ\227 \238n Temni\254a[ENTER]P\227ianjenilor. Dac\227 g\227se\186ti ceva acolo anun\254\227-m\227[ENTER]imediat!"
