gameforge.main_quest_lv50._220_say = "Ai g\227sit a 10-a pagin\227 din Jurnalul Secret pe[ENTER]Muntele Sohan (\222ara de ghea\254\227). Se afla \238ntr-o[ENTER]cutie veche cu ni\186te pagini. Du-o lui Uriel."
gameforge.main_quest_lv50._230_say = "Ah, ai g\227sit a zecea pagin\227 care lipsea din[ENTER]jurnal![ENTER]Super, ne apropiem de finalul pove\186tii. Este bine[ENTER]c\227 totul a fost scris \238n acest jurnal, altfel era[ENTER]pierdut totul. S\227 vedem ce scrie pe pagin\227."
gameforge.main_quest_lv50._235_sayTitle = "a zecea pagin\227:"
gameforge.main_quest_lv50._240_sayReward = "Am reusit sa scapam de primul atac insa urmatorul[ENTER]va fi curand. Terenul ii va opri pe soldatii de[ENTER]fier ai lui Lee Seops si ne va da unele avantaje,[ENTER]dar sunt prea multi. Nu putem castiga. Singura[ENTER]sansa este sa terminam cercetarea magiei negre.[ENTER]In intuneric omoram inamicii si mergem in Pestera[ENTER]Paianjenilor. Ma rog pentru o urma de speranta..."
gameforge.main_quest_lv50._250_say = "Ohh! Se pare c\227 am ajuns. \206n cur\238nd vom afla[ENTER]puterea Magiei \206ntunecate. Trebuie s\227 te \238ntorci[ENTER]\238n Temni\254a P\227ianjenilor \238nc\227 odat\227. S\227 sper\227m c\227[ENTER]a 11 pagina se g\227se\186te acolo."
gameforge.main_quest_lv50._260_say = "\170i iat\227 bine meritata te recompens\227."
