gameforge.main_quest_lv50._340_say = "Ai g\227sit a unsprezecea pagin\227 din jurnal \238n[ENTER]Temni\254a P\227ianjenilor. Du-o lui Uriel."
gameforge.main_quest_lv50._350_say = "Ai g\227sit ceva nout\227\254i? Aha, a unsprezecea pagin\227![ENTER]S\227 vedem...[ENTER]Ah da, pare simplu. Am devenit bun \238n citirea[ENTER]acestor caractere. Acum fi atent!"
gameforge.main_quest_lv50._355_sayTitle = "Pagina 11:"
gameforge.main_quest_lv50._360_sayReward = "A e\186uat. In ciuda tuturor preg\227tirilor trebuie s\227[ENTER]ne mi\186cam repede. Acum multi dintre noi sunt[ENTER]accidenta\254i sau au \238nnebunit. Magia \238ntunecat\227[ENTER]chiar este rea. Armata lui Lee Seop a intrat \238n[ENTER]noi dar asta e irelevant acum. Nu avem destui[ENTER]oameni s\227 ne ap\227ram \186i vom pieri oricum."
gameforge.main_quest_lv50._365_sayTitle = "Continuarea paginii 11:"
gameforge.main_quest_lv50._370_sayReward = "Un ultim g\226nd tine armata \238ntreag\227 \186i ii d\227[ENTER]putere: informa\254ia fals\227 din Valea Dragonului. Nu[ENTER]am fost anun\254a\254i despre efectele secundare ale[ENTER]magiei \238ntunecate. Vor pl\227ti pentru asta."
gameforge.main_quest_lv50._380_say = "Totul a fost diferit \238n final, nu a ie\186it asa cum[ENTER]sperau. Un final nefericit.[ENTER]Din p\227cate nu po\254i avea \238ncredere \238n nimeni care[ENTER]are leg\227tur\227 cu magia neagr\227. Trebuiau s\227 se[ENTER]g\226ndeasc\227 la asta. Este interesant c\227 cel care a[ENTER]scris aceste pagini a reu\186it s\227 adune at\226tea[ENTER]informa\254ii despre aceste lucruri interzise. Cine[ENTER]\186tie ce scop aveau informatorii s\227i. \206ns\227 trebuie[ENTER]s\227 terminam calea pe care am \238nceput-o chiar dac\227[ENTER]este periculos. \170tim deja multe lucruri \186i este o[ENTER]ru\186ine s\227 renun\254am acum."
gameforge.main_quest_lv50._390_say = "Ai fost deja \238n Valea Seungryong. Nu cred c\227 vom[ENTER]mai g\227si ceva acolo. M\227 \238ntreb unde am mai putea[ENTER]c\227uta... \170tiu! Memorialele au jucat un rol[ENTER]important \238n perioada cercet\227rilor noastre. \170i[ENTER]\238nc\227 exist\227 memoriale ce nu le-am investigat p\226n\227[ENTER]acum. Cele din celelalte regate! Este foarte[ENTER]periculos acolo. Probabil vei fi atacat constant.[ENTER]A\186a c\227 preg\227te\186te-te bine \186i revino la mine c\226nd[ENTER]e\186ti gata."
gameforge.main_quest_lv50._400_say = "Dar \238nainte \238\254i voi da o recompens\227 pentru a[ENTER]unsprezecea pagin\227."
gameforge.main_quest_lv50._40_targetVid = "Mergi la \238nv\227\254atul Uriel"
gameforge.main_quest_lv50._410_sayReward = "Ai primit 6.000.000 puncte de experien\254\227.[ENTER]Ai primit 150.000 Yang.[ENTER]Ai primit Medalia Dragonului.[ENTER]Indiciu: Pentru urm\227toarea misiune trebuie sa ai[ENTER]lvl 55."
gameforge.main_quest_lv50._50_sayTitle = "Am g\227sit a noua pagin\227"
gameforge.main_quest_lv50._60_say = "Ai g\227sit a noua pagin\227 \238n Temni\254a P\227ianjenilor.[ENTER]Du-o lui Uriel."
gameforge.main_quest_lv50._70_say = "Ai mai g\227sit \186i alte informa\254ii despre magia[ENTER]neagr\227? Wow, a noua pagin\227! Sunt curios dac\227[ENTER]magia va func\254iona.[ENTER]S\227 arunc\227m o privire. S\227 vedem ce scrie aici..."
gameforge.main_quest_lv50._75_sayTitle = "Pagina a noua:"
gameforge.main_quest_lv50._80_sayReward = "Lee Seop a \238nceput s\227 atace. \170i \238nc\227 nu \186tim cum[ENTER]s\227 folosim magia neagr\227. Sunt nervos. Suntem la[ENTER]limit\227 \238ncerc\226nd s\227 ne ap\227ram regatul dar puterea[ENTER]noastr\227 nu este suficient\227. Armata inamic\227 este[ENTER]prea puternic\227 \186i dac\227 nu se va \238nt\226mpla un[ENTER]miracol o s\227 pierdem b\227t\227lia. Trebuie s\227 ne[ENTER]retragem. Ar fi bine s\227 ne retragem \238ntr-un loc[ENTER]neaccesibil cailor lor: \222ara de Ghea\254\227. Cu pu\254in[ENTER]noroc vom mai avea timp s\227 continu\227m cercetarea.[ENTER]Oh, Zeii s\227 ne ajute..."
gameforge.main_quest_lv50._90_say = "Hmm ... atacul a \238nceput \238nainte ca ei s\227[ENTER]cerceteze cum trebuie magia \238ntunecat\227 a\186a c\227 au[ENTER]fost nevoi\254i s\227 se retrag\227 \238n \222ara de Ghea\254\227.[ENTER]Cred c\227 se refereau la Muntele Sohan care mai[ENTER]este denumit a\186a. Trebuie s\227 cautam mai multe[ENTER]indicii, mergi pe Muntele Sohan \186i vezi ce po\254i[ENTER]g\227si."
