gameforge.main_quest_lv90._130_say = "Arunca o privire in jurul insulei si raporteaza[ENTER]Amiralului Angmur ce ai descoperit."
gameforge.main_quest_lv90._140_sayReward = "Aceasta este prima destinatie: %d, %d"
