gameforge.neutral_warp._20_sayTitle = "B\227tr\226nul:"
gameforge.neutral_warp._30_say = "Bun\227![ENTER]Eu \186tiu cum se ajunge de aici \238ntr-o alt\227[ENTER]regiune. Dac\227 \238mi dai ni\186te yang, pot s\227 te duc[ENTER]\238ntr-acolo."
