gameforge.neutral_warp._65_npcChat = "Doresc sa merg la sora Femeii batrane."
gameforge.neutral_warp._70_say = "Batrana mi-a spus deja ca vii. Ea a spus ca nu ar[ENTER]trebui sa te taxez pentru aceasta calatorie,[ENTER]pentru ca faci o favoare. Bem ceai de multe ori[ENTER]impreuna si ma bucur sa o ajut. Dar sa nu crezi[ENTER]ca va ramane asa, in viitor! Ai grij\227 acolo,[ENTER]pentru ca cei afiliate cu regatele straine nu[ENTER]sunt prea amabili."
gameforge.new_christmas = {}
gameforge.new_christmas._010_npcChat = "Ho ho ho!"
gameforge.new_christmas._020_say = "Oh, tu e\186ti![ENTER]Nu ne-am vazut de ceva vreme.[ENTER]\206nc\227 un an care vine \186i pleac\227, ho ho![ENTER]Poate c\227 te \238ntrebi de ce m-am \238ntors \238n ora\186.[ENTER]D\227-mi voie s\227-\254i explic..."
gameforge.new_christmas._030_say = "Timpurile sunt grele. Nimeni nu vrea s\227 cumpere[ENTER]c\227r\254i sau alte lucruri \238n aceste timpuri.[ENTER]La v\226rsta mea este at\226t de obositor s\227 zbor pe o[ENTER]sanie condus\227 de reni.[ENTER]A\186a c\227, din cauza asta, am decis s\227 s\227rb\227toresc[ENTER]Cr\227ciunul acestui an aici, \238n ora\186."
gameforge.new_christmas._040_say = "Daca mai ai intrebari te poti intoarce oricand.[ENTER]Craciun Fericit!"
gameforge.new_christmas._050_npcChat = "Doresti niste vin fiert?"
gameforge.new_christmas._060_say = "Ho ho ho! Banuiesc ca stii ce e asta, nu-i asa?[ENTER]Nu exista bautura mai buna pe timp de iarna![ENTER]Amesteci vinul cu putina scortisoara si cateva[ENTER]cuisoare... mmmmm!"
gameforge.new_christmas._070_say = "In aceste vremuri friguroase o inghititura de vin[ENTER]fiert iti va arata lumea mai buna! Iti da putere[ENTER]si viteza de miscare. Doresti sa incerci? Foarte[ENTER]bine, vine imediat!"
gameforge.new_christmas._080_say = "Se pare ca iti place gustul vinului fiert ho ho![ENTER]Simti cum te iau caldurile? Ah, si gustul... atat[ENTER]de dulce si aromat![ENTER]Craciun Fericit!"
gameforge.new_christmas._090_npcChat = "Mai mult vin fiert te rog!"
gameforge.new_christmas._100_say = "Asteapta o secunda![ENTER]Am uitat un mic detaliu![ENTER]Pot prepara vin fiert pentru tine doar o data pe[ENTER]zi, nu am ingrediente suficiente pentru a face[ENTER]mai mult. Si dureaza doar 20 de ore. Intr-o[ENTER]sticla sunt 6 portii, iar efectul unei[ENTER]inghitituri dureaza 30 de minute. Foloseste-le cu[ENTER]grija!"
gameforge.new_christmas._110_say = "Esti binevenit! Ai asteptat destul timp. Aceasta[ENTER]bautura minunata te face sa plutesti, ho ho ho![ENTER]Sper sa-ti placa. Craciun Fericit!"
gameforge.new_christmas._120_say = "Ce, doresti mai mult?[ENTER]Imi pare rau dar cred ca iti ajunge. Nu au trecut[ENTER]24 de ore de cand ai baut ultima portie de vin[ENTER]fiert. Prea mult nu cred ca-ti face bine, sa[ENTER]stii! Vino mai tarziu. Pana atunci bucura-te de[ENTER]festivitate!"
gameforge.new_christmas_gift_box = {}
gameforge.new_christmas_gift_box._010_say = "Din %d, mai poti despacheta %d."
gameforge.new_christmas_gift_box._020_say = "Deschide urmatorul cadou in %d minute."
gameforge.new_christmas_sock = {}
gameforge.new_christmas_sock._010_npcChat = "Ce este cu aceasta Soseta?"
gameforge.new_christmas_sock._020_say = "Sosetele! Aproape ca am uitat de ele! Am vrut sa[ENTER]ascund cadourile in sosetele agatate deasupra[ENTER]semineului. Oricum, aceste creaturi anti-Craciun[ENTER]le-au furat pe toate! Ajuta-ma sa le recuperez."
gameforge.new_christmas_sock._030_say = "\170osetele nu sunt u\186or de g\227sit. Ai nevoie de un[ENTER]Ren T\226n\227r pentru a le g\227si."
gameforge.new_christmas_sock._040_say = "Nu-i a\186a c\227 e dr\227gu\254?[ENTER]Are \186i un miros foarte fin. Un adev\227rat[ENTER]specialist \238n g\227sirea \186osetelor![ENTER]Va sta cu tine 2 ore \186i te va ajuta la c\227utare.[ENTER]Apoi va fi obosit \186i va avea nevoie de 24 de ore[ENTER]de odihn\227 pentru a putea continua.[ENTER]Dac\227 nu vrei s\227 a\186tep\254i at\226t, arunc\227 o privire la[ENTER]moneda rotativ\227 de jos din dreapta, am auzit c\227[ENTER]un alt Ren T\226n\227r a\186teapt\227 acolo. Dar voi fi[ENTER]bucuros dac\227 vei veni s\227 m\227 vezi \186i m\226ine!"
gameforge.new_christmas_sock._050_npcChat = "Iti aduc sosete!"
gameforge.new_christmas_sock._060_say = "Adu-mi cel putin 5 Sosete si vei primi o[ENTER]recompensa.[ENTER]Beacs, mirosul Sosetelor murdare este[ENTER]insuportabil! Revino cand ai colectat suficiente.[ENTER]Craciun Fericit!"
gameforge.new_christmas_sock._070_say = "Ho ho ho, ai adunat destule sosete. Hmm, da-mi sa[ENTER]vad.[ENTER]Iacs, acest miros! Cu siguranta sunt cele care[ENTER]trebuie![ENTER]Craciun Fericit!"
gameforge.new_christmas_sock._080_npcChat = "- Ren T\226n\227r"
gameforge.new_christmas_sock._090_say = "Ai primit deja de la mine un Sigiliu pentru Renul[ENTER]T\226n\227r pe ziua de ast\227zi. M\227 tem c\227 micul prieten[ENTER]are nevoie de odihna. M\226ine va fi \238n plin\227 form\227.[ENTER]Dac\227 nu vrei s\227 a\186tep\254i at\226t, arunc\227 o privire la[ENTER]moneda rotativ\227 de jos din dreapta, am auzit c\227[ENTER]un alt Ren T\226n\227r a\186teapt\227 acolo. Dar voi fi[ENTER]bucuros dac\227 vei veni s\227 m\227 vezi \186i m\226ine!"
gameforge.new_christmas_sock._100_say = "Mi-ai adus deja sosetele pe ziua de azi. Tine[ENTER]minte, mai poti aduce doar peste 24 de ore."
gameforge.new_quest_lv17 = {}
gameforge.new_quest_lv17._010_target = "Wonda-Rim:"
gameforge.new_quest_lv17._012_say_title = "Wonda-Rim:"
gameforge.new_quest_lv17._020_say_title = "Cadoul pentru Chaegirab"
gameforge.new_quest_lv17._021_say = "Unchiul meu Chaegirab \186i-a dedicat \238ntreaga viat\227[ENTER]cu cercetarea \186i a investit fiecare Yang \238n[ENTER]cercet\227rile sale. Tot timpul a fost bun cu mine[ENTER]a\186a c\227 vreau s\227-i fac un cadou. \206mi pare r\227u, a[ENTER]ap\227rut o eroare la \238mbun\227t\227\254ire. Este vechiul[ENTER]profesor al unchiului meu \186i \238l cunoa\186te foarte[ENTER]bine."
gameforge.new_quest_lv17._030_say = "Dar nu-i spune nimic unchiului meu!"
gameforge.new_quest_lv17._031_say = "Ma vei ajuta?"
gameforge.new_quest_lv17._039_say_title = "Uriel:"
gameforge.new_quest_lv17._040_say_title = "Vorbe\186te cu Uriel"
gameforge.new_quest_lv17._040_target = "Uriel:"
gameforge.new_quest_lv17._041_say = "Vorbe\186te cu Uriel despre fostul s\227u elev[ENTER]Chaegirab."
gameforge.new_quest_lv17._042_say = "Uriel este \238n %s."
gameforge.new_quest_lv17._050_say_title = "Wonda-Rim vrea s\227-i fac\227 un cadou lui Chaegirab[ENTER]..."
gameforge.new_quest_lv17._051_say = "Este foarte simplu, pl\227cerea unui om de \186tiin\254\227[ENTER]\238n via\254a vine de la cercet\227ri. Cel mai bun mod de[ENTER]a-l face fericit pe Chaegirab este de a-l sus\254ine[ENTER]\238n cercet\227rile sale. Lupul Mu-Rang vine rar pe[ENTER]aceste p\227m\238nturi iar blana sa se g\227se\186te foarte[ENTER]rar. Cinci buc\227\254i de blan\227 cred c\227 ar fi de[ENTER]ajuns. Po\254i s\227-i spui asta lui Wonda-Rim."
gameforge.new_quest_lv17._052_say = "Sunt sigur c\227 aceast\227 blan\227 \238l va impresiona."
gameforge.new_quest_lv17._060_select = "Da, il voi anunta."
gameforge.new_quest_lv17._065_say_title = "\206napoi la Wonda-Rim"
gameforge.new_quest_lv17._066_say = "Uriel s-a g\238ndit la un cadou m\227re\254 pentru[ENTER]Chaegirab. Acum \238ntoarce-te la Wonda-Rim \186i[ENTER]spune-i."
gameforge.new_quest_lv17._067_say = "Wonda-Rim este \238n %s."
gameforge.new_quest_lv17._070_say = "Sugestia lui Uriel este bun\227. Av\238nd in vedere c\227[ENTER]vreau s\227 fie o surpriz\227 trebuie sa pun mana pe[ENTER]blan\227. M\227 po\254i ajuta ucig\238nd 5 lupi Mu-Rang?"
gameforge.new_quest_lv17._071_say = "Trebuie sa ucid Lupii Mu-Rang pentru a pune mana[ENTER]pe blan\227."
gameforge.new_quest_lv17._072_say = "Cinci sunt destui."
gameforge.new_quest_lv17._073_say = "S\227 mergem!"
gameforge.new_quest_lv17._074_notice = "Ai jefuit blan\227 de calitate."
gameforge.new_quest_lv17._075_say = "V\238neaz\227 lupii Mu-Rang pentru blana lor."
gameforge.new_quest_lv17._076_say_reward = "P\238n\227 acum ai str\238ns %s din cele 5 bl\227nuri."
gameforge.new_quest_lv17._081_say_title = "Blana pentru Wonda-Rim"
gameforge.new_quest_lv17._082_say = "Ai jefuit destul\227 blan\227, acum du-o lui Wonda-Rim."
gameforge.new_quest_lv17._092_say_reward = "Ai str\238ns deja %s buc\227\254i de blan\227 de lup."
gameforge.new_quest_lv17._110_say = "Aceasta este chiar blan\227 de calitate, mul\254umesc.[ENTER]Po\254i s-o duci unchiului meu?"
gameforge.new_quest_lv17._120_target = "Unchiul Chaegirab"
gameforge.new_quest_lv17._121_say = "Wonda-Rim te roag\227 s\227 duci blana lui Chaegirab."
gameforge.new_quest_lv17._122_say = "Chaegirab este \238n %s."
gameforge.new_quest_lv17._130_say = "Aha, deci ce are de g\238nd s\227 fac\227?"
gameforge.new_quest_lv17._131_say = "De la cine este blana? Este de la Wonda-Rim, dar[ENTER]ai omor\238t lupii pentru el?[ENTER]Este jenant s\227 am un nepot care ii face pe al\254ii[ENTER]s\227 lucreze pentru el. Asa c\227 \238mi pare r\227u, nu pot[ENTER]accepta blana."
gameforge.new_quest_lv17._132_say_reward = "Spune-i lui Wonda-Rim c\227 dac\227 vrea cu adev\227rat[ENTER]s\227-mi fac\227 cadou s\227 mearg\227 s\227 v\238neze chiar el."
gameforge.new_quest_lv17._140_say = "Chaegirab nu a acceptat blana \186i este \186i sup\227rat[ENTER]pe Wonda-Rim pentru ca este lene\186. Chaegirab te-a[ENTER]trimis \238napoi la Wonda-Rim."
gameforge.new_quest_lv17._141_say = "Ce a zis unchiul meu? Sper c\227 i-a pl\227cut cadoul!?"
gameforge.new_quest_lv17._142_1_select = "Da, a fost incantat."
gameforge.new_quest_lv17._142_2_select = "Nu, chiar deloc."
gameforge.new_quest_lv17._143_say = "Minunat, \238mi place sa le fac bucurii celorlal\254i.[ENTER]\170i bine\238n\254eles \238\254i voi da o recompens\227 pe m\227sur\227.[ENTER]Poftim, ia asta!"
gameforge.new_quest_lv17._144_say_reward_a = "Ai primit 20000 puncte de experien\254\227.[ENTER]Ai primit 20000 Yang.[ENTER]Ai primit un Nod de aur."
gameforge.new_quest_lv17._144_say_reward_b = "Ai min\254it pe Wonda-Rim asa c\227 ai pierdut puncte[ENTER]de bine/r\227u."
gameforge.new_quest_lv17._145_say = "Nu a acceptat blana? Poate nu a fost o idee bun\227[ENTER]s\227 te trimit pe tine la v\238n\227toare. Data viitoare[ENTER]voi \238ncerca altcumva."
gameforge.new_quest_lv17._146_say_reward = "Dar nu vreau ca toat\227 munca ta s\227 fie \238n zadar:[ENTER]mergi la Yang-Shin. El \238\254i va cump\227ra blana la un[ENTER]pre\254 bun."
gameforge.new_quest_lv17._147_say = "Ce \238ntoarcere nea\186teptat\227 de situa\254ie. Cel pu\254in[ENTER]ai r\227mas cu blana. Mergi la v\238n\227torul Yang-Shin[ENTER]din \254inutul Yayang pentru a-i vinde blana."
gameforge.new_quest_lv17._148_say = "Ce \238ntoarcere nea\186teptat\227 de situa\254ie. M\227car ai[ENTER]r\227mas cu blana. Mergi la v\238n\227torul Yang-Shin \238n[ENTER]\254inutul Bokjung pentru a-i vinde blana."
gameforge.new_quest_lv17._149_say = "Ce \238ntoarcere nea\186teptat\227 de situa\254ie. M\227car ai[ENTER]r\227mas cu blana. Mergi la v\238n\227torul Yang-Shin \238n[ENTER]\254inutul Bakra pentru a-i vinde blana."
gameforge.new_quest_lv17._151_say = "Blana Mu-Rang? \206mi cade bine. \206mi voi face din ea[ENTER]ni\186te perechi de lenjerie. Poftim Yang pentru[ENTER]efortul t\227u. Oh, am g\227sit aceast\227 carte ieri,[ENTER]poate ii g\227se\186ti tu o \238ntrebuin\254are."
gameforge.new_quest_lv17._152_say_reward = "Ai primit 40000 puncte de experien\254\227.[ENTER]Ai primit 10000 Yang.[ENTER]Ai primit o Carte de Skilluri."
