gameforge.new_quest_lv17._161_say_title = "Yang-Shin :"
gameforge.new_quest_lv22 = {}
gameforge.new_quest_lv22._010_target = "Gardian:"
gameforge.new_quest_lv22._011_say = "Gardianul are o misiune pentru tine, mergi \186i[ENTER]vezi despre ce e vorba."
gameforge.new_quest_lv22._015_npcChat = "Fratele bolnav"
gameforge.new_quest_lv22._016_send_letter = "Gardian bolnav"
gameforge.new_quest_lv22._017_say_title = "Gardian:"
gameforge.new_quest_lv22._018_say_title = "Baek-Go :"
gameforge.new_quest_lv22._019_say_title = "Gardian Turnul Demonilor"
gameforge.new_quest_lv22._021_say = "Sunt \238ngrijorat \238n leg\227tur\227 cu fratele meu,[ENTER]Gardianul de la Turnul Demonilor. In ultimul timp[ENTER]nu s-a sim\254it bine iar acum este bolnav. Are[ENTER]dureri mari de cap \186i m\238nc\227rimi de piele dar nu[ENTER]poate sa-\186i p\227r\227seasc\227 locul. Po\254i face rost de[ENTER]tratament pentru el de la Baek-Go?"
gameforge.new_quest_lv22._022_say = "Voi merge chiar eu, dar Turnul Demonilor este \238n[ENTER]Templul Hwang chiar \238n centrul V\227ii Seungryong.[ENTER]\170i tot locul mi\186un\227 de creaturi s\227lbatice ..."
gameforge.new_quest_lv22._023_say = "Ai revenit. Ai uitat care sunt simptomele? Ar[ENTER]trebui s\227 ascul\254i atunci c\226nd cineva vorbe\186te cu[ENTER]tine... Fratele meu are dureri de cap \186i irita\254ie[ENTER]de piele. Acum du-te \186i spune-i lui Baek-Go!"
gameforge.new_quest_lv22._024_select = "Ajuta fratele"
gameforge.new_quest_lv22._025_say_title = "Tratamentul lui Baek-Go"
gameforge.new_quest_lv22._026_say = "Vorbe\186te cu Baek-Go despre tratamentul pentru[ENTER]Gardianul de la Turnul Demonilor."
gameforge.new_quest_lv22._027_say = "Baek-Go este \238n %s."
gameforge.new_quest_lv22._030_target = "Baek-Go :"
gameforge.new_quest_lv22._031_say = "A\186adar ai nevoie de tratament? Trebuie s\227-mi zici[ENTER]care sunt simptomele mai \238nt\238i."
gameforge.new_quest_lv22._032_1_select = "Dureri de cap si eruptii cutanate"
gameforge.new_quest_lv22._032_2_select = "Dureri de gat si crampe"
gameforge.new_quest_lv22._032_3_select = "Nu stiu."
gameforge.new_quest_lv22._035_say = "Arat\227 ca ni\186te zg\226rieturi de demoni. Acest lucru[ENTER]apare atunci c\226nd prea multe c\227pu\186e mi\186un\227 \238n[ENTER]jur. Pot produce ceva care \238l poate ajuta. \206nsa[ENTER]trebuie s\227 faci rost de ni\186te ingrediente."
gameforge.new_quest_lv22._040_say = "Am nevoie de:"
gameforge.new_quest_lv22._041_say_reward = "Trebuie sa v\226nezi:"
gameforge.new_quest_lv22._042_say = "Mai am nevoie de:"
gameforge.new_quest_lv22._043_say = "Nu am auzit de a\186a boal\227. E\186ti sigur ca Gardianul[ENTER]\254i-a zis corect simptomele? \206n locul t\227u l-a\186[ENTER]\238ntreba din nou."
gameforge.new_quest_lv22._044_say = "Nu pot da diagnosticul f\227r\227 a \186tii care sunt[ENTER]simptomele. Du-te \186i \238ntreab\227 din nou."
gameforge.new_quest_lv22._050_set_title = "Tratament"
gameforge.new_quest_lv22._056_notice = "Perfect, acum \238mi mai lipse\186te doar %s[ENTER]m\227nunchiuri de plante medicinale."
gameforge.new_quest_lv22._057_notice = "Cam astea sunt ierburile de care am nevoie. Acum[ENTER]mergi repede la Baek-Go."
gameforge.new_quest_lv22._058_notice = "Bine, acum mai sunt doar %s bucati de ficat."
gameforge.new_quest_lv22._060_notice = "Ah, pu\254in ficat. Acum mai am nevoie de %s."
gameforge.new_quest_lv22._061_notice = "Cam de at\226t ficat am nevoie. Acum mergi repede la[ENTER]Baek-Go."
gameforge.new_quest_lv22._062_notice = "Din p\227cate acest ficat nu-mi este folositor."
gameforge.new_quest_lv22._063_say = "Mai ai nevoie de inca %s x Ierburi Medicinale+."
gameforge.new_quest_lv22._064_say = "Mai ai nevoie de %s x Ficat Tigru+."
gameforge.new_quest_lv22._065_say = "Acum ai toate ingredientele pentru tratament.[ENTER]Du-le lui Baek-Go."
gameforge.new_quest_lv22._066_say = "Colecteaza ingredientele pentru tratamentul lui[ENTER]Baek-Go."
gameforge.new_quest_lv22._070_say = "Mul\254umesc, acum pot produce tratamentul \238mpotriva[ENTER]zg\238rieturilor de demon."
gameforge.new_quest_lv22._071_say = "Gata! Poftim tratamentul. \206ns\227 nu uita c\227[ENTER]tratamentul nu tine mult - asa c\227 trebuie sa-l[ENTER]duci pacientului t\227u \238n urm\227toarele %s minute."
gameforge.new_quest_lv22._072_say = "Po\254i g\227si pe fratele gardianului \238n centrul[ENTER]Templului Hwang. Dar s\227 fi atent \238n timp ce te[ENTER]\238ndrep\254i acolo pentru c\227 Valea Seungryong este[ENTER]plin\227 de creaturi s\227lbatice."
gameforge.new_quest_lv22._073_say = "Nu este de ajuns. Ai pierdut cumva din[ENTER]ingrediente? Nu pot face nimic f\227r\227 restul[ENTER]ingredientelor."
gameforge.new_quest_lv22._080_target = "Gardian Turnul Demonilor"
gameforge.new_quest_lv22._082_set_clock = "Timp r\227mas"
gameforge.new_quest_lv22._083_say = "Mai ai destul timp \238ns\227 te po\254i gr\227bi. Asa c\227[ENTER]gr\227be\186te-te c\227tre Paznic \238n Seungryong \238nainte ca[ENTER]tratamentul s\227 treac\227."
gameforge.new_quest_lv22._084_say = "Timpul a trecut din cauz\227 c\227 te-ai mi\186cat prea[ENTER]\238ncet. \206ns\227 po\254i duce tratamentul Panicului[ENTER]Turnului Demonilor, s-ar putea s\227 fie \238nc\227[ENTER]folositor."
gameforge.new_quest_lv22._085_say = "Mul\254umesc c\227 ai adus tratamentul. M\238nc\227rimea asta[ENTER]m\227 omoar\227."
gameforge.new_quest_lv22._086_say = "Oh, acest tratament este folositor. Deja simt cum[ENTER]m\238nc\227rimea dispare."
gameforge.new_quest_lv22._087_say = "Ai primit o recompens\227 pe m\227sur\227 pentru asta."
gameforge.new_quest_lv22._088_say_reward = "Ai primit 50,000 puncte de experien\254\227.[ENTER]Ai primit 12,000 Yang.[ENTER]Ai primit Pantofi de Aur +4.[ENTER]Ai primit 5 Po\254iuni Mov."
gameforge.new_quest_lv22._089_say = "Oh, nu este bun deloc. Tratamentul a expirat -[ENTER]c\238t \254i-a luat sa ajungi aici?"
gameforge.new_quest_lv22._090_say = "Hmm, a\186teapt\227 o secund\227 ... se pare c\227 este mai[ENTER]bine. Da, func\254ioneaz\227! \206n acest caz nu voi fi[ENTER]r\227u. Vei primi pana la urma recompensa. \206ntuneric"
gameforge.new_quest_lv22._091_say = "Se pare c\227 ai pierdut tratamentul. Mergi din nou[ENTER]\186i v\238neaz\227 pentru alte ingrediente necesare lui[ENTER]Baek-Go.\206n cur\238nd voi deveni chiar eu un demon[ENTER]dac\227 nu scap de aceste m\238nc\227rimi."
gameforge.new_quest_lv22._095_say_reward = "Ai primit 50000 puncte de experien\254\227.[ENTER]Ai primit 8000 Yang."
gameforge.new_quest_lv22._098_say = "Iar ai pierdut medicamentele? Niciodat\227 nu am dat[ENTER]peste o persoan\227 a\186a z\227p\227cit\227 \238n via\254a mea! Ei[ENTER]bine, nu putem face nimic \238n privin\254a asta."
gameforge.new_quest_lv22._100_say_reward = "Ai primit 25.000 puncte de experienta."
