gameforge.new_quest_lv26._021_say = "Yang-Shin are probleme \238n a g\227si un loc bun de[ENTER]v\238n\227toare. Mergi la el \186i vezi cu ce-l po\254i[ENTER]ajuta."
gameforge.new_quest_lv26._025_say = "Nimic nu mai e la fel de c\226nd au \238nceput s\227 cad\227[ENTER]Pietrele Metin. Chiar \186i v\226natul a devenit[ENTER]imposibil pentru c\227 animalele au \238nceput s\227 se[ENTER]poarte ciudat. Sunt sigur c\227 hoinarul Nakajima[ENTER]locuie\186te pe undeva pe acolo \186i \186tie locuri bune[ENTER]pentru v\226nat. \206l po\254i g\227si \186i \238ntreba?"
gameforge.new_quest_lv26._030_target = "Nakajima:"
gameforge.new_quest_lv26._031_say = "A\186adar vrei s\227 \186tii un loc bun pentru v\238nat? Nu[ENTER]te gr\227bi, dac\227 eu te pot ajuta atunci tu trebuie[ENTER]s\227-mi faci un favor."
gameforge.new_quest_lv26._032_say = "Ar trebui s\227 \186tii ... nu locuiesc aici \238n[ENTER]s\227lb\227ticie c\227 a\186a vreau eu. Sunt nevoit s\227 m\227[ENTER]ascund de ferocitatea armatei. A\186 vrea sa \186tiu c\227[ENTER]draga mea so\254ie Ah-Yu este anun\254at\227 c\227 sunt \238nc\227[ENTER]\238n via\254a. O po\254i anun\254a? Dar nu uita, mesajul[ENTER]este doar pentru Ah-Yu! \206n schimb ea \238\254i va zice[ENTER]unde ne-am s\227rutat prima data - a\186 vrea s\227 m\227[ENTER]\238nt\238lnesc cu ea acolo iar acel loc este un loc[ENTER]bun de v\238nat."
gameforge.new_quest_lv26._034_say_title = "Nakajima:"
gameforge.new_quest_lv26._035_say_title = "Ah-Yu:"
gameforge.new_quest_lv26._036_say_title = "Caut\227-l pe Nakajima"
gameforge.new_quest_lv26._037_say = "Nakajima ar trebui s\227 \186tie locuri bune pentru[ENTER]v\238nat. C\227uta-l."
gameforge.new_quest_lv26._038_say = "Nakajima este \238n %s."
gameforge.new_quest_lv26._040_say = "Tu e\186ti Nakajima? Yang-Shin m-a trimis! El caut\227[ENTER]ni\186te locuri bune pentru v\238nat, poate ai idee[ENTER]unde pot g\227si aceste locuri?!"
gameforge.new_quest_lv26._050_target = "Ah-Yu:"
gameforge.new_quest_lv26._051_say = "Nakajima este un dezertor \186i acum trebuie s\227 se[ENTER]ascund\227 de armat\227. \170otia sa, Ah-Yu, crede c\227 a[ENTER]pierit \238n r\227zboi. Anun\254-o c\227 Nakajima este \238n[ENTER]via\254\227."
gameforge.new_quest_lv26._052_say = "Ah-Yu este \238n %s."
gameforge.new_quest_lv26._057_say = "Nakajima ... tr\227ie\186te? Iubitul meu so\254 tr\227ie\186te?[ENTER]Nici nu \186tiu cum s\227-\254i mul\254umesc pentru veste.[ENTER]Voi merge de \238ndat\227 \238n Valea Yonjang pentru a m\227[ENTER]\238nt\238lni cu el."
gameforge.new_quest_lv26._058_say = "Mul\254umesc pentru c\227 ai f\227cut posibila aceast\227[ENTER]re\238nt\226lnire. Ia acest Trandafir cu tine, poate \238l[ENTER]d\227ruie\186ti cuiva drag? \170i acum... te rog scuz\227-m\227,[ENTER]dar trebuie s\227 m\227 gr\227besc!"
gameforge.new_quest_lv26._061_say = "Valea Yonjang - locul unde Nakajima \186i Ah-Yu s-au[ENTER]s\227rutat pentru prima data - \238nc\227 este un loc bun[ENTER]de v\238nat."
gameforge.new_quest_lv26._062_say = "Yang-Shin va fi \238nc\226ntat c\226nd va auzi asta. Mergi[ENTER]la %s \186i spune-i vestea cea bun\227."
gameforge.new_quest_lv26._063_say = "Valea Yonjang? Sun\227 promi\254\227tor, mai ales c\227 n-am[ENTER]auzit ca vreo piatr\227 Metin s\227 fi c\227zut acolo.[ENTER]Probabil voi putea vana acolo cum trebuie.[ENTER]Poftim, meri\254i aceast\227 recompens\227."
gameforge.new_quest_lv26._064_sayReward = "Ai primit 35000 puncte de experien\254\227."
gameforge.new_quest_lv26._065_sayReward = "Ai primit 17500 Yang."
gameforge.new_quest_lv28 = {}
gameforge.new_quest_lv28._010_target = "Yu-Hwan: "
gameforge.new_quest_lv28._011_say = "Yu-Hwan, muzicianul, are nevoie de ajutorul t\227u.[ENTER]Mergi \186i vezi cu ce-l po\254i ajuta."
gameforge.new_quest_lv28._015_npcChat = "Grijile lui Ah-Yu"
gameforge.new_quest_lv28._016_say = "Ah-Yu are ceva \238n minte \186i nu vrea s\227 afle[ENTER]Yu-Hwan. Mergi la ea \186i vezi dac\227 \238\254i va zice[ENTER]\254ie."
gameforge.new_quest_lv28._017_say = "Ah-Yu este \238n %s."
gameforge.new_quest_lv28._018_select = "Voi vorbi cu Ah-Yu in curand!"
gameforge.new_quest_lv28._019_say_title = "Ah-Yu:"
gameforge.new_quest_lv28._020_say_title = "Yu-Hwan: "
gameforge.new_quest_lv28._021_say = "O cuno\186ti pe Ah-Yu cea care str\238nge ierburi[ENTER]medicinale pentru po\254iunile mele? P\238n\227 ieri era[ENTER]\238n toane bune, dar de ieri ceva s-a \238nt\238mplat cu[ENTER]ea \186i nu vrea s\227-mi zic\227 ce s-a \238nt\238mplat. Te rog[ENTER]s\227 mergi la ea \186i afl\227 ce se \238nt\238mpl\227. Poate \238\254i[ENTER]va zice \254ie."
gameforge.new_quest_lv28._022_say = "Este dragu\254 din partea lui Yu-Hwan c\227-\186i face[ENTER]griji pentru mine. \170i da, ceva s-a \238nt\226mplat...[ENTER]Dar nu vreau s\227 vorbesc despre asta, \238nsa mi-a[ENTER]dat de furc\227 toat\227 treaba asta! Este vorba despre[ENTER]Yang-Shin, v\226n\227torul.[ENTER]De c\226nd a aflat ca so\254ul meu, Nakajima, este[ENTER]dezertor m\227 \186antajeaz\227 \238ntruna.[ENTER]Yang-Shin \238mi spune c\227-l va g\227si pe so\254ul meu![ENTER]\170i-l va ucide..."
gameforge.new_quest_lv28._023_say = "De data asta cere o Lab\227 de Urs pentru t\227cerea[ENTER]lui \238nsa nu pot merge la v\238n\227toare eu. Ma po\254i[ENTER]ajuta?"
gameforge.new_quest_lv28._024_set_title = "V\238n\227toarea de ur\186i"
gameforge.new_quest_lv28._025_notice = "S\227 mergem la v\238n\227toare! Pentru a ob\254ine Lab\227 de[ENTER]Urs cel mai bine e s\227 omori Bera."
gameforge.new_quest_lv28._026_notice = "Am jefuit o Lab\227 de Urs."
gameforge.new_quest_lv28._027_notice = "Ar trebui s\227 ajung\227. Acum \238napoi la Yang-Shin!"
gameforge.new_quest_lv28._028_notice = "Aceast\227 Lab\227 de Urs este nefolositoare."
gameforge.new_quest_lv28._029_say = "Mai ai nevoie de \238nc\227 %s x Labe de Urs."
gameforge.new_quest_lv28._031_say_reward = "Trebuie sa v\226nezi:"
gameforge.new_quest_lv28._032_say = "Ah-Yu te-a rugat s\227 duci la bun sf\238r\186it cerin\254a[ENTER]lui Yang-Shin."
gameforge.new_quest_lv28._032_say_reward = "Mai ai nevoie de %s x Labe de Urs. V\238neaz\227 Bera[ENTER]pentru a le procura."
gameforge.new_quest_lv28._035_target = "Yang-Shin :"
gameforge.new_quest_lv28._036_say = "Ai procurat Labele de Urs necesare. Du-le la[ENTER]Yang-Shin pentru a pl\227ti datoria lui Ah-Yu."
gameforge.new_quest_lv28._037_say = "Yang-Shin este in %s."
gameforge.new_quest_lv28._038_say_title = "Yang-Shin :"
gameforge.new_quest_lv28._040_npcChat = "\170antajul"
gameforge.new_quest_lv28._041_say_title = "Labe de Urs"
gameforge.new_quest_lv28._042_say = "Mi-ai adus Labe de Urs? Te rog nu m\227 judeca[ENTER]gre\186it! Tr\227im \238n vremuri grele acum c\227 v\226n\227toarea[ENTER]a devenit foarte grea de c\226nd pietrele Metin au[ENTER]transformat animalele \238n bestii feroce. Via\254a de[ENTER]v\226n\227tor n-a fost a\186a de grea p\226n\227 acum."
gameforge.new_quest_lv28._043_say = "Te rog spune-i lui Ah-Yu c\227 nu are de ce s\227 se[ENTER]\238ngrijoreze. Poate s\227 fie sigur\227 de lucrul asta.[ENTER]Cel pu\254in pan\227 voi avea nevoie de altceva ...[ENTER]hehehe!"
gameforge.new_quest_lv28._044_say = "Poftim? Ai vrut s\227 ma tragi \238n piept? Voiam Labe[ENTER]de Urs proaspete!"
gameforge.new_quest_lv28._045_say_reward = "Frumos din partea ta c\227 o ajuti pe Ah-Yu. Iar[ENTER]asta \238nseamn\227 c\227 trebuie sa faci ce zic eu. Acum[ENTER]du-te \186i v\226neaz\227 \186i te \238ntorci c\226nd ai dou\227 Labe[ENTER]de Urs!"
gameforge.new_quest_lv28._046_say = "D\227-i vestea lui Ah-Yu c\227 Yang-Shin va \238nceta s-o[ENTER]mai \186antajeze."
gameforge.new_quest_lv28._051_say = "E\186ti salvatorul nostru, \238\254i sunt recunosc\227toare.[ENTER]Poftim, ia tot Yangul meu. Nu este mult dar \238l[ENTER]meri\254i."
gameforge.new_quest_lv28._055_1_select = "Multumesc, imi va fi de folos."
gameforge.new_quest_lv28._055_2_select = "Nu, nu pot accepta asta."
gameforge.new_quest_lv28._056_say = "Asta este tot ce am. Dar ar merita dac\227 as putea[ENTER]scap\227 de acest barbar."
gameforge.new_quest_lv28._057_say = "Mul\254umesc! Locul t\227u l\238ng\227 Zeul Dragon este[ENTER]asigurat."
gameforge.new_quest_lv28._058_say_reward = "Ai primit %s Yang."
gameforge.new_quest_lv28._059_say_reward = "Ai primit %s puncte de experien\254\227."
gameforge.new_quest_lv28._070_say = "Am nevoie de:"
