gameforge.new_quest_lv29._010_target = "Yonah:"
gameforge.new_quest_lv29._015_npcChat = "Portelanul spart"
gameforge.new_quest_lv29._020_say_title = "Yonah:"
gameforge.new_quest_lv29._021_say = "Frumosul meu Por\254elan Celadon! Este \238n familia[ENTER]mea de trei genera\254ii iar acum trei din cele mai[ENTER]pre\254ioase vaze sunt sparte. Am v\227zut c\227 Taurean[ENTER]se \238nv\238rtea \238n jurul magaziei, el trebuie sa fie[ENTER]cel vinovat."
gameforge.new_quest_lv29._022_say = "Nu ar fi primul, dar deja s-a dep\227\186it limita.[ENTER]Cineva trebuie s\227-i bage min\254ile \238n cap! Ai timp[ENTER]pentru asta?"
gameforge.new_quest_lv29._023_1_select = "Cu pl\227cere"
gameforge.new_quest_lv29._023_2_select = "Nu este treaba mea"
gameforge.new_quest_lv29._024_say = "Nu am timp s\227 educ copii a\186a c\227 trebuie s\227-l[ENTER]educi chiar tu. Oricum, am \238ndoiala ca vei reuzi[ENTER]..."
gameforge.new_quest_lv29._030_target = "Taurean :"
gameforge.new_quest_lv29._031_say = "Pre\254ioasa ma\186in\227 de \254esut a familiei lui Yonah \186i[ENTER]cele trei vaze pre\254ioase din por\254elan sunt acum[ENTER]sparte. El crede ca Taurean este de vina. Mergi[ENTER]la Taurean \186i afl\227 dac\227 e a\186a."
gameforge.new_quest_lv29._032_say = "Taurean este \238n %s."
gameforge.new_quest_lv29._033_say_title = "Taurean :"
gameforge.new_quest_lv29._034_say_reward = "De ce te ui\254i a\186a la mine? Nu am f\227cut nimic ..."
gameforge.new_quest_lv29._035_say_reward = "Ce ai f\227cut cu vazele lui Yonah?"
gameforge.new_quest_lv29._036_say_reward = "Vaze? Yonah? Nu \186tiu despre ce vorbe\186ti!"
gameforge.new_quest_lv29._037_say_reward = "Atunci \238mi po\254i explica de ce trei dintre vaze[ENTER]sunt sparte?"
gameforge.new_quest_lv29._038_say_reward = "\206\254i jur c\227 nu m-am apropiat de nicio vaz\227 \186i nici[ENTER]m\227car pe Yonah nu l-am v\227zut. \206n schimb am[ENTER]petrecut toat\227 ziua lupt\226ndu-m\227 cu Harang. M-a[ENTER]\238nchis \186i \238n hambar pentru o vreme! Mergi \186i[ENTER]\238ntreab-o dac\227 nu m\227 crezi!"
gameforge.new_quest_lv29._040_target = "Harang:"
gameforge.new_quest_lv29._041_say = "Taurean pretinde c\227 este nevinovat. S-a jucat[ENTER]toat\227 ziua cu Harang \186i nu avea cum s\227 sparg\227[ENTER]vazele. Mergi la Harang \186i \238ntreab-o dac\227 e a\186a."
gameforge.new_quest_lv29._042_say_reward = "Harang l-ai v\227zut recent pe Taurean?"
gameforge.new_quest_lv29._043_say_title = "Harang:"
gameforge.new_quest_lv29._044_say_reward = "Taurean? Da, ne-am jucat toat\227 ziua. S-a[ENTER]\238nt\238mplat ceva?"
gameforge.new_quest_lv29._045_say_reward = "Yonah spune ca Taurean a spart trei dintre vazele[ENTER]lui."
gameforge.new_quest_lv29._046_say_reward = "Yonah este r\227u. De fiecare dat\227 c\226nd ne apropiem[ENTER]de el, ne gone\186te pe mine \186i pe Taurean.[ENTER]\206ntotdeauna este prea grijuliu cu por\254elanul s\227u.[ENTER]Singurul care se poate apropia de vazele lui[ENTER]pre\254ioase este Gr\227jdarul. Poate le-a spart el!?"
gameforge.new_quest_lv29._047_say = "Harang este \238n %s."
gameforge.new_quest_lv29._050_target = "Gr\227jdar;"
gameforge.new_quest_lv29._051_say = "Harang sus\254ine c\227 Taurean este nevinovat. \206ns\227[ENTER]s-ar putea ca altcineva s\227 fi spart vazele. Ar[ENTER]trebui s\227-l \238ntrebi pe prietenul lui Yonah,[ENTER]Gr\227jdarul."
gameforge.new_quest_lv29._052_say = "Oh, b\227tr\226nul Yonah. At\226t de \238ngrijorat este de[ENTER]por\254elanul s\227u \238nc\226t d\227 vina pe copiii satului.[ENTER]Nu-\186i d\227 seama c\227 pietrele Metin sunt de vin\227 -[ENTER]de c\226nd au \238nceput s\227 cad\227 pe p\227m\226nturile[ENTER]noastre, resursele nu mai sunt ce erau \238nainte.[ENTER]Inclusiv por\254elanul a \238nceput s\227 se strice. \206ns\227[ENTER]Yonah refuz\227 s\227 cread\227 asta..."
gameforge.new_quest_lv29._053_say = "Sunt sigur c\227 pentru a-l \238mpac\227 trebuie s\227[ENTER]str\238ngi pentru el ni\186te f\238n."
gameforge.new_quest_lv29._054_say = "Gr\227jdarul este \238n[ENTER]%s sau %s."
gameforge.new_quest_lv29._061_say = "Nu-l po\254i \238nvinov\227\254i pe Taurean pentru[ENTER]stric\227ciunile f\227cute lui Yonah. Efectele[ENTER]secundare ale pietrelor Metin sunt de vin\227.[ENTER]Str\238nge f\238n pentru Yonah pentru a avea grij\227 mai[ENTER]mare de por\254elanul s\227u. Sunt sigur c\227 unii din[ENTER]s\227teni te poate ajuta."
gameforge.new_quest_lv29._062_say = "Po\254i g\227si %s \186i %s \238n fata por\254ilor satului. Sunt[ENTER]sigur ca po\254i str\238nge destul fan din p\227l\227riile de[ENTER]paie pe care le poarta."
gameforge.new_quest_lv29._063_notice = "Voi face o frumoas\227 leg\227tur\227 de fan din asta.[ENTER]Acum mai am nevoie doar de %s."
gameforge.new_quest_lv29._064_notice = "Aceasta p\227l\227rie nu este f\227cut\227 din paie ci din[ENTER]fibre de nuc\227 de cocos. Nu \238mi este folositoare."
gameforge.new_quest_lv29._065_1_say = "V\227d c\227 ai la tine mult f\238n, sunt sigur c\227 Yonah[ENTER]se va calma dac\227 ii dai \186i lui."
gameforge.new_quest_lv29._065_notice = "Aceast\227 p\227l\227rie nu este f\227cut\227 din paie ci din[ENTER]fibre de nuc\227 de cocos. Si mai este \186i \238ntr-o[ENTER]stare jalnic\227 ..."
gameforge.new_quest_lv29._066_say = "Po\254i sa v\238nezi \186i Infanterist S\227lbatic sau[ENTER]Infanterist S\227lbatic Dur pentru a procura fan din[ENTER]p\227l\227riile lor de paie."
gameforge.new_quest_lv29._067_say_reward = "Ai str\238ns %s din %s m\227nunchiuri de f\238n."
gameforge.new_quest_lv29._068_notice = "Ai furat un m\227nunchi de f\238n."
gameforge.new_quest_lv29._070_npcChat = "Capita de fan"
gameforge.new_quest_lv29._071_say_reward = "Taurean, ai spus c\227 ai fost pe l\238ng\227 c\227pi\254a de[ENTER]f\238n recent. Ai luat cumva f\238n cu tine?"
gameforge.new_quest_lv29._072_say_reward = "Sa vedem ... totul a fost b\227gat \238n p\227rul meu \186i[ENTER]pantofi. Po\254i vedea? Poftim ceva mai mult, ia-l."
gameforge.new_quest_lv29._073_notice = "Nu este mult f\238n dar este destul pentru a face o[ENTER]mic\227 leg\227tur\227 cu el. Acum \238mi mai lipse\186te %s."
gameforge.new_quest_lv29._074_say_reward = "Nu a fost eu, jur! Nu \254i-a zis Harang c\227 am avut[ENTER]o alterca\254ie l\238ng\227 c\227pi\254a de fan?"
gameforge.new_quest_lv29._075_say_reward = "Ai fost la c\227pi\254a de f\238n mai devreme, nu? Ai luat[ENTER]cumva f\238n de acolo?"
gameforge.new_quest_lv29._076_say_reward = "De unde \186tii despre c\227pi\254a? Poftim, \238nc\227 am f\238n[ENTER]\238n haine? Oh da, uite aici."
gameforge.new_quest_lv29._077_say_reward = "Pot avea asta?"
gameforge.new_quest_lv29._078_say_reward = "Presupun c\227 ..."
gameforge.new_quest_lv29._079_say_reward = "Nu am timp acum. Trebuie s\227-l calmez pe Taurean[ENTER]\238n leg\227tur\227 cu toat\227 treaba cu vazele."
gameforge.new_quest_lv29._080_npcChat = "F\226n pentru Yonah"
gameforge.new_quest_lv29._081_say_reward = "Mai este f\226n \238n grajd care ar trebui dus lui[ENTER]Yonah?"
gameforge.new_quest_lv29._082_say_title = "Gr\227jdar;"
gameforge.new_quest_lv29._083_say_reward = "Nu mai avem mult f\238n. Animalele s\227lbatice \186i[ENTER]bandi\254ii din afara satului ne-au prevenit sa nu[ENTER]mai t\227iem f\238n."
gameforge.new_quest_lv29._084_say_reward = "Dar \238\254i pot da pu\254in!"
gameforge.new_quest_lv29._085_notice = "Nu este mult, dar pentru o leg\227tur\227 ajunge. Acum[ENTER]\238mi mai lipsesc \238nc\227 %s."
gameforge.new_quest_lv29._086_say_reward = "\206mi pare r\227u dar nu mai pot face nimic pentru[ENTER]tine."
gameforge.new_quest_lv29._090_send_letter = "F\226n \238n loc de lovituri"
gameforge.new_quest_lv29._091_say = "Ai str\238ns destul f\226n pentru Yonah. Du-l \238n %s."
gameforge.new_quest_lv29._101_say_reward = "Nu este vina lui Taurean ci efectele secundare[ENTER]ale pietrelor Metin care au f\227cut ca por\254elanul[ENTER]s\227 fie fragil."
gameforge.new_quest_lv29._102_say_title = "Yonah:"
gameforge.new_quest_lv29._103_say_reward = "Ce ai zis? Nu are nici un sens!"
gameforge.new_quest_lv29._104_say_reward = "Taurean s-a jucat cu Harang l\238ng\227 c\227pi\254a de fan[ENTER]toat\227 ziua."
gameforge.new_quest_lv29._105_say_reward = "Prietenul t\227u, Gr\227jdarul, \238\254i trimite salutari \186i[ENTER]uite aici, \254i-am adus ni\186te fan pentru a avea mai[ENTER]mare grij\227 de vaze."
gameforge.new_quest_lv29._106_say_reward = "Recunosc, sunt pu\254in jenat de atitudinea care am[ENTER]avut-o. Dar ar trebui s\227 \186tii ca sunt ata\186at de[ENTER]acest por\254elan pentru c\227-mi treze\186te amintiri[ENTER]despre familie."
gameforge.new_quest_lv29._107_say_reward = "Trebuie s\227-mi cer scuze fat\227 de tine \186i de[ENTER]Taurean. Poftim o mic\227 recompens\227 pentru[ENTER]eforturile tale."
gameforge.new_quest_lv29._108_notice = "Ai primit un bonus de %s puncte de experien\254\227."
gameforge.new_quest_lv29._109_say_reward = "Prietenul t\227u, Gr\227jdarul, \238\254i trimite salutari \186i[ENTER]uite aici, \254i-am adus ni\186te fan pentru a avea mai[ENTER]mare grij\227 de vaze."
gameforge.new_quest_lv29._110_say_reward = "Este frumos din partea ta dar \238mi mai po\254i aduce[ENTER]\238nc\227 %s leg\227turi de f\238n pentru ca vazele s\227 fie[ENTER]\238n siguran\254\227?"
gameforge.new_quest_lv29._111_say_reward = "Se pare c\227 este din ce \238n ce mai greu s\227 g\227sesc[ENTER]fan, dar vazele sunt pre\254ioase pentru mine. Dac\227[ENTER]ai g\227si fan pentru mine \254i-as fi recunosc\227tor \186i[ENTER]\254i-as da Yang \238n schimb."
gameforge.new_quest_lv29._112_say_reward = "Acel pu\186ti Harang este prieten cu Taurean."
gameforge.new_quest_lv29._113_say_reward = "Aproape nimeni nu ma crede c\226nd zic ca l-am v\227zut[ENTER]pe pu\186ti \238n jurul depozitului."
gameforge.new_quest_lv29._114_say_reward = "Totul e ok. Poftim o mic\227 recompens\227 pentru[ENTER]eforturile tale."
gameforge.new_quest_lv29._115_say_reward = "Poftim, %s Yang."
