gameforge.new_quest_lv42._010_send_letter = "Ghior\254 ghior\254"
gameforge.new_quest_lv42._020_target = "Oktavio:"
gameforge.new_quest_lv42._021_say = "Stomacul meu c\238r\238ie ca un porc s\227lbatic. Poate ar[ENTER]trebui s\227-l vizitez pe Octavio. El face cea mai[ENTER]bun\227 tocan\227 de fructe de mare din zon\227."
gameforge.new_quest_lv42._022_say_title = "Oktavio:"
gameforge.new_quest_lv42._023_say = "Vrei ni\186te tocan\227 de fructe de mare? Oh, \238mi pare[ENTER]r\227u dar \238n buc\227t\227ria mea nu a mai fost peste[ENTER]demult. De obicei, pescarul \238mi aduce peste[ENTER]proasp\227t din ad\238ncuri pentru tocana."
gameforge.new_quest_lv42._024_say = "Nu a mai fost pe aici de zile bune. Po\254i merge la[ENTER]el \186i vezi ce s-a \238nt\238mplat?"
gameforge.new_quest_lv42._025_say = "Octavio este \238n %s."
gameforge.new_quest_lv42._026_select = "Sunt plecat sa gasesc pescarul!"
gameforge.new_quest_lv42._030_target = "Pescarul:"
gameforge.new_quest_lv42._031_say = "Zilele calme pe mare au trecut! Din ce \238n ce mai[ENTER]multi pescari dispar \238n fiecare zi, este[ENTER]groaznic! De c\226nd pietrele Metin au c\227zut \238n[ENTER]mare, lini\186titele balene de dinainte s-au[ENTER]transformat acum \238n mon\186tri marini. Pescuitul a[ENTER]devenit acum o afacere periculoas\227."
gameforge.new_quest_lv42._032_say = "Suli\254ele noastre nu mai pot str\227punge pielea[ENTER]balenelor care a devenit mai dura dec\238t cea a[ENTER]orcilor."
gameforge.new_quest_lv42._033_say = "Poate Yonah \186tie ce e de f\227cut. Obi\186nuia s\227[ENTER]mearg\227 pe mare des \186i s\227 v\226neze balene."
gameforge.new_quest_lv42._034_say_title = "Pescarul:"
gameforge.new_quest_lv42._035_say = "Octavio a\186teapt\227 dup\227 pestele proasp\227t din[ENTER]ad\238ncuri. Mergi \186i \238ntreab\227 pescarul de ce[ENTER]\238nt\238rzie livrarea."
gameforge.new_quest_lv42._036_say = "Pescarul este \238n %s."
gameforge.new_quest_lv42._037_send_letter = "Mon\186trii Furio\186i de Mare"
gameforge.new_quest_lv42._038_say = "Pescarul te roag\227 s\227-l \238ntrebi pe Yonah cum poate[ENTER]s\227 v\238neze balenele?"
gameforge.new_quest_lv42._039_say = "Yonah este \238n %s."
gameforge.new_quest_lv42._040_target = "Yonah:"
gameforge.new_quest_lv42._041_say = "Am auzit ce s-a \238nt\226mplat cu balenele. O afacere[ENTER]nepl\227cut\227 pentru pescari. Chiar dac\227 se[ENTER]aventureaz\227 \238n larg, suli\254ele lor sunt prea slabe[ENTER]pentru a trece prin pielea groas\227 a balenelor.[ENTER]C\226nd v\226nam eu balene foloseam arme speciale, arme[ENTER]care erau capabile sa str\227pung\227 pielea groas\227 a[ENTER]acestora. Erau capabile s\227 str\227pung\227 orice..."
gameforge.new_quest_lv42._042_say = "Este o tehnic\227 special\227 de a vana balene folosind[ENTER]acele arme speciale. Singurul care poate face[ENTER]aceste arme este Fierarul."
gameforge.new_quest_lv42._043_say_reward = "Mergi la fierar"
gameforge.new_quest_lv42._044_say_title = "Yonah:"
gameforge.new_quest_lv42._045_say = "Yonah recomand\227 folosirea unor suli\254e puternice[ENTER]\186i ascu\254ite. Mergi la Fierar \186i vezi dac\227 poate[ENTER]face astfel de suli\254e."
gameforge.new_quest_lv42._050_target = "Fierarul"
gameforge.new_quest_lv42._051_say = "Da, am auzit de astfel de suli\254e \186i da, le pot[ENTER]face. Dar am nevoie de o Piatr\227 diamant."
gameforge.new_quest_lv42._052_say = "Am nevoie de:"
gameforge.new_quest_lv42._053_say_reward = "Desf\227\186urare:"
gameforge.new_quest_lv42._054_say_title = "Fierarul"
gameforge.new_quest_lv42._060_set_title = "Piatr\227 diamant"
gameforge.new_quest_lv42._061_notice = "S\227 vedem. Am nevoie de un t\238rn\227cop pentru a[ENTER]sparge piatra. M\227 \238ntreb dac\227 t\238rn\227copul meu este[ENTER]pe aici pe undeva sau dac\227 Deokbae trebuie s\227-mi[ENTER]aduc\227 altul nou?"
gameforge.new_quest_lv42._062_say = "Mai ai nevoie de \238nc\227 %s x Pietre diamant."
gameforge.new_quest_lv42._063_say = "Acum ai tot de ce ai nevoie. Mergi \238napoi la[ENTER]Fierar."
gameforge.new_quest_lv42._064_say = "Perfect, acum am tot ce am nevoie. Revino m\226ine[ENTER]la aceea\186i or\227 pentru a lua suli\254ele. Acest tip[ENTER]de o\254el trebuie prelucrat cu grij\227."
gameforge.new_quest_lv42._065_say = "Po\254i procura Pietre diamant s\227p\238nd cu t\238rn\227copul[ENTER]la mina de z\227c\227m\238nt de diamante."
gameforge.new_quest_lv42._066_say = "Fierarul are nevoie de Pietre diamant pentru a[ENTER]face acele suli\254e. Mergi la Z\227c\227m\226nt de diamante[ENTER]\186i cauta acele Pietre de diamant. Dac\227 nu ai un[ENTER]t\238rn\227cop pentru a s\227pa atunci po\254i cump\227ra unul[ENTER]de la Deokbae."
gameforge.new_quest_lv42._067_say = "Fierarul este \238n %s."
gameforge.new_quest_lv42._068_say = "Mai avem nevoie de \238nc\227 %s x Pietre diamant[ENTER]\238nainte sa ne apucam sa facem suli\254ele."
gameforge.new_quest_lv42._070_set_title = "Suli\254ele"
gameforge.new_quest_lv42._071_set_clock = "Timp de a\186teptare: %s"
gameforge.new_quest_lv42._072_say = "Fierarul trebuia s\227 termine p\238n\227 acum. Mergi la[ENTER]el \186i ia suli\254ele speciale."
gameforge.new_quest_lv42._073_say = "Suli\254ele nu sunt gata \238nc\227, mai trebuie s\227[ENTER]a\186tep\254i pu\254in."
gameforge.new_quest_lv42._074_say = "Poftim suli\254ele. Du-le Pescarului."
gameforge.new_quest_lv42._075_say = "Te-am rugat s\227 a\186tep\254i pana c\226nd suli\254ele sunt[ENTER]gata. Revino mai t\226rziu."
gameforge.new_quest_lv42._079_say = "Ai primit ni\186te suli\254e de la Fierar. Du-le[ENTER]Pescarului."
gameforge.new_quest_lv42._080_say = "Minunat! Aceste suli\254e sunt \238ntr-adev\227r bune![ENTER]Acum ne putem apar\227 de atacurile balenelor.[ENTER]Anun\254\227-l pe Octavio ca v\227 avea pe\186te proasp\227t \238n[ENTER]cur\238nd."
gameforge.new_quest_lv42._081_say_reward = "Ai primit 500000 Yang."
gameforge.new_quest_lv42._082_say_reward = "Ai primit de 3x recompens\227 speciala:"
gameforge.new_quest_lv42._083_say = "Nu avem destule suli\254e pentru a alunga balenele."
gameforge.new_quest_lv42._084_say_reward = "Te rog du-te \238napoi la Fierar \186i roag\227-l s\227 mai[ENTER]fac\227 unele."
gameforge.new_quest_lv42._090_say = "Pescarii sunt bine echipa\254i acum \186i pot v\238na \238n[ENTER]largul marii din nou. Mergi la Octavio \186i[ENTER]\238ncearc\227 s\227-l convingi c\227 va primi \238n cur\238nd[ENTER]pestele proasp\227t."
gameforge.new_quest_lv42._095_say = "Ce ai zis? Balenele lini\186tite de odinioar\227 au[ENTER]devenit adev\227ra\254i mon\186trii? \206ngrozitor ...[ENTER]Mul\254umesc c\227 i-ai ajutat pe pescari. O mare parte[ENTER]din meniul meu depinde de munca lor."
gameforge.new_quest_lv42._096_say = "Oh, c\238t despre stomacul t\227u \238nfometat:[ENTER]Bine\238n\254eles c\227 \238\254i pot oferi tocana de fructe de[ENTER]mare, dar nu mai bine ai vrea sushi?"
gameforge.new_quest_lv42._098_say_reward = "Ai primit 750000 puncte de experien\254\227.[ENTER]Ai primit 2 por\254ii de Sushi."
gameforge.new_quest_lv43 = {}
gameforge.new_quest_lv43._005_send_letter = "Viziteaz\227 pe Wonda-Rim"
gameforge.new_quest_lv43._006_send_letter = "Orfanul"
gameforge.new_quest_lv43._010_target = "Wonda-Rim:"
gameforge.new_quest_lv43._011_say = "N-ai mai auzit nimic de Wonda-Rim. Rela\254ia cu[ENTER]unchiul s\227u s-a \238mbun\227t\227\254it \186i e posibil s\227 fi[ENTER]uitat toat\227 \238nt\238mplarea cu Blana Mu-Rang. De ce[ENTER]nu mergi s\227-l vizitezi?"
gameforge.new_quest_lv43._012_say = "Wonda-Rim este \238n %s."
gameforge.new_quest_lv43._020_say = "Este frumos din partea ta sa vi pe aici."
gameforge.new_quest_lv43._021_say_title = "Wonda-Rim:"
gameforge.new_quest_lv43._022_say = "Pe mine m-a adus unchiul meu, Chaegirab. Eu \186i[ENTER]unchiul meu \238ntotdeauna ne-am \238n\254eles bine... dar[ENTER]c\226nd l-am \238ntrebat despre p\227rintii mei a evitat[ENTER]s\227 r\227spund\227.[ENTER]Mi-a zis doar c\227 sunt mor\254i."
gameforge.new_quest_lv43._023_say_reward = "\206ntr-o zi am de g\238nd s\227 m\227 \238nsor asa c\227 vreau[ENTER]s\227-mi \186tiu originile. Po\254i vorbi cu unchiul meu[ENTER]\186i s\227-l \238ntrebi despre p\227rintii mei? Dar te rog[ENTER]nu-i zice c\227 te-am trimis eu."
gameforge.new_quest_lv43._024_select = "Voi vorbi cu el!"
gameforge.new_quest_lv43._025_say = "Wonda-Rim nu este nepotul lui Chaegirab, a fost[ENTER]crescut doar de el. Acum a venit momentul s\227 afle[ENTER]cine sunt adev\227ra\254ii lui p\227rinti. \206ntreab\227-l pe[ENTER]Chaegirab despre adev\227ra\254ii p\227rinti a lui[ENTER]Wonda-Rim."
gameforge.new_quest_lv43._026_say = "Chaegirab este \238n %s."
gameforge.new_quest_lv43._030_target = "Chaegirab:"
gameforge.new_quest_lv43._031_say_title = "Chaegirab:"
gameforge.new_quest_lv43._032_say = "Wonda-Rim ... nu, nu sunt unchiul s\227u natural. Nu[ENTER]\186tiu cine sunt p\227rintii lui. Am ascuns adev\227rul[ENTER]crez\238nd c\227 \238nc\227 nu a venit momentul s\227 afle. Dar[ENTER]poate totu\186i timpul a sosit ..."
gameforge.new_quest_lv43._033_say = "L-am g\227sit al\227turi de un grup de Orci Lupt\227tori[ENTER]\238n Valea Seungryong. Dac\227 vrei s\227 afli ceva legat[ENTER]de p\227rintii lui atunci numai de la Orci vei afla."
gameforge.new_quest_lv43._034_say = "Poate am fost prea dur cu el dar \238nc\227 m\227 consider[ENTER]unchiul sau."
gameforge.new_quest_lv43._035_say_reward = "Mergi \238n Valea Seungryong \186i v\226neaz\227 Orci[ENTER]Lupt\227tori p\226n\227 c\226nd g\227se\186ti un indiciu despre[ENTER]p\227rin\254ii lui Wonda-Rim."
gameforge.new_quest_lv43._036_say = "Ai g\227sit o scrisoare veche \238n sacul unui Orc[ENTER]Lupt\227tor. Este indescifrabil\227 dar uit\238ndu-te[ENTER]atent vezi numele lui Wonda-Rim scris. Asta este[ENTER]dovada care ai cautat-o, acum \238ntoarce-te la[ENTER]Wonda-Rim."
gameforge.new_quest_lv43._041_say = "S\227 mergem. Cea mai bun\227 modalitate de a g\227si[ENTER]dovezi despre p\227rintii lui Wonda-Rim este s\227[ENTER]omoram Orci Lupt\227tori."
gameforge.new_quest_lv43._043_notice = "Indicii despre Wonda-Rim..."
gameforge.new_quest_lv43._045_say = "Ti-am zis tot ce \186tiu. Singura dovad\227 care o avem[ENTER]sunt Orcii Lupt\227tori, dar nu po\254i avea o discu\254ie[ENTER]civilizat\227 cu ei."
gameforge.new_quest_lv43._049_say = "O Scrisoare? S\227 vedem ... este greu de descifrat[ENTER]ce scrie ... este vorba despre un raid, orcii au[ENTER]ars o ferm\227 \186i proprietarii au trebuit sa fug\227[ENTER]sa-\186i salveze vie\254ile \238ns\227 au l\227sat \238n urma un[ENTER]copil ... \186i aici e un nume."
gameforge.new_quest_lv43._050_say = "Mul\254umesc c\227 mi-au adus asta, acum \186tiu ce s-a[ENTER]\238nt\238mplat cu adev\227rat."
gameforge.new_quest_lv43._051_say = "Ar trebui sa vorbesc cu Chaegirab, a trecut prin[ENTER]multe pentru a m\227 salva. Voi \238ncerca s\227 fiu un[ENTER]nepot mai bun. Pe cur\238nd prietene."
gameforge.new_quest_lv43._052_say_title = "Informatie:"
gameforge.new_quest_lv43._053_say_reward = "Ai primit 32000 Yang."
gameforge.new_quest_lv43._054_say_reward = "Ai primit 1250000 puncte de experien\254\227."
gameforge.new_quest_lv43._060_say = "Ai vorbit cu unchiul meu Chaegirab? O idee ?[ENTER]Despre ce vorbesti? Daca nu ai nimic de aratat,[ENTER]atunci ar trebui sa te opresti din ghicit![ENTER][ENTER]Te rog intreaba-l pe Unchiul meu din nou. La urma[ENTER]urmelor, te platesc pentru asta."
gameforge.new_quest_lv52 = {}
gameforge.new_quest_lv52._010_send_letter = "Scrisoare de la C\227pitan"
gameforge.new_quest_lv52._020_say_title = "Concet\227\254ean loial"
gameforge.new_quest_lv52._021_say_reward = "As vrea s\227-mi faci un favor. Nu mai pot dormi[ENTER]noaptea chiar dac\227 urmez tratamentul lui Baek-Go.[ENTER]Po\254i s\227-l cau\254i \186i s\227-l \238ntrebi de un tratament[ENTER]mai puternic?"
gameforge.new_quest_lv52._022_say = "Baek-Go este \238n %s."
gameforge.new_quest_lv52._030_set_title = "Un somn lini\186tit noaptea"
gameforge.new_quest_lv52._035_target = "Baek-Go :"
gameforge.new_quest_lv52._040_say = "C\227pitanul are probleme su somnul. Mergi la[ENTER]Baek-Go \186i \238ntreab\227-l dac\227 are un tratament mai[ENTER]puternic."
gameforge.new_quest_lv52._041_say = "Tratament de somn pentru C\227pitan? \206mi pare r\227u[ENTER]dar n-am nimic mai puternic. Totu\186i, Yu-Hwan[ENTER]poate face un tratament mai bun cu acela\186i efect."
gameforge.new_quest_lv52._042_say = "Ah, ai primit scrisoarea. Nu \186tiu ce sa ma mai[ENTER]fac, nu pot dormi lini\186tit noaptea. Te rog[ENTER]ajuta-ma \186i cere-i lui Baek-Go sfaturi."
gameforge.new_quest_lv52._042_select = "Atunci mai bine merg la Yu-Hwan!"
gameforge.new_quest_lv52._043_say = "Baek-Go este \238n %s."
gameforge.new_quest_lv52._044_say_title = "Baek-Go :"
gameforge.new_quest_lv52._045_say = "Yu-Hwan este \238n %s."
gameforge.new_quest_lv52._046_say = "Atunci du-te la Capitan si spune-i ca nu il poti[ENTER]ajuta."
gameforge.new_quest_lv52._049_say_title = "Yu-Hwan: "
gameforge.new_quest_lv52._050_target = "Yu-Hwan: "
gameforge.new_quest_lv52._051_say = "Baek-Go nu mai are nici un tratament puternic,[ENTER]\238nsa Yu-Hwan s-ar putea s\227 te ajute."
gameforge.new_quest_lv52._052_say = "Il cunosc pe C\227pitan. De ceva timp \238ndeplinesc[ENTER]misiuni pentru el dar \238\254i zic siguri c\227 acele[ENTER]tratamente nu-l ajut\227."
gameforge.new_quest_lv52._053_say = "Exist\227 un alt motiv pentru care C\227pitanul nu[ENTER]poate dormi noaptea. Si crede-m\227 c\227 \186tie exact[ENTER]motivul. \206ns\227 este ceva ce trebuie s\227 rezolve el[ENTER]singur. Mergi la el \186i \238ntreab\227-l."
gameforge.new_quest_lv52._054_say_title = "C\227pitan"
gameforge.new_quest_lv52._055_say_reward = "Ah, ai primit scrisoarea mea. Chiar nu \186tiu ce s\227[ENTER]mai fac. Mergi te rog la Baek-Go si cere-i sfatul[ENTER]\238n speran\254a c\227 voi putea dormi din nou lini\186tit[ENTER]noaptea."
gameforge.new_quest_lv52._055_select = "Da Domnule!"
gameforge.new_quest_lv52._056_say = "Multumesc!"
gameforge.new_quest_lv52._056_say_reward = "Am fost deja la el \186i nu are nici un alt[ENTER]tratament mai puternic. Dar \238l voi caut\227 pe[ENTER]Yu-Hwan \186i-l voi \238ntreba dac\227 are el ceva mai[ENTER]puternic."
gameforge.new_quest_lv52._060_target = "C\227pitan"
gameforge.new_quest_lv52._061_say = "Yu-Hwan nu doreste sa spuna secretele nimanui,[ENTER]este un lucru neplacut. Asa ca va trebui sa[ENTER]vorbesti cu Capitanul despre asta. Daca nu stim[ENTER]care este cauza nu putem rezolva nimic cu[ENTER]insomniile lui, asa ca mergi la %s."
gameforge.new_quest_lv52._062_say_reward = "Nu mai exist\227 tratament puternic pentru somn. Dar[ENTER]C\227pitane, poate g\227sesc un leac dac\227 a\186 \186tii din[ENTER]ce cauz\227 nu po\254i dormi noaptea."
gameforge.new_quest_lv52._063_say_reward = "Nu pot zice motivul mai ales unui t\238n\227r ca tine."
gameforge.new_quest_lv52._064_say_reward = "Nu pot zice motivul mai ales unei tinere ca tine."
gameforge.new_quest_lv52._065_say_reward = "Dar dac\227 nu voi avea \238n cur\238nd un tratament voi[ENTER]\238nnebuni. Cred totu\186i c\227 trebuie ...[ENTER]Nu uita \238ns\227 ca ce auzi acum este doar pentru[ENTER]tine: Sunt b\238ntuit de patru fantome \238n fiecare[ENTER]noapte. Dar asta nu este tot, chiar eu sunt[ENTER]vinovat de moartea lor."
gameforge.new_quest_lv52._066_say_reward = "Sunt patru solda\254i. Fantomele solda\254ilor spun c\227[ENTER]au fost tortura\254i \186i uci\186i in Valea Seungryong.[ENTER]Eu am fost cel care a dat ordinul s\227 mearg\227[ENTER]acolo, eu i-am trimis spre pierire."
gameforge.new_quest_lv52._067_say_reward = "Ce putem face \238n privin\254a acestor fantome?"
gameforge.new_quest_lv52._068_say_reward = "Vor s\227 fie r\227zbunate! Ce ar trebui s\227 fac? Dac\227[ENTER]voi pleca s\227-i r\227zbun atunci satul va r\227m\238ne f\227r\227[ENTER]ap\227rare \186i va fi cucerit. Si dac\227 nu merg atunci[ENTER]voi \238nnebuni \238ncetul cu \238ncetul."
gameforge.new_quest_lv52._069_say_reward = "Dac\227 nu a\186 fi responsabil de siguran\254a satului,[ENTER]atunci a\186 merge. Vad dec\238t o singur\227 solu\254ie:"
gameforge.new_quest_lv52._070_say_reward = "Altcineva ar trebui sa r\227zbune solda\254ii \238n locul[ENTER]meu. Dar cum s\227 trimit al\254i oameni \238n Valea[ENTER]Seungryong \186i sa fie uci\186i \186i ei?"
gameforge.new_quest_lv52._071_say_reward = "O astfel de decizie nu este u\186oar\227."
gameforge.new_quest_lv52._080_1_select = "Siguranta satului ..."
gameforge.new_quest_lv52._080_2_select = "Nu va fi usor ..."
gameforge.new_quest_lv52._080_3_select = "Nu te po\254i a\186tepta la a\186a ceva!"
gameforge.new_quest_lv52._081_say_reward = "... are mai mult\227 greutate dec\238t la\186itatea ta.[ENTER]Voi r\227zbuna oamenii t\227i. \170i dac\227 nu m\227 \238ntorc, ne[ENTER]vom vedea la noapte!"
gameforge.new_quest_lv52._082_say_reward = "... av\238nd de-a face cu asupritori. Dar vei dormi[ENTER]lini\186tit la noapte, promit!"
gameforge.new_quest_lv52._083_say_reward = "Ai vreo dorin\254\227 \238nainte de moarte? Este foarte[ENTER]periculos s\227 te pui cu asupritorii. \206ncearc\227 s\227[ENTER]le zici acelor fantome c\238t de folositor e\186ti[ENTER]aici."
gameforge.new_quest_lv52._084_say_reward = "Ai dreptate. Dar am sperat c\227 te vei oferi de[ENTER]bun\227 voie."
gameforge.new_quest_lv52._090_1_select = "A\186adar ..."
gameforge.new_quest_lv52._090_2_select = "Nu, nu m\227 voi descurca!"
gameforge.new_quest_lv52._091_say_reward = "... dac\227 sunt ultima ta speran\254\227, atunci te voi[ENTER]ajuta."
gameforge.new_quest_lv52._092_say_reward = "Voi \238ncerca asta, o alt\227 fantom\227 te va g\227si."
gameforge.new_quest_lv52._093_say_reward = "OK. S\227-ti dau ni\186te Yang pentru eforturile tale."
gameforge.new_quest_lv52._093_say_reward_exp = "Ai primit 20000 puncte de experien\254\227."
gameforge.new_quest_lv52._093_say_reward_gold = "Ai primit 25.000 Yang."
gameforge.new_quest_lv52._100_notice = "Discu\254ia a luat sf\238r\186it."
gameforge.new_quest_lv52._110_say_reward = "M\227 a\186teptam s\227 zici asta dar din p\227cate nu \186tiu[ENTER]care asupritori l-au omor\238t."
gameforge.new_quest_lv52._111_say_reward = "\206ti voi trimite o scrisoare. Fantomele mi-au zis[ENTER]c\227 r\227zbunarea trebuie s\227 aibe loc \238n Triunghiul[ENTER]Zeului Dragon. Acolo sunt trei piloni care[ENTER]formeaz\227 Triunghiul."
gameforge.new_quest_lv52._120_set_title = "R\227zbun\227 4 din cei cazuti"
gameforge.new_quest_lv52._125_say_title = "Scrisoare de la C\227pitan"
gameforge.new_quest_lv52._130_say_reward = "Mai sunt inc\227 3 solda\254i de r\227zbunat."
gameforge.new_quest_lv52._131_say = "Se pare c\227 ai avut succes. Tocmai ce am auzit[ENTER]vocea unuia dintre solda\254ii c\227zu\254i care mi-a zis[ENTER]c\227 m\227 iart\227 acum pentru ca a fost r\227zbunat. \170i[ENTER]asta doar datorit\227 tie."
gameforge.new_quest_lv52._132_say = "Te rog r\227zbun\227 \186i pe ceilal\254i solda\254i \186i omoar\227[ENTER]pe Despot \206ntunecat, \206ncant\227tor \206ntunecat, Despot[ENTER]\206nalt, \206ncant\227tor \206nalt. Nu uita c\227 \238i poti[ENTER]elibera doar \238n triunghiul Zeului Dragon."
gameforge.new_quest_lv52._140_say_reward = "\206nc\227 2 solda\254i de r\227zbunat."
gameforge.new_quest_lv52._141_say = "Ai omor\238t un alt criminal al solda\254ilor mei!"
gameforge.new_quest_lv52._150_say_reward = "A mai r\227mas un singur soldat de r\227zbunat."
gameforge.new_quest_lv52._151_say = "E\186ti uimitor. O alt\227 fantom\227 a unui soldat a stat[ENTER]acum c\238teva minute \238n fata mea si m-a salutat. S-[ENTER]ar putea s\227 fie dificil de g\227sit ultimul[ENTER]criminal."
gameforge.new_quest_lv52._160_say = "Fantomele care \238l b\238ntuiau pe C\227pitan erau cele[ENTER]ale tinerilor solda\254i cazu\254i in misiune. Ei au[ENTER]fost omor\238\254i de Despot \238ntunecat, \206nc\238nt\227tor[ENTER]\238ntunecat, Despot \238nalt, Inc\226nt\227tor \238nalt."
gameforge.new_quest_lv52._161_say = "Trebuie s\227 omori asupritorii responsabili in[ENTER]Triunghiul Dragonului pentru a r\227zbuna solda\254ii[ENTER]c\227zu\254i."
gameforge.new_quest_lv52._162_say = "Triunghiul Zeului Dragon se afl\227 \238n Valea[ENTER]Seungryong."
