gameforge.new_quest_lv54._020_say_title = "Provizia proasp\227t\227"
gameforge.new_quest_lv54._030_say = "Este dificil s\227 motivezi armata in acest moment[ENTER]mai ales c\227 este greu s\227 facem rost de provizii[ENTER]proaspete. V\226nz\227toarea de la Magazinul General[ENTER]ne-a trimis doar o cantitate mic\227 de licori de[ENTER]care avem nevoie."
gameforge.new_quest_lv54._031_say_reward = "Te rog s\227 mergi la V\226nz\227toarea de la Magazinul[ENTER]General sa vezi ce probleme are."
gameforge.new_quest_lv54._032_select = "Iti voi oferi licorile!"
gameforge.new_quest_lv54._040_say_title = "Negustoreasa de diverse:"
gameforge.new_quest_lv54._040_set_title = "Provizii Proaspete"
gameforge.new_quest_lv54._050_target = "Negustoreasa de diverse:"
gameforge.new_quest_lv54._051_say = "Aprovizionarea proasp\227t\227 este grea \238n acest[ENTER]moment. Drumurile pentru nego\254 au devenit[ENTER]nesigure, pline de ho\254i \186i animale s\227lbatice.[ENTER]Negustorii Ambulan\254i, de la care m\227 aprovizionez,[ENTER]nu au nicio \186ans\227 \238mpotriva tigrilor."
gameforge.new_quest_lv54._052_say = "Poate C\227pitanul \186i solda\254ii lui te pot ajuta.[ENTER]Mergi te rog la el si vezi dac\227 poate trimite[ENTER]solda\254ii c\227 s\227 apere comercian\254ii."
gameforge.new_quest_lv54._054_say = "Mergi la V\226nz\227toarea de la Magazinul General \186i[ENTER]vezi de ce \238ntarzie cu aprovizionarea cu po\254iuni."
gameforge.new_quest_lv54._055_say = "V\226nz\227toarea de la Magazinul General este \238n %s."
gameforge.new_quest_lv54._056_say_title = "C\227pitan"
gameforge.new_quest_lv54._060_say = "S\227 am grij\227 de drumurile pentru nego\254? Mi-ar face[ENTER]pl\227cere s\227 fac asta. Dar nu am destui solda\254i[ENTER]care s\227 apere V\226nz\227torii Ambulan\254i din celelalte[ENTER]regate."
gameforge.new_quest_lv54._061_say = "Mai mult de at\226t, noi solda\254ii trebuie s\227 v\226nam[ENTER]tigrii. Doar v\226n\227torii din tribul v\226n\227torilor au[ENTER]dreptul s\227 fac\227 asta. Nu va exista pace in sat[ENTER]daca aceast\227 regula va fi \238nc\227lcat\227."
gameforge.new_quest_lv54._062_say_reward = "Ar trebui s\227 vorbe\186ti cu Yang-Shin. El este[ENTER]membru al grupului de v\238n\227tori. E posibil ca el[ENTER]s\227 te ajute \238n problema cu tigrii."
gameforge.new_quest_lv54._064_say = "Mergi la C\227pitan \186i \238ncearc\227 s\227-l convingi s\227[ENTER]protejeze drumurile de nego\254 de tigrii."
gameforge.new_quest_lv54._065_say = "C\227pitanul este \238n %s."
gameforge.new_quest_lv54._070_target = "Yang-Shin :"
gameforge.new_quest_lv54._071_say = "Mul\254i dintre v\238n\227torii mei au fost \238nrola\254i \238n[ENTER]armat\227 \186i au pierit \238n r\227zboi. Acum este greu s\227[ENTER]men\254inem popula\254ia echilibrat\227. Pisicile[ENTER]s\227lbatice au devenit acum o mare problem\227 mai[ENTER]ales c\227-\186i extind teritoriul \186i pun \238n pericol[ENTER]c\227l\227torii."
gameforge.new_quest_lv54._072_say = "Dac\227 ne aju\254i \238\254i voi oferi acest Scut Tigru +3[ENTER]care a fost al camaradului meu Mi-Song. Pentru[ENTER]a-l ob\254ine trebuie s\227 reduci din popula\254ia de[ENTER]tigrii."
gameforge.new_quest_lv54._073_say = "Tigrul Blestemat Alb are multe incontrabilita\254i."
gameforge.new_quest_lv54._074_say = "Ca dovad\227, am nevoie de:"
gameforge.new_quest_lv54._075_say = "Trebuie sa v\226nezi:"
gameforge.new_quest_lv54._076_say = "Caut\227-l pe Yang-Shin \186i \238ncearc\227 s\227-l convingi s\227[ENTER]asigure drumurile de nego\254 de tigrii."
gameforge.new_quest_lv54._077_say_title = "Yang-Shin :"
gameforge.new_quest_lv54._078_say = "Yang-Shin este in %s."
gameforge.new_quest_lv54._080_set_title = "Blan\227 de tigru"
gameforge.new_quest_lv54._081_notice = "Ah, un exemplar bun. \206nc\227 %s din ele."
gameforge.new_quest_lv54._082_notice = "Rezolvat! Acum \238ntoarce-te repede \238napoi la[ENTER]Yang-Shin."
gameforge.new_quest_lv54._083_notice = "Aceast\227 blan\227 de tigru este nefolositoare."
gameforge.new_quest_lv54._084_say = "Mai ai nevoie de \238nc\227 %s x Blan\227 lucioas\227 de[ENTER]tigru."
gameforge.new_quest_lv54._085_say = "Jefuie\186te Blan\227 lucioas\227 de tigru de la Tigru[ENTER]Blestemat Alb."
gameforge.new_quest_lv54._090_npcChat = "Am facut rost de Blana lucioasa de tigru."
gameforge.new_quest_lv54._091_say = "Nu este de ajuns. Cum pot afla cu ajutorul[ENTER]acestor bl\227nuri c\227 drumurile sunt sigure din nou?"
gameforge.new_quest_lv54._092_say = "\206n sf\226r\186it! Aceste bl\227nuri \238mi vor aduce profit[ENTER]mare ... \206nc\227 e\186ti aici? Datorita \254ie drumurile[ENTER]sunt din nou sigure. Sunt convins c\227 vei primi o[ENTER]recompens\227 pe m\227sur\227 de la C\227pitan."
gameforge.new_quest_lv54._093_say = "Si acum pleac\227. Trebuie s\227 cur\227\254 blana."
gameforge.new_quest_lv54._094_say = "Oh, C\227pitanul nu \254i-a dat nicio recompens\227? Asta[ENTER]nu e problema mea. \170i \238n cazul \238n care \238ncerci s\227[ENTER]m\227 p\227c\227le\186ti pentru bl\227nuri: Uit\227 de asta, nu m\227[ENTER]voi desp\227r\254i de ele!"
gameforge.new_quest_lv54._095_say_reward = "Dar \254i-am promis un scut a\186a c\227-l vei primi."
gameforge.new_quest_lv54._096_say = "Recompens\227:"
gameforge.new_quest_lv54._097_say_reward = "Ai primit Scut Tigru +3."
gameforge.new_quest_lv54._098_say = "Vrei s\227 m\227 tragi in piept cu ni\186te blan\227? In[ENTER]acest fel drumurile nu vor fi sigure vreodat\227."
gameforge.new_quest_lv54._099_say_reward = "Mergi la v\226n\227toare pana reu\186e\186ti sa str\226ngi %s[ENTER]blan\227!"
gameforge.new_quest_lv54._100_say = "Asta e tot., acum mergi \238napoi la Yang-Shin."
gameforge.new_quest_lv54._101_say_reward = "Ai primit 3750000 puncte de experien\254\227."
gameforge.new_quest_lv54._102_say_reward = "Ai primit 125000 Yang."
