gameforge.new_quest_lv7._021_say = "Ai copii? Atunci cu siguran\254\227 vei \238n\254elege[ENTER]grijile mele ... este vorba de fiica mea! A[ENTER]\238nt\226lnit un b\227rbat care a z\227p\227cit-o de tot si a[ENTER]fugit cu el intr-un alt regat."
