gameforge.new_quest_lv7._023_say = "El este din regatul Jinno. Bine\238n\254eles c\227 m-am[ENTER]\238mpotrivit. M\227 g\226ndeam c\227 o doamna din regatul[ENTER]Chunjo nu se poate c\227s\227tori cu un b\227rbat din[ENTER]regatul Jinno."
gameforge.new_quest_lv7._024_say = "El este din regatul Shinsoo. Bine\238n\254eles c\227 m-am[ENTER]\238mpotrivit. M\227 g\226ndeam c\227 o doamna din regatul[ENTER]Jinno nu se poate c\227s\227tori cu un b\227rbat din[ENTER]regatul Shinsoo."
gameforge.new_quest_lv7._030_say = "Am \238n\254eles c\227 vrea s\227 se m\227rite cu el acolo."
gameforge.new_quest_lv7._031_say = "Acum fiica mea a\186teapt\227 un semn de la mine. Ce ar[ENTER]trebui s\227 fac? Este singurul meu copil![ENTER]Bine\238n\254eles c\227 ii voi da binecuv\226ntarea mea. Te[ENTER]rog s\227 mergi la Femeia B\227tr\226na si roag-o s\227 ajute[ENTER]la preg\227tiri."
