gameforge.new_quest_lv7._052_say = "Florile sunt \186i ele importante pentru nunt\227 -[ENTER]nicio nunt\227 nu poate avea loc f\227r\227 un buchet mare[ENTER]de flori pentru mireas\227. Buchetul trebuie s\227[ENTER]con\254in\227 urm\227toarele flori:"
