gameforge.new_quest_lv7._137_say = "\206ntoarce-te la Octavio \238n Pyungmoo \238n regatul[ENTER]Jinno."
gameforge.new_quest_lv7._140_say = "Poftim florile pentru nunta fiicei lui Octavio.[ENTER]Trebuie \238nm\226nate miresei cu binecuv\226ntare. Ar[ENTER]trebui s\227 \186tie de la cine sunt."
gameforge.new_quest_lv7._141_say = "Sunt flori frumoase ca si mireasa. Te rog[ENTER]anun\254\227-l pe Octavio c\227 este invitat la ceremonie.[ENTER]\170tiu c\227 va fi \238ncantat."
