gameforge.new_quest_lv75._010_target = "Heuk-Young:"
gameforge.new_quest_lv75._020_set_title = "Agenda unei Legende"
gameforge.new_quest_lv75._021_say = "Am g\227sit r\227m\227\186i\254ele acestui r\227zboinic. Nu \238mi dau[ENTER]seama dac\227 este Sura, cel pe care`l caut\227[ENTER]Heuk-Young, dar sunt sigur c\227 va fi interesat\227."
gameforge.new_quest_lv75._022_say = "Nu doar un singur Sura a murit aici ci \186i al\254ii,[ENTER]le-am v\227zut chiar r\227m\227\186itele. M\227 \238ntreb dac\227[ENTER]acest r\227zboinic legendar este, de asemenea,[ENTER]printre ei? Trebuie s\227 anun\254 pe Heuk-Young despre[ENTER]acest lucru."
gameforge.new_quest_lv75._023_say = "Am g\227sit o bucat\227 veche de h\238rtie, \238nghe\254at\227 \238n[ENTER]Golem Gheat\227 lume de jos. Abia pot s-o citesc,[ENTER]dar poate sa fie un indiciu folositor pentru[ENTER]Heuk-Young."
gameforge.new_quest_lv75._024_say = "Am g\227sit c\238teva lucruri care ar putea fi[ENTER]folositoare pentru Heuk-Young. Ar trebui sa merg[ENTER]la ea \186i s\227-i dau bucata de h\238rtie. Apoi ii pot[ENTER]zice \186i despre cadavru."
gameforge.new_quest_lv75._025_say = "Heuk-Young m-a rugat s\227 fiu cu ochii-n patru dup\227[ENTER]orice indiciu despre legendarul Sura. Din p\227cate[ENTER]nu am idee dup\227 ce sa ma uit ..."
gameforge.new_quest_lv75._030_say = "Uit\227-te dup\227 legendarul lupt\227tor Akuma. El a fost[ENTER]cel mai faimos Sura care a tr\227it vreodat\227 \186i[ENTER]aproape invincibil. Se zvone\186te c\227 l-a provocat[ENTER]chiar \186i pe \238mp\227rat. Cred ca acesta este locul[ENTER]unde Akuma a disp\227rut acum peste 100 de ani.[ENTER]Uit\227-te dup\227 indicii care pot fi de folos."
gameforge.new_quest_lv75._040_say = "manechin"
gameforge.new_quest_lv75._050_npcChat = "Examinarea R\227zboinicilor C\227zu\254i"
gameforge.new_quest_lv75._060_say = "Pare s\227 fie r\227m\227\186i\254ele unui lupt\227tor. Mana st\238nga[ENTER]nu pare sa fie a unui om. Trebuie s\227-i povestesc[ENTER]lui Heuk-Young despre asta."
gameforge.new_quest_lv75._070_notice = "O pagin\227 de carte... \238nghe\254at\227 \238n r\227m\227\186i\254ele unui[ENTER]Golem de Ghea\254\227 Subteran..."
gameforge.new_quest_lv75._090_say = "Nu \238\254i pot spune cu precizie ceea ce c\227utam.[ENTER]Arunc\227 o privire \238n jur \186i \238ntoarce-te c\226nd ai[ENTER]descoperit ceva."
gameforge.new_quest_lv75._100_say = "Ce ai g\227sit? Da-mi voie sa vad!"
gameforge.new_quest_lv75._105_say = "O noti\254\227, ce fel de scris e acesta? Trebuie s\227[ENTER]fie foarte vechi. S-ar putea sa fi g\227sit ceva[ENTER]important. Ceea ce este scris aici pare s\227-mi fie[ENTER]familiar. Se pare c\227 aceast\227 pagin\227 a f\227cut parte[ENTER]dintr-o carte."
gameforge.new_quest_lv75._109_say = "Dac\227 am putea g\227si mai multe pagini totul ar[ENTER]c\227p\227ta un \238n\254eles. Arunc\227 o privire dup\227 mai[ENTER]multe indicii!"
gameforge.new_quest_lv75._110_say = "Ai revenit. Spune-mi, ai g\227sit ceva?"
gameforge.new_quest_lv75._115_say = "Un Sura mort, poate fi chiar el sau un urma\186[ENTER]de-al lui. Avem nevoie de mai multe dovezi pentru[ENTER]a fi siguri. Uit\227-te dup\227 indicii care ne-ar[ENTER]putea spune adev\227rul. Arme, bijuterii sau poate[ENTER]noti\254e, orice."
gameforge.new_quest_lv75._120_say = "Scheletul unui Sura \186i o pagin\227 de carte? D\227-mi[ENTER]voie s\227 arunc o privire la pergament ... S-ar[ENTER]putea s\227 fi g\227sit r\227m\227\186i\254ele lui Akuma. Cu toate[ENTER]acestea avem nevoie de mai multe dovezi. Te rog[ENTER]s\227 g\227se\186ti mai multe pagini din carte."
gameforge.new_quest_lv75._130_say = "Am g\227sit c\238teva indicii \238ns\227 nu sunt sigur dac\227[ENTER]adev\227ratul Sura a fost aici. Am nevoie de mai[ENTER]multe informa\254ii."
gameforge.new_quest_lv75._140_1_select = "Bine"
gameforge.new_quest_lv75._140_2_select = "Creatur\227 de ghea\254\227"
gameforge.new_quest_lv75._140_3_select = "La marginea disper\227rii"
gameforge.new_quest_lv75._140_4_select = "Teroarea neagr\227"
gameforge.new_quest_lv75._140_5_select = "Fa\254a mor\254ii"
gameforge.new_quest_lv75._140_6_select = "Soarta r\227zboinicului"
gameforge.new_quest_lv75._140_7_select = "Nu, nu sunt interesat."
gameforge.new_quest_lv75._150_say = "Pot descifra doar p\227r\254i din mesaj. Ei spun ceva[ENTER]despre via\254a curtat\227 \186i despre o dragoste[ENTER]excesiv\227 de aventur\227 ..."
gameforge.new_quest_lv75._160_1_say = "Scrisul de pe pergament este \238ng\227lbenit \186i vechi[ENTER]ca \186i cum ar fi fost scris de o persoan\227 b\227tr\238n\227[ENTER]sau slab\227: \" ... Creaturi de gheat\227.[ENTER]Nici m\227car Sura cu aptitudinile sale nu a putut[ENTER]s\227 le \238nving\227. Unele dintre ele \238nc\227 mi\186un\227 \238n[ENTER]pe\186teri \186i trebuie sa fiu atent \238n cazul \238n care[ENTER]m\227 g\227sesc. Pan\227 recent ele \238mi ofereau protec\254ie,[ENTER]dar acum ... \" Aici scrisul nu se mai observa."
gameforge.new_quest_lv75._160_2_say = "Aceast\227 pagin\227 este foarte uzat\227. Dup\227 data[ENTER]aflat\227 \238n col\254ul de sus se poate considera un fel[ENTER]de jurnal: \"Nu este pentru prima dat\227 c\226nd \238mi[ENTER]doream s\227 fi ac\254ionat diferit \238n timp ce c\227utam[ENTER]Grota. Am fost foarte mul\254umit de mine \238nsumi![ENTER]Toate aceste lucruri au dus acum c\227tre moartea[ENTER]mea...\" Ultimul cuv\226nt este \238ngro\186at."
gameforge.new_quest_lv75._160_3_say = "Paginile pergamentului sunt distruse, buc\227\254i din[ENTER]ele par s\227 fie rupte. Se pot descifra doar p\227r\254i[ENTER]din mesaj: \"... Curtea \238mp\227ratului... atunci c\226nd[ENTER]c\227rturarii m-au \238nv\227\254at tot ce \186tiu au vrut cu[ENTER]disperare s\227 cunoasc\227... deschiderea u\186oar\227 a[ENTER]portalului, dar... moarte \186i teroare \238n[ENTER]\238ntuneric...\" Restul scrisului este[ENTER]indescifrabil."
gameforge.new_quest_lv75._160_4_say = "Pe aceast\227 pagin\227 din pergament vei g\227si o[ENTER]schi\254\227: o poz\227 a unei femei. Sub poz\227 se g\227sesc[ENTER]ni\186te cuvinte care \238\254i sunt familiare. Totu\186i[ENTER]scrisul este nedescifrabil: \" Moartea \238\186i arat\227[ENTER]fa\254a - Am descoperit asta ieri. M-am uitat pu\254in[ENTER]la creatur\227 \238nainte ca frica s\227 pun\227 st\227p\238nire.[ENTER]Oh, dragul meu Sunmi, dac\227 \186tiam! Dac\227 \186tiam[ENTER]dinainte de acest lucru nu p\227\186eam la acest nivel![ENTER]\""
gameforge.new_quest_lv75._160_5_say = "\206n timpul Dinastiei Hee-Se a locuit un Sura[ENTER]legendar pe nume Akuma. Era at\226t de iscusit \238n[ENTER]lupte \238nc\226t abia g\227sea adversari cu care s\227-\186i[ENTER]m\227soare puterea. \206ntr-o zi a g\227sit ni\186te noti\254e[ENTER]despre un loc ascuns \186i uitat de lume \186i s-a[ENTER]decis s\227 g\227seasc\227 acest loc. A \238nv\227\254at s\227[ENTER]g\227seasc\227 portale \186i s\227 le \186i foloseasc\227. A promis[ENTER]iubitei sale Sunmi c\227 se va \238ntoarce dup\227 ce va[ENTER]g\227si acel loc...[ENTER]\238ns\227 nu s-a mai \238ntors niciodat\227."
gameforge.new_quest_lv75._170_say = "Scrisul era indescifrabil ca si cum cel care a[ENTER]scris nu mai avea vlaga deloc ..."
gameforge.new_quest_lv75._171_say = "Nu are nicio logic\227. Avem nevoie de mai multe[ENTER]pagini."
gameforge.new_quest_lv75._172_say = "Incep sa imi dau seama ce s-a intamplat aici. Dar[ENTER]totusi exista multe lucruri de care nu-mi dau[ENTER]seama."
gameforge.new_quest_lv75._173_say = "Vrei sa cunosti detaliile?"
gameforge.new_quest_lv75._174_say = "O alt\227 pagin\227! Cel care a scris aceste lucruri[ENTER]trebuia s\227 fie foarte disperat. S\227 fac un rezumat[ENTER]la ceea ce scrie?"
gameforge.new_quest_lv75._175_say = "Unele pagini sunt foarte deteriorate incat pot[ENTER]doar ghici despre ce se vorbeste. Totusi incep[ENTER]sa-mi dau seama ce s-a petrecut in aceste pesteri[ENTER]acum multi ani in urma."
gameforge.new_quest_lv75._176_say = "Nu prea mult lipseste. Vrei sa stii ce am gasit?"
gameforge.new_quest_lv75._177_say = "Se pare ca nu lipsesc foarte multe pagini."
gameforge.new_quest_lv75._178_say = "Vrei sa stii ce am gasit pana acum?"
gameforge.new_quest_lv75._180_notice = "Am g\227sit ultima pagin\227 la Golem de Ghea\254\227[ENTER]Subteran."
gameforge.new_quest_lv75._185_send_letter = "Trebuie sa fie toate paginile!"
gameforge.new_quest_lv75._190_notice = "Am g\227sit aceast\227 pagin\227 la Golem de Ghea\254\227[ENTER]Subteran."
gameforge.new_quest_lv75._195_send_letter = "Am g\227sit o pagin\227!"
gameforge.new_quest_lv75._200_npcChat = "Caut\227 R\227zboinici C\227zu\254i"
gameforge.new_quest_lv75._210_say = "Trei pagini din pergament se afla langa acel[ENTER]schelet uman. Se pare ca au fost rupe din carte.[ENTER]Scrisul de pe pagini este greu de citit."
gameforge.new_quest_lv75._220_say = "Cred ca este destul. LE voi duce la Heuk-Young."
gameforge.new_quest_lv75._230_say = "Ma intreb a cui sunt ramasitele? Ce e sigur e[ENTER]faptul ca nu are nimic pe ele care pot sa fie[ENTER]folosite in ziua de azi."
gameforge.new_quest_lv75._240_send_letter = "Am toate paginile!"
gameforge.new_quest_lv75._250_say = "Ar trebui sa ma intorc la Heuk-Young. Poate ea[ENTER]reuseste sa puna cap la cap problema."
gameforge.new_quest_lv75._270_say = "Sunt surprins ca ai gasit atatea lucruri in acele[ENTER]pesteri. Aceste pagini par sa fie dintr-o carte.[ENTER]Ceea ce este scris pe ele este foarte interesant.[ENTER]Si a devenit si mai interesant atunci cand am[ENTER]auzit si despre celelalte intamplari ... Daca`mi[ENTER]dai acele pagini le voi lega si voi face cartea.[ENTER]Poate o sa le ai la indemana atunci cand mergi la[ENTER]Grota Exilului. Daca nu este folositoare tie,[ENTER]atunci sunt sigur ca vom gasi pe cineva care sa[ENTER]cumpere."
gameforge.new_quest_lv75._280_say = "Am legat paginile si am facut cartea si am[ENTER]adaugat si cateva notite de ale mele. Poate iti[ENTER]vor fi folositoare. Iti voi spune si restul[ENTER]povestirii daca vrei."
gameforge.new_quest_lv75._290_1_select = "Da, spune-mi mai mult."
gameforge.new_quest_lv75._290_2_select = "Nu, nu sunt interesat in asta."
gameforge.new_quest_lv75._310_say = "Ce doresti de la mine? Nu vezi ca citesc?"
gameforge.new_quest_lv75._320_say = "Soon:"
gameforge.new_quest_lv75._330_say = "Cartea care o ai este foarte interesanta. De unde[ENTER]o ai? Pot sa arunc o privire la ea?"
gameforge.new_quest_lv75._340_say = "Acestea sunt notitele din Grota Exilului, nu-i[ENTER]asa? Sunt vechi. Scrisul este vechi si[ENTER]nedescifrabil ... A fost greu sa pui mana pe o[ENTER]astfel de carte. Bineinteles mi`ar place sa fi[ENTER]pus mana pe o astfel de carte. Ai fi interesat[ENTER]s-o vinzi?"
gameforge.new_quest_lv75._350_1_select = "Da"
gameforge.new_quest_lv75._350_2_select = "Nu"
gameforge.new_quest_lv75._360_say = "Cati Yang doresti pentru carte?"
gameforge.new_quest_lv75._370_say = "Haha, esti glumet. Se vede ca nu se pot face[ENTER]afaceri usoare cu tine. Pretul e de 500000 Yang[ENTER]pentru Jurnalul Legendar. Accepta sau pleaca!"
gameforge.new_quest_lv75._380_1_select = "Voi lua cei 500000 Yang."
gameforge.new_quest_lv75._380_2_select = "Sa uitam atunci."
gameforge.new_quest_lv75._390_say = "Ok, atunci uita."
gameforge.new_quest_lv75._400_say = "Nu, imi pare rau, e prea scump ptr mine."
gameforge.new_quest_lv75._410_say = "Sa-ti fac alta propunere. Iti dau %s Yang pentru[ENTER]jurnal."
gameforge.new_quest_lv75._420_say = "Iti convine?"
gameforge.new_quest_lv75._425_say = "Este ultima mea oferta!"
gameforge.new_quest_lv75._430_1_select = "Voi lua cei %s Yang."
gameforge.new_quest_lv75._430_2_select = "Asta inseamna ca nu vom face afaceri impreuna."
gameforge.new_quest_lv75._440_say = "Cum doresti ..."
gameforge.new_quest_lv75._450_say = "Nu este chiar ieftin. Dar doresc sa fiu generos."
gameforge.new_quest_lv75._460_say = "Generozitatea mea are o limita. Iti dau cei[ENTER]500000 Yang pentru jurnal."
gameforge.new_quest_lv75._470_say = "Accepta sau pleaca!"
gameforge.new_quest_lv75._480_say = "Ok, atunci uita."
gameforge.new_quest_lv75._490_say = "Ce rusine. Poate te razgandesti mai tarziu."
