gameforge.new_quest_premium_lv4._100_say_reward = "Trebuie sa v\226nezi:"
gameforge.new_quest_premium_lv4._10_targetVid = "Negustoreasa de diverse:"
gameforge.new_quest_premium_lv4._110_say = "Cauta pe Negustorul de arme si \238ntreab\227-l de ce[ENTER]nu mai c\226nta sub geamul negustoarei de la[ENTER]Magazinul General."
gameforge.new_quest_premium_lv4._120_qSetTitle = "Adun\227 Liliac"
