gameforge.new_quest_premium_lv4._150_notice = "Din p\227cate, acest liliac s-a uscat deja."
gameforge.new_quest_premium_lv4._160_say = "Ai nevoie de urm\227toarele ramuri de liliac: %s"
gameforge.new_quest_premium_lv4._170_say = "Nu este destul. Acest liliac ajunge doar pentru[ENTER]c\226teva pic\227turi!"
gameforge.new_quest_premium_lv4._180_say = "Ahh, liliac! Acum mai am nevoie doar de Esen\254\227 de[ENTER]Mosc. O po\254i comanda doar \238n unele magazine[ENTER]speciale. O moned\227 care se rote\186te \238\254i poate[ENTER]ar\227ta drumul. Vei avea nevoie de c\226teva Jetoane[ENTER]de Dragon \186i sunt sigur c\227 ai p\227strat c\226teva,[ENTER]nu-i a\186a? Vei fi pe deplin mul\254umit! Pe urma \238\254i[ENTER]po\254i ridica comanda de la Administratorul[ENTER]Depozitului. Atunci voi avea toate ingredientele."
gameforge.new_quest_premium_lv4._190_say = "Te rog gr\227be\186te-te si adu-mi Esen\254\227 de Mosc. Vei[ENTER]primi o recompensa."
gameforge.new_quest_premium_lv4._200_say_reward = "Continua sa v\226nezi pana \238mi vei putea aduce %s[ENTER]crengi de liliac!"
