gameforge.pony_levelup._660_select = "1 val(1) 25.00%"
gameforge.pony_levelup._680_say = "Se pare c\227, calul t\227u a evoluat. Dar \238n ochii[ENTER]mei, \238nc\227 mai e\186ti un \238ncep\227tor \238n ceea ce[ENTER]prive\186te rela\254ia ta cu calul. De aceea, s\227[ENTER]exersezi mai mult c\227l\227ria. C\227l\227ritul este baza[ENTER]rela\254iei cu calul. \206nal\254\227-te pe cal \186i f\227 o[ENTER]rotire \238n jurul axei tale. Medalia ta de cal \238\254i[ENTER]va dezv\227lui rezultatul antrenamentului de ast\227zi."
