gameforge.skill_reset2._10_npcChat = "Deprecierea abilit\227\254ilor"
gameforge.skill_reset2._110_say = "Daca te r\227zg\226nde\186ti, mai vino o dat\227 pe la mine[ENTER]mai t\226rziu."
gameforge.skill_reset2._120_say = "Tu nu ai destui Yang. F\227r\227 ace\186tia, nu te pot[ENTER]ajuta, deoarece \186i eu trebuie s\227 tr\227iesc din[ENTER]ceva."
gameforge.skill_reset2._130_say = "Acest obiect iti ofera posibilitatea sa uiti[ENTER]ultimul antrenament si sa incepi altul complet[ENTER]nou. In orice caz, trebuie sa ai minim nivel 31[ENTER]pentru a putea face asta. Vei putea sa iti[ENTER]schimbi destinul. Esti sigur ca doresti sa te[ENTER]intorci la skillurile vechi care te-au facut ceea[ENTER]ce esti astazi?"
gameforge.skill_reset2._135_say = "Nu urmezi nicio \206nv\227\254\227tur\227 \186i nu ai puncte de[ENTER]abilitate de resetat!"
gameforge.skill_reset2._140_say = "Acest obiect poate fi folosit de la nivel 31."
gameforge.skill_reset2._20_say = "Nu ai urmat nicio \206nv\227\254\227tur\227! At\226ta timp c\226t nu[ENTER]ai folosit niciun punct de status nici nu le po\254i[ENTER]reseta. Revino atunci c\226nd vei pune un punct[ENTER]gre\186it de status \238n timpul \238nv\227\254\227turii \186i te voi[ENTER]ajuta cu pl\227cere."
gameforge.skill_reset2._30_say = "Nivelul t\227u este de %s.[ENTER]Eu nu te pot ajuta. Cu acest nivel, nu mai po\254i[ENTER]schimba \238nv\227\254\227tura. Numai p\226n\227 la nivelul 30 po\254i[ENTER]alege o \238nv\227\254\227tur\227 nou\227."
gameforge.skill_reset2._40_say = "Nu urmezi nicio \206nv\227\254\227tur\227 \186i nu ai puncte de[ENTER]abilitate de resetat!"
gameforge.skill_reset2._50_say = "E bine c\227 ai venit la mine.[ENTER]Ochii t\227i exprim\227 o mare \238ngrijorare. Eu \238i ajut[ENTER]pe oameni s\227-\186i uite \238nv\227\254\227tura pentru a putea[ENTER]\238ncepe totul de la cap\227t.[ENTER]Vrei s\227-\254i ui\254i \238nv\227\254\227tura \186i s\227 iei totul de la[ENTER]\238nceput?[ENTER]Asta te cost\227 %s yang."
gameforge.skill_reset2._60_select = "Nu deprecia."
gameforge.skill_reset2._70_say = "Ho, ho, nu-i a\186a c\227 nu-\254i merge bine? Fa\254a ta \238mi[ENTER]spune c\227 ai nevoie de ajutor.[ENTER]Nu esti mul\254umit cu \238nv\227\254\227tura ta?[ENTER]Eu a\186 putea s\227 te fac s\227-\254i ui\254i \238nv\227\254\227tura, ca[ENTER]prin minune."
gameforge.skill_reset2._80_say = "Asta \238nseamn\227 c\227 te po\254i implica \238ntr-o alt\227[ENTER]\238nv\227\254\227tur\227. Din p\227cate \238ns\227, pierzi toate[ENTER]punctele pe care le-ai acumulat prin citirea[ENTER]c\227r\254ilor. Vrei \238ntr-adev\227r s\227 ui\254i totul \186i s\227 o[ENTER]iei de la cap\227t?[ENTER]Atunci d\227-mi %s yang."
gameforge.skill_reset2._90_select = "Deprecierea abilit\227\254ilor"
