gameforge.subquest_01._140_sayTitle = "Yonah:"
gameforge.subquest_01._150_say = "Oh draga! La naiba! Nu m\227 pot opri din tu\186it! Cum[ENTER]s\227 lucrez \238n condi\254iile astea?[ENTER]V\226nz\227toarea de la Magazinul General te-a trimis?[ENTER]Am Sticle Goale, dar nu pot s\227-\254i dau pe gratis."
gameforge.subquest_01._160_say = "Eu am astm\227. Mi s-a spus c\227 s\226mburii de piersic\227[ENTER]ar fi un leac nemaipomenit. Dac\227 \238mi faci rost de[ENTER]ni\186te s\226mburi de piersic\227, \238\254i dau o sticl\227[ENTER]goal\227. \206i g\227se\186ti la mistre\254ii din afara[ENTER]ora\186ului. Ei dezgroap\227 semin\254ele de piersic\227 pe[ENTER]care le \238nsem\226n\254eaz\227 \254\227ranii."
