gameforge.subquest_04._140_npcChat = "O scrisoare de la fierar"
gameforge.subquest_04._150_sayTitle = "Culeg\227torul de lemne Deokbae:"
gameforge.subquest_04._160_say = "Bine ai venit. Am c\238teva securi bune aici. Vrei[ENTER]s\227 cumperi una? Nu ai nevoie de secure? Atunci de[ENTER]ce te afli aici? Ah, o scrisoare de la Fierar.[ENTER]Mul\254umesc. Eu sunt t\227ietor de lemne dar v\238nd \186i[ENTER]securi alese \186i alte unelte. Uneori comand unele[ENTER]unelte de la el. Asa am devenit buni prieteni."
gameforge.subquest_04._170_say = "Ar trebui s\227 mai ies la o b\227ut\227 cu el la barul[ENTER]Seo-Pyung.[ENTER]\206\254i mul\254umesc c\227 mi-ai adus scrisoarea, \186i[ENTER]transmite-i fierarului salut\227ri de la mine."
gameforge.subquest_04._180_say = "O scrisoare de la fierar?[ENTER]Oh, c\226t timp a trecut de atunci.[ENTER]Unde e scrisoarea? Sper c\227 n-ai pierdut-o pe[ENTER]drum, nu-i a\186a?"
gameforge.subquest_04._190_select = "Poftim"
gameforge.subquest_04._200_select = "Totu\186i nu"
gameforge.subquest_04._20_say = "Hei, tu, noule aventurier! A\186 vrea s\227-\254i cer un[ENTER]serviciu.[ENTER]\206l \186tii pe un tip cu numele de Deokbae?[ENTER]E un t\227ietor de lemne \186i bun prieten de-al meu. E[ENTER]un pic plictisitor, dar este unul dintre pu\254inii[ENTER]t\227ietori de lemne s\226rguincio\186i."
gameforge.subquest_04._210_say = "\206ncheie quest-ul?"
gameforge.subquest_04._220_say = "M\227 bucur mult. \206ntoarce-te cur\226nd!"
gameforge.subquest_04._230_say = "A\186adar ai pierdut-o?[ENTER]Dispari din ochii mei!"
gameforge.subquest_04._240_say = "Du-te la fierer \186i adu-l. Nu pierde \238ns\227[ENTER]scrisoarea de aceast\227 dat\227!"
gameforge.subquest_04._250_sayReward = "Mergi inapoi la Fierar si primeste-ti recompensa."
gameforge.subquest_04._260_targetVid = "\206napoi la Fierar"
gameforge.subquest_04._270_npcChat = "Am dus scrisoarea."
gameforge.subquest_04._280_say = "Deci, ce mai face Deokbae? Hehe, nu s-a schimbat[ENTER]deloc. Mul\254umesc. Ia asta ca si recompens\227. Nu[ENTER]este mult, dar poate fi folositoare \238ntr-o zi.[ENTER]Mul\254umesc din nou."
gameforge.subquest_04._290_sayReward = "Ai primit 4000 de puncte de experien\254\227.[ENTER]Ai primit 3000 Yang."
gameforge.subquest_04._30_say = "Nu l-am v\227zut de mult timp, \186i i-am trimis o[ENTER]scrisoare ca s\227-l \238ntreb ce mai face.[ENTER]Vreau s\227-i duci tu scrisoarea. \206n sat sunt multe[ENTER]probleme, a\186a c\227 fii atent! \170i nu \238ndoi[ENTER]scrisoarea!"
gameforge.subquest_04._40_say = "Oh, nu \186tii cum s\227 ajungi \238n urm\227torul sat? Apas\227[ENTER]litera \" M \" pentru a vedea harta \238n miniatur\227.[ENTER]Un punct albastru va fi afi\186at pe hart\227. Acel[ENTER]punct reprezint\227 portalul care te duce \238n zona[ENTER]adiacent\227. Al doilea sat este de asemenea situat[ENTER]acolo."
gameforge.subquest_04._50_select = "A\186a am s\227 fac."
gameforge.subquest_04._60_select = "Nu mul\254umesc."
gameforge.subquest_04._70_say = "Sigur dore\186ti s\227 renunti la misiune?"
gameforge.subquest_04._80_say = "\206ntoarce-te \238n cur\226nd la mine."
gameforge.subquest_04._90_say = "Atunci nu..."
