gameforge.subquest_08._120_sayTitle = "Negustorul Arme:"
gameforge.subquest_08._130_say = "Poftim? Pl\227cint\227 de orez? Este o nou\227 arm\227!? Da,[ENTER]atunci po\254i ...[ENTER]Oh, te referi la Pl\227cint\227 de orez. De ce n-ai zis[ENTER]din prima? Cel mai bine e s\227 mergi la Octavio. El[ENTER]cunoa\186te totul despre m\238nc\227ruri."
