gameforge.subquest_08._180_say = "Ai un drum lung \238naintea ta.[ENTER]P\226n\227 data viitoare."
gameforge.subquest_08._190_say = "A\186adar, cu siguran\254\227 vei lipsi. Ne mai vedem!"
gameforge.subquest_08._200_say = "Vei vedea, se va merita. C\227l\227torie pl\227cut\227!"
gameforge.subquest_08._20_say = "Scuz\227-m\227 te rog, ma po\254i ajuta? Copilul meu[ENTER]pl\238nge \238ntruna \186i nu \186tiu ce s\227 mai fac s\227-l[ENTER]lini\186tesc. Copilul meu ador\227 Pl\227cint\227 de orez \186i[ENTER]s-ar putea s\227 ajute asta. Cred c\227 Negustorul de[ENTER]armuri \186tie de unde se poate lua pl\227cinta. \206l[ENTER]po\254i \238ntreba pentru mine?"
gameforge.subquest_08._210_makequestbutton = "G\227se\186te-l pe Yu-Rang."
