gameforge.subquest_08._230_sayReward = "Mergi la Yu-Rang v\238nz\227torul de pl\227cint\227. \206l[ENTER]g\227se\186ti \238n satul vecin."
gameforge.subquest_08._240_sayTitle = "Yu-Rang:"
gameforge.subquest_08._250_say = "Te pot ajuta? Oh, Pl\227cint\227 de orez! Desigur c\227[ENTER]\238\254i pot da! Dar ... po\254i face ceva \238nainte pentru[ENTER]mine? Un b\227iat pe nume Taurean vine des pe la[ENTER]mine \186i m\227 deranjeaz\227 f\227r\227 sa-i fac nimic. Dac\227-l[ENTER]pedepse\186ti \238\254i voi da Pl\227cint\227 de orez."
gameforge.subquest_08._260_makequestbutton = "G\227se\186te-l pe Taurean"
