gameforge.subquest_08._40_say = "Dar ... nu pot p\227r\227si acest loc \186i copilul[ENTER]terorizeaz\227 \238ntreaga vecin\227tate ... Nu va dura[ENTER]mult. E\186ti sigur ca n-ai destul timp?"
