gameforge.subquest_10._130_makequestbutton = "Acul de p\227r furat."
gameforge.subquest_10._140_sayReward = "\206ntreab\227-l pe negustorul de arme de acul de p\227r."
gameforge.subquest_10._150_say = "Ce? Crezi ca i-am furat negustoarei de diverse[ENTER]acul de p\227r? Nu, nu, chiar nu. Sincer![ENTER]Hm.. Am fost acolo s\227-i fac o vizit\227 negustoarei[ENTER]de diverse![ENTER]Dar ea n-a fost acolo; \238n schimb am v\227zut \238n[ENTER]locul ei o arca\186\227 jur\227m\226nt alb. C\226nd m-a v\227zut, a[ENTER]fugit. Poate c\227 ea a furat acul de p\227r."
