gameforge.subquest_10._190_npcChat = "Am aici Ac decorativ pentru p\227r."
gameforge.subquest_10._200_say = "Oh, mul\254umesc mult.[ENTER]\206n sf\226r\186it, am din nou acul meu de p\227r favorit.[ENTER]M-ai ajutat deja de at\226tea ori. Cum m-a\186 putea[ENTER]revan\186a? Am o hart\227 de c\227l\227rie. E doar o mic\227[ENTER]aten\254ie; mie nu-mi mai folose\186te, deoarece eu nu[ENTER]-mi voi mai p\227r\227si a\186a de lesne magazinul.[ENTER]Accept-o \238n semn de recuno\186tin\254\227. \206\254i mul\254umesc[ENTER]mult."
gameforge.subquest_10._20_say = "Te rog, ascult\227-m\227, m\227 simt at\226t de r\227u. Am[ENTER]plecat un pic din magazin, deoarece trebuia s\227[ENTER]rezolv ceva foarte important. \206n lipsa mea,[ENTER]cineva mi-a furat acul de p\227r favorit."
