gameforge.subquest_10._260_say = "Unde este acul meu de p\227r favorit?[ENTER]N-a fost s\227 fie ... pa"
gameforge.subquest_10._270_say = "Mul\254umesc. Chiar conteaz\227 foarte mult pentru mine."
