gameforge.subquest_11._110_npcChat = "L-ai v\227zut pe fratele lui Mirine?"
gameforge.subquest_11._120_say = "M-am \238ndr\227gostit, f\227r\227 s\227 \186tiu c\227 iubirea[ENTER]\238nseamn\227 desp\227r\254ire. Pe cine cau\254i? Pe fratele[ENTER]lui Mirine? Am stat un pic cu el de vorb\227 \238nainte[ENTER]s\227 plece \238n mun\254i pentru a c\227uta ierburi rare ...[ENTER]Nu \186tiu unde e acum. V\226n\227torul acestui sat merge[ENTER]des \238n mun\254i. De ce nu-l \238ntrebi?[ENTER]Tra la la, iubirea e trist\227, dar frumoas\227."
gameforge.subquest_11._130_targetVid = "\206ntreab\227-l pe Yang-Shin de fratele lui Mirine."
gameforge.subquest_11._140_say = "Fratele lui Mirine? Da, era \238n c\227utare de plante[ENTER]\238n mun\254i. A fost at\226t de bucuros atunci c\226nd a[ENTER]g\227sit ni\186te plante rare. Voia s\227 cumpere ni\186te[ENTER]haine pentru sora lui din profitul pe care-l[ENTER]scotea din afacerea cu plante. Este foarte[ENTER]dr\227gu\254. Sunt sigur c\227 se va \238ntoarce \238n c\226teva[ENTER]zile. Nu crezi?"
gameforge.subquest_11._150_targetVid = "Poveste\186te-i lui Mirine nout\227\254ile."
gameforge.subquest_11._160_npcChat = "Nout\227\254ile despre fratele lui Mirine."
gameforge.subquest_11._170_say = "Uite, am primit o scrisoare de la fratele meu![ENTER]Mi-a scris c\227 a g\227sit un loc plin de plante \186i va[ENTER]dura p\238n\227 se va \238ntoarce acas\227.[ENTER]\206mi cer scuze, nu trebuia s\227 te deranjez cu[ENTER]a\186aceva. Poftim, nu este mult, dar sper ca vei[ENTER]accepta \186i m\227 vei ierta. Mul\254umesc pentru ajutor."
gameforge.subquest_11._180_sayReward = "Prime\186ti 122.000 puncte de experien\254\227.[ENTER]Ai primit 5.000 Yang."
gameforge.subquest_11._20_npcChat = "G\227se\186te-l pe fratele meu."
gameforge.subquest_11._30_say = "Pot s\227-\254i cer o favoare? Fratele meu e plecat de[ENTER]mult. \170i nu mai am nicio veste de la el. \206ncep[ENTER]s\227-mi fac griji. Ai putea s\227-l cau\254i?"
gameforge.subquest_11._40_say = "Fratele meu voia s\227-l viziteze pe muzicianul[ENTER]Yu-Hwan din satul vecin. Dac\227 mergi la Yu-Hwan,[ENTER]cu siguran\254\227 c\227 \238\254i va da nout\227\254i despre fratele[ENTER]meu. \206\254i mul\254umesc de pe-acuma."
gameforge.subquest_11._50_select = "Ok, am s-o rezolv."
gameforge.subquest_11._60_say = "E\186ti sigur c\227 te dai b\227tut la aceast\227 misiune?"
gameforge.subquest_11._70_say = "Mii de mul\254umiri. Te rog caut\227-l pentru mine. \206mi[ENTER]fac mari griji. Pe cur\226nd."
gameforge.subquest_11._80_say = "P\227cat c\227 nu vrei s\227 m\227 aju\254i...[ENTER]Pe cur\226nd."
gameforge.subquest_11._90_say = "Vrei s\227-l cau\254i pentru mine?[ENTER]Mii de mul\254umiri. Sunt foarte \238ngrijorat\227 pentru[ENTER]el. Mult noroc."
