gameforge.subquest_12._120_sayTitle = "Mi-Jung din Jur\227m\238ntul Alb"
gameforge.subquest_12._130_sayReward = "Mergi \186i ucide pe Mi-Jung din jur\227m\226ntul alb.[ENTER]Apoi mergi \238napoi la Gardian."
gameforge.subquest_12._140_targetVid = "Mergi la Gardian."
gameforge.subquest_12._150_sayTitle = "Ai ucis pe Mi-Jung din Jur\227m\238ntul alb"
gameforge.subquest_12._160_sayReward = "\206ntoarce-te la Gardian pentru a-\254i primi[ENTER]recompensa."
gameforge.subquest_12._170_npcChat = "Am ucis pe Mi-Jung"
gameforge.subquest_12._180_say = "Oh, tu chiar e\186ti a\186a bun cum se spune. E\186ti[ENTER]nemaipomenit de bun. Mul\254umit\227 \254ie, problema cu[ENTER]jur\227m\226ntul alb s-a simplificat. Bravo!"
gameforge.subquest_12._190_sayReward = "Ai primit 122000 puncte de experien\254\227.[ENTER]Ai primit 20000 Yang.[ENTER]Ai primit Br\227\254ar\227 de Argint."
gameforge.subquest_12._20_say = "Vino un pic aici. E\186ti un lupt\227tor bun. Am auzit[ENTER]multe despre tine de la comandant."
gameforge.subquest_12._30_say = "Po\254i s\227 faci ceva \238mpotriva lui Mi-Jung de la[ENTER]jur\227m\226ntul alb, care ne face at\226t de multe[ENTER]probleme? E greu s\227 protej\227m satul \186i locuitorii[ENTER]s\227i de desele atacuri ale jur\227m\226ntului alb. Dac\227[ENTER]o ucidem pe Mi-Jung, una dintre conduc\227torii lor,[ENTER]vom reu\186i s\227 schimb\227m situa\254ia. Siguran\254a satului[ENTER]nostru se afl\227 \238n m\226inile tale.[ENTER]Am \238ncredere \238n tine."
gameforge.subquest_12._40_select = "Da, o voi face."
gameforge.subquest_12._50_select = "Nu acum"
gameforge.subquest_12._60_say = "Chiar nu vrei s\227 ne aju\254i? "
gameforge.subquest_12._70_say = "Nu este momentul potrivit. Revino mai t\226rziu."
gameforge.subquest_12._80_say = "Dac\227 tu nu vrei, nu se poate face nimic.[ENTER]Atunci, pleac\227 ..."
gameforge.subquest_12._90_say = "Chiar nu vrei s\227 ne aju\254i? "
gameforge.subquest_13 = {}
gameforge.subquest_13._100_targetVid = "Mergi la Ariyoung"
gameforge.subquest_13._10_targetVid = "Confec\254ionez materiale pentru arme."
gameforge.subquest_13._110_targetVid = "Mergi la Ah-Yu."
gameforge.subquest_13._120_sayReward = "Negustorul de arme are nevoie de ajutorul t\227u.[ENTER]F\227-i rost de minereu de fier de la Uriel \186i p\238nz\227[ENTER]de la Ariyoung."
gameforge.subquest_13._130_npcChat = "Ich brauche Eisenerz"
gameforge.subquest_13._140_say = "Ai nevoie de minereu de fier? \222i-a\186 putea da eu,[ENTER]dac\227 \238mi faci un serviciu."
gameforge.subquest_13._150_say = "Am pierdut ceva c\226nd am fugit de tigri pentru[ENTER]a-mi salva via\254a: un pachet care con\254inea c\227r\254i[ENTER]importante, legate \238ntre ele cu ni\186te c\226rpe.[ENTER]Dac\227 nu le recuperez nu voi putea continua[ENTER]cercet\227rile despre Pietrele Metin. Adu-mi[ENTER]pachetul \238napoi \186i vei primi ni\186te minereu de[ENTER]fier."
gameforge.subquest_13._160_npcChat = "Am g\227sit pachetul."
gameforge.subquest_13._170_say = "Mul\254umesc![ENTER]Apelez la tine mult prea des pentru sevicii.[ENTER]Poftim ni\186te minereu de fier. Sper s\227-\186i[ENTER]\238ndeplineasc\227 scopul."
gameforge.subquest_13._180_say = "Poftim? Ai nevoie de mai mult minereu de fier?[ENTER]E\186ti con\186tient c\227 nu creste \238n copaci! \206\254i voi da[ENTER]mai mult dar \238nainte trebuie s\227-mi faci o[ENTER]favoare. Tigrii mi-au furat Pachetul. A trebuit[ENTER]s\227 fug pentru a-mi salva via\254a \186i erau documente[ENTER]foarte importante \238n el. Dac\227 nu-l pot recupera[ENTER]nu voi putea continua cercetarea despre Pietrele[ENTER]Metin. Te rog recupereaz\227-mi pachetul."
gameforge.subquest_13._190_say = "Dar \254i-am dat deja. Ai uitat?"
gameforge.subquest_13._200_sayTitle = "Pachet g\227sit"
gameforge.subquest_13._20_npcChat = "Material pentru arme"
gameforge.subquest_13._210_say = "Ai g\227sit bocceaua lui Uriel. Du-te \238napoi la el."
gameforge.subquest_13._220_npcChat = "D\227-mi in."
gameforge.subquest_13._230_say = "Ai nevoie de p\238nza? Am dat-o lui Ah-Yu. A\186teapt\227![ENTER]Dac\227 tot o vezi ii po\254i da \186i aceast\227 scrisoare.[ENTER]Suntem prieteni buni dar din cauza copilului ei[ENTER]nu ne-am mai v\227zut demult. Ii voi spune sa-\254i dea[ENTER]\186i p\238nz\227 ..."
gameforge.subquest_13._240_say = "Ariyoung:[ENTER]Cu siguran\254\227 c\227 ai primit in de la Ah-Yu, nu-i[ENTER]a\186a?"
gameforge.subquest_13._250_npcChat = "Scrisoarea lui Ariyoung"
gameforge.subquest_13._260_say = "O scrisoare de la Ariyoung? Este pl\227cut sa auzi[ENTER]vesti de la ea dup\227 at\226ta timp. Obi\186nuiam s\227 ne[ENTER]\238nt\226lnim des sa vorbim dar \238n ultimul timp a[ENTER]devenit cam greu acest lucru. A\186teapt\227 pu\254in.[ENTER]Scrie \238n scrisoare c\227 ai nevoie de P\226nz\227!?[ENTER]Ariyoung mi-a dat a\186a ceva \186i \238\254i pot da \186i \254ie.[ENTER]Mul\254umesc ca ai adus scrisoarea.[ENTER]\206i voi trimite r\227spuns imediat..."
gameforge.subquest_13._270_qSetTitle = "S\227 mergem la Negustorul de arme"
gameforge.subquest_13._280_targetVid = "Mergi la negustorul de arme."
gameforge.subquest_13._290_sayTitle = "Pred\227 materialele"
gameforge.subquest_13._300_sayReward = "Am marfa. Hai la negustorul de arme."
gameforge.subquest_13._30_say = "Hei, trebuie s\227-mi faci un serviciu. \206ncerc s\227[ENTER]confectionez arme noi. Nu e u\186or s\227 g\227sesc[ENTER]materialele adecvate pentru aceasta. Am multe[ENTER]comenzi \186i nu pot s\227 plec \238n c\227utarea[ENTER]materialelor. Ai putea s\227 le procuri tu \238n locul[ENTER]meu?"
gameforge.subquest_13._310_say = "Bravo. E\186ti foarte rapid \186i capabil. Las\227-m\227 acum[ENTER]s\227 m\227 ocup de arme.[ENTER]*cioc, cioc *[ENTER]Iat\227-le. Acestea sunt noile tipuri de arme.[ENTER]Am f\227cut tot ce am putut. Sper c\227-\254i place arma.[ENTER]S\227 te bucuri de ea!"
gameforge.subquest_13._320_sayTitle = "Recompens\227:"
gameforge.subquest_13._330_sayReward = "Ai primit 122000 puncte de experien\254\227.[ENTER]Ai primit 20000 Yang."
gameforge.subquest_13._340_sayReward = "Ai primit Sabie lat\227 +3."
gameforge.subquest_13._350_sayReward = "Ai primit Pumnal Foarfece +3."
gameforge.subquest_13._360_sayReward = "Ai primit Evantai P\227un +3."
gameforge.subquest_13._40_say = "Bine\238n\254eles c\227 te voi r\227spl\227ti pentru asta. C\226nd[ENTER]armele vor fi gata \238\254i voi da una din ele.[ENTER]Am nevoie de urm\227toarele materiale: minereu de[ENTER]fier \186i in.[ENTER]Minereu de fier g\227se\186ti la Uriel \186i in la[ENTER]Ariyoung. D\227-mi de \186tire c\226nd ai g\227sit toate[ENTER]materialele."
gameforge.subquest_13._50_say = "Chiar nu vrei s\227 \238ndepline\186ti sarcina?"
gameforge.subquest_13._60_say = "Cred c\227 a fost prea mult pentru tine.[ENTER]Revino c\226nd ai timp!"
gameforge.subquest_13._70_say = "Dac\227 nu vrei, nu se poate face nimic.[ENTER]Pe cur\226nd."
gameforge.subquest_13._80_say = "Foarte bine![ENTER]De \238ndat\227 ce armele vor fi gata, vei primi una de[ENTER]la mine. Mult noroc."
gameforge.subquest_13._90_sendLetter = "Caut\227 materiale"
