gameforge.subquest_15._100_targetVid = "\206ntoarce-te la Gardianul Ora\186ului"
gameforge.subquest_15._10_targetVid = "Eun-Jung din Jur\227m\238ntul Alb"
gameforge.subquest_15._110_sayReward = "Ai ucis pe Eun-Jung din Jur\227m\238ntul Alb.[ENTER]\206ntoarce-te la Gardianul Ora\186ului \186i rapoteaz\227-i."
gameforge.subquest_15._120_say = "E\186ti mai bun dec\238t m-am a\186teptat. Noi nu am putut[ENTER]face nimic \238mpotriva celor doi lideri din[ENTER]Jur\227m\238ntul Alb iar tu i-ai \238nfr\238nt cu u\186urin\254\227."
gameforge.subquest_15._130_say = "Incredibil. Ar trebui s\227 prime\186ti o recompens\227 pe[ENTER]m\227sur\227. Ia te rog asta \186i continu\227 sa munce\186ti[ENTER]pentru men\254inerea lini\186tii satului."
gameforge.subquest_15._140_sayReward = "Ai primit 150000 puncte de experien\254\227.[ENTER]Ai primit 25000 Yang.[ENTER]Ai primit Colier de Aur +4."
gameforge.subquest_15._20_say = "Vino aici pentru un moment.[ENTER]Am auzit multe despre tine de la C\227pitan. Pari[ENTER]ne\238nfricat. De aceea am nevoie din nou de[ENTER]ajutorul t\227u: Jur\227m\238ntul Alb se poart\227 \186i mai[ENTER]ciudat dec\238t \238nainte."
gameforge.subquest_15._30_say = "Ai ucis pe Mi-Jung, liderul Jur\227m\238ntului Alb. Dar[ENTER]\238nc\227 suntem \238n pericol! Pericolul din partea[ENTER]Jur\227m\238ntului Alb e mai mare ca niciodat\227."
gameforge.subquest_15._40_say = "Pentru a pune cap\227t trebuie eliminat liderul[ENTER]Eun-Jung. Cu restul n-ar trebui s\227 fie probleme.[ENTER]Mergi \186i ucide pe Eun-Jung! Soarta noastr\227 este[ENTER]\238n m\238inile tale!"
gameforge.subquest_15._50_sayTitle = "Gardian:"
gameforge.subquest_15._60_say = "Revii mai t\238rziu? E\186ti persoana potrivit\227 pentru[ENTER]asta."
gameforge.subquest_15._70_say = "Nu pute\254i? Bine. Pe cur\226nd."
gameforge.subquest_15._80_say = "\170tiam c\227 ne vei ajuta. Ucide-l tu pe Eun-Jung;[ENTER]noi ne ocup\227m de resul. Mult noroc!"
gameforge.subquest_15._90_sayReward = "Ucide liderul Eun-Jung \238n speran\254a c\227 Jur\227m\238ntul[ENTER]Alb se va potoli."
gameforge.subquest_16 = {}
gameforge.subquest_16._100_qSetTitle = "\206ntreab\227 pe Yu-Hwan"
gameforge.subquest_16._10_targetVid = "Caut\227 cavaleria blindat\227."
gameforge.subquest_16._110_targetVid = "Mergi la Yu-Hwan"
gameforge.subquest_16._120_say = "Viata e frumoas\227 - dragostea e frumoas\227 ...[ENTER]Oh, din nou tu? Ce dore\186ti acum? Informa\254ii[ENTER]despre cavaleria \238n armur\227? De ce m\227 \238ntrebi[ENTER]asta?[ENTER]C\227pitanul are planuri m\227re\254e?"
gameforge.subquest_16._130_sayTitle = "Yu-Hwan: "
gameforge.subquest_16._140_say = "Povesti adev\227rate despre cavaleria \238n armur\227 au[ENTER]supravie\254uit trecerii timpului \186i cunosc c\238teva[ENTER]c\238ntece despre cavaleria \238n armur\227. A\186teapt\227 o[ENTER]secund\227 ...[ENTER]Oh, te gr\227be\186ti? \206n zile astea nimeni nu mai are[ENTER]r\227bdare s\227 asculte ...[ENTER]Deci, cavaleria lui Isup a fost aproape[ENTER]invincibil\227, solda\254i bine antrena\254i, armuri[ENTER]rezistente \186i \238n acela\186i timp rapid\227."
gameforge.subquest_16._150_say = "A fost cea mai mare \186i cea mai antrenat\227[ENTER]cavalerie vreodat\227. Multe \254ari au fost supuse[ENTER]pentru c\227 nimeni \186i nimic nu putea opri aceasta[ENTER]cavalerie. Dar ai nevoie de metode dure de[ENTER]antrenament \186i mult minereu de fier de calitate[ENTER]superioar\227 pentru a forma o asa cavalerie. Ar[ENTER]trebui s\227-l \238ntrebi pe Negustorul ambulant \186i pe[ENTER]Uriel despre asta. Ei poate \186tiu mai multe[ENTER]detalii."
gameforge.subquest_16._160_makequestbutton = "Mergi la Negustorul ambulant"
gameforge.subquest_16._170_qSetTitle = "Cavaleria blindat\227."
gameforge.subquest_16._180_targetVid = "Negustorul ambulant:"
gameforge.subquest_16._190_sayReward = "Muzicianul Yu-Hwan spune ca Negustorul ambulant[ENTER]\186i Uriel de\254in informa\254ii despre cavaleria[ENTER]blindat\227. Prima dat\227 mergi la Negustorul[ENTER]ambulant."
gameforge.subquest_16._200_sayTitle = "Negustorul ambulant:"
gameforge.subquest_16._20_npcChat = "Cavaleria blindat\227."
gameforge.subquest_16._210_say = "Ce dore\186ti de la un simplu Negustor ambulant ca[ENTER]mine? Armura de fier de la cavaleria blindat\227?[ENTER]Acestea sunt pove\186ti vechi, cine e interesat de[ENTER]ele? Trebuie s\227-mi c\238\186tig existen\254a asa ca nu pot[ENTER]sta la discu\254ii toat\227 ziua."
gameforge.subquest_16._220_say = "Ce spui? Ah da, cavaleria.[ENTER]Din c\238te \186tiu eu purtau armuri speciale \186i[ENTER]producerea unei asemena armuri necesita[ENTER]cuno\186tin\254e speciale. Au fost cele mai bune armuri[ENTER]f\227cute vreodat\227. Cu\254itele obi\186nuite \186i s\227ge\254ile[ENTER]nu puteau str\227punge aceste armuri."
gameforge.subquest_16._230_say = "\206\254i po\254i imagina c\226t de importante erau armurile[ENTER]prin banii necesari pentru a \238nfiin\254a cavaleria.[ENTER]Se spune c\227 au folosit toate trezoriile[ENTER]regatelor! Dac\227 a\186 vinde a\186a armuri a\186 fi[ENTER]asigurat pe viat\227."
gameforge.subquest_16._240_say = "\206n zile nostre, armurile pot fi f\227cute cu Pietre[ENTER]Metin. Cu aceste tipuri de armuri nu mai este un[ENTER]vis \238n a avea o cavalerie ca \238n vremurile[ENTER]str\227vechi. Vorbesc prea mult, trebuie sa plec."
gameforge.subquest_16._250_sayTitle = "Cavaleria blindat\227."
gameforge.subquest_16._260_say = "Negustorul ambulant \186tia ceva despre armurile de[ENTER]fier ale cavaleriei blindate. Acum mergi \238n[ENTER]urm\227torul sat \186i vorbe\186te cu Uriel despre[ENTER]antrenament."
gameforge.subquest_16._270_sayTitle = "Uriel:"
gameforge.subquest_16._280_say = "Ce te aduce pe aici? Cavaleria blindat\227? Normal[ENTER]s\227 cunosc c\238te ceva despre ea, to\254i \186tiu. Aceast\227[ENTER]cavalerie va trece \238n istorie ca fiind una dintre[ENTER]cele mai m\227re\254e. O parte din ce se spune despre[ENTER]cavalerie este exagerat \238nsa de acei solda\254i se[ENTER]temeau multi."
gameforge.subquest_16._290_say = "Cavaleria blindat\227 era superioar\227 tuturor mai[ENTER]ales datorit\227 antrenamentului dur. Doar cei mai[ENTER]buni reu\186eau s\227 termine antrenamentul,[ENTER]majoritatea nu supravie\254uiau. Dac\227 ar exista \186i[ENTER]\238n zile e noastre un asemenea antrenament multi[ENTER]solda\254i n-ar mai exista."
gameforge.subquest_16._300_say = "\206\254i voi da c\238teva detalii despre antrenament[ENTER]pentru a \186tii c\238te ceva despre el. \170tiu c\227 ni\186te[ENTER]r\227zboaie teribile se duc \238n acest moment, \238nsa nu[ENTER]sunt sigur dac\227 e o idee bun\227 sa ridic\227m o[ENTER]cavalerie ca cea din timpuri str\227vechi."
gameforge.subquest_16._30_say = "Am o nou\227 sarcin\227 pentru tine. Ai ordinul s\227[ENTER]aduni informa\254ii despre cavaleria \238narmat\227. Era[ENTER]unitatea cea mai important\227 a lui Isup, regele[ENTER]\238ntemeietor \186i ap\227r\227torul continentului."
gameforge.subquest_16._310_say = "Du-te la comandant \186i raporteaz\227-i tot ce ai[ENTER]aflat despre cavaleria \238narmat\227."
gameforge.subquest_16._320_makequestbutton = "Mergi la c\227pitan"
gameforge.subquest_16._330_npcChat = "Raport despre cavaleria blindat\227"
gameforge.subquest_16._340_sayTitle = "C\227pitan"
gameforge.subquest_16._350_say = "Ai reu\186it s\227 fli ceva? Spune-mi ...[ENTER]Hmm, foarte interesant. Nu este nimic mai mult[ENTER]dec\238t armuri grele \186i antrenament dur? Atunci ar[ENTER]fi posibil! O asemenea armat\227 ar putea reuni cele[ENTER]trei regate!"
gameforge.subquest_16._360_say = "Dar va fi costisitor \186i vom avea nevoie de o[ENTER]mul\254ime de fierari buni. Vom recruta oameni[ENTER]pentru a deveni cei mai buni dintre cei mai buni.[ENTER]Nu, nu te uita asa la mine. Nu-\254i face griji,[ENTER]pentru moment ai f\227cut destule."
gameforge.subquest_16._370_say = "Poftim recompensa \186i odihne\186te-te![ENTER]Ne vedem mai t\238rziu!"
gameforge.subquest_16._380_sayReward = "Ai primit 150.000 puncte de experien\254\227.[ENTER]Ai primit 30.000 Yang.[ENTER]Ai primit cercei de aur."
gameforge.subquest_16._40_say = "Cu informa\254iile str\238nse de tine vom putea m\227ri[ENTER]puterea militar\227. Viziteaz\227-l prima data pe[ENTER]muzicianul Yu-Hwan. Sunt sigur c\227 \186tie c\238te ceva[ENTER]despre cavaleria lui Isup."
gameforge.subquest_16._50_say = "Asa cum \238\254i place. Pe mai t\226rziu atunci."
gameforge.subquest_16._60_say = "Voi conduce o asemenea cavalerie vreodat\227?[ENTER]Fi atent."
gameforge.subquest_16._70_say = "Mul\254umesc, ai grij\227 de tine. "
gameforge.subquest_16._80_sayTitle = "Cavaleria blindat\227."
gameforge.subquest_16._90_sayReward = "C\227pitanul are nevoie de informa\254ii despre[ENTER]legendara cavalerie a lui Isup. Muzicianul[ENTER]Yu-Hwan probabil are informa\254ii despre asta.[ENTER]Mergi \186i \238ntreab\227-l."
gameforge.subquest_17 = {}
gameforge.subquest_17._100_targetVid = "Vorbe\186te cu V\226nz\227toarea de la magazinul General."
gameforge.subquest_17._10_targetVid = "Povestea So\254ului lui Ariyoung."
gameforge.subquest_17._110_say = "Mergi la V\226nz\227toarea de diverse \186i \238ntreab\227 de[ENTER]so\254ul lui Ariyoung."
gameforge.subquest_17._120_npcChat = "So\254ul lui Ariyoung"
gameforge.subquest_17._130_say = "Este o poveste trist\227. Nu \186tie ce a p\227\254it so\254ul[ENTER]ei? El este \238ntr-un loc de unde nu se \238ntoarce[ENTER]nimeni...[ENTER]Era pe drumul \238napoi spre sat c\226nd deodat\227 a fost[ENTER]atacat de c\227tre Banda V\226ntul Negru."
gameforge.subquest_17._140_say = "Va fi dezam\227git\227 c\226nd ii vei povesti.[ENTER]Se iubeau reciproc. Dar trebuie s\227 afle.. Altfel[ENTER]incertitudinea o va ucide."
gameforge.subquest_17._150_targetVid = "Ve\186ti proaste"
gameforge.subquest_17._160_sayTitle = "Ariyoung:"
gameforge.subquest_17._170_say = "V\226nz\227toarea de la Magazinul General are ve\186ti[ENTER]proaste. Mergi la Ariyoung \186i poveste\186te-i despre[ENTER]moartea so\254ului ei."
gameforge.subquest_17._180_npcChat = "So\254ul t\227u a murit..."
gameforge.subquest_17._190_say = "Ce... ce spui?! El... el a fot ucis de Banda[ENTER]V\226ntul negru? Oh... nu... e mort...[ENTER]Nu \186tiu ce m\227 fac f\227r\227 el!"
gameforge.subquest_17._200_say = "\206mi aduci te rog trupul so\254ului meu? Astfel \238mi[ENTER]voi putea lua r\227mas bun de la el. Iar dac\227 nu e[ENTER]posibil, adu-mi o amintire de la el. Sunt sigur\227[ENTER]c\227 Goo-Pae din Banda V\226ntul Negru va avea cu[ENTER]siguran\254\227 ceva. Te rog, adu-mi orice po\254i, dac\227[ENTER]i-a apar\254inut lui."
gameforge.subquest_17._20_say = "A trecut mult timp de c\226nd n-am auzit nimic de[ENTER]so\254ul meu. \206mi fac griji. Sper c\227 nu i s-a[ENTER]\238nt\226mplat nimic. \170tiu: Nu-\254i folose\186te[ENTER]\238ngrijorarea c\226nd nu po\254i face nimic.Dar inima[ENTER]mea bate at\226t de rapid \238nc\226t nu m\227 pot calma."
gameforge.subquest_17._210_select = "Da, te ajut."
gameforge.subquest_17._220_say = "\206ntoarce-te dac\227 te r\227zg\226nde\186ti. Te rog..."
gameforge.subquest_17._230_say = "Nu ai g\227sit nimic? Ei bine, mul\254umesc oricum...[ENTER]Oh, biata de mine!"
gameforge.subquest_17._240_say = "Nu pot s\227-\254i spun c\226t sunt de recunosc\227toare. M\227[ENTER]voi ruga pentru tine."
gameforge.subquest_17._250_sendLetter = "Omoar\227 ni\186te Goo-Pae"
gameforge.subquest_17._260_say = "Banda V\226ntul Negru l-a jefuit \186i omor\226t pe so\254ul[ENTER]lui Ariyoung. Ucide-l pe Goo-Paes p\226n\227 g\227se\186ti o[ENTER]amintire de la so\254ul ei."
gameforge.subquest_17._270_npcChat = "Despre so\254ul t\227u..."
gameforge.subquest_17._280_say = "Cum a mers? Ai g\227sit ceva legat de so\254ul meu? A[ENTER]\238nsemnat totul pentru mine. Nimic?"
gameforge.subquest_17._290_select = "Nu \238nc\227. Voi mai c\227uta!"
gameforge.subquest_17._300_say = "Goo-Pae din Banda V\226ntul Negru nu e un adversar[ENTER]usor. Du-te \186i odihne\186te-te. Mul\254umesc pentru[ENTER]ajutor."
gameforge.subquest_17._30_say = "Sper ca V\226nz\227toarea de diverse s\227 fi auzit ceva[ENTER]despre so\254ul meu. Ea are mul\254i clien\254i; Poate i-a[ENTER]povestit cineva ceva."
gameforge.subquest_17._310_say = "Atunci va trebui s\227 a\186tept dup\227 alt erou care m\227[ENTER]va ajuta.[ENTER]La revedere."
gameforge.subquest_17._320_say = "Oh, e\186ti at\226t de amabil! Te rog, adu-mi o[ENTER]amintire de la so\254ul meu."
gameforge.subquest_17._330_sendLetter = "Verigheta lui Ariyoung"
gameforge.subquest_17._340_targetVid = "Mergi la Ariyoung"
gameforge.subquest_17._350_sayTitle = "Mergi la Ariyoung"
