gameforge.subquest_18._10_targetVid = "Unde s-a Ascuns?"
gameforge.subquest_18._110_npcChat = "Unde este so\254ul t\227u?"
gameforge.subquest_18._120_say = "Nu \186tiu unde s-ar putea ascunde.[ENTER]A devenit a\186a bun \238n asta \238nc\226t e greu s\227-l[ENTER]g\227sesc. Chiar trebuie s\227-i leg un clopo\254el la gat[ENTER]a\186a cum mi-a fost recomandat?"
gameforge.subquest_18._130_npcChat = "Gase\186te-l pe Soon!"
gameforge.subquest_18._140_say = "Auzi un poem minunat. \206nc\226ntat de cuvintele pe[ENTER]care le auzi dai peste un b\227rbat \238mbr\227cat \238n[ENTER]vechituri.[ENTER][ENTER]El trebuie s\227 fie so\254ul lui Aranyo![ENTER][ENTER]C\226nd voiai s\227 te \238ntorci la Aranyo te-a apucat de[ENTER]um\227r."
gameforge.subquest_18._150_say = "Tu nu e\186ti de prin locurile astea. Te-a trimis[ENTER]so\254ia mea?[ENTER]Oh nu! El \186tie cine sunt! Ce s\227-i spun acum?"
gameforge.subquest_18._153_select = "Ha, ha. Treceam pe aici din \238nt\226mplare."
gameforge.subquest_18._157_select = "De fapt"
gameforge.subquest_18._160_say = "Aha. Ce m\227 bucur s\227 te cunosc, ha, ha.[ENTER]Ce vreme minunat\227, nu-i a\186a?[ENTER]Ai citit vreo carte bun\227 \238n ultima vreme? Eu[ENTER]citesc momentan cartea despre Oja. \222i-o recomand[ENTER]din suflet."
gameforge.subquest_18._170_say = "Am dreptate, nu? Am ajuns s\227 nu mai pot citi \238n[ENTER]pace \238n propria cas\227. Nu vrea sa priceap\227 \186i tot[ENTER]trimite oameni s\227 m\227 g\227seasc\227 ... M-ai g\227sit acum[ENTER]aici dar \238n secunda urm\227toare pot sa fiu \238n alt\227[ENTER]parte. Ce ai zice dac\227 n-ai \186opti nimic c\227 m-ai[ENTER]g\227sit aici? Dac\227 faci asta \238\254i voi da sfaturi[ENTER]bune legate de v\238n\227toare."
gameforge.subquest_18._180_sendLetter = "\206napoi la Aranyo"
gameforge.subquest_18._190_say = "\206ntoarce-te la Aranyo \186i spune-i c\227 nu l-ai g\227sit[ENTER]pe Soon."
gameforge.subquest_18._200_npcChat = "Secretul lui Soon."
gameforge.subquest_18._20_sayTitle = "Aranyo:"
gameforge.subquest_18._210_say = "Nu l-ai g\227sit?[ENTER]Eu am montat chiar \186i capcane. Unde Dumnezeu s-o[ENTER]fi ascuns? Sunt at\226t de ocupat\227. Ce mai destin[ENTER]mizerabil!"
gameforge.subquest_18._220_sendLetter = "\206napoi la Soon"
gameforge.subquest_18._230_say = "\206ntoarce-te la Soon \186i spune-i c\227 ai avut succes."
gameforge.subquest_18._240_npcChat = "Am ajuns."
gameforge.subquest_18._250_say = "Totul a decurs bine? Mi-ai salvat via\254a! \222ine[ENTER]asta aventurierule. Cum am promis, uite[ENTER]recompensa."
gameforge.subquest_18._260_sayReward = "Ai primit 7000 puncte de experien\254\227."
gameforge.subquest_18._270_sayReward = "Ai primit 10000 Yang."
gameforge.subquest_18._280_say = "\206ntoarce-te la Aranyo \186i spune-i unde l-ai g\227sit[ENTER]pe Soon."
gameforge.subquest_18._290_npcChat = "Jocul de-a va\254i-ascunselea e dificil."
gameforge.subquest_18._300_say = "\206\254i mul\254umesc mult c\227 nu m-ai dat \238n vileag. E[ENTER]tare greu s\227 te ascunzi de propria nevast\227. Eu nu[ENTER]vreau dec\226t s\227 studiez ni\254el."
gameforge.subquest_18._30_say = "So\254ul meu este \238ntr-adev\227r cea mai mare[ENTER]nenorocire a mea; \238\186i zice \238nv\227\254at![ENTER]\206n timp ce noi ne zbatem pentru p\226inea cea de[ENTER]toate zilele, el nu face altceva dec\226t s\227[ENTER]citeasc\227 c\227r\254i.[ENTER]L-ai v\227zut? Cum Dumnezeu m-am m\227ritat eu cu un[ENTER]vierme roade-carte ca \227sta?"
gameforge.subquest_18._310_npcChat = "Loca\254ia lui Soon"
gameforge.subquest_18._320_say = "L-ai g\227sit?[ENTER]Mul\254umesc! Dac\227 afl\227 c\227 l-ai g\227sit s-ar putea s\227[ENTER]se ascund\227 iar. Voi merge la el de \238ndat\227. De[ENTER]data asta voi pune mana pe el! \222ine asta ca[ENTER]recuno\186tin\254\227 din partea mea."
gameforge.subquest_18._33_select = "Te ajut."
gameforge.subquest_18._37_select = "Nu am timp pentru asta."
gameforge.subquest_18._40_say = "Vrei s\227 \238nchei aceast\227 sarcin\227?"
gameforge.subquest_18._50_say = "Na bine ...[ENTER]Poate te ui\254i mai t\226rziu s\227 vezi ce face."
gameforge.subquest_18._60_say = "Poate \238l g\227se\186ti totu\186i... "
gameforge.subquest_18._70_say = "A\186 fi foarte recunosc\227toare pentru asta. Dac\227[ENTER]descoperi un scrib\227l\227u am\227r\226t, anun\254\227-m\227.[ENTER]Presupun c\227 este singurul din sat. Poate c\227[ENTER]tocmai compune o poezie sau dou\227, \186i prefer\227 s\227[ENTER]fie singur. Dac\227 afl\227 c\227 \238l caut, s-ar putea s\227[ENTER]fug\227. Fii deci atent!"
gameforge.subquest_18._80_sendLetter = "G\227se\186te-l pe Soon"
gameforge.subquest_18._90_sayTitle = "Caut\227 \186oarecele de bibliotec\227"
