gameforge.subquest_19._150_say = "Piele neprelucrat\227 de lup, minunat ... Oh, nu.[ENTER]Aceasta nu este bun\227. \206ntoarce-te la Lupii Gri.[ENTER]Po\254i g\227si alta mai buna!?"
gameforge.subquest_19._160_say = "Am nevoie de un p\227m\227tuf pentru praf ca lumea. \206mi[ENTER]pare r\227u, dar \227sta nu-mi folose\186te la nimic."
gameforge.subquest_19._170_select = "Mai \238ncerc odat\227,"
gameforge.subquest_19._180_select = "Nu mai am chef."
gameforge.subquest_19._190_say = "Chiar vrei s\227 \238nchei aceast\227 sarcin\227?"
gameforge.subquest_19._200_say = "\206ntoarce-te mai t\238rziu."
gameforge.subquest_19._20_say = "Oh, aceast\227 tus\227 va fi fatal\227 pentru mine. Nu am[ENTER]cu ce cur\227\254\227 casa a\186a c\227 tot praful plute\186te \238n[ENTER]aer. Oh, de ce nu am un cur\227\254itor de praf? Fiul[ENTER]meu l-a luat pentru a lucra la un fel de arm\227."
gameforge.subquest_19._210_say = "\170tiu c\227 este greu, dar mai \238ncearc\227 totu\186i odat\227."
gameforge.subquest_19._220_say = "Mul\186umesc c\227 te ocupi de asta."
gameforge.subquest_19._230_say = "Tu e\186ti aventurierul care a fost aici recent![ENTER]C\238t de grav\227 este tusea mea? Dup\227 cum po\254i auzi[ENTER]situa\254ia nu s-a \238mbun\227t\227\254it deloc. Casa este \238nc\227[ENTER]plina de praf.[ENTER][ENTER]Oh? Ai adus Piele neprelucrat\227 de lup? \206\254i[ENTER]mul\254umesc! A\186teapt\227 aici, m\227 \238ntorc imediat."
gameforge.subquest_19._240_say = "Unu doi, unu doi. Un picior \238n fa\254a celuilalt ...[ENTER]a\186a ... am revenit. \206n sf\238r\186it pot cur\227\254a casa[ENTER]cum trebuie. Am g\227sit ceva ce a\186 vrea sa-\254i dau.[ENTER]Nu \186tiu dac\227 valoreaz\227 ceva dar sper c\227 odat\227 \238\254i[ENTER]va fi de folos. Mul\254umesc din nou."
gameforge.subquest_19._250_sendLetter = "Ceva pr\227fuit"
gameforge.subquest_19._260_say = "Ai primit ca r\227splat\227 un obiect, care pare s\227 fie[ENTER]un gunoi. \206l \186tergi de praf din curiozitate."
gameforge.subquest_19._270_say = "Este o armur\227 veche, de \238nalt\227 calitate, opera[ENTER]unui fierar bun. Ce noroc!"
gameforge.subquest_19._280_say = "O armur\227 veche care \238nc\227 poate s\227 fie folosit\227."
gameforge.subquest_19._290_say = "Un set de armuri dar spre dezam\227girea ta sunt[ENTER]nefolositoare."
gameforge.subquest_19._300_sayReward = "Ai primit 15000 puncte de experien\254\227."
gameforge.subquest_19._30_select = "\206\254i fac rost de unul."
gameforge.subquest_19._40_say = "*C\226h\226 -c\226h\226* Totul e plin de praf aici. Am[ENTER]neap\227rat nevoie de un p\227m\227tuf pentru praf cum se[ENTER]cuvine.[ENTER]Vrei s\227 m\227 aju\254i?"
gameforge.subquest_19._50_say = "A trecut ceva timp dar cred c\227 so\254ul meu,[ENTER]odihneasc\227-se-n pace, a f\227cut-o din Piele[ENTER]neprelucrata de lup.[ENTER][ENTER]Po\254i face rost de piele pentru o femeie b\227tr\238n\227?[ENTER]Po\254i procura de la Lupii gri."
gameforge.subquest_19._60_say = "Chiar vrei s\227 \238ntrerupi?"
gameforge.subquest_19._70_say = "Ups, p\227cat; \186i eu credeam c\227 vrei s\227 m\227 aju\254i.[ENTER]Poate te mai g\226nde\186ti \186i treci iar\227\186i pe aici."
gameforge.subquest_19._80_say = "La ce r\227splat\227 te po\254i a\186tepta de la o femeie a\186a[ENTER]de b\227tr\226n\227 \186i s\227rac\227?"
gameforge.subquest_19._90_say = "Nu este u\186or s\227 procuri Piele neprelucrat\227 de[ENTER]lup, dar totu\186i voi \238ncerca. Pana la urma, vreau[ENTER]sa devin \238ntr-o zi un mare r\227zboinic."
