gameforge.subquest_22._50_say = "Dac\227 Fierarul va afla despre asta se va sup\227ra \186i[ENTER]nu-mi va mai repara vreodat\227 securea. M\227 po\254i[ENTER]ajut-o s-o recuperez?"
gameforge.subquest_22._60_select = "Refuz\227"
gameforge.subquest_22._70_say = "Vrei s\227 abandonezi c\227utarea?"
gameforge.subquest_22._80_say = "Oh, c\226nd ai timp, treci pe la mine."
gameforge.subquest_22._90_say = "Prea greu? Atunci nu putem face nimic. Dar ai[ENTER]mare grij\227; peste tot mi\186un\227 s\227lbatici."
gameforge.subquest_23 = {}
gameforge.subquest_23._100_sendLetter = "Uit\227-te dup\227 Yu-Hwan"
gameforge.subquest_23._10_targetVid = "Te rog caut\227-l pe fratele meu mai mare!"
gameforge.subquest_23._110_targetVid = "Mergi la Yu-Hwan"
gameforge.subquest_23._120_say = "Iar a disp\227rut fratele mai mare al lui Mirine.[ENTER]N-a mai dat de mult timp nici un semn de via\254\227.[ENTER]Ultimul semn de la el a fost o scrisoare. Du-te[ENTER]la Yu-Hwan, pentru a-l c\227uta pe fratele mai mare[ENTER]al lui Mirine."
gameforge.subquest_23._130_npcChat = "L-ai v\227zut pe fratele lui Mirine?"
gameforge.subquest_23._140_say = "Fratele lui Mirine? \206mi pare r\227u dar nu te pot[ENTER]ajuta cu asta. Nu am mai vorbit nici eu recent cu[ENTER]el. Abia \238mi amintesc c\226nd l-am v\227zut ultima[ENTER]dat\227. Sunt \186i eu \238ngrijorat.[ENTER]Este posibil s\227 se fi \238nt\226mplat ceva cu el? Mergi[ENTER]\186i \238ntreab\227-l pe v\226n\227torul Yang-Shin. El este tot[ENTER]timpul pus \238n mi\186care \186i probabil l-a v\227zut."
gameforge.subquest_23._150_sendLetter = "Uita-te dup\227 Yang-Shin"
gameforge.subquest_23._160_targetVid = "Mergi la v\226n\227torul Yang-Shin"
gameforge.subquest_23._170_say = "V\238n\227torul Yang-Shin este tot timpul pus pe[ENTER]mi\186care. Poate el l-a v\227zut pe fratele lui[ENTER]Mirine."
gameforge.subquest_23._180_npcChat = "L-ai v\227zut pe fratele lui Mirine?"
gameforge.subquest_23._190_say = "Te referi la fratele mai mare a lui Mirine?[ENTER]Ultima dat\227 c\226nd l-am v\227zut se \238ndrepta c\227tre[ENTER]Valea Seungryong pentru a culege plante[ENTER]medicinale. M-am mirat ce cauta acolo av\226nd \238n[ENTER]vedere c\227 zona este foarte periculoas\227."
gameforge.subquest_23._200_say = "Trebuia s\227-l fi oprit. Cred c\227 ceva s-a \238nt\238mplat[ENTER]cu el acolo. Mai bine ai merge \238n Valea[ENTER]Seungryong sa-l cau\254i."
gameforge.subquest_23._20_npcChat = "De ce plangi?"
gameforge.subquest_23._210_select = "Incepe c\227utarea"
gameforge.subquest_23._220_say = "Renun\254\227 la c\227utare? "
gameforge.subquest_23._230_say = "Mirine a fost foarte sup\227rat\227.[ENTER]Voi reveni mai t\238rziu."
gameforge.subquest_23._240_say = "Dac\227 de un frate mai \238n v\238rst\227 nu se \186tie nimic[ENTER]asta nu \238nseamn\227 c\227 a p\227\254it ceva. Nu e\186ti obligat[ENTER]s\227 mergi \238n acea zona periculoas\227 doar pentru ca[ENTER]o fata t\238n\227ra te-a rugat s-o faci."
gameforge.subquest_23._250_say = "Misiunea nu este at\226t de nesemnificativ\227 precum[ENTER]pare.[ENTER]Valea Seungryong este o zon\227 periculoas\227.[ENTER]Dar \254i-am promis, a\186a c\227 m\227 \254in de promisiune."
gameforge.subquest_23._260_sendLetter = "Fratele Disp\227rut"
gameforge.subquest_23._270_targetVid = "Caut\227-l \238n Valea Seungryong pe fratele mai \238n[ENTER]v\238rst\227."
gameforge.subquest_23._280_sayTitle = "Caut\227-l pe fratele lui Mirine"
gameforge.subquest_23._290_say = "Fratele lui Mirine caut\227 plante medicinale \238n[ENTER]Valea Seungryong. Mergi acolo \186i vezi dac\227 e ok.[ENTER]Teleporterul te poate ajuta dac\227 vrei s\227 ajungi[ENTER]mai repede."
gameforge.subquest_23._300_npcChat = "Cadavrul!"
gameforge.subquest_23._30_say = "Un moment te rog ...[ENTER]Mi-ai adus o dat\227 o scrisoare de la fratele meu,[ENTER]nu-i a\186a?[ENTER]\222i-am fost foarte recunosc\227toare pentru asta.[ENTER]Dar de atunci, nu mai \186tiu nimic de el. Fratele[ENTER]meu nu s-a \238ntors \238nc\227. El caut\227 ierburi[ENTER]t\227m\227duitoare pentru mine."
gameforge.subquest_23._310_say = "Un cadavru este \238ntins pe jos. Este o persoan\227[ENTER]t\238n\227r\227 \186i se pare c\227 str\238ngea Ginseng. Se poate[ENTER]s\227 fie fratele mai mare a lui Mirine. La gat are[ENTER]un lan\254 cu un pendativ. Il voi da jos \186i duce lui[ENTER]Mirine."
gameforge.subquest_23._320_sendLetter = "Mergi la Mirine"
gameforge.subquest_23._330_sayTitle = "Ve\186ti proaste"
gameforge.subquest_23._340_say = "Ai g\227sit un pendativ la gatul cadavrului din[ENTER]Valea Seungryong, pendativ care are inscrip\254ionat[ENTER]pe el numele lui Mirine. Mergi la Mirine \186i du-i[ENTER]lan\254ul cu pendativ."
gameforge.subquest_23._350_npcChat = "Cunosti acest colier?"
gameforge.subquest_23._360_say = "Oh, acest colier ... Fratele meu obi\186nuia s\227-l[ENTER]poarte tot timpul. Am unul la fel. Am\238ndoi purtam[ENTER]unul pentru a ne g\227si reciproc. Dar ... fratele[ENTER]meu nu mai este aici acum ... ci doar colierul."
gameforge.subquest_23._370_say = "S\227racul meu frate ...[ENTER]\170i toate din cauza r\227zboiului. Fratele meu vindea[ENTER]plante medicinale, era singura modalitate de a[ENTER]face bani \186i de a ne cump\227ra m\238ncare. Muncea mult[ENTER]pentru ca eu s\227 am ce manca. \170i acum este mort.[ENTER]Doar din cauza mea ..."
gameforge.subquest_23._380_say = "\206\254i mul\254umesc c\227 mi-ai adus aceste obiecte. Cel[ENTER]pu\254in \186tiu acuma ce s-a \238nt\226mplat. Dac\227 nu m-ai[ENTER]fi ajutat, n-a\186 fi aflat niciodat\227 ce s-a[ENTER]\238nt\226mplat cu fratele meu."
gameforge.subquest_23._390_say = "Voi p\227stra cu grij\227 medalionul fratelui meu mai[ENTER]mare, iar l\227n\254i\186orul \254i-l voi da \254ie, \238n semn de[ENTER]mul\254umire. Cu siguran\254\227, \238\254i va fi de ajutor.[ENTER][ENTER]\206\254i mul\254umesc pentru ajutor. Cu siguran\254\227, c\227 el[ENTER]este acum \238n ceruri, nu crezi?"
gameforge.subquest_23._400_sayReward = "Ai primit 600000 puncte de experien\254\227.[ENTER]Ai primit 35000 Yang."
gameforge.subquest_23._40_say = "Dar \238mi fac mari griji din cauza lui, deoarece nu[ENTER]mai \186tiu nimic despre el. Scuz\227-m\227, dar ai putea[ENTER]s\227-l mai cau\254i o dat\227 pe fratele meu? Poate \186tie[ENTER]Yu-Hwan ceva de el."
gameforge.subquest_23._50_select = "Refuz\227"
gameforge.subquest_23._60_say = "Vrei s\227 renun\254i la c\227utare?"
gameforge.subquest_23._70_say = "Oh ...[ENTER]Am s\227 a\186tept aici. Poate mai t\238rziu? Te rog?"
gameforge.subquest_23._80_say = "Nu am timp![ENTER]Mult noroc sa-\254i g\227se\186ti fratele."
gameforge.subquest_23._90_say = "E dr\227gu\254 s\227 o aju\254i pe s\227rmana fat\227; \186i-apoi nici[ENTER]nu-i mare lucru de f\227cut.[ENTER]A\186adar, la treab\227!"
gameforge.subquest_24 = {}
gameforge.subquest_24._100_say = "Sigur dore\186ti s\227 renunti la misiune?"
gameforge.subquest_24._10_targetVid = "Pl\227cint\227 de orez a lui Yu-Rang"
gameforge.subquest_24._110_say = "C\226nd ai timp te rog revino. Nu \186tiu cum vom[ENTER]supravie\254ui f\227r\227 a vinde Pl\227cint\227 de Orez."
gameforge.subquest_24._120_say = "Totul se \238nv\238rte \238n jurul celor boga\254i care o[ENTER]batjocoresc pe Yang ca si cum n-ar exista o zi de[ENTER]m\238ine. Nici m\227car nu \186tim dac\227 vom avea ce m\238nca[ENTER]m\238ine. Pleac\227!"
gameforge.subquest_24._130_say = "Mul\254umesc. E\186ti foarte amabil. Voi a\186tepta aici[ENTER]p\226n\227 vei reveni."
gameforge.subquest_24._140_sendLetter = "Pl\227cint\227 de Orez Furat\227"
gameforge.subquest_24._150_say = "Adu \238napoi pl\227cinta lui Yu-Rang de la P\227ianjenii[ENTER]din desert. Dac\227 te mi\186ti \238ncet p\227ianjenii vor[ENTER]manca pl\227cinta sau se vor usca de la soare.[ENTER]Gr\227be\186te-te!"
gameforge.subquest_24._160_sayReward = "Ucide P\227ianjenii Puii din de\186ertul Yongbi."
gameforge.subquest_24._170_npcChat = "Despre Pl\227cinta de orez furat\227"
gameforge.subquest_24._180_say = "Poftim, p\227ianjenii au m\238ncat deja pl\227cinta? Oh,[ENTER]nu! Sau deja s-au uscat?! Te rog nu-mi spune c\227[ENTER]totul e pierdut!"
gameforge.subquest_24._190_select = "Nu, totul e ok!"
gameforge.subquest_24._200_select = "Renunt."
gameforge.subquest_24._20_npcChat = "Pl\227cinta ta de orez furat\227"
gameforge.subquest_24._210_say = "Nu po\254i pan\227 la urm\227 s-o faci? Pl\227cinta este[ENTER]foarte important\227 pentru mine. Te rog.[ENTER][ENTER]Vrei s\227 renunti la misiune pentru a g\227si \238n[ENTER]desert pl\227cinta lui Yu-Rang?"
gameforge.subquest_24._220_select = "Mai \238ncerc odat\227,"
gameforge.subquest_24._230_select = "\206mi pare r\227u, este prea greu."
gameforge.subquest_24._240_say = "Nu-mi vine s\227 cred. Cine te va ajuta?"
gameforge.subquest_24._250_say = "Fii dr\227gu\254![ENTER]Ajut\227-m\227"
gameforge.subquest_24._260_say = "A\186adar, vei continua c\227utarea? Mul\254umesc! Te rog[ENTER]s\227 \238ncerci s\227 g\227se\186ti pl\227cinta c\238t mai repede[ENTER]posibil."
gameforge.subquest_24._270_say = "Nu, e prea t\226rziu. Chiar dac\227 o g\227se\186ti, ea va fi[ENTER]uscat\227 \186i nu mai pot s-o v\226nd."
gameforge.subquest_24._280_say = "Te ui\254i pe p\227m\238nt \186i vezi buc\227\254i din pl\227cinta[ENTER]l\227sata de p\227ianjeni \238n urma lor. Din p\227cate s-au[ENTER]uscat to\254i."
gameforge.subquest_24._290_sayReward = "Ai pierdut prea mult timp p\226n\227 ai g\227sit pl\227cinta.[ENTER]Misiunea a dat gre\186."
gameforge.subquest_24._300_sendLetter = "\206napoi la Yu-Rang"
gameforge.subquest_24._30_say = "Salut, ce mai face mama ta? "
gameforge.subquest_24._310_targetVid = "Mergi \238napoi la Yu-Rang."
gameforge.subquest_24._320_say = "Ai salvat la timp pl\227cinta lui Yu-Rang de la[ENTER]p\227ianjeni. Du-i-o lui Yu-Rang."
gameforge.subquest_24._330_npcChat = "Esti norocoas\227. Poftim pl\227cinta."
gameforge.subquest_24._340_say = "Oh, Dumnezeule, tu e\186ti fantastic![ENTER]N-am cuvinte. Acum pot s-o duc m\226ine la pia\254\227 s\227[ENTER]o v\226nd. \206\254i mull\254umesc mult."
gameforge.subquest_24._350_sayReward = "Ai primit 900000 puncte de experien\254\227."
gameforge.subquest_24._360_sayReward = "Ai primit 25.000 Yang."
gameforge.subquest_24._40_say = "Oh, \238i merge mai bine. Mul\254umesc de \238ntrebare."
gameforge.subquest_24._50_say = "Ar\227\254i de parc\227 ai avea probleme. Ce s-a \238nt\226mplat?"
gameforge.subquest_24._60_say = "Aici v\226nd pl\227cint\227 \238n fiecare zi, dar ceva[ENTER]teribil s-a \238nt\226mplat azi. P\227ianjenii Uria\186i[ENTER]mi-au furat pl\227cinta. A fost \238nsp\227im\226nt\227tor \186i nu[ENTER]m-am luptat cu ei. Acum nu mai am deloc Pl\227cint\227[ENTER]de Orez pentru v\226nzare. Cum voi supravie\254ui?[ENTER]Familia mea nu are alt venit..."
gameforge.subquest_24._70_select = "O voi g\227si, pentru tine."
gameforge.subquest_24._80_select = "Din p\227cate nu am timp"
gameforge.subquest_24._90_sayTitle = "\206ntrebare:"
gameforge.subquest_25 = {}
gameforge.subquest_25._100_npcChat = "Ce i\254i place?"
gameforge.subquest_25._10_targetVid = "Huahn-So"
gameforge.subquest_25._110_say = "Ei, de c\226nd mi-am pierdut so\254ul \238n r\227zboi, m\227[ENTER]simt foarte singur\227. Hm. Ce m-ar face s\227 m\227 simt[ENTER]mai bine? So\254ul meu obi\186nuia s\227-mi aduc\227 Flori."
gameforge.subquest_25._120_say = "Au fost Flori care cresc destul de departe de[ENTER]satul nostru. De\186i drumul era periculos, el \238mi[ENTER]aducea aceste flori. Nici nu mai pot vedea[ENTER]florile astea, de c\226nd so\254ul meu a murit. Dar \238n[ENTER]zile ca aceasta, \238mi lipse\186te mult. Oh, ce-am[ENTER]spus? E cu totul nepotrivit. Te rog, uit\227 ce-am[ENTER]spus."
gameforge.subquest_25._130_qSetTitle = "\206ntoarce-te la Huahn-So"
gameforge.subquest_25._140_makequestbutton = "\206ntoarce-te la Huahn-So"
gameforge.subquest_25._150_targetVid = "Huahn-So"
gameforge.subquest_25._160_say = "Lui Ariyoung \238i lipsesc florile pe care so\254ul ei[ENTER]le aducea mereu. Mergi la Huahn-So \186i spune-i[ENTER]asta."
gameforge.subquest_25._170_npcChat = "Cadoul pentru Ariyoung..."
gameforge.subquest_25._180_say = "A\186adar, ce dore\186te Ariyoung? Nu i-ai spus nimic[ENTER]despre mine, nu-i a\186a? Hm, vrea o floare din[ENTER]acelea cum obi\186nuia s\227-i aduc\227 so\254ul ei? Locul[ENTER]acela e destul de departe de sat, \186i pentru mine[ENTER]ar fi foarte greu s\227 ajung acolo. \170i ar putea fi[ENTER]pe acolo mon\186trii precum tigrii."
gameforge.subquest_25._190_say = "Exact! De ce nu m\227 aju\254i? De ce nu culegi pur si[ENTER]simplu florile pentru mine? Asta ar fi un avantaj[ENTER]pentru am\226ndoi. Cum? Asta nu face parte din[ENTER]\238n\254elegere? Haide, chiar nu vezi c\226t m\227[ENTER]str\227duiesc s\227 o cuceresc? Ajut\227-m\227! Te voi[ENTER]r\227spl\227ti cu o gr\227mad\227 de Yang!"
gameforge.subquest_25._200_select = "Refuz\227"
gameforge.subquest_25._20_npcChat = "Oh, draga mea Ariyoung"
gameforge.subquest_25._210_say = "Sigur dore\186ti s\227 renunti la misiune?"
gameforge.subquest_25._220_say = "La naiba. Cum s\227 fac rost de acele Flori?[ENTER]Te rog revino dac\227 te r\227zg\226nde\186ti."
gameforge.subquest_25._230_say = "N-ai fost indragostit(a) niciodat\227? Nu \186tii ce[ENTER]simt eu pentru Ariyoung? Oh Ariyoung..."
gameforge.subquest_25._240_say = "\206\254i mul\254umesc mult! Te rog, adu-mi aceste flori."
gameforge.subquest_25._250_qSetTitle = "Ia florile"
gameforge.subquest_25._260_targetVid = "Flori"
gameforge.subquest_25._270_sayTitle = "Flori pentru Ariyoung"
gameforge.subquest_25._280_say = "Pentru a-l ajuta pe Huahn-So, spune-i lui[ENTER]Ariyoung cum se simte acesta, trebuie sa faci[ENTER]rost de flori speciale. Florile se g\227sesc \238n[ENTER]col\254ul h\227r\254ii \238n primul sat."
gameforge.subquest_25._290_npcChat = "Nu am g\227sit nicio Floare."
gameforge.subquest_25._300_say = "Oh, fir-ar s\227 fie![ENTER]Voiam s\227-i m\227rturisesc sentimentele mele. E at\226t[ENTER]de greu s\227-i c\226\186tigi iubirea. Draga mea Ariyoung[ENTER]..."
gameforge.subquest_25._30_say = "O cunosti pe Doamna Ariyoung? Ei bine, este...[ENTER]nu, a fost casatorita. So\254ul ei a murit acum[ENTER]c\226\254iva ani \186i de atunci traieste singura. Are o[ENTER]personalitate impresionant\227 \186i \238nc\227 este o femeie[ENTER]foarte frumoasa. S-a m\227ritat foarte t\226n\227r\227 si eu[ENTER]am ajuns t\226rziu... "
gameforge.subquest_25._310_select = "Voi mai incerca."
gameforge.subquest_25._320_select = "Renun\254."
gameforge.subquest_25._330_say = "Sigur dore\186ti s\227 renunti la misiune?"
gameforge.subquest_25._340_say = "Oh...[ENTER]\206n cazul \238n care te r\227zg\226nde\186ti...[ENTER]Te voi a\186tepta aici.[ENTER]Te rog, ajut\227-m\227!"
gameforge.subquest_25._350_say = "Oare a\186a se va sf\226r\186i iubirea mea? Ariyoung..."
gameforge.subquest_25._360_say = "\206\254i mul\254umesc forte mult. \206nseamn\227 c\227 \186i tu e\186ti[ENTER]\238ndr\227gostit, dac\227 \238n\254elegi ce simt eu pentru[ENTER]Ariyoung."
gameforge.subquest_25._370_npcChat = "Florile preferate ale lui Ariyoung"
gameforge.subquest_25._380_say = "Aceste flori arat\227 ca acelea pe care le-a descris[ENTER]Ariyoung. Voi culege c\226teva."
gameforge.subquest_25._390_qSetTitle = "\206ntoarce-te la Huahn-So"
gameforge.subquest_25._400_say = "Am g\227sit florile preferate ale lui Ariyoung \186i am[ENTER]cules c\226teva. Ar trebui s\227 le duc lui Huahn-So[ENTER]pentru a-\186i m\227rturisi dragostea pentru Ariyoung."
gameforge.subquest_25._40_say = "Dar so\254ul ei a murit \238n r\227zboi. De aceea a r\227mas[ENTER]v\227duv\227 de t\226n\227r\227. Vreau s\227 \186tie ce simt pentru[ENTER]ea! \170tiu c\227 este o rug\227minte egoist\227, dar m\227 po\254i[ENTER]ajuta te rog?"
gameforge.subquest_25._410_npcChat = "Poftim florile favorite ale lui Ariyoung."
gameforge.subquest_25._420_say = "Oh, acestea sunt florile? Acum ii pot zice lui[ENTER]Ariyoung ce simt pentru ea. Crezi ca e prea[ENTER]devreme pentru asta? Dar stai, nu conteaz\227.[ENTER]Trebuie s\227-i spun pan\227 nu e prea t\238rziu. Poftim[ENTER]recompensa, \238\254i mul\254umesc mult."
gameforge.subquest_25._430_sayReward = "Ai primit 400.000 puncte de experien\254\227."
gameforge.subquest_25._440_sayReward = "Ai primit 12.000 Yang."
gameforge.subquest_25._50_say = "Crezi c\227-i plac b\227rba\254ii chipe\186i? Sau hainele[ENTER]frumoase? \206nt\226i de toate, trebuie s\227 aflu ce \238i[ENTER]place, \186i apoi, pot s\227 vorbesc cu ea. Po\254i afla[ENTER]toate astea pentru mine, te rog? Dar \238n nici un[ENTER]caz s\227 nu-i spui nimic despre mine! Te implor! Te[ENTER]voi recompensa pentru asta."
gameforge.subquest_25._60_qSetTitle = "Mergi la Ariyoung"
gameforge.subquest_25._70_makequestbutton = "Mergi la Ariyoung"
gameforge.subquest_25._80_targetVid = "Mergi la Ariyoung"
gameforge.subquest_25._90_say = "Huahn-So o iube\186te pe v\227duva Ariyoung. Ca s\227-l[ENTER]aju\254i pe Huahn-So, s\227-i poat\227 m\227rturisi dragostea[ENTER]lui, trebuie s\227 aflii ce \238i place lui Ariyoung.[ENTER]\206ntreab-o a\186adar pe ce \238i place, da ai grij\227 s\227[ENTER]nu te dai de gol!"
gameforge.subquest_26 = {}
gameforge.subquest_26._100_say = "Este pierdera ta; ratezi \186ansa vie\254ii tale."
gameforge.subquest_26._10_targetVid = "Mergi la Administratorul Depozitului."
gameforge.subquest_26._110_say = "Foarte bine! \170tiam c\227 vei fi interesat. C\226nd faci[ENTER]rost revino \186i \238mparte-le cu mine."
gameforge.subquest_26._120_sendLetter = "Mergi la Octavio"
gameforge.subquest_26._130_targetVid = "Ok-gu"
gameforge.subquest_26._140_sayTitle = "Mergi la Octavio"
gameforge.subquest_26._150_say = "Magazionerul \254i-a dat un indiciu bun: supa de[ENTER]picioare de broasc\227 este un leac bun pentru[ENTER]amor\254eal\227 si oase. \206ntreab\227-l pe Octavio dac\227[ENTER]poate face supa."
gameforge.subquest_26._160_npcChat = "Sup\227 de pulpe de broasc\227?"
gameforge.subquest_26._170_say = "Sup\227 de pulpe de broasc\227 ... Desigur, am f\227cut[ENTER]c\226ndva. Dar asta a fost demult. Pe vremea aceea[ENTER]\238nc\227 nu mi-era fric\227 de mon\186trii, astfel \238nc\226t,[ENTER]puteam procura cu u\186urin\254\227 pulpe de broasc\227."
gameforge.subquest_26._180_say = "Ins\227 acum ... sunt prea b\227tr\226n \186i obosit. Cu acea[ENTER]sup\227 pot rec\227p\227ta energie \238ns\227 broa\186tele nu sunt[ENTER]u\186or de omor\226t. Daca mi-ai aduce pulpe de broasca[ENTER]voi face cea mai buna supa de pulpe de broasca[ENTER]pentru noi."
gameforge.subquest_26._190_select = "Sigur, o fac."
gameforge.subquest_26._200_select = "Nu pot "
gameforge.subquest_26._20_npcChat = "Cum te simti?"
gameforge.subquest_26._210_say = "Sigur dore\186ti s\227 renunti la misiune?"
gameforge.subquest_26._220_say = "E\186ti ocupat?[ENTER]Revino dac\227 te r\227zg\226nde\186ti "
gameforge.subquest_26._230_say = "Supa mea nu este foarte cunoscut\227.[ENTER]Dac\227 ai cunoa\186te-o, ai face-o.[ENTER]Bine, la revedere."
gameforge.subquest_26._240_say = "Atunci gr\227be\186te-te![ENTER]Voi preg\227ti toate cele necesare pentru supa de[ENTER]pulpe de broasc\227."
gameforge.subquest_26._250_sendLetter = "Pulpe de broasc\227 g\227site"
gameforge.subquest_26._260_targetVid = "Oktavio:"
gameforge.subquest_26._270_sendLetter = "F\227 rost de pulpe de broasc\227"
