gameforge.subquest_32._150_npcChat = "Am nevoie de A\254\227 de cusut."
gameforge.subquest_32._160_say = "Producerea a\254ei de cusut nu este grea. Dar atunci[ENTER]nu voi mai avea timp s\227 fac altceva. Am cusut[ENTER]hainele lui Ah-Yu si a\186 vrea s\227 i le duci."
