gameforge.subquest_32._300_say = "E\186ti in c\227utare de bijuterii?[ENTER]\206\254i pot da bijuterii dac\227 m\227 aju\254i. \206n momentul[ENTER]de fa\254\227 lucrez la un tratament \238mpotriva[ENTER]durerilor \186i am nevoie de un ingredient: Ficat de[ENTER]Tigru. Sunt greu de ob\254inut. Am nevoie de 100[ENTER]Ficat de Tigru."
gameforge.subquest_32._30_say = "Este greu pentru noi, Negustorii Ambulan\254i, pe[ENTER]timp de r\227zboi.[ENTER]Bunurile sunt cerute pretutindeni dar cererile de[ENTER]bunuri noi sunt a\186a de rapide \238nc\226t nu \186tiu dac\227[ENTER]am ceea ce trebuie s\227 ofer. Ca s\227 nu mai zic de[ENTER]animalele s\227lbatice care a\186teapt\227 s\227 atace[ENTER]trec\227torii ca ni\186te mon\186tri feroce.[ENTER]Nu vrei s\227 c\226\186tigi ni\186te Yang? A\186 putea s-o fac[ENTER]cu pu\254in ajutor."
gameforge.subquest_32._310_say = "Deasemenea am nevoie si de ni\186te Plante[ENTER]Medicinale care tot de la Tigrii le procuri. Le[ENTER]place s\227 se t\227v\227leasc\227 peste ele pentru ca au un[ENTER]miros pl\227cut. \206\254i voi da o bucat\227 de bijuterie[ENTER]dac\227-mi aduci Plantele Medicinale \186i Ficat de[ENTER]Tigru."
gameforge.subquest_32._320_say = "V\226neaz\227 pentru asta tigrii sau tigrii albi."
gameforge.subquest_32._330_say = "Ce zici? Batem palma?"
gameforge.subquest_32._340_say = "Este prea grea pentru tine aceast\227 misiune? Nu-mi[ENTER]pot imagina asta! Revino c\226nd te r\227zg\226nde\186ti."
gameforge.subquest_32._350_say = "Ai ajuns p\238n\227 aici pentru Negustor si renun\254i[ENTER]acum? Cum vrei ...[ENTER]S\227 ai o zi pl\227cut\227."
gameforge.subquest_32._360_say = "Foarte bine, asta ne va ajuta pe am\226ndoi.[ENTER]Mul\254umesc si mult noroc."
gameforge.subquest_32._370_npcChat = "Primesc acum bucata de bijuterie?"
gameforge.subquest_32._380_say = "S\227 analiz\227m ... 100 Ficat de Tigru \186i Plantele[ENTER]Medicinale, totul e ok. Mul\254umesc.[ENTER]Poftim recompensa, chiar meri\254i bucata de[ENTER]bijuterie."
