gameforge.subquest_32._50_say = "Am nevoie si de o bucat\227 de Bijuterie si A\254\227 de[ENTER]cusut. Una o vei lua de la V\226nz\227toare Magazin[ENTER]General iar cealalt\227 de la Ariyoung. Nu este u\186or[ENTER]s\227 procuri at\226t de multe obiecte, \238ns\227 vinderea[ENTER]colierelor este o bun\227 afacere. Ce p\227rere ai?[ENTER]Suna interesant?"
gameforge.subquest_32._510_say = "Sarcina este prea dificil\227? Cel pu\254in ai[ENTER]\238ncercat. Intr-o zi te voi anun\254a daca am o[ENTER]sarcin\227 mai u\186oar\227 pentru tine."
gameforge.subquest_32._520_say = "Da, mai \238ncerci o dat\227?[ENTER]Mul\254umesc.[ENTER]Te voi a\186tepta."
gameforge.subquest_32._60_say = "Sigur dore\186ti s\227 renunti la misiune?"
