gameforge.subquest_33._30_say = "Hei, am descoperit ni\186te informa\254ii ciudate \238n[ENTER]scrierile vechi. Textul spune c\227 ar exista o[ENTER]Hart\227 a Comorii \238n satul acesta. Cuno\186ti[ENTER]zeit\227\254ile p\227zitoare ale animalelor din afara[ENTER]ora\186ului: Zeitatea C\226inelui, Zeitatea Ursului,[ENTER]Zeitatea Tigrului \186i Zeitatea Porcului?"
gameforge.subquest_33._310_sayTitle = "Caut\227 comoara"
gameforge.subquest_33._320_say = "Hmm, sub piatra B\227tr\226nului...[ENTER]N-am idee. Poate trebuie s\227-l \238ntreb pe B\227tr\226n.[ENTER]De ce trebuie s\227 fie a\186a de departe B\227tr\226nul?[ENTER]Offf."
gameforge.subquest_33._330_sayTitle = "B\227tr\226nul:"
gameforge.subquest_33._340_say = "Ce cau\254i? O comoara? Haha, o vei c\227ut\227 mult timp[ENTER]de acum \238nainte. arat\227-mi harta ... hmmm. Cred c\227[ENTER]este acolo \186i acolo ... mult noroc ... hihi ..."
gameforge.subquest_33._350_say = "Acesta trebuie s\227 fie locul! Offf, p\227m\226ntul e[ENTER]at\226t de tare. Hmm ...[ENTER][ENTER]Se pare c\227 v\227d o cutie."
