gameforge.subquest_33._370_sayTitle = "\206napoi la Soon"
gameforge.subquest_33._380_say = "Ai s\227pat \238n locul potrivit \186i ai g\227sit Comoara![ENTER]Mergi la Soon \186i anun\254\227-l despre descoperire."
gameforge.subquest_33._390_npcChat = "Am gasit comoara."
gameforge.subquest_33._400_say = "Ce surpriz\227 pl\227cut\227.! S\227 vedem ... minunat. Exact[ENTER]a\186a a fost descris\227 comoara \238n vechile scrieri.[ENTER]Acum mai trebuie s\227 aflu doar cum deschid[ENTER]comoara. Dar asta nu e problema ta. Mul\254umesc![ENTER]Poftim, ia o recompens\227 de la mine."
gameforge.subquest_33._40_say = "Un vechi basm spune c\227 ace\186ti 4 zei mon\186tri au[ENTER]\238mp\227r\254it harta \238n 4 \186i au protejat aceste[ENTER]teritorii. Nu sunt sigur c\227 e adev\227rat. Po\254i[ENTER]verifica asta pentru mine? Te rog, aceast\227[ENTER]incertitudine m\227 omoar\227... Te implo, te rog[ENTER]ajut\227-m\227!"
gameforge.subquest_33._410_sayReward = "Prime\186ti 1.400.000 puncte de experien\254\227."
gameforge.subquest_33._420_sayReward = "Ai primit 25.000 Yang."
