gameforge.subquest_33._440_sayReward = "Ai primit zb Coif Cetate+1."
gameforge.subquest_33._450_sayReward = "Ai primit Glug\227 de O\254el +1"
gameforge.subquest_33._460_sayReward = "Ai primit o P\227l\227rie Lumina Soarelui+1."
gameforge.subquest_33._470_say = "Deci, unde e? Chiar \238\254i ba\254i joc de mine? Nici[ENTER]m\227car nu l-ai g\227sit, a\186a-i?"
gameforge.subquest_33._50_say = "Nu e\186ti interesat de vechea Hart\227 a Comorii? E\186ti[ENTER]ciudat... Voi arunca un ochi peste scrierile[ENTER]vechi, poate g\227sesc ceva indicii. Revino dac\227 te[ENTER]r\227zg\226nde\186ti."
