gameforge.subquest_34._180_say = "Du-te \238napoi la c\227pitan, \186i raporteaz\227-i c\227 i-ai[ENTER]ucis pe generali."
gameforge.subquest_34._185_npcChat = "Am ucis Generalii."
gameforge.subquest_34._190_say = "Hmmm ... i-ai \238nvins pe generali.[ENTER]F\227r\227 generali, ceilal\254i sunt o nimica toat\227.[ENTER]Prelu\227m noi restul. Clanul v\226ntului negru ne[ENTER]st\227tea \238n coast\227, dar mul\254umit\227 ajutorului t\227u,[ENTER]putem \238nl\227tura acum necazul.[ENTER]Poftim r\227splata ta. Sper c\227 ne vom revedea."
