gameforge.subquest_34._20_sayTitle = "C\227pitan"
gameforge.subquest_34._210_sayReward = "Ai primit un Inel pentru Limb\227 (limb\227 \238n sensul[ENTER]de limb\227 matern\227)"
gameforge.subquest_34._30_say = "De\186i tu ai \238nfr\226nt 'Clanul v\226ntului negru', ei[ENTER]tot nu ne las\227 \238n pace.[ENTER]\206n loc s\227 stea lini\186ti\254i, ei se comport\227 \238n[ENTER]continuare ca o hoard\227 de s\227lbatici.[ENTER]Dac\227 vrem s\227-i \238nfr\226ngem, trebuie s\227-i ucidem pe[ENTER]generalii v\226ntului negru."
gameforge.subquest_34._40_say = "Dup\227 ce vor fi \238nfr\226n\254i generalii, vor c\227dea \186i[ENTER]ceilal\254i. Va fi o lupt\227 grea, dar avem nevoie de[ENTER]o victorie \238mpotriva generalilor v\226ntului negru:[ENTER]Jak-To, To-Su \186i Gu-Ryung.[ENTER]Dac\227 \238i \238nfr\226ngem, nu va trebui s\227 ne mai facem[ENTER]griji din cauza 'clanului v\226ntului negru'.[ENTER]\206\254i urez mult noroc \186i m\227 rog pentru victoria ta."
gameforge.subquest_34._50_say = "Sigur dore\186ti s\227 renunti la misiune?"
gameforge.subquest_34._60_say = "Hmmm ... caut\227-m\227 din nou c\226nd vei fi preg\227tit.[ENTER]Sunt pu\254ini oameni a\186a de capabili ca tine."
gameforge.subquest_34._70_say = "Nu po\254i ...[ENTER]Altfel cum s\227 \238nfr\226ngem 'clanul v\226ntului negru'[ENTER]...?"
gameforge.subquest_34._80_say = "\170tiam sigur c\227 m\227 pot baza pe tine! Odat\227 uci\186i[ENTER]generalii bandei, ceilal\254i membri nu vor mai face[ENTER]probleme."
