gameforge.subquest_36._130_say = "Grajdurile duc lips\227 de f\238n. Str\226nge 10 c\227pi\254e de[ENTER]f\238n si du-i-le Gr\227jdarului \238nainte ca, caii sa[ENTER]moar\227 de foame. Po\254i procura f\238n \238n timp ce[ENTER]v\226nezi."
gameforge.subquest_36._140_npcChat = "Ai nevoie de f\238n?"
gameforge.subquest_36._150_say = "Ai venit aici pentru ca Yonah te-a trimis? Am[ENTER]auzit multe despre tine. Oh, se pare c\227 to\254i caii[ENTER]sunt \238nfometa\254i. Trebuie s\227-i salv\227m. Ajuta-m\227 si[ENTER]adu-mi f\238n pentru ei."
gameforge.subquest_36._160_say = "Promisiunea este promisiune. De asemenea as vrea[ENTER]sa c\227l\227rasesc mai t\226rziu un cal. Trebuie neap\227rat[ENTER]sa g\227sesc f\238n."
