gameforge.subquest_36._300_sayReward = "Ai primit Cartea Misiunii."
gameforge.subquest_36._30_say = "Hey, am o \238ntrebare pentru tine! \170tiu c\227[ENTER]altcineva este responsabil pentru grajduri \238ns\227[ENTER]am avut multe necazuri \238n ultima vreme. Caii au[ENTER]avut mult de lucru \238n timpul r\227zboiului dar \186i[ENTER]cel mai puternic cal are limitele sale."
gameforge.subquest_36._40_say = "Avem mul\254i cai \186i hran\227 pu\254in\227, a\186a c\227 mul\254i[ENTER]dintre ei ne mor. Ne po\254i face rost de hran\227, ca[ENTER]ei s\227 poat\227 cre\186te? Numai tu po\254i \238ndeplini[ENTER]aceast\227 misiune. Culege 10 buc\227\254i de f\226n \186i du-le[ENTER]la grajd.[ENTER]El va \238n\254elege c\226nd \238i vei spune c\227 te-am trimis[ENTER]eu."
