gameforge.subquest_36._90_say = "\170tiu c\227 e\186ti ocupat \238ns\227 \238\254i apreciez ajutorul.[ENTER]Caii sunt importan\254i \238n ziua de azi si chiar avem[ENTER]nevoie de f\226n."
