gameforge.subquest_37._100_say = "Yonah se chinuie din r\227sputeri s\227 produc\227 alt[ENTER]por\254elan dar experimentele sale nu dau roade.[ENTER]Mergi la Uriel \186i \238ntreab\227-l dac\227 \186tie ceva[ENTER]despre Por\254elanul Celadon."
gameforge.subquest_37._10_targetVid = "Secretul Por\254elanului Celadon"
gameforge.subquest_37._110_npcChat = "Cunosti Portelanul Celadon?"
gameforge.subquest_37._120_sayTitle = "Uriel:"
gameforge.subquest_37._130_say = "Por\254elanul Celadon? Ei bine, sunt expert \238n[ENTER]istorie \186i \238n \186tiin\254\227, dar arta nu m\227[ENTER]intereseaz\227. De aceea mi-e team\227 c\227 nu-\254i pot[ENTER]spune nimic despre Por\254elanul Celadon. Dar poate[ENTER]\186tie Soon? Nu este el foarte popular, dar el[ENTER]cite\186te multe c\227r\254i. Poate \186tie ceva despre asta."
gameforge.subquest_37._140_makequestbutton = "Du-te la Soon"
gameforge.subquest_37._150_targetVid = "Mergi la Soon"
gameforge.subquest_37._160_say = "Din p\227cate Uriel nu \186tie nimic despre Por\254elanul[ENTER]Celadon. Dar Soon cite\186te multe chestii prin[ENTER]c\227r\254ile sale. Mergi la el si \238ntreab\227-l dac\227 \186tie[ENTER]ceva cum se produce por\254elanul."
gameforge.subquest_37._170_sayTitle = "Soon:"
gameforge.subquest_37._180_say = "Ce dore\186ti? Nu m\227 deranja c\226nd citesc! Huh?[ENTER]Por\254elan Celadon? Bine\238n\254eles ca \186tiu despre el.[ENTER]Am citit o gr\227mad\227 de lucruri despre el. De ce?[ENTER]Nu degeaba mi se zice \" viermele c\227r\254ilor \".[ENTER]\206n\254eleg totul ce a fost scris in c\227r\254i!"
gameforge.subquest_37._190_say = "A\186 putea scrie pe h\226rtie procesul de produc\254ie al[ENTER]Por\254elanului Celadon \186i astea toate \186tinde-le din[ENTER]cap. Dar de ce a\186 face asta? A\186teapt\227, am o idee:[ENTER]am \238ntrebat la Negustorul ambulant din satul[ENTER]vecin de o carte dar nu am timp s\227 v\227d dac\227 o[ENTER]are. Mergi la el \186i vezi de carte \186i apoi te voi[ENTER]ajuta cu por\254elanul."
gameforge.subquest_37._200_makequestbutton = "Porne\186te spre negustorul ambulant."
gameforge.subquest_37._20_sayTitle = "Yonah:"
gameforge.subquest_37._210_targetVid = "Du-te la negustorul ambulant"
gameforge.subquest_37._220_say = "Soon cunoa\186te totul despre Por\254elanul Celadon.[ENTER]Insa nu \238\186i \238mparte cuno\186tiin\254ele daca nu[ENTER]prime\186te ceva in schimb. Mergi la Negustorul[ENTER]ambulant pentru a lua cartea ceruta de Soon."
gameforge.subquest_37._230_npcChat = "M-a trimis Soon ..."
gameforge.subquest_37._240_say = "Hey, te-ai \238ntors sa m\227 aju\254i? Ah, vrei cartea[ENTER]cerut\227 de Soon? Oricum aveam de g\226nd s\227 vin in[ENTER]sat \238nsa Soon este prea modest \238ncat s\227 vina el,[ENTER]a\186a c\227 trimite pe altcineva. Hmm, poftim. Nu[ENTER]\238n\254eleg ce g\227se\186te interesant Soon la aceste[ENTER]car\254i. Este mai important s\227 c\226\186tigi Yang repede."
gameforge.subquest_37._250_qSetTitle = "\206ntoarcere Soon"
gameforge.subquest_37._260_targetVid = "\206ntoarcere Soon"
gameforge.subquest_37._270_say = "Ai adus cartea lui Soon de la Negustorul[ENTER]ambulant. Mergi la Soon \186i du-i cartea ca sa-ti[ENTER]zic\227 cum se face Por\254elanul Celadon."
gameforge.subquest_37._280_npcChat = "Am ob\254inut cartea."
gameforge.subquest_37._290_say = "Yay! \206n sf\226r\186it am primit noua carte! Mul\254umesc![ENTER]Nu mai prea exist\227 c\227r\254i care sa nu le fi citit[ENTER]... Am notat ce este mai important pentru a face[ENTER]Por\254elanul Celadon. Daca urmezi notele mele vei[ENTER]ob\254ine un por\254elan de calitate. Si acum a venit[ENTER]momentul s\227 citesc noua carte."
gameforge.subquest_37._300_makequestbutton = "\206napoi la Yonah"
gameforge.subquest_37._30_say = "Hmm, nu este bun\227. Si nici asta ... Ohh, hey![ENTER]Uite aici: produc mult por\254elan dar majoritatea[ENTER]se sparge pe loc."
