gameforge.subquest_37._350_sayReward = "Ai primit 35000 Yang."
gameforge.subquest_37._360_sayReward = "Prime\186ti papuci de jade+3"
gameforge.subquest_37._40_say = "Voi \238ncerca o nou\227 metod\227. E foarte greu s\227[ENTER]produci por\254elan-Seladon, \186i de aceea sunt pu\254ini[ENTER]cei care reu\186esc. Dar eu am nevoie de el pentru[ENTER]operele mele de art\227. \206n cazul acesta ...[ENTER]Da, \238n\254eleptul Uriel ar putea s\227 \186tie![ENTER]Du-te la Uriel \186i \238ntreab\227-l de ob\254inerea[ENTER]por\254elanului-Seladon. Cu siguran\254\227 c\227 el va avea[ENTER]un sfat pentru tine."
gameforge.subquest_37._50_say = "Sigur dore\186ti s\227 renunti la misiune?"
gameforge.subquest_37._60_say = "Hm, e\186ti foarte ocupat?[ENTER]Aminte\186te-\254i s\227 treci iar\227\186i pe la mine c\226nd ai[ENTER]timp."
gameforge.subquest_37._70_say = "Vreu s\227 produc cel mai bun por\254elan ...[ENTER]\206n\254eleg ... la revedere..."
gameforge.subquest_37._80_say = "Mul\254umesc. Uriel va \186tii ce are de f\227cut."
gameforge.subquest_37._90_targetVid = "S\227 mergem la Uriel."
