gameforge.subquest_38._100_say = "Arcul \238mpodobit al v\226n\227torului Lavishly a fost[ENTER]furat. Mergi la Sangsun Dong \186i recupereaz\227 arcul[ENTER]de la maimu\254ele hoa\254e."
