gameforge.subquest_38._120_targetVid = "Mergi la v\226n\227torul Yang-Shin"
gameforge.subquest_38._125_say = "Ai g\227sit Arcul \206mpodobit al V\226n\227torului. Adu+l[ENTER]\238napoi la Yang-Shin."
gameforge.subquest_38._130_npcChat = "Iat\227 arcul ..."
gameforge.subquest_38._140_say = "Wow, asta e! Arcul meu! Onoarea mi-a fost[ENTER]restaurat\227. Am suferit mult timp de c\226nd l-am[ENTER]pierdut. \206\254i mul\254umesc pentru ajutor. Este o[ENTER]onoare s\227-\254i d\227ruiesc asta aici, poate nu este[ENTER]cine \186tie ce, dar \238\254i dau din toata inima."
gameforge.subquest_38._150_sayReward = "Prime\186ti 1.500.000 experien\254\227."
gameforge.subquest_38._160_sayReward = "Ai primit 35000 Yang."
gameforge.subquest_38._170_sayReward = "Ai primit Mantia Curajului."
gameforge.subquest_38._180_say = "Ai g\227sit Arcul meu? Dar unde e? L-ai pierdut din[ENTER]nou?"
gameforge.subquest_38._190_select = "Voi c\227uta \238n continuare."
gameforge.subquest_38._200_say = "A\186a s\227 fie![ENTER]Ai grij\227 de tine!"
gameforge.subquest_38._20_say = "Hei, e\186ti un pic atent la ceea ce-\254i spun?[ENTER]Dup\227 cum vezi, sunt un v\226n\227tor. Familia mea[ENTER]v\226neaz\227 de multe genera\254ii prin locurile acestea.[ENTER]Suntem v\226n\227tori cu to\254ii, o familie de onoare.[ENTER]Dar am f\227cut o mare gre\186eala care m\227 dezonoreaz\227[ENTER]\238n fa\254a familiei mele."
gameforge.subquest_38._210_say = "Po\254i \238ncerca din nou? Mul\254umesc.[ENTER]Cu skillurile tale ar trebui s\227 fii in stare."
gameforge.subquest_38._30_say = "Este vorba despre un Arc \238mpodobit Lavishly care[ENTER]a fost furat de maimu\254e acum o perioad\227 de timp.[ENTER]Am fost la v\226n\227toare \238n Donjonul Maimu\254elor unde[ENTER]s-a \238nt\226mplat nepl\227cutul incident. Am fost[ENTER]neatent c\226teva secunde \186i maimu\254ele au profitat[ENTER]de situa\254ie."
gameforge.subquest_38._40_say = "Nu am fost niciodat\227 \238n Sangsun Dong (Temni\254a[ENTER]maimu\254elor expert), a\186a c\227 nu cunosc drumul pe[ENTER]acolo si am nevoie de ajutorul t\227u. C\226\254iva[ENTER]localnici mi-au zis c\227 e\186ti talentat, din acest[ENTER]motiv \254i-am cerut ajutorul. Nu pot face \254at\227[ENTER]str\227mo\186ilor mei f\227r\227 acel arc."
gameforge.subquest_38._50_sayTitle = "Yang-Shin :"
gameforge.subquest_38._60_say = "Oh, trebuie s\227-l recuperez numaidec\226t ...[ENTER]Te rog, vino iar\227\186i c\226nd ai timp.[ENTER]R\227m\226i cu bine."
gameforge.subquest_38._70_say = "A\186adar ...[ENTER]Ai grij\227 la drum."
gameforge.subquest_38._80_say = "\206l vei g\227si u\186or, deoarece este un arc extrem de[ENTER]frumos \238mpodobit. \206\254i voi oferi o r\227splat\227 mare[ENTER]pentru el."
gameforge.subquest_38._90_sayTitle = "Caut\227 Arcul \238mpodobit Lavishly."
