gameforge.subquest_39._160_sayTitle = "Baek-Go :"
gameforge.subquest_39._170_say = "Oh, tu e\186ti? Tratezi un pacient? Zi-mi ce este \238n[ENTER]neregul\227 cu el ... hmm ... si ce tratament a[ENTER]luat? Poftim?! Nu-i de mirare c\227 se simte \186i mai[ENTER]r\227u! Acest tratament este total nepotrivit."
gameforge.subquest_39._180_say = "Este noroc c\227 \238nc\227 tr\227ie\186te! Este periculos s\227[ENTER]tratezi un pacient bolnav incorect. Dar \186tiu ce-l[ENTER]poate ajuta. Exist\227 o plant\227 care \238nvinge otrava[ENTER]din corp \186i \238l face bine. \206ns\227 c\227utarea ei este[ENTER]periculoas\227."
gameforge.subquest_39._190_say = "Din cate \186tiu acea plant\227 cre\186te doar in Sangsun[ENTER]Dong (Temni\254a maimu\254elor expert). \206ns\227 este[ENTER]recoltat\227 doar pentru Lordul Maimu\254\227 c\227reia \238i[ENTER]place s-o m\227n\226nce. Trebui s\227 ucizi Lordul Maimu\254\227[ENTER]pentru a procura planta. Apoi pot face[ENTER]tratamentul corect."
