gameforge.subquest_39._280_targetVid = "\206napoi la Baek-Go"
gameforge.subquest_39._290_sayTitle = "Am g\227sit planta Maimu\254ei Puternice"
gameforge.subquest_39._300_say = "Ai luat planta Maimu\254ei Puternice de la Lordul[ENTER]Maimu\254\227. Du-o lui Baek-Go ca s\227 poat\227 face[ENTER]tratamentul pentru Balso."
gameforge.subquest_39._30_say = "\206\254i mul\254umesc c\227 mi-ai adus leacul de cur\226nd. Dar[ENTER]avem o problem\227... Efectul leacului a sc\227zut[ENTER]puternic \238n ultima vreme; cred c\227 acesta s-a[ENTER]alterat.[ENTER]*tuse* - Am nevoie urgent de un tratament."
gameforge.subquest_39._310_sayTitle = "Adu planta din Sangsun Dong"
gameforge.subquest_39._320_say = "Baek-Go poate face tratamentul pentru boala lui[ENTER]Balso. Are nevoie pentru asta de planta Maimu\254ei[ENTER]Puternice. O po\254i procura de la Lordul Maimu\254\227[ENTER]din Dungeonul Maimu\254ei Puternice."
gameforge.subquest_39._330_npcChat = "Planta Maimutei Puternice"
gameforge.subquest_39._340_say = "Se pare ca boala se extinde \238ntr-o epidemie \238ns\227[ENTER]nu \186tim de ce. Totu\186i, Organiza\254ia Academic\227 a[ENTER]zis ca exista un tratament cu ajutorul Plantelor[ENTER]Maimu\254elor. Ce este? Ai g\227sit deja planta?"
