gameforge.subquest_39._380_select = "Nu pot face."
gameforge.subquest_39._390_select = "Vreau s\227 ajut!"
gameforge.subquest_39._400_say = "Maimu\254ele sunt prea puternice pentru mine. Nu pot[ENTER]face rost de plant\227. \206mi pare r\227u."
gameforge.subquest_39._40_say = "\170tiu, c\227 \238n ora\186ul vecin, tr\227ie\186te un doctor.[ENTER]Po\254i s\227 mergi la el \186i s\227-i relatezi starea mea,[ENTER]ca s\227-\254i spun\227 cum pot fi ajutat? Dup\227 cum vezi,[ENTER]\238n starea mea, nu am cum s\227 p\227r\227sesc ora\186ul. \206\254i[ENTER]sunt foarte recunosc\227tor c\227 m-ai ajutat \186i ultima[ENTER]dat\227, \186i te voi r\227spl\227ti \186i de aceast\227 dat\227."
gameforge.subquest_39._410_say = "Refuzi s\227 aju\254i oamenii care sunt la suferin\254\227?[ENTER]Dispari din fa\254a mea!"
gameforge.subquest_39._420_say = "Ai dreptate. Cineva trebuie s\227 fac\227 rost de[ENTER]plant\227 pentru acei oameni bolnavi. Voi avea grij\227[ENTER]de asta."
gameforge.subquest_39._430_say = "Atunci, gr\227be\186te-te!"
gameforge.subquest_39._440_say = "Ai reu\186it s\227 faci rost de planta Maimu\254ei[ENTER]Puternice! Sper s\227 fie de ajutor. A\186teapt\227 o[ENTER]secund\227 ... voi produce tratamentul imediat ..."
gameforge.subquest_39._450_sayTitle = "Baek-Go :"
gameforge.subquest_39._460_say = "Poftim tratamentul. Mergi acum la pacient \186i[ENTER]trateaz\227-l. Ar trebui s\227 se simt\227 mai bine dup\227[ENTER]tratament. Spune-i te rog c\227 e mai bine s\227[ENTER]\238ntrebe \238nainte un doctor ce tratament e mai bun."
