gameforge.subquest_39._500_say = "Baek-Go a f\227cut un tratament din planta Maimu\254ei[ENTER]Puternice care poate trata multe boli. Du[ENTER]tratamentul la Balso \238n satul vecin."
gameforge.subquest_39._50_say = "Sigur dore\186ti s\227 renunti la misiune?"
gameforge.subquest_39._510_npcChat = "Iat\227 leacul."
