gameforge.subquest_39._530_say = "Mul\254umesc c\227 m-ai ajutat. Nu am multi prieteni.[ENTER]Poftim, \186tiu c\227 nu este cine \186tie ce dar \254i-l dau[ENTER]din inim\227. Te rog accept\227."
