gameforge.subquest_40._120_say = "Ai str\238ns toate cele 5000 V\238rf de S\227geat\227. Du-le[ENTER]la C\227pitan."
gameforge.subquest_40._130_say = "Armata are probleme mari \238n a face rost de[ENTER]s\227ge\254i. Ucide Arca\186 al Ciumei de pe Muntele Sohan[ENTER]\186i ia de la ei V\238rf de S\227geat\227 pentru C\227pitan.[ENTER]5000 sunt de ajuns."
gameforge.subquest_40._140_npcChat = "Despre Varf de Sageata ..."
gameforge.subquest_40._150_say = "Ace\186ti Arca\186i ai Ciumei au o boal\227 care s-a[ENTER]\238mpr\227\186tiat pe tot continentul. Nici m\227car[ENTER]doctorii no\186tri nu pot explica de ce. V\226rfurile[ENTER]de S\227geat\227 sunt necontaminate pentru moment, dar[ENTER]pe zi ce trece devin din ce \238n ce mai toxice."
gameforge.subquest_40._160_select = "Voi accepta."
gameforge.subquest_40._170_say = "Sigur dore\186ti s\227 renunti la misiune?"
gameforge.subquest_40._180_say = "\222i-e team\227 de boal\227.[ENTER]Lini\186te\186te-te \186i vino iar."
gameforge.subquest_40._190_say = "E\186ti sigur? Renun\254i?[ENTER]Poate c\227 e misunea prea grea.[ENTER]Voi ruga pe altcineva ...[ENTER]Ok, ia restul \186i du-te."
gameforge.subquest_40._200_say = "V\227d ...[ENTER]Tu nu renun\254i, sau?[ENTER]Atunci, la treab\227!"
gameforge.subquest_40._20_say = "Aten\254ie r\227zboinicilor! Dup\227 cum vede\254i atacurile[ENTER]din partea inamicilor cresc pe zi ce trece. Am[ENTER]primit alerta \186i din partea lui Yu-Hwan. Pentru a[ENTER]scurta povestea: nu avem destule s\227ge\254i!"
gameforge.subquest_40._210_npcChat = "Poftim 5000 V\226rf de s\227geat\227!"
gameforge.subquest_40._220_say = "Bine lucrat! Acum ne putem preg\227ti pentru atac.[ENTER]\206\254i voi da ordinul s\227 faci de \238ndat\227 ni\186te[ENTER]s\227ge\254i. Sper c\227 putem conta pe tine \186i \238n viitor."
gameforge.subquest_40._230_say = "Poftim recompensa. Data viitoare c\226nd o s\227 am o[ENTER]misiune important\227 vei fi primul anun\254at.[ENTER]Numai bine!"
gameforge.subquest_40._240_sayReward = "Ai primit 4500000 puncte de experien\254\227."
gameforge.subquest_40._250_sayReward = "Ai primit 50.000 Yang"
gameforge.subquest_40._260_sayReward = "Ai primit 3 x Lovitur\227 Critic\227.[ENTER]Ai primit 3 x Lovitur\227 P\227trunz\227toare."
gameforge.subquest_40._30_say = "Arca\186ii sunt importan\254i \238n r\227zboi. De \238ndat\227 ce[ENTER]inamicii sunt \238n raza arca\186ilor ace\186tia deschid[ENTER]focul. \206n felul asta ii punem pe fuga sau[ENTER]miscoram din num\227rul lor. Dar dac\227 sunt prea[ENTER]multe atacuri \238ntr-un interval mic de timp[ENTER]r\227m\238nem fara s\227ge\254i."
gameforge.subquest_40._40_say = "De asta avem nevoie de tine! Mergi pe Muntele[ENTER]Sohan \186i ucide Arca\186ii Ciumei pentru a procura[ENTER]V\238rfurile de S\227geat\227. Acele v\238rfuri sunt toxice[ENTER]dar ne ajut\227 s\227 \238nfr\238ngem inamicul. Avem nevoie[ENTER]de 5000 V\238rfuri de S\227geata. Ce zici? Accep\254i?"
gameforge.subquest_40._50_select = "Accept."
gameforge.subquest_40._60_select = "Este greu pentru mine."
gameforge.subquest_40._70_say = "Sigur dore\186ti s\227 renunti la misiune?"
gameforge.subquest_40._80_say = "Este prea departe Muntele Sohan pentru tine?[ENTER]G\238nde\186te-te bine. Aceast\227 misiune este de o[ENTER]importan\254\227 mare."
gameforge.subquest_40._90_say = "Hmm, \254i-e team\227 de arca\186ii ciumei? Te-am estimat[ENTER]gre\186it. Nu mai am nicio speran\254\227 de salvare[ENTER]pentru noi."
