gameforge.subquest_41._170_say = "Hmm, hmm ... Ce experien\254\227! Hr\227nitor, nu prea[ENTER]dulce ... ce gust incredibil! \170tiam c\227 va merita[ENTER]efortul. Nu reu\186eam f\227r\227 ajutorul t\227u. Mul\254umesc."
