gameforge.subquest_41._200_say = "Vreau neap\227rat s\227 g\227tesc asta...[ENTER]Nu conteaz\227, mul\254umesc. Numai bine \186i ai grij\227 de[ENTER]tine."
gameforge.subquest_41._20_say = "Cum te sim\254i? Tocmai citeam o carte de bucate[ENTER]care mi-a dat-o Soon. Am g\227sit \238n ea o re\254et\227[ENTER]interesant\227 numit\227 \" Ochi de P\227ianjeni speciali[ENTER]\". Nu am v\227zut pana acum a\186aceva. Dar tu? Se pare[ENTER]ca este o re\254et\227 speciala din alt\227 \254ar\227."
