gameforge.subquest_41._60_say = "Vreau neap\227rat s\227 g\227tesc aceast\227 re\254et\227. A\186adar,[ENTER]dac\227 vrei s\227-mi faci un serviciu, hai pe la mine,[ENTER]te rog."
gameforge.subquest_41._70_say = "Hm ... de unde fac eu rost de ochii \227\186tia?[ENTER]OK, pe cur\226nd."
gameforge.subquest_41._80_say = "Mul\254umesc, \186tiam c\227-mi vei face acest serviciu.[ENTER]Pentru asta, \238\254i voi servi o m\226ncare excep\254ional\227."
