gameforge.subquest_48._120_say = "Unul dintre spioni \238\186i duce traiul ca pescar \238n[ENTER]satul Yongan din regatul Shinsoo . \206ncearc\227 s\227[ENTER]intri \238n leg\227tur\227 cu el dup\227 care raporteaz\227-i[ENTER]C\227pitanului."
gameforge.subquest_48._130_say = "Unul dintre spioni \238\186i duce traiul ca pescar \238n[ENTER]satul Joan din regatul Chunjo. \206ncearc\227 s\227 intri[ENTER]\238n leg\227tur\227 cu el dup\227 care raporteaz\227-i[ENTER]C\227pitanului."
gameforge.subquest_48._140_npcChat = "Ce faci acum?"
gameforge.subquest_48._150_say = "Psst, nu f\227 g\227l\227gie, trop\227itorule! \206mi alungi[ENTER]to\254i pe\186tii. Ce cau\254i de fapt aici?[ENTER]La halul \238n care p\227\186e\186ti, at\226t de g\227l\227gios \186i[ENTER]ne\238ndem\226natic, n-oi fi venit s\227 pescuie\186ti."
gameforge.subquest_48._160_say = "Ah, \238n\254eleg.[ENTER]Te a\186teptam de mult. Ai \238nt\226rziat. N-a fost u\186or[ENTER]s\227 ob\254in informa\254iile f\227r\227 a fi descoperit.[ENTER]Trebuie s\227 \186tii, c\227 du\186manii stau la p\226nd\227[ENTER]pretutindeni \186i de-abia a\186teapt\227 s\227 ne d\227m de[ENTER]gol."
gameforge.subquest_48._170_say = "Hai, s\227 nu fim v\227zu\254i \238mpreun\227! Nu cumva s\227 ne[ENTER]mai descopere careva. Poftim documentele.[ENTER]Porne\186te de \238ndat\227 la drum \186i du-i-le direct[ENTER]c\227pitanului!"
gameforge.subquest_48._180_say = "Stai un pic! Am aici ceva pentru tine. Un mic[ENTER]cadou. Acum, porne\186te la drum! Cu bine!"
gameforge.subquest_48._190_sayReward = "E\186ti curios \186i ai deschis pachetul care \254i l-a[ENTER]dat spionul."
gameforge.subquest_48._200_say = "Perfect! Scrumbie pr\227jit\227! Evident c\227 spionul[ENTER]\186tie c\238te ceva despre pescuit."
gameforge.subquest_48._20_say = "Cu calm soldat![ENTER]Av\238nd \238n vedere ca toate \254inuturile vecine sunt[ENTER]inamice este bine s\227 avem spioni infiltra\254i care[ENTER]s\227 adune informa\254ii pentru noi. Este important c\227[ENTER]ace\186ti spioni s\227 nu fie descoperi\254i."
gameforge.subquest_48._210_sayReward = "Ai primit 3 scrumbii pr\227jite."
gameforge.subquest_48._220_sendLetter = "\206napoi la c\227pitan"
gameforge.subquest_48._230_targetVid = "C\227pitanul"
gameforge.subquest_48._240_say = "Primejdioasa c\227l\227torie c\227tre Pyungmoo \238n regatul[ENTER]Jinno s-a \238ncheiat cu succes. Ai primit raportul[ENTER]e la spion care este deghizat ca pescar. Acum[ENTER]mergi repede \238napoi \238n regatul t\227u \186i du raportul[ENTER]C\227pitanului."
gameforge.subquest_48._250_say = "Primejdioasa c\227l\227torie c\227tre Yongan \238n regatul[ENTER]Shinsoo s-a \238ncheiat cu succes. Ai primit[ENTER]raportul e la spion care este deghizat ca pescar.[ENTER]Acum mergi repede \238napoi \238n regatul t\227u \186i du[ENTER]raportul C\227pitanului."
gameforge.subquest_48._260_say = "Primejdioasa c\227l\227torie c\227tre Joan \238n regatul[ENTER]Chunjo s-a \238ncheiat cu succes. Ai primit raportul[ENTER]e la spion care este deghizat ca pescar.[ENTER]Acum mergi repede \238napoi \238n regatul t\227u \186i du[ENTER]raportul C\227pitanului."
gameforge.subquest_48._270_npcChat = "Misiunea a avut succes."
gameforge.subquest_48._280_say = "Acestea sunt documentele? Minunat! Acum c\227 \186tim[ENTER]ce pun la cale inamicii putem s\227 ne ap\227ram. Ai[ENTER]f\227cut un mare favor regatului."
gameforge.subquest_48._290_sayReward = "Ai primit 5500000 puncte de experien\254\227."
gameforge.subquest_48._300_sayReward = "Ai primit 50.000 Yang"
gameforge.subquest_48._30_say = "Cu siguran\254\227 trebuie s\227-l cuno\186ti pe Yu-Hwan,[ENTER]muzicianul. Este \186i spion \186i lucreaz\227 pentru noi.[ENTER]Un singur spion este pu\254in asa c\227 avem mai multi[ENTER]\238mpr\227\186tia\254i peste tot. Unul dintre ei este \238n[ENTER]primul sat deghizat ca pescar."
gameforge.subquest_48._40_say = "Av\238nd \238n vedere c\227 nu pot lua leg\227tura direct cu[ENTER]el am nevoie de ajutorul unor sold\227\254i ne\238nfrica\254i[ENTER]ca tine. Mergi te rog la Pescar \186i adu ultimul[ENTER]raport. Este foarte important pentru[ENTER]supravie\254uirea regatului."
gameforge.subquest_48._50_say = "Sigur dore\186ti s\227 renunti la misiune?"
gameforge.subquest_48._60_say = "Nu te preg\227te\186ti mai \238nt\226i? Ok, atunci revin-o[ENTER]mai t\226rziu. Te voi a\186tepta. Dar te rog[ENTER]gr\227be\186te-te. Am nevoie de raport!"
gameforge.subquest_48._70_say = "Ce este \238n neregul\227 cu tine? Data trecut\227 te-ai[ENTER]descurcat de minune. Si acum abandonezi \254ara?[ENTER]Da\227a a\186a dore\186ti nu am ce face."
