gameforge.subquest_49 = {}
gameforge.subquest_49._100_sayTitle = "Ce e Bingsu?"
gameforge.subquest_49._10_targetVid = "Bingsu?"
gameforge.subquest_49._110_say = "Taurean a avut o mica ne\238n\254elegere cu Harang[ENTER]pentru c\227 nu crede c\227 po\254i face \238nghe\254at\227 pe timp[ENTER]de var\227. Mergi la Harang \186i \238ntreab\227-o ce \186tie[ENTER]despre Bingsu."
gameforge.subquest_49._120_qSetTitle = "\206ntreab\227 pe Harang."
gameforge.subquest_49._130_targetVid = "\206ntreab\227 pe Harang."
gameforge.subquest_49._140_npcChat = "Ce e Bingsu?"
gameforge.subquest_49._150_say = "Taurean crede ca \186tie totul. Nici m\227car nu \186tie[ENTER]ce este Bingsu! Cum nu po\254i \186tii nimic despre[ENTER]ceva at\226t de delicios?[ENTER]Nici tu nu \186tii ce este Bingsu? Atunci cel mai[ENTER]bine e s\227 mergi la Octavio \238n satul vecin. Este[ENTER]un buc\227tar renumit \186i cunoa\186te multe re\254ete. Mi-a[ENTER]f\227cut odat\227 Bingsu ... mmmmh. El \238\254i va demonstra[ENTER]ca am dreptate."
gameforge.subquest_49._160_makequestbutton = "S\227 mergem s\227-l vedem pe Octavio"
gameforge.subquest_49._170_say = "Taurean vrea neap\227rat s\227 \186tie ce este Bingsu.[ENTER]Mergi la patronul restaurantului, la Octavio.[ENTER]Sunt sigur ca el te va putea ajuta."
gameforge.subquest_49._180_npcChat = "Stii ce este Bingsu?"
gameforge.subquest_49._190_say = "Bingsu? Normal c\227 \186tiu ce e! Orice buc\227tar bun[ENTER]\186tie cum s\227 prepare Bingsu. Pentru \238nceput ai[ENTER]nevoie de gheata sf\227r\238mat\227, dup\227 care pui zahar,[ENTER]buc\227\254i nici de orez \186i \238n final fructe proaspete[ENTER]pentru decor."
gameforge.subquest_49._200_say = "De ce \238ntrebi? Pentru ca Taurean \186i Harang se[ENTER]cearta pe tema asta? Nu este nimic nou. Dar[ENTER]Harang are dreptate. Bingsu este un preparat[ENTER]popular pe timpul verii. Taurean este un b\227iat[ENTER]bun chiar dac\227 uneori este enervant. Dac\227 faci[ENTER]rost de ingrediente \238\254i pot prepara Bingsu."
gameforge.subquest_49._20_npcChat = "Bingsu?"
gameforge.subquest_49._210_say = "Vreau s\227-i fac cinste lui Taurean \186i s\227-i dau[ENTER]Bingsu. Ce parare ai? Po\254i aduce ghea\254\227 de pe[ENTER]Muntele Sohan?"
gameforge.subquest_49._220_say = "Sigur dore\186ti s\227 renunti la misiune?"
gameforge.subquest_49._230_say = "\206\254i place \238nghe\254ata? Sau deja ai m\226ncat prea[ENTER]mult\227 \238n ultima vreme? Este pentru Taurean a\186a c\227[ENTER]te rog ..."
gameforge.subquest_49._240_say = "P\227cat. Taurean va fi dezam\227git. Pe cur\226nd."
gameforge.subquest_49._250_say = "Foarte bine. am nevoie de buc\227\254i de gheata[ENTER]fermecat\227 de pe muntele Sohan. Adu-mi 50 de[ENTER]buc\227\254i de ghea\254\227. Apoi voi putea face Bingsu."
gameforge.subquest_49._260_targetVid = "Mergi la Octavio"
gameforge.subquest_49._270_say = "%s[ENTER]Ai str\238ns buc\227\254ile de gheata pentru Bingsu lui[ENTER]Taurean. Du-le lui Octavio."
gameforge.subquest_49._275_say = "Am str\238ns buc\227\254ile de ghea\254\227."
gameforge.subquest_49._280_say = "Octavio a c\227zut de acord s\227 fac\227 Bingsu pentru[ENTER]Taurean dar are nevoie de ghea\254\227 pentru asta.[ENTER]Omoar\227 Ghea\254\227 Fermecat\227 de pe Muntele Sohan \186i[ENTER]str\226nge 50 de buc\227\254i de ghea\254\227. Du-le apoi lui[ENTER]Octavio."
gameforge.subquest_49._285_say = "Caut\227 ghea\254\227"
gameforge.subquest_49._290_npcChat = "Poftim, am adus bucatile de gheata."
gameforge.subquest_49._300_say = "Ah, foarte bine! Partea cea mai dificila \238n[ENTER]prepararea Bingsu a trecut. Acum mai trebuie sa[ENTER]adaug pu\254in zah\227r \186i ni\186te fructe. Poftim! O[ENTER]\238nghe\254at\227 pentru Taurean."
gameforge.subquest_49._30_sayTitle = "Taurean :"
gameforge.subquest_49._310_say = "Scuze, \238ns\227 este prea pu\254in. Trebuie s\227 aduci mai[ENTER]mult pentru c\227 dac\227 nu cantitatea va fi mic\227."
gameforge.subquest_49._320_select = "Da, o nou\227 \238ncercare."
gameforge.subquest_49._330_say = "\170tiu c\227 drumul este lung \186i mon\186trii sunt[ENTER]puternici. Dac\227 este prea dificil pentru tine[ENTER]atunci nu putem face nimic. Pe cur\238nd."
gameforge.subquest_49._340_say = "\206ncearc\227 din nou. Cu curajul t\227u po\254i reu\186i!"
gameforge.subquest_49._350_targetVid = "Bingsu?"
gameforge.subquest_49._360_say = "Rezolvat: Octavio a f\227cut Bingsu cu ghea\254\227 de pe[ENTER]muntele Sohan. \206ntoarce-te repede la Taurean[ENTER]\238nainte s\227 se topeasc\227."
gameforge.subquest_49._370_npcChat = "Poftim, Bingsu!"
gameforge.subquest_49._380_say = "Aceasta este Bingsu? Chiar are gust special. Bun[ENTER]\186i proasp\227t. Nu am gustat p\226n\227 acum a\186a ceva,[ENTER]mul\254umesc! Se pare c\227 Harang are dreptate. Nu am[ENTER]mai gustat ceva at\226t de bun p\226n\227 acum..."
gameforge.subquest_49._390_sayReward = "Ai primit 6000000 puncte de experien\254\227."
gameforge.subquest_49._400_sayReward = "Ai primit 70000 Yang."
gameforge.subquest_49._40_say = "Ast\227zi am avut o ne\238n\254elegere cu Harang. Puteam[ENTER]... Ea sus\254ine c\227 acolo se prepar\227 ceva gustos[ENTER]din buc\227\254i de ghea\254\227. Se cheam\227 Bingsu."
gameforge.subquest_49._410_sayReward = "Ai primit un Pergament de r\227zboi."
gameforge.subquest_49._420_say = "Bingsu pentru mine, \254i-ai amintit?"
gameforge.subquest_49._430_say = "Doamne, am uitat complet. hmm, s\227 mai \238ncerc? Sau[ENTER]s\227 renun\254?"
gameforge.subquest_49._440_select = "Da, voi continua."
gameforge.subquest_49._450_select = "Renunt."
gameforge.subquest_49._460_say = "Nu pot. \206mi pare r\227u."
gameforge.subquest_49._50_say = "Acest lucru este posibil numai iarna, atunci c\226nd[ENTER]este foarte frig. Dar ea sus\254ine c\227 se poate \186i[ENTER]acum. Po\254i afla ce face aceast\227 Bingsu pe timp de[ENTER]var\227? Dac\227 exist\227 cu adev\227rat acest lucru..."
gameforge.subquest_49._60_say = "Sunt sigur c\227 Bingsu are un gust delicios. E\186ti[ENTER]sigur c\227 nu ma vei ajuta s-o prepar?"
gameforge.subquest_49._70_say = "Dac\227 vrei s-o faci mai t\226rziu, anun\254\227-m\227, te rog."
gameforge.subquest_49._80_say = "Chiar as vrea s\227 \238ncerc Bingsu ...[ENTER]Dar ai dreptate. Poate c\227 Harang vrea doar s\227 se[ENTER]dea mare \186i tare \186i Bingsu nici s\227 nu existe."
gameforge.subquest_49._90_say = "Mul\254umesc pentru ajutor. Anun\254\227-m\227 dac\227 afli ceva[ENTER]nout\227\254i."
